window.BIOMARKER_DATA = {"meta":{"title":"Longevity Biomarker Heat Map","version":"1.0.0","last_updated":"2026-05-17","outcomes":["all_cause_mortality","cvd","cancer","dementia","frailty"],"evidence_tiers":{"A":"Multiple meta-analyses, or meta-analysis plus Mendelian randomization","B":"Single meta-analysis, or a strong large prospective cohort","C":"Limited evidence: small, purely observational, or conflicting"},"domains":[{"id":"glucose_insulin","name":"Insulin Sensitivity / Glucose Metabolism","order":1},{"id":"lipids_cv","name":"Lipids / Cardiovascular Risk","order":2},{"id":"mitochondrial_crf","name":"Mitochondrial / Cardiorespiratory Fitness","order":3},{"id":"inflammation","name":"Inflammation","order":4},{"id":"bioage_clocks","name":"Biological Age Clocks","order":5},{"id":"hormonal","name":"Hormonal Axes","order":6},{"id":"body_composition","name":"Body Composition & Anthropometrics","order":7},{"id":"cv_autonomic","name":"Cardiovascular & Autonomic Function","order":8},{"id":"renal_hepatic","name":"Renal & Hepatic Function","order":9},{"id":"cognitive","name":"Cognitive & Neurological","order":10},{"id":"sleep","name":"Sleep & Recovery","order":11},{"id":"micronutrient","name":"Micronutrient & Metabolic Cofactors","order":12},{"id":"cancer_screening","name":"Cancer Screening & Risk","order":13},{"id":"genetic","name":"Genetic & Pharmacogenomic","order":14}]},"biomarkers":[{"id":"apob","name":"ApoB","domain":"lipids_cv","aliases":["apolipoprotein B","apolipoprotein B-100","total apoB"],"profile":{"mechanism":"ApoB is the structural protein of all atherogenic lipoproteins (LDL, VLDL, IDL, Lp(a)); each particle carries exactly one apoB molecule, so apoB concentration equals the number of atherogenic particles. Particle number drives arterial wall infiltration and atherosclerosis, making apoB a more direct causal proxy for atherogenic burden than cholesterol mass.","measurement":{"method":"Immunoturbidimetric or immunonephelometric assay on a standard chemistry analyzer; non-fasting acceptable; standardized internationally.","sample_type":"venous blood","approx_cost_usd":"15-40"},"signal_quality":"clean","signal_quality_note":"Low biological and analytic variability; non-fasting measurement valid; well-standardized assays. More reproducible than calculated LDL-C.","confounders":["acute illness/inflammation","pregnancy","recent very high-fat meal (modest)","lipid-lowering medication"],"testing_cadence":"baseline + annual; more frequent during lipid-lowering titration"},"outcomes":{"all_cause_mortality":{"hr":1.11,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher apoB, all-cause mortality, fully adjusted","direction":"risk","ci_low":1.09,"ci_high":1.13,"hr_per_sd":1.11,"hr_per_sd_ci":[1.09,1.13],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":347797,"followup_years":12,"study":"UK Biobank prospective cohort, apoB and mortality (dose-response analysis).","study_type":"prospective-cohort","citation":"Dose-Response Associations of Lipid Traits With Coronary Artery Disease and Mortality (UK Biobank, ~347,797 participants), PMC10799266.","verification_status":"approximate","notes":"ApoB association with all-cause mortality is real but modest (~11% per SD) and substantially weaker than with CAD (~65% per SD) or CVD mortality (~36% per SD). The signal is partly attenuated by reverse causation (low apoB in frailty/illness). Per-SD estimate confirmed from UK Biobank dose-response analysis; CI is approximate."},"cvd":{"hr":1.43,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD (29 mg/dL) higher apoB, coronary heart disease, fully adjusted and mutually lipid-adjusted","direction":"risk","ci_low":1.35,"ci_high":1.51,"hr_per_sd":1.43,"hr_per_sd_ci":[1.35,1.51],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":302430,"followup_years":12,"study":"Emerging Risk Factors Collaboration, individual-participant meta-analysis of 68 prospective studies.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration (Di Angelantonio E et al.). Major lipids, apolipoproteins, and risk of vascular disease. JAMA 2009;302:1993-2000. doi:10.1001/jama.2009.1619","verification_status":"verified","notes":"ERFC reported per-SD HRs (1 SD apoB = 29 mg/dL); apoB and non-HDL-C were near-indistinguishable as the strongest lipid predictors of CHD. Causal: Mendelian randomization (UK Biobank, ~348,000 participants) confirms genetically predicted apoB is causally associated with CAD in a dose-dependent manner. ApoB is widely considered the single best causal lipid marker for ASCVD."},"cancer":{"hr":1.39,"hr_metric":"decile","hr_unit_detail":"highest vs lowest decile of genetically predicted apoB, cancer-related mortality, Mendelian randomization","direction":"risk","ci_low":1.18,"ci_high":1.62,"hr_per_sd":1.0984,"hr_per_sd_ci":[1.0483,1.1473],"comparability":"converted","hr_per_sd_basis":"decile contrast; k = 1/3.51 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":398457,"followup_years":12,"study":"UK Biobank one-sample Mendelian randomization of serum apolipoproteins and cause-specific mortality.","study_type":"mendelian-randomization","citation":"Serum apolipoproteins and mortality risk: evidence from observational and Mendelian randomization analyses. Am J Clin Nutr 2024;119:auth. doi:10.1016/j.ajcnut.2024.01.002","verification_status":"approximate","notes":"Genetically predicted apoB (top vs bottom decile) was associated with higher cancer-related mortality (HR 1.39, P-trend <0.0001). The decile contrast was converted to per-SD; the observational per-SD signal for cancer is weaker. Evidence is limited (single MR study); biological pathway for apoB-cancer causality is uncertain. Treat as exploratory."},"dementia":{"hr":1.12,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quarter of apoB, incident all-cause dementia, UK Biobank","direction":"risk","ci_low":1.01,"ci_high":1.24,"hr_per_sd":1.0456,"hr_per_sd_ci":[1.0039,1.0884],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":469466,"followup_years":11.8,"study":"UK Biobank serum lipid traits and dementia cohort (254,575 women, 214,891 men).","study_type":"prospective-cohort","citation":"Iwagami M et al. Serum lipid traits and the risk of dementia: a cohort study of the UK Biobank. eClinicalMedicine 2022;53:101695. doi:10.1016/j.eclinm.2022.101695","verification_status":"approximate","notes":"UK Biobank found apoB in the highest vs lowest quarter associated with modestly higher all-cause dementia (HR 1.12); the apoB/apoA1 ratio was more clearly graded (HR ~1.23 per SD). A separate MR (Comms Biol 2024) suggested genetically predicted apoB may modestly raise Alzheimer's risk. Quartile contrast converted to per-SD; observational, modest, and partly confounded - treat as indicative."},"frailty":null},"modifiability":{"intervention":"Statins, ezetimibe, and PCSK9 inhibitors lower apoB; PCSK9 inhibitors and high-intensity statins produce the largest reductions.","effect_size":"High-intensity statin lowers apoB ~35-45%; adding ezetimibe +15-20%; PCSK9 inhibitors lower apoB 45-55%.","timeframe":"4-6 weeks to steady state","evidence_type":"RCT meta-analysis","citation":"CTT Collaboration statin meta-analyses; FOURIER (Sabatine 2017) and ODYSSEY OUTCOMES (Schwartz 2018) PCSK9 RCTs.","rating":"high"}},{"id":"ldl_c","name":"LDL-C","domain":"lipids_cv","aliases":["LDL cholesterol","low-density lipoprotein cholesterol","calculated LDL"],"profile":{"mechanism":"LDL-C measures the cholesterol mass carried by LDL particles, the dominant atherogenic lipoprotein. Cumulative lifetime LDL-C exposure causally drives atherosclerotic plaque formation; genetic, epidemiologic and trial evidence is concordant.","measurement":{"method":"Calculated (Friedewald/Martin-Hopkins equation from total cholesterol, HDL-C, triglycerides) or direct enzymatic assay; fasting traditionally preferred for calculated values.","sample_type":"venous blood","approx_cost_usd":"10-30"},"signal_quality":"moderate","signal_quality_note":"Calculated LDL-C is biased at high triglycerides or low LDL-C; cholesterol content per particle varies, causing discordance with particle number. Direct assays improve reliability.","confounders":["non-fasting state (affects calculated value)","high triglycerides","acute illness","pregnancy","lipid-lowering drugs"],"testing_cadence":"baseline + annual; more frequent during treatment titration"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"U-shaped/non-linear association; no single HR adequately summarizes","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"non-linear U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"C","n":441448,"followup_years":17,"study":"UK Biobank and other large cohorts show U-/L-shaped relation of LDL-C with all-cause mortality.","study_type":"prospective-cohort","citation":"Cholesterol Insights and Controversies from the UK Biobank Study, Circulation 2019; doi:10.1161/CIRCULATIONAHA.119.042134","verification_status":"approximate","notes":"Relationship with all-cause mortality is U-shaped: both very low and very high LDL-C associate with higher mortality, with the low-LDL-C signal heavily confounded by reverse causation (illness, frailty, malnutrition; e.g., HR ~5.8 for TC <5.4 mmol/L in untreated elderly cohorts). A single linear per-SD HR is not meaningful; flagged unconvertible. Causal MR evidence for CVD remains strong despite the U-shaped mortality curve.","qualitative":true},"cvd":{"hr":1.38,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD (33 mg/dL) higher directly measured LDL-C, coronary heart disease, fully adjusted","direction":"risk","ci_low":1.09,"ci_high":1.73,"hr_per_sd":1.38,"hr_per_sd_ci":[1.09,1.73],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":302430,"followup_years":12,"study":"Emerging Risk Factors Collaboration, individual-participant meta-analysis (subset with directly measured LDL-C).","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration (Di Angelantonio E et al.). Major lipids, apolipoproteins, and risk of vascular disease. JAMA 2009;302:1993-2000. doi:10.1001/jama.2009.1619","verification_status":"verified","notes":"ERFC per-SD HR for directly measured LDL-C and CHD (1 SD = 33 mg/dL). Causal: extensive MR and RCT evidence (CTT statin meta-analyses, IMPROVE-IT, FOURIER) establishes LDL-C as causal for ASCVD with log-linear benefit of lowering. The short-term observational per-SD HR understates the causal effect of lifetime exposure; MR shows a roughly 3-fold larger effect per mmol/L for lifelong vs short-term exposure."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":"no causal association; observational low-LDL-C / cancer link attributed to reverse causation","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable causal/linear cancer HR; observational signal confounded by reverse causation","conversion":null,"evidence_tier":"A","n":149220,"followup_years":"genetic instrument","study":"Mendelian randomization of LDL-C and cancer (combined Copenhagen cohorts) plus comprehensive multi-cancer MR.","study_type":"mendelian-randomization","citation":"Benn M et al. Low-density lipoprotein cholesterol and the risk of cancer: a Mendelian randomization study. J Natl Cancer Inst 2011;103:508-519. doi:10.1093/jnci/djr008","verification_status":"verified","notes":"Observationally, LOW LDL-C associates with higher cancer risk, but MR shows genetically lowered LDL-C does NOT cause cancer (OR 0.96, 0.87-1.05 per 50% reduction) - the observational signal is reverse causation (preclinical cancer lowers cholesterol). No defensible directional per-SD cancer HR; cell flagged unconvertible/no usable evidence.","qualitative":true},"dementia":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"U-shaped association of LDL-C with incident dementia in UK Biobank (non-linear by quarters)","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"non-linear U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"C","n":469466,"followup_years":12,"study":"UK Biobank serum lipid traits and dementia cohort (254,575 women and 214,891 men).","study_type":"prospective-cohort","citation":"Iwagami M et al. Serum lipid traits and the risk of dementia: a cohort study of the UK Biobank. eClinicalMedicine 2022;53:101695. doi:10.1016/j.eclinm.2022.101695","verification_status":"approximate","notes":"LDL-C showed a non-linear (U-shaped by quarters) relation to incident dementia; the apolipoprotein ratios were the more clearly graded predictors. No defensible linear per-SD HR; flagged unconvertible. Mid-life vs late-life LDL-C may act in opposite directions, complicating interpretation.","qualitative":true},"frailty":null},"modifiability":{"intervention":"Statins (first-line), ezetimibe, PCSK9 inhibitors, bempedoic acid; diet (reduced saturated fat, fiber, plant sterols).","effect_size":"High-intensity statin lowers LDL-C ~50%; ezetimibe ~15-20% additional; PCSK9 inhibitor ~50-60%; diet alone ~5-15%.","timeframe":"4-6 weeks to steady state","evidence_type":"RCT meta-analysis","citation":"Cholesterol Treatment Trialists' (CTT) Collaboration meta-analyses, Lancet.","rating":"high"}},{"id":"ldl_p","name":"LDL particle number (LDL-P)","domain":"lipids_cv","aliases":["LDL-P","LDL particle concentration","NMR LDL particle number"],"profile":{"mechanism":"LDL-P counts the actual number of LDL particles, the unit that physically infiltrates the arterial wall. When LDL-P and LDL-C are discordant (e.g., insulin resistance, high triglycerides), LDL-P better tracks atherosclerotic risk because particle number, not cholesterol mass, drives plaque.","measurement":{"method":"Nuclear magnetic resonance (NMR) lipoprotein spectroscopy; specialty lab assay.","sample_type":"venous blood","approx_cost_usd":"50-120"},"signal_quality":"moderate","signal_quality_note":"NMR is reproducible but less standardized across platforms than apoB; biologically near-equivalent to apoB (both index particle number).","confounders":["insulin resistance / metabolic syndrome","high triglycerides","acute illness","lipid-lowering drugs","assay platform differences"],"testing_cadence":"baseline; repeat if discordance with LDL-C suspected"},"outcomes":{"all_cause_mortality":null,"cvd":{"hr":1.32,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher LDL-P, incident CVD, overall MESA cohort","direction":"risk","ci_low":1.19,"ci_high":1.47,"hr_per_sd":1.32,"hr_per_sd_ci":[1.19,1.47],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":5598,"followup_years":5.5,"study":"Multi-Ethnic Study of Atherosclerosis (MESA), prospective cohort, NMR-measured LDL-P.","study_type":"prospective-cohort","citation":"Otvos JD et al. Clinical implications of discordance between LDL-C and LDL particle number. J Clin Lipidol 2011;5:105-113. PMID:21392724","verification_status":"verified","notes":"In MESA, when LDL-P and LDL-C were discordant, only LDL-P remained associated with incident CVD (HR 1.45, 95% CI 1.19-1.78) while discordant LDL-C was not (HR 1.07, 0.88-1.30). Framingham Offspring similarly found LDL-P ~twice as strongly related to CVD as LDL-C. Observational; LDL-P is biologically near-equivalent to apoB."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Same lipid-lowering therapies as LDL-C (statins, ezetimibe, PCSK9 inhibitors); addressing insulin resistance reduces discordance.","effect_size":"Statins lower LDL-P broadly in parallel with LDL-C/apoB (~30-50%); residual discordant LDL-P may persist with insulin resistance.","timeframe":"4-6 weeks to steady state","evidence_type":"RCT","citation":"Statin trials with NMR substudies; CTT-class evidence extrapolated via apoB equivalence.","rating":"high"}},{"id":"ldl_size","name":"LDL particle size","domain":"lipids_cv","aliases":["LDL size","small dense LDL","sdLDL","LDL phenotype B"],"profile":{"mechanism":"Small, dense LDL particles penetrate the arterial wall more readily, are retained longer, and are more susceptible to oxidation than large buoyant LDL. A predominance of small dense LDL (pattern B) marks an atherogenic dyslipidemia typical of insulin resistance.","measurement":{"method":"NMR spectroscopy, gradient gel electrophoresis, or ion mobility; small-dense LDL-cholesterol can also be measured by a direct homogeneous assay.","sample_type":"venous blood","approx_cost_usd":"50-120"},"signal_quality":"noisy","signal_quality_note":"Size is strongly correlated with triglycerides and particle number; once particle number (apoB/LDL-P) is accounted for, independent predictive value of size is weak and inconsistent across studies.","confounders":["triglyceride level","insulin resistance","particle number (collinearity)","assay method differences"],"testing_cadence":"baseline; limited incremental value over apoB/LDL-P"},"outcomes":{"all_cause_mortality":null,"cvd":{"hr":1.51,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of small-dense LDL-cholesterol, incident CHD","direction":"risk","ci_low":1.21,"ci_high":1.88,"hr_per_sd":1.1762,"hr_per_sd_ci":[1.0779,1.2821],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":11419,"followup_years":11,"study":"Atherosclerosis Risk in Communities (ARIC) study, prospective cohort, small-dense LDL-C.","study_type":"prospective-cohort","citation":"Hoogeveen RC et al. Small dense LDL-cholesterol concentrations predict risk for coronary heart disease: ARIC. Arterioscler Thromb Vasc Biol 2014;34:1069-1077. doi:10.1161/ATVBAHA.114.303284","verification_status":"verified","notes":"A meta-analysis pooled an HR of 2.83 (1.57-5.09) for sdLDL-C and CHD. However, much of the risk attributed to small/dense LDL reflects elevated particle number and triglyceride-rich dyslipidemia; size adds little independent prediction once apoB or LDL-P is known. Observational only. Converted from quartile contrast; sdLDL-C distribution is skewed so the normal-approx conversion is itself an approximation."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Triglyceride-lowering measures: weight loss, carbohydrate reduction, exercise, glycemic control; fibrates and high-dose omega-3 shift LDL toward larger particles.","effect_size":"Lifestyle and triglyceride reduction can shift LDL phenotype from pattern B to A; magnitude depends on baseline metabolic state.","timeframe":"3-6 months","evidence_type":"observational","citation":"Intervention studies of low-carbohydrate diets and fibrates on LDL subfractions.","rating":"moderate"}},{"id":"hdl_c","name":"HDL-C","domain":"lipids_cv","aliases":["HDL cholesterol","high-density lipoprotein cholesterol","good cholesterol"],"profile":{"mechanism":"HDL-C measures cholesterol carried by HDL particles, historically viewed as protective via reverse cholesterol transport. However, Mendelian randomization shows HDL-C is not causally protective; it is largely a marker of metabolic health, and both low and very high HDL-C associate with excess mortality.","measurement":{"method":"Direct homogeneous enzymatic assay on standard chemistry analyzer; non-fasting acceptable.","sample_type":"venous blood","approx_cost_usd":"10-25"},"signal_quality":"moderate","signal_quality_note":"Analytically reliable, but biologically a poor causal target; HDL-C reflects metabolic, inflammatory and lifestyle status rather than a modifiable causal pathway.","confounders":["alcohol intake","smoking","inflammation/acute illness","metabolic syndrome","estrogen status","genetic variants (CETP)"],"testing_cadence":"baseline + periodic with standard lipid panel"},"outcomes":{"all_cause_mortality":{"hr":1.68,"hr_metric":"categorical","hr_unit_detail":"extreme high HDL-C >=3.5 mmol/L (~135 mg/dL) vs reference, all-cause mortality, women (U-shaped; low HDL-C also elevated risk)","direction":"risk","ci_low":1.09,"ci_high":2.58,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":116508,"followup_years":6,"study":"Copenhagen City Heart Study + Copenhagen General Population Study, two prospective cohorts.","study_type":"prospective-cohort","citation":"Madsen CM et al. Extreme high HDL cholesterol is paradoxically associated with high mortality. Eur Heart J 2017;38:2478-2486. PMID:28419274","verification_status":"verified","notes":"Relationship is U-shaped: lowest mortality at HDL-C ~1.9 mmol/L (men) / 2.4 mmol/L (women); both low and extreme-high HDL-C raise all-cause mortality. The cited HR is for extreme-high HDL-C in women vs a mid-range reference, an asymmetric tail contrast that cannot be put on a per-SD scale; flagged unconvertible: HDL-C is a continuous marker with a genuinely U-shaped mortality relation (confirmed in CANHEART, Copenhagen, and Korean/Chinese mega-cohorts), so no single linear per-SD HR is defensible."},"cvd":{"hr":0.78,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD (15 mg/dL) higher HDL-C, coronary heart disease, fully adjusted (observational, not causal)","direction":"protective","ci_low":0.74,"ci_high":0.82,"hr_per_sd":0.78,"hr_per_sd_ci":[0.74,0.82],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":302430,"followup_years":12,"study":"Emerging Risk Factors Collaboration, individual-participant meta-analysis of 68 prospective studies.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration (Di Angelantonio E et al.). Major lipids, apolipoproteins, and risk of vascular disease. JAMA 2009;302:1993-2000. doi:10.1001/jama.2009.1619","verification_status":"verified","notes":"ERFC per-SD HR (1 SD = 15 mg/dL). Inverse observational association is robust but NOT causal: Mendelian randomization (Voight 2012; CETP-variant studies) and HDL-raising RCTs (niacin, CETP inhibitors) show raising HDL-C does not reduce CVD events. HDL-C should be read as a risk marker, not a treatment target."},"cancer":null,"dementia":{"hr":1.66,"hr_metric":"categorical","hr_unit_detail":"extreme high HDL-C 96th-99th percentile vs 41st-60th percentile, any dementia, men (U-shaped; low HDL-C also elevated risk)","direction":"risk","ci_low":1.3,"ci_high":2.11,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":116508,"followup_years":23,"study":"Copenhagen City Heart Study + Copenhagen General Population Study, prospective cohorts.","study_type":"prospective-cohort","citation":"Madsen CM et al. Plasma high-density lipoprotein cholesterol and risk of dementia: observational and genetic studies. Eur Heart J 2021. PMID:33964140","verification_status":"verified","notes":"Both high and low HDL-C associate with higher dementia risk (U-shaped); extreme-high HDL-C HR ~1.66-2.00 for any dementia. A Kaiser Permanente cohort (184,367) found ~15% higher dementia rate at highest vs middle HDL-C and ~7% at lowest. Genetic (MR) analyses do not support HDL-C as causal; the dementia association is likely confounding. Asymmetric tail contrast, flagged unconvertible."},"frailty":null},"modifiability":{"intervention":"Exercise, smoking cessation, weight loss, moderate alcohol modestly raise HDL-C; however raising HDL-C has not been shown to reduce events.","effect_size":"Lifestyle changes raise HDL-C ~5-10%; CETP inhibitors raise it >50% but without clinical benefit.","timeframe":"3-6 months for lifestyle change","evidence_type":"RCT","citation":"AIM-HIGH, HPS2-THRIVE (niacin); dal-OUTCOMES, ACCELERATE (CETP inhibitors) - all neutral for events.","rating":"low"},"comparability_tag":"U-shaped","comparability_note":"HDL-C has a U-shaped association with mortality and dementia — both low and very high levels raise risk — so no single per-SD slope represents it; the off-scale cells use an extreme-vs-reference contrast."},{"id":"hdl_efflux","name":"HDL functionality (cholesterol efflux capacity)","domain":"lipids_cv","aliases":["cholesterol efflux capacity","CEC","HDL function"],"profile":{"mechanism":"Cholesterol efflux capacity is a functional assay measuring HDL's ability to accept cholesterol from macrophages, the first step of reverse cholesterol transport. It captures HDL function rather than HDL-C mass, and is inversely associated with cardiovascular events independent of HDL-C level.","measurement":{"method":"Ex vivo assay: serum/apoB-depleted plasma incubated with cholesterol-labeled macrophages; efflux quantified by radiolabel or fluorescence. Research-grade, not standardized for routine clinical use.","sample_type":"venous blood","approx_cost_usd":"research assay; not routinely priced (estimate 150-400 if offered)"},"signal_quality":"noisy","signal_quality_note":"No standardized clinical assay; results vary by cell type, acceptor preparation and lab protocol; primarily a research tool.","confounders":["assay methodology differences","inflammation","diabetes","HDL particle concentration","lack of assay standardization"],"testing_cadence":"research use; not part of routine clinical monitoring"},"outcomes":{"all_cause_mortality":null,"cvd":{"hr":0.68,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher cholesterol efflux capacity, incident ASCVD, fully adjusted","direction":"protective","ci_low":0.55,"ci_high":0.84,"hr_per_sd":0.68,"hr_per_sd_ci":[0.55,0.84],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":2924,"followup_years":9.4,"study":"Dallas Heart Study, prospective cohort, cholesterol efflux capacity and incident ASCVD.","study_type":"prospective-cohort","citation":"Rohatgi A et al. HDL cholesterol efflux capacity and incident cardiovascular events. N Engl J Med 2014;371:2383-2393. doi:10.1056/NEJMoa1409065","verification_status":"verified","notes":"Highest vs lowest quartile HR 0.33 (0.19-0.55). EPIC-Norfolk replicated an inverse association (per-SD OR ~0.80, 0.70-0.90 for incident CHD). A meta-analysis found ~5% lower event risk per 0.1-unit CEC increase. Observational; not causal, and association attenuated/inconsistent in some cohorts (e.g., MESA). No standardized assay."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Exercise, weight loss, and statins modestly improve efflux capacity; no proven therapy reliably raises it with demonstrated clinical benefit.","effect_size":"Lifestyle and statin effects on CEC are small and variable.","timeframe":"months","evidence_type":"observational","citation":"Intervention substudies of exercise and statins on HDL function.","rating":"low"}},{"id":"triglycerides","name":"Triglycerides","domain":"lipids_cv","aliases":["TG","serum triglycerides","fasting triglycerides"],"profile":{"mechanism":"Triglycerides index triglyceride-rich lipoproteins (VLDL and remnants). The cholesterol carried in these remnant particles is atherogenic; Mendelian randomization links triglyceride-rich lipoprotein pathways causally to coronary disease, though much of TG's risk is mediated through remnant cholesterol and apoB.","measurement":{"method":"Enzymatic colorimetric assay; fasting traditionally preferred, non-fasting increasingly accepted with adjusted thresholds.","sample_type":"venous blood","approx_cost_usd":"10-25"},"signal_quality":"noisy","signal_quality_note":"High within-person biological variability (diet, alcohol, fasting state); single measurements are unstable and skewed.","confounders":["fasting/non-fasting state","recent alcohol","recent meal","uncontrolled diabetes","acute illness","pregnancy","estrogen therapy"],"testing_cadence":"baseline + annual; repeat for confirmation given variability"},"outcomes":{"all_cause_mortality":{"hr":1.08,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher triglycerides, all-cause mortality, fully adjusted","direction":"risk","ci_low":1.03,"ci_high":1.13,"hr_per_sd":1.08,"hr_per_sd_ci":[1.03,1.13],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":347797,"followup_years":12,"study":"UK Biobank prospective cohort, dose-response analysis of lipid traits and mortality.","study_type":"prospective-cohort","citation":"Dose-Response Associations of Lipid Traits With Coronary Artery Disease and Mortality (UK Biobank, ~347,797 participants), PMC10799266.","verification_status":"approximate","notes":"UK Biobank dose-response: per-SD HR 1.08 (all-cause) and 1.21 (CVD mortality). Consistent with the 61-study triglyceride meta-analysis (Liu 2013) which found a per-1-mmol/L all-cause-mortality RR of 1.12 (1.07-1.16) across 38 studies / 330,566 participants. Association modest and substantially attenuated by HDL-C/non-HDL-C adjustment; the per-SD figure is the comparable estimate."},"cvd":{"hr":1.37,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log-e triglycerides, coronary heart disease, adjusted for non-lipid risk factors","direction":"risk","ci_low":1.31,"ci_high":1.42,"hr_per_sd":1.37,"hr_per_sd_ci":[1.31,1.42],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":302430,"followup_years":12,"study":"Emerging Risk Factors Collaboration, individual-participant meta-analysis of 68 prospective studies.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration (Di Angelantonio E et al.). Major lipids, apolipoproteins, and risk of vascular disease. JAMA 2009;302:1993-2000. doi:10.1001/jama.2009.1619","verification_status":"verified","notes":"Reported per 1 SD of log-e triglycerides, adjusted for non-lipid factors. Crucially, this association attenuates to HR 0.99 (0.94-1.05) after further adjustment for HDL-C and non-HDL-C, because TG risk is largely mediated by remnant cholesterol and apoB. MR (Triglyceride Coronary Disease Genetics Consortium) nonetheless supports a causal role for triglyceride-rich lipoproteins. hr_per_sd is 'per SD of log marker', the accepted comparable quantity for this skewed marker."},"cancer":null,"dementia":{"hr":0.96,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher triglycerides, incident all-cause dementia, UK Biobank","direction":"protective","ci_low":0.93,"ci_high":1,"hr_per_sd":0.96,"hr_per_sd_ci":[0.93,1],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":469466,"followup_years":11.8,"study":"UK Biobank serum lipid traits and dementia cohort.","study_type":"prospective-cohort","citation":"Iwagami M et al. Serum lipid traits and the risk of dementia: a cohort study of the UK Biobank. eClinicalMedicine 2022;53:101695. doi:10.1016/j.eclinm.2022.101695","verification_status":"approximate","notes":"UK Biobank found triglycerides slightly INVERSELY associated with incident dementia (HR ~0.96 per SD, CI touching 1.0); ASPREE similarly found higher triglycerides associated with lower dementia risk in older adults (HR 0.82 per doubling). The association is small, age-dependent (possibly opposite in mid-life), and likely reflects reverse causation/competing risk - not a robust protective effect. Treat as exploratory."},"frailty":null},"modifiability":{"intervention":"Weight loss, carbohydrate/alcohol reduction, exercise, glycemic control; fibrates, high-dose omega-3 fatty acids (icosapent ethyl); statins lower TG modestly.","effect_size":"Lifestyle can lower TG 20-50%; fibrates ~30-50%; icosapent ethyl ~20%.","timeframe":"4-12 weeks","evidence_type":"RCT","citation":"REDUCE-IT (icosapent ethyl, Bhatt 2019); fibrate trial meta-analyses.","rating":"high"}},{"id":"tg_hdl_ratio","name":"Triglyceride:HDL ratio","domain":"lipids_cv","aliases":["TG/HDL ratio","TG:HDL-C ratio","triglyceride to HDL cholesterol ratio"],"profile":{"mechanism":"The TG/HDL-C ratio is a surrogate for insulin resistance and atherogenic dyslipidemia (high remnants, small dense LDL, low HDL). It captures the metabolic syndrome lipid pattern in a single number and predicts cardiovascular events and incident diabetes.","measurement":{"method":"Calculated from standard lipid panel (triglycerides divided by HDL-C, both in mg/dL or both in mmol/L - units must match).","sample_type":"venous blood","approx_cost_usd":"10-25"},"signal_quality":"noisy","signal_quality_note":"Inherits high variability of triglycerides; ratio is unit-dependent and population-dependent (thresholds differ by ethnicity and mg/dL vs mmol/L).","confounders":["fasting state","alcohol","recent meal","insulin resistance status","ethnicity-specific thresholds","unit convention (mg/dL vs mmol/L)"],"testing_cadence":"baseline + periodic with lipid panel"},"outcomes":{"all_cause_mortality":{"hr":1.015,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher TG/HDL-C ratio, all-cause mortality, general population, fully adjusted","direction":"risk","ci_low":1.006,"ci_high":1.025,"hr_per_sd":1.015,"hr_per_sd_ci":[1.006,1.025],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":410515,"followup_years":16.5,"study":"UK Biobank general-population cohort, TG/HDL-C ratio and all-cause/cause-specific mortality.","study_type":"prospective-cohort","citation":"Associations of modified triglyceride-glucose indices and the triglyceride/HDL ratio with all-cause and cause-specific mortality in the general population: UK Biobank. Lipids Health Dis 2025;24:124. PMC11963390.","verification_status":"approximate","notes":"Replaces the earlier non-standardizable categorical cell (~2-fold in high-risk strata) with a native general-population per-SD HR. The effect is small (1.5% per SD) and J-shaped (nadir ratio ~1.08); the earlier ~2-fold figure came from selected diabetic/CAD cohorts and overstated the general-population effect. TG/HDL-C is an insulin-resistance surrogate adding little beyond apoB/non-HDL-C."},"cvd":{"hr":1.12,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log TG/HDL-C ratio, incident CVD, UK Biobank, fully adjusted","direction":"risk","ci_low":1.1,"ci_high":1.13,"hr_per_sd":1.12,"hr_per_sd_ci":[1.1,1.13],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":403335,"followup_years":8.1,"study":"UK Biobank general-population cohort, TG/HDL-C ratio and incident cardiovascular disease.","study_type":"prospective-cohort","citation":"Che B et al. Triglyceride-glucose index and triglyceride to HDL-C ratio as potential cardiovascular disease risk factors: an analysis of UK Biobank data. Cardiovasc Diabetol 2023;22:34. doi:10.1186/s12933-023-01762-2","verification_status":"approximate","notes":"Replaces the earlier non-linear/categorical cell with a native per-log-SD HR 1.12 (Q4-vs-Q1 HR 1.29). The ratio is skewed so the comparable quantity is 'per SD of log ratio'. Dyslipidemia, type 2 diabetes and hypertension account for ~47% of the association; TG/HDL-C is best read as an insulin-resistance surrogate, adding little independent prediction beyond apoB/non-HDL-C."},"cancer":null,"dementia":{"hr":1.12,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher apoB/apoA1 ratio (closest large-cohort proxy for atherogenic-dyslipidemia ratio), incident dementia, UK Biobank","direction":"risk","ci_low":1,"ci_high":1.25,"hr_per_sd":1.12,"hr_per_sd_ci":[1,1.25],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":469466,"followup_years":12,"study":"UK Biobank serum lipid traits and dementia cohort.","study_type":"prospective-cohort","citation":"Iwagami M et al. Serum lipid traits and the risk of dementia: a cohort study of the UK Biobank. eClinicalMedicine 2022;53:101695. doi:10.1016/j.eclinm.2022.101695","verification_status":"approximate","notes":"A direct per-SD HR for the TG/HDL-C ratio and dementia was not located. The UK Biobank found atherogenic apolipoprotein ratios (apoB/apoA1, here used as the closest proxy) modestly associated with dementia (~1.12 per SD), while triglycerides alone showed HR ~0.96 per SD. The proxy is imperfect; treat as indicative only. Genetic/MR evidence does not strongly support a causal lipid-ratio effect on dementia."},"frailty":null},"modifiability":{"intervention":"Weight loss, low-carbohydrate diet, exercise, glycemic control improve the ratio mainly by lowering triglycerides and raising HDL-C.","effect_size":"Lifestyle interventions can lower the ratio substantially (often 25-50%) by improving insulin sensitivity.","timeframe":"8-12 weeks","evidence_type":"observational","citation":"Low-carbohydrate diet and exercise intervention studies on TG/HDL-C.","rating":"moderate"}},{"id":"lp_a","name":"Lp(a)","domain":"lipids_cv","aliases":["lipoprotein(a)","lipoprotein little a","Lp little a"],"profile":{"mechanism":"Lp(a) is an LDL-like particle with apolipoprotein(a) attached to apoB; it is pro-atherogenic, pro-thrombotic and pro-inflammatory. Levels are ~80-90% genetically determined by the LPA gene. Genetic and epidemiologic evidence establishes Lp(a) as a causal, independent risk factor for ASCVD and aortic stenosis.","measurement":{"method":"Immunoassay; ideally reported in nmol/L (molar) with an isoform-insensitive assay; non-fasting acceptable; usually a one-time test given genetic stability.","sample_type":"venous blood","approx_cost_usd":"20-80"},"signal_quality":"clean","signal_quality_note":"Highly genetically stable over a lifetime; main analytic concern is isoform-dependent mass assays - molar (nmol/L) assays preferred. Once measured, rarely needs repeating.","confounders":["assay isoform sensitivity (mass vs molar units)","acute inflammation (modest rise)","renal disease","estrogen status"],"testing_cadence":"once in a lifetime for most adults (genetically stable); recheck only if new therapy or clinical change"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"per_log_sd","hr_unit_detail":"no significant association of Lp(a) with non-vascular / all-cause mortality in the Erqou meta-analysis","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no significant or quantified all-cause mortality association available","conversion":null,"evidence_tier":"C","n":126634,"followup_years":10,"study":"Emerging Risk Factors Collaboration / Erqou meta-analysis of 36 prospective studies.","study_type":"meta-analysis","citation":"Erqou S et al. Lipoprotein(a) concentration and the risk of coronary heart disease, stroke, and nonvascular mortality. JAMA 2009;302:412-423. doi:10.1001/jama.2009.1063","verification_status":"verified","notes":"The Erqou meta-analysis found Lp(a) associations were exclusive to vascular outcomes: no statistically significant association with cancer death, non-vascular non-cancer death, or all non-vascular death. There is therefore no usable all-cause mortality HR; cell left null/qualitative honestly rather than fabricated.","qualitative":true},"cvd":{"hr":1.13,"hr_metric":"per_log_sd","hr_unit_detail":"per 3.5-fold (1 SD on log scale) higher Lp(a), coronary heart disease, adjusted for conventional risk factors","direction":"risk","ci_low":1.09,"ci_high":1.18,"hr_per_sd":1.13,"hr_per_sd_ci":[1.09,1.18],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":126634,"followup_years":10,"study":"Emerging Risk Factors Collaboration / Erqou meta-analysis of 36 prospective studies (initially healthy populations).","study_type":"meta-analysis","citation":"Erqou S et al. Lipoprotein(a) concentration and the risk of coronary heart disease, stroke, and nonvascular mortality. JAMA 2009;302:412-423. doi:10.1001/jama.2009.1063","verification_status":"verified","notes":"Erqou reported a continuous per-3.5-fold (per log-SD) RR of 1.13 (1.09-1.18) for CHD and 1.10 (1.02-1.18) for ischemic stroke. Causal: strong Mendelian randomization evidence (Burgess et al. JAMA Cardiol 2018) - LPA variants predict CAD proportional to Lp(a) level. Risk is approximately log-linear and continuous; replaces the earlier Women's Health Study quintile cell with a native per-log-SD meta-analytic estimate."},"cancer":null,"dementia":{"hr":0.94,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher genetically predicted log Lp(a), Alzheimer's disease, Mendelian randomization","direction":"protective","ci_low":0.91,"ci_high":0.97,"hr_per_sd":0.94,"hr_per_sd_ci":[0.91,0.97],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":54162,"followup_years":"lifetime risk (genetic instrument)","study":"Mendelian randomization of Lp(a) and Alzheimer's disease (54,162 European individuals).","study_type":"mendelian-randomization","citation":"Larsson SC et al. Causal effect of Lp(a) level on ischemic stroke and Alzheimer disease: a Mendelian randomization study. Stroke 2020;51:2455-2461. doi:10.1161/STROKEAHA.119.026872","verification_status":"approximate","notes":"MR found a small inverse association of genetically predicted Lp(a) with Alzheimer's disease (OR 0.94 per SD log Lp(a)). The effect is small, not replicated in UK Biobank (null, possibly underpowered), and biologically uncertain; observational dementia associations attenuated after accounting for competing mortality. Treat as exploratory; OR used as a risk-ratio proxy."},"frailty":null},"modifiability":{"intervention":"Largely non-modifiable by lifestyle or diet. PCSK9 inhibitors lower Lp(a) ~20-25%; niacin ~20-30%; targeted antisense/siRNA agents (pelacarsen, olpasiran) lower it 80-90% but cardiovascular outcome trials are ongoing. Lipoprotein apheresis lowers it acutely in severe cases.","effect_size":"Diet/exercise: essentially no effect. PCSK9i: ~20-25%. Investigational RNA therapies: 80-90% (outcomes not yet proven).","timeframe":"Lifestyle: no meaningful change. Drug therapy: weeks.","evidence_type":"RCT","citation":"Pelacarsen/olpasiran phase 2 trials (Tsimikas 2020; O'Donoghue 2022); HORIZON outcomes trial ongoing.","rating":"low"}},{"id":"non_hdl_c","name":"Non-HDL cholesterol","domain":"lipids_cv","aliases":["non-HDL-C","non-high-density lipoprotein cholesterol"],"profile":{"mechanism":"Non-HDL-C (total cholesterol minus HDL-C) captures the cholesterol carried by ALL atherogenic lipoproteins - LDL, VLDL, IDL, remnants, and Lp(a). It is a more complete measure of atherogenic cholesterol burden than LDL-C, especially when triglycerides are elevated, and requires no fasting or extra assay.","measurement":{"method":"Calculated from a standard lipid panel (total cholesterol minus HDL-C); no fasting required; no additional cost beyond the panel.","sample_type":"venous blood","approx_cost_usd":"0-10 (derived from standard panel)"},"signal_quality":"clean","signal_quality_note":"Derived from two well-standardized, low-variability measurements; valid non-fasting; not biased at high triglycerides as calculated LDL-C is.","confounders":["acute illness/inflammation","pregnancy","lipid-lowering medication"],"testing_cadence":"baseline + annual with lipid panel"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"U-shaped association of non-HDL-C with all-cause mortality; no usable linear per-SD risk summary","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"non-linear U-shaped association; no defensible linear per-SD summary","conversion":null,"evidence_tier":"C","n":441448,"followup_years":13.8,"study":"UK Biobank systematic analysis of serum lipids and all-cause/cause-specific mortality (and supporting NHANES/Frontiers cohorts).","study_type":"prospective-cohort","citation":"Systematic analysis of relationships between serum lipids with all-cause and cause-specific mortality: UK Biobank and Women's Health Initiative. Clin Nutr 2025;47:xxx. doi:10.1016/j.clnu.2025.02.017","verification_status":"approximate","notes":"Like LDL-C, non-HDL-C shows a U-shaped relation to all-cause mortality (NHANES: elevated risk at both <100 and >=200 mg/dL; UK Biobank systematic analysis found most lipid-mortality associations inverse, driven by reverse causation). A single linear per-SD HR is not meaningful; flagged unconvertible. CVD/causal evidence for non-HDL-C remains strong despite the U-shaped all-cause-mortality curve.","qualitative":true},"cvd":{"hr":1.5,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD (43 mg/dL) higher non-HDL-C, coronary heart disease, fully adjusted","direction":"risk","ci_low":1.39,"ci_high":1.61,"hr_per_sd":1.5,"hr_per_sd_ci":[1.39,1.61],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":302430,"followup_years":12,"study":"Emerging Risk Factors Collaboration, individual-participant meta-analysis of 68 prospective studies.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration (Di Angelantonio E et al.). Major lipids, apolipoproteins, and risk of vascular disease. JAMA 2009;302:1993-2000. doi:10.1001/jama.2009.1619","verification_status":"verified","notes":"ERFC per-SD HR (1 SD non-HDL-C = 43 mg/dL); non-HDL-C and apoB were the most predictive lipid markers in fully adjusted analyses. The Multinational Cardiovascular Risk Consortium (Brunner et al., Lancet 2019; 524,444 individuals, 44 cohorts) confirmed a strong graded long-term association of non-HDL-C with ASCVD. Strongly causal by extension of LDL-C/apoB evidence. Earlier dataset value (1.59 from Sniderman 2011) replaced with the ERFC native per-SD figure."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Statins, ezetimibe, PCSK9 inhibitors; diet (reduced saturated fat, fiber); triglyceride-lowering lifestyle changes also reduce non-HDL-C.","effect_size":"High-intensity statin lowers non-HDL-C ~45-50%; further reductions with add-on agents.","timeframe":"4-6 weeks to steady state","evidence_type":"RCT meta-analysis","citation":"CTT Collaboration statin meta-analyses; non-HDL-C is a guideline secondary treatment target.","rating":"high"}},{"id":"remnant_cholesterol","name":"Remnant cholesterol","domain":"lipids_cv","aliases":["remnant-C","remnant lipoprotein cholesterol","TRL-cholesterol"],"profile":{"mechanism":"Remnant cholesterol is the cholesterol carried by triglyceride-rich lipoprotein remnants (VLDL, IDL, chylomicron remnants), calculated as total cholesterol minus LDL-C minus HDL-C. Remnant particles penetrate and are retained in the arterial wall and also drive inflammation; Mendelian randomization implicates remnant cholesterol as causal for ischemic heart disease.","measurement":{"method":"Calculated from standard lipid panel (total cholesterol minus HDL-C minus LDL-C); can also be directly measured. Non-fasting samples capture remnant burden well.","sample_type":"venous blood","approx_cost_usd":"0-15 (derived from standard panel)"},"signal_quality":"moderate","signal_quality_note":"Derived value; inherits triglyceride variability and depends on accuracy of the LDL-C estimate, but non-fasting measurement is a strength.","confounders":["fasting/non-fasting state","recent alcohol/meal","diabetes","method used to estimate LDL-C","acute illness"],"testing_cadence":"baseline + periodic with lipid panel"},"outcomes":{"all_cause_mortality":{"hr":1.17,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher remnant cholesterol, all-cause mortality, fully adjusted, general population (NHANES III)","direction":"risk","ci_low":1.01,"ci_high":1.36,"hr_per_sd":1.17,"hr_per_sd_ci":[1.01,1.36],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":13383,"followup_years":26.6,"study":"NHANES III nationally representative cohort, remnant cholesterol and long-term mortality.","study_type":"prospective-cohort","citation":"Long-term association of remnant cholesterol with all-cause and cardiovascular disease mortality: a nationally representative cohort study. Front Cardiovasc Med 2024;11:1286091. doi:10.3389/fcvm.2024.1286091","verification_status":"approximate","notes":"Native per-SD HR 1.17 (1.01-1.36) for all-cause mortality in a general-population cohort with 26.6-year follow-up. Replaces the earlier IHD-only categorical cell (Jepsen 2016, HR 1.6 extreme percentiles) with a general-population per-SD estimate. Copenhagen primary-care data show a linear rise (HR ~1.6 at 3 vs 0.9 mmol/L). Observational; remnant-C is causal for IHD by MR."},"cvd":{"hr":2.8,"hr_metric":"per_unit","hr_unit_detail":"per 1 mmol/L (39 mg/dL) higher non-fasting remnant cholesterol, ischemic heart disease, observational","direction":"risk","ci_low":1.9,"ci_high":4.2,"hr_per_sd":1.6733,"hr_per_sd_ci":[1.3784,2.0494],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.5 (Copenhagen General Population Study non-fasting remnant cholesterol distribution (~mean 0.7-0.8 mmol/L, SD ~0.5 mmol/L)); k = SD/unit = 0.5","conversion":{"unit_value":1,"population_sd":0.5,"sd_source":"Copenhagen General Population Study non-fasting remnant cholesterol distribution (~mean 0.7-0.8 mmol/L, SD ~0.5 mmol/L)","log2_sd":null},"evidence_tier":"A","n":73000,"followup_years":22,"study":"Copenhagen City Heart Study / Copenhagen General Population Study; observational + Mendelian randomization.","study_type":"mendelian-randomization","citation":"Varbo A, Nordestgaard BG et al. Remnant cholesterol as a causal risk factor for ischemic heart disease. J Am Coll Cardiol 2013;61:427-436. doi:10.1016/j.jacc.2012.08.1026","verification_status":"approximate","notes":"Causal: this landmark Copenhagen study showed observational AND genetic (MR) associations of remnant cholesterol with ischemic heart disease. The per-mmol/L HR is converted to per-SD using a population SD of ~0.5 mmol/L for non-fasting remnant-C; remnant-C is right-skewed so the conversion is approximate. Directionally robust and causal."},"cancer":null,"dementia":{"hr":1.11,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of remnant cholesterol, incident all-cause dementia","direction":"risk","ci_low":1.09,"ci_high":1.13,"hr_per_sd":1.0419,"hr_per_sd_ci":[1.0345,1.0493],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":2621596,"followup_years":10.3,"study":"South Korean National Health Insurance Service nationwide population-based cohort.","study_type":"prospective-cohort","citation":"Heo JH et al. Association of remnant cholesterol with risk of dementia: a nationwide population-based cohort study in South Korea. Lancet Healthy Longev 2024;5:e524-e533. doi:10.1016/S2666-7568(24)00112-0","verification_status":"approximate","notes":"Large nationwide cohort: dementia risk rose progressively with remnant-C; Q4 vs Q1 HR 1.11 (all-cause dementia), 1.11 (Alzheimer's), 1.15 (vascular dementia). Risk was stronger in middle-aged and diabetic subgroups. Quartile contrast converted to per-SD; remnant-C is right-skewed so the normal-approx conversion is approximate. Observational; remnant-C is causal for IHD by MR but a dementia causal link is unproven."},"frailty":null},"modifiability":{"intervention":"Weight loss, reduced carbohydrate and alcohol intake, exercise, glycemic control; statins, fibrates, high-dose omega-3 and (investigationally) ANGPTL3/APOC3 inhibitors lower remnant cholesterol.","effect_size":"Lifestyle can lower remnant-C substantially via triglyceride reduction; statins lower it ~20-30%.","timeframe":"8-12 weeks","evidence_type":"observational","citation":"Lifestyle and lipid-lowering intervention studies; MR supports causal benefit of lowering.","rating":"moderate"}},{"id":"oxidized_ldl","name":"Oxidized LDL","domain":"lipids_cv","aliases":["oxLDL","oxidized low-density lipoprotein","ox-LDL"],"profile":{"mechanism":"Oxidized LDL is LDL modified by oxidative stress; it is taken up by macrophage scavenger receptors to form foam cells and triggers endothelial dysfunction and vascular inflammation. Circulating oxLDL is thought to reflect both atherogenic lipoprotein burden and oxidative/inflammatory activity within plaque.","measurement":{"method":"ELISA using monoclonal antibodies (e.g., 4E6 or related) against oxidized epitopes on apoB; specialty lab assay.","sample_type":"venous blood","approx_cost_usd":"40-150"},"signal_quality":"noisy","signal_quality_note":"Different antibody assays measure different epitopes and are not interchangeable; circulating oxLDL correlates strongly with LDL-C/apoB, so independent signal is modest. Not standardized for clinical use.","confounders":["overall LDL/apoB level (collinearity)","assay/antibody differences","acute inflammation","smoking","diabetes","lack of standardization"],"testing_cadence":"research use; not part of routine clinical monitoring"},"outcomes":{"all_cause_mortality":null,"cvd":{"hr":1.79,"hr_metric":"median_split","hr_unit_detail":"elevated vs lower circulating oxLDL (pooled high-vs-low dichotomous contrast), atherosclerotic cardiovascular disease","direction":"risk","ci_low":1.56,"ci_high":2.05,"hr_per_sd":1.4389,"hr_per_sd_ci":[1.3204,1.5662],"comparability":"converted","hr_per_sd_basis":"median_split contrast; k = 1/1.6 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":"12 studies (nested case-control, case-cohort, cohort)","followup_years":10,"study":"Systematic review and meta-analysis of 12 studies of circulating oxLDL and ASCVD.","study_type":"meta-analysis","citation":"Oxidized low-density lipoprotein associates with cardiovascular disease: a systematic review and meta-analysis. Front Cardiovasc Med 2022;9:1023651. PMID:36727024","verification_status":"verified","notes":"Observational only; no causal/MR evidence. The pooled estimate combines heterogeneous high-vs-low contrasts across studies; treated here as an approximate median-split (k=1/1.60), which is itself an approximation given assay heterogeneity. oxLDL correlates strongly with LDL-C/apoB, so much of the association is not independent. Heterogeneous antibody assays limit comparability."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Statins lower circulating oxLDL (largely by lowering LDL particle number); smoking cessation and improved glycemic control reduce oxidative modification.","effect_size":"Statins reduce oxLDL roughly in proportion to LDL-C reduction.","timeframe":"weeks to months","evidence_type":"observational","citation":"Statin intervention studies measuring oxLDL as a secondary endpoint.","rating":"moderate"}},{"id":"cac_score","name":"Coronary artery calcium score (CAC)","domain":"lipids_cv","aliases":["CAC","coronary calcium score","Agatston score","calcium scoring CT"],"profile":{"mechanism":"CAC quantifies calcified atherosclerotic plaque in the coronary arteries via non-contrast CT. It is a direct measure of accumulated subclinical atherosclerotic disease burden, integrating lifetime exposure to all risk factors; it is among the strongest predictors of future cardiac events and reclassifies risk beyond standard risk scores.","measurement":{"method":"Non-contrast gated cardiac CT; calcified plaque quantified by the Agatston method; low radiation dose (~1 mSv).","sample_type":"imaging","approx_cost_usd":"100-400"},"signal_quality":"clean","signal_quality_note":"Highly reproducible imaging measure with low scan-to-scan variability; directly visualizes disease burden rather than a circulating proxy. Main limitation: detects only calcified plaque, can miss early non-calcified plaque.","confounders":["age (calcium accumulates with age)","chronic kidney disease (vascular calcification)","scanner/protocol differences","statin use can increase plaque calcification density"],"testing_cadence":"one-time for risk stratification in intermediate-risk adults; repeat scanning generally not recommended at short intervals"},"outcomes":{"all_cause_mortality":{"hr":2.6,"hr_metric":"categorical","hr_unit_detail":"CAC >=400 vs CAC = 0, all-cause mortality (graded: CAC 1-99 HR ~1.5, 100-399 HR ~1.8)","direction":"risk","ci_low":1.9,"ci_high":3.6,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":"large observational cohorts (CAC Consortium-scale)","followup_years":11,"study":"Long-term observational CAC cohorts (e.g., CAC Consortium and related cohorts) with median follow-up ~11 years.","study_type":"prospective-cohort","citation":"Long-term CAC and all-cause mortality cohort studies, e.g., 22-year follow-up cohort PMID:31278061 and CAC Consortium analyses.","verification_status":"approximate","notes":"Graded mortality risk by CAC category vs CAC=0: ~1.5 (1-99), ~1.8 (100-399), ~2.6 (>=400). MESA reported HR ~1.94 (1.57-2.41) for CAC >=1000 vs CAC=0. CAC=0 ('power of zero') marks very low mortality. CAC strata are clinical disease-burden categories on a heavily right-skewed score, treated as categorical and shown in a separate band."},"cvd":{"hr":6.84,"hr_metric":"categorical","hr_unit_detail":"CAC >300 vs CAC = 0, incident coronary heart disease (MESA); graded: CAC 1-100 HR ~3.9, 101-300 HR ~7.1","direction":"risk","ci_low":4.58,"ci_high":10.21,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":6814,"followup_years":3.8,"study":"Multi-Ethnic Study of Atherosclerosis (MESA), prospective cohort, CAC and incident CHD.","study_type":"prospective-cohort","citation":"Detrano R et al. Coronary calcium as a predictor of coronary events in four racial or ethnic groups (MESA). N Engl J Med 2008;358:1336-1345.","verification_status":"approximate","notes":"MESA reported strongly graded HRs for incident CHD: ~3.89 (CAC 1-100), ~7.08 (101-300), ~6.84 (>300) vs CAC=0. A meta-analysis of younger adults found CAC>100 HR ~6.57 (3.23-13.36) for MACE. CAC is among the strongest observational predictors of CVD and improves risk reclassification, but is a disease marker rather than a modifiable factor; treated as categorical."},"cancer":{"hr":2,"hr_metric":"categorical","hr_unit_detail":"CAC >=400 vs CAC = 0, incident lung and colorectal cancer (total/all-site cancer NOT significantly associated)","direction":"risk","ci_low":1.2,"ci_high":3.4,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":6271,"followup_years":12.9,"study":"Multi-Ethnic Study of Atherosclerosis (MESA), prospective cohort, CAC and incident cancer.","study_type":"prospective-cohort","citation":"Handy CE et al. (MESA). Coronary artery calcium is associated with increased risk for lung and colorectal cancer in men and women. PMC9016360.","verification_status":"approximate","notes":"CAC >=400 vs CAC=0 predicted incident lung+colorectal cancer (HR 2.0; log(CAC+1) continuous HR ~1.1/unit) but was NOT associated with total cancer or hormone-related cancers. Likely reflects shared risk factors (smoking) rather than causation. Site-specific signal only; treated as categorical (Agatston strata)."},"dementia":{"hr":1.71,"hr_metric":"categorical","hr_unit_detail":"CAC >=1001 vs CAC = 0, incident dementia (graded: CAC 1-400 HR ~1.23, 401-1000 HR ~1.35)","direction":"risk","ci_low":1.18,"ci_high":2.48,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":6293,"followup_years":12,"study":"Multi-Ethnic Study of Atherosclerosis (MESA), prospective cohort, CAC and incident dementia.","study_type":"prospective-cohort","citation":"Fujiyoshi A et al. Coronary artery calcium and risk of dementia in MESA. Circ Cardiovasc Imaging 2017;10:e005564. doi:10.1161/CIRCIMAGING.116.005564","verification_status":"approximate","notes":"MESA found a graded association of CAC with incident dementia: ~+23% (CAC 1-400), ~+35% (401-1000), ~+71% (>=1001) vs CAC=0, independent of vascular risk factors and APOE4. Association attenuated to non-significance after adjusting for interim CVD but remained after excluding interim stroke. CIs are approximate; treated as categorical (Agatston strata)."},"frailty":null},"modifiability":{"intervention":"CAC reflects established calcified plaque and does not regress; the score itself cannot be lowered. Statins paradoxically increase calcified plaque density while stabilizing plaque. The actionable response is aggressive risk-factor and lipid management triggered by an elevated score.","effect_size":"CAC score is essentially fixed/non-regressing; clinical value is in guiding intensity of preventive therapy.","timeframe":"not applicable (score does not decrease)","evidence_type":"observational","citation":"Statin-CAC progression studies; guideline use of CAC to guide therapy intensity.","rating":"fixed"},"comparability_tag":"Non-normal","comparability_note":"Coronary artery calcium has a large point mass at zero and a long skewed tail, and risk rises across graded clinical strata rather than along a smooth slope — it is reported by CAC category, not per SD."},{"id":"cimt","name":"Carotid intima-media thickness (cIMT)","domain":"lipids_cv","aliases":["cIMT","carotid IMT","CCA-IMT","carotid intima-media thickness"],"profile":{"mechanism":"cIMT measures the combined thickness of the intima and media layers of the carotid artery wall by ultrasound. Increased cIMT reflects subclinical atherosclerosis and arterial aging and is associated with future stroke and myocardial infarction, though it adds limited incremental predictive value over standard risk factors.","measurement":{"method":"B-mode carotid ultrasound; standardized measurement of mean common carotid artery wall thickness; operator-dependent.","sample_type":"imaging","approx_cost_usd":"100-300"},"signal_quality":"moderate","signal_quality_note":"Operator- and protocol-dependent; measurement definitions vary (near vs far wall, segments included), limiting comparability. Reproducible within standardized protocols.","confounders":["age","operator/sonographer variability","measurement protocol differences (segment, wall)","ultrasound equipment differences"],"testing_cadence":"one-time for risk assessment; serial measurement of progression has not proven clinically useful"},"outcomes":{"all_cause_mortality":{"hr":1.54,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of carotid IMT, all-cause mortality, adjusted for risk factors, plaque and CRP","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1.219,"hr_per_sd_ci":null,"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":4191,"followup_years":12,"study":"Cardiovascular Health Study, prospective cohort of older community-dwelling adults.","study_type":"prospective-cohort","citation":"Cao JJ et al. Association of carotid artery intima-media thickness, plaques, and C-reactive protein with future cardiovascular disease and all-cause mortality (Cardiovascular Health Study). Circulation 2007;116:32-38. doi:10.1161/CIRCULATIONAHA.106.645606","verification_status":"approximate","notes":"Highest vs lowest cIMT tertile carried ~54% higher all-cause mortality after adjustment for risk factors, carotid plaque and CRP. Smaller cohorts (e.g., Hokkaido LILAC) report a positive cIMT-all-cause-mortality gradient. Tertile contrast converted to per-SD; the source CI was not captured so the cell is approximate. Observational; cIMT is a subclinical-atherosclerosis marker."},"cvd":{"hr":1.27,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher mean common carotid artery IMT, CVD events, age- and sex-adjusted","direction":"risk","ci_low":1.17,"ci_high":1.37,"hr_per_sd":1.27,"hr_per_sd_ci":[1.17,1.37],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"multiple cohorts (pooled)","followup_years":10,"study":"Systematic review and meta-analysis of cIMT definitions and future CVD across prospective cohorts.","study_type":"meta-analysis","citation":"Varying Definitions of Carotid Intima-Media Thickness and Future Cardiovascular Disease: a systematic review and meta-analysis. J Am Heart Assoc 2023;12:e031217. doi:10.1161/JAHA.123.031217","verification_status":"verified","notes":"Per-SD HRs from meta-analyses are consistent: ~1.25-1.36 for CVD events, ~1.25 for MI, ~1.32 for stroke. Observational only - cIMT is a marker of subclinical atherosclerosis; serial regression of cIMT with therapy has not translated into proven event reduction, and it adds modest incremental value over standard risk scores."},"cancer":null,"dementia":{"hr":1.08,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD (0.19 mm) higher carotid intima-media thickness, incident dementia, fully adjusted","direction":"risk","ci_low":1.04,"ci_high":1.13,"hr_per_sd":1.08,"hr_per_sd_ci":[1.04,1.13],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":12459,"followup_years":24,"study":"Atherosclerosis Risk in Communities Neurocognitive Study (ARIC-NCS), prospective cohort.","study_type":"prospective-cohort","citation":"Kresge HA et al. Association of carotid intima-media thickness and other carotid ultrasound features with incident dementia in ARIC-NCS. J Am Heart Assoc 2021;10:e020489. doi:10.1161/JAHA.120.020489","verification_status":"verified","notes":"ARIC-NCS reported a native per-SD HR of 1.08 (1.04-1.13) for incident dementia (highest vs lowest quintile HR 1.25, 1.08-1.45). Mid-life cIMT is prospectively associated with dementia, consistent with a vascular contribution to cognitive decline. Observational; cIMT is a subclinical-atherosclerosis marker, not a treatment target."},"frailty":null},"modifiability":{"intervention":"Statins, blood pressure control, and lifestyle changes slow or modestly reverse cIMT progression.","effect_size":"Statins can slow progression and produce small regression of cIMT; absolute changes are small.","timeframe":"1-2 years for measurable change","evidence_type":"RCT meta-analysis","citation":"Meta-analyses of statin and antihypertensive trials measuring cIMT progression (surrogate endpoint).","rating":"moderate"}},{"id":"apoe_genotype","name":"ApoE genotype","domain":"lipids_cv","aliases":["APOE genotype","apolipoprotein E genotype","APOE e4","ApoE4 carrier status"],"profile":{"mechanism":"APOE has three common alleles (e2, e3, e4) encoding apolipoprotein E, which mediates clearance of triglyceride-rich and remnant lipoproteins. The e4 allele raises LDL-C and remnant levels and modestly increases coronary heart disease risk; it is also the strongest common genetic risk factor for late-onset Alzheimer's disease. e2 lowers LDL-C but can predispose to type III hyperlipoproteinemia.","measurement":{"method":"Genotyping of the two APOE SNPs (rs429358, rs7412) by PCR or array; a single test, results are lifelong.","sample_type":"venous blood","approx_cost_usd":"50-200"},"signal_quality":"clean","signal_quality_note":"Genotype is fixed and measured with essentially no biological or analytic variability; the test is definitive once performed.","confounders":["none for the genotype itself (fixed)","phenotypic expression modified by environment, sex, ancestry"],"testing_cadence":"once in a lifetime (genotype is fixed)"},"outcomes":{"all_cause_mortality":{"hr":1.16,"hr_metric":"categorical","hr_unit_detail":"APOE e4 heterozygote vs e3/e3, all-cause mortality (e4/e4 homozygotes HR 1.59, 1.24-2.06)","direction":"risk","ci_low":1.07,"ci_high":1.26,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":14091,"followup_years":15.4,"study":"Pooled analysis of two population-based cohorts (Three-City study + Whitehall II).","study_type":"pooled-cohort","citation":"Pooled analyses of APOE4 and all-cause mortality. Lancet Healthy Longev 2024;5:e413-e421. doi:10.1016/S2666-7568(24)00066-7","verification_status":"verified","notes":"Replaces the earlier single small elderly-cohort cell with a pooled two-cohort meta-analytic estimate: e4 heterozygotes HR 1.16 (1.07-1.26), e4/e4 homozygotes HR 1.59 (1.24-2.06) vs e3/e3. Excess mortality was only partly mediated by dementia. Genotype is a fixed categorical/causal exposure; remains categorical."},"cvd":{"hr":1.09,"hr_metric":"categorical","hr_unit_detail":"e4 carrier vs non-carrier (predominantly e3/e3), incident coronary heart disease","direction":"risk","ci_low":1,"ci_high":1.19,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":25630,"followup_years":11,"study":"EPIC-Norfolk prospective cohort, English men and women aged 40-79.","study_type":"prospective-cohort","citation":"APOE genotype and coronary heart disease in EPIC-Norfolk; reviewed in Apolipoprotein E Genotype and Cardiovascular Diseases in the Elderly, PMC2908458.","verification_status":"approximate","notes":"e4 carriage is associated with a modest increase in CHD risk (~6-46% across populations); estimate cited is from EPIC-Norfolk. The effect is partly mediated by higher LDL-C and remnant cholesterol. e2 is generally associated with lower LDL-C and lower CHD risk. Genotype is causal/genetic but effect on CVD is small."},"cancer":null,"dementia":{"hr":3.2,"hr_metric":"categorical","hr_unit_detail":"approx odds/risk ratio for one e4 allele (heterozygote) vs e3/e3 for late-onset Alzheimer's disease; e4/e4 homozygotes carry roughly 8-12x risk","direction":"risk","ci_low":2.8,"ci_high":3.8,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":"multiple meta-analyses / large consortia","followup_years":"lifetime risk","study":"Meta-analyses of APOE and Alzheimer's disease (e.g., AlzGene, Farrer 1997 and subsequent consortia).","study_type":"meta-analysis","citation":"Farrer LA et al. Effects of age, sex, and ethnicity on the association between APOE genotype and Alzheimer disease. JAMA 1997;278:1349-1356; and subsequent meta-analyses.","verification_status":"approximate","notes":"APOE e4 is the strongest common genetic risk factor for late-onset Alzheimer's: roughly 3x for one e4 allele and 8-12x (some estimates higher) for e4/e4 homozygotes vs e3/e3; e2 is protective. Magnitude varies by ancestry (weaker in some African-ancestry populations). This is a genetic/causal association. Cited CI is approximate/illustrative for the heterozygote estimate."},"frailty":null},"modifiability":{"intervention":"Genotype is fixed and cannot be changed. e4 carriers benefit from earlier and more intensive management of modifiable risk factors (LDL-C lowering, blood pressure, exercise, sleep) for both cardiovascular and dementia risk.","effect_size":"Not applicable - genotype is immutable; downstream lipid and cognitive risk is partially modifiable.","timeframe":"not applicable","evidence_type":"mechanistic","citation":"APOE biology; risk-factor modification trials in e4 carriers.","rating":"fixed"},"comparability_tag":"Genotype","comparability_note":"ApoE is a genotype (e2/e3/e4 allele status), not a continuous measurement — there is no standard deviation to standardize against; HRs are e4-carrier group contrasts."},{"id":"vo2max","name":"VO2max (relative)","domain":"mitochondrial_crf","aliases":["maximal oxygen uptake","cardiorespiratory fitness","peak VO2","CRF","aerobic capacity"],"profile":{"mechanism":"VO2max integrates the capacity of the lungs, heart, vasculature and skeletal-muscle mitochondria to deliver and utilize oxygen. It is the single most robust functional predictor of all-cause and cardiovascular mortality, and declining VO2max tracks the loss of physiologic reserve that defines biological aging.","measurement":{"method":"Gold standard: graded maximal exercise test (treadmill or cycle ergometer) with expired-gas analysis (cardiopulmonary exercise testing, CPET). Submaximal estimates and treadmill-time-derived METs are common surrogates in large cohorts.","sample_type":"functional test","approx_cost_usd":"150-400"},"signal_quality":"clean","signal_quality_note":"Directly measured CPET VO2max is highly reproducible (test-retest CV ~3-5%). Estimated/submaximal values introduce moderate noise; effort dependence and ceiling at true max are the main measurement issues.","confounders":["age","sex","body composition / adiposity","submaximal vs maximal effort","altitude","beta-blocker use","test modality (treadmill vs cycle)","reverse causation from subclinical disease"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":0.87,"hr_metric":"per_unit","hr_unit_detail":"per 1-MET higher maximal aerobic capacity","direction":"protective","ci_low":0.84,"ci_high":0.9,"hr_per_sd":0.7569,"hr_per_sd_ci":[0.7056,0.81],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 2 (Within-cohort CRF SD ~2 MET (~7 mL/kg/min), consistent with FRIEND registry reference distributions (Kaminsky 2015 Mayo Clin Proc) and large treadmill cohorts.); k = SD/unit = 2","conversion":{"unit_value":1,"population_sd":2,"sd_source":"Within-cohort CRF SD ~2 MET (~7 mL/kg/min), consistent with FRIEND registry reference distributions (Kaminsky 2015 Mayo Clin Proc) and large treadmill cohorts."},"evidence_tier":"A","n":"33060 (across 33 cohorts)","followup_years":11,"study":"Kodama 2009, JAMA, meta-analysis of prospective cohorts in healthy adults.","study_type":"meta-analysis","citation":"Kodama S, et al. Cardiorespiratory fitness as a quantitative predictor of all-cause mortality and cardiovascular events in healthy men and women: a meta-analysis. JAMA. 2009;301(19):2024-2035. doi:10.1001/jama.2009.681. PMID:19454641","verification_status":"verified","notes":"Per-1-MET RR for all-cause mortality 0.87 (0.84-0.90). Mandsager 2018 (JAMA Netw Open, n=122,007, median 8.4y) found low vs elite fitness adjusted HR 5.04 (4.10-6.20) with no upper limit of benefit. A per-1-SD CPET-VO2 estimate of HR ~0.82 (0.69-0.97) is reported in heart-failure CPET cohorts; the per-MET meta-analytic estimate is retained as the strongest population-level figure. Observational; 2-sample Mendelian randomization found VO2max not robustly causally associated with longevity, suggesting residual confounding/reverse causation inflates observational estimates."},"cvd":{"hr":0.85,"hr_metric":"per_unit","hr_unit_detail":"per 1-MET higher maximal aerobic capacity (CHD/CVD events)","direction":"protective","ci_low":0.82,"ci_high":0.88,"hr_per_sd":0.7225,"hr_per_sd_ci":[0.6724,0.7744],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 2 (Within-cohort CRF SD ~2 MET (~7 mL/kg/min), FRIEND registry reference distributions (Kaminsky 2015 Mayo Clin Proc).); k = SD/unit = 2","conversion":{"unit_value":1,"population_sd":2,"sd_source":"Within-cohort CRF SD ~2 MET (~7 mL/kg/min), FRIEND registry reference distributions (Kaminsky 2015 Mayo Clin Proc)."},"evidence_tier":"A","n":"84323 (across cohorts for CHD/CVD)","followup_years":11,"study":"Kodama 2009, JAMA, meta-analysis of prospective cohorts.","study_type":"meta-analysis","citation":"Kodama S, et al. JAMA. 2009;301(19):2024-2035. doi:10.1001/jama.2009.681. PMID:19454641","verification_status":"verified","notes":"Per-1-MET RR for combined CHD/CVD events 0.85 (0.82-0.88). Consistent with later dose-response meta-analyses. Observational."},"cancer":{"hr":0.8,"hr_metric":"per_unit","hr_unit_detail":"per 1-MET higher CRF, cancer incidence (women)","direction":"protective","ci_low":0.69,"ci_high":0.92,"hr_per_sd":0.64,"hr_per_sd_ci":[0.4761,0.8464],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 2 (Within-cohort CRF SD ~2 MET (~7 mL/kg/min), FRIEND registry reference distributions (Kaminsky 2015 Mayo Clin Proc).); k = SD/unit = 2","conversion":{"unit_value":1,"population_sd":2,"sd_source":"Within-cohort CRF SD ~2 MET (~7 mL/kg/min), FRIEND registry reference distributions (Kaminsky 2015 Mayo Clin Proc)."},"evidence_tier":"B","n":71654,"followup_years":16.4,"study":"Schmid & Leitzmann 2015, Annals of Oncology, systematic review/meta-analysis of CRF and cancer mortality; incidence HR from CRF-cancer-in-women cohort literature.","study_type":"meta-analysis","citation":"Schmid D, Leitzmann MF. Cardiorespiratory fitness as predictor of cancer mortality: a systematic review and meta-analysis. Ann Oncol. 2015;26(2):272-278. doi:10.1093/annonc/mdu250. PMID:25009011","verification_status":"approximate","notes":"Schmid 2015 meta-analysis (6 prospective studies, 71,654 individuals, 2,002 cancer deaths, median 16.4y) showed a strong graded inverse association of CRF with total cancer mortality. The per-1-MET incidence HR 0.80 is drawn from a CRF-cancer-in-women cohort and is approximate. Observational; site-specific effects vary (strongest for lung, colorectal)."},"dementia":{"hr":0.81,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD higher cardiorespiratory fitness, incident all-cause dementia","direction":"protective","ci_low":0.73,"ci_high":0.89,"hr_per_sd":0.81,"hr_per_sd_ci":[0.73,0.89],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"large veteran/clinical CRF cohorts","followup_years":8,"study":"Cheng 2023-type analyses of objectively measured CRF and incident dementia; per-1-SD increment associated with reduced all-dementia risk.","study_type":"prospective-cohort","citation":"Cheng Y, et al. Cardiorespiratory fitness and risk of Alzheimer's disease and related dementias among American veterans. Alzheimers Dement. 2023; companion per-SD analyses report incident all-dementia IRR ~0.81 (0.73-0.89) and Alzheimer's IRR ~0.83 (0.72-0.97) per 1-SD higher CRF.","verification_status":"approximate","notes":"Per-1-SD CRF: incident all-dementia IRR 0.81 (0.73-0.89); replaces the earlier Defina 2013 quintile contrast (highest vs lowest quintile HR 0.64, 0.54-0.77) with a native per-SD estimate. The Defina Cooper Center study (n=19,458, median 25y, 1,659 cases) remains the landmark long-follow-up cohort. Observational; reverse causation over long follow-up partially mitigated by midlife/baseline measurement."},"frailty":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"higher cardiorespiratory fitness associated with lower incident frailty; no measured-VO2max per-SD HR available","direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no directly-measured-VO2max per-SD incident-frailty HR exists; the closest evidence uses physical-activity exposure rather than CPET VO2max, so it cannot be standardized to a per-SD VO2max hazard ratio","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Prospective cohorts consistently show baseline physical activity / fitness predicts incident frailty (e.g. Whitehall II: >=2.5 h/week activity at age 50, incident frailty HR 0.66, 0.54-0.81; trajectory cohorts HR 0.42-0.70 for sustained high vs low activity). VO2max correlates cross-sectionally with Fried frailty score (r ~ -0.40).","study_type":"prospective-cohort","citation":"Physical activity and incident frailty literature, e.g. Whitehall II (Bouillon 2013); 7-year activity-trajectory cohorts. No prospective cohort reports a per-SD hazard ratio for directly measured VO2max and incident frailty.","verification_status":"unverified","notes":"Low fitness/activity is a strong, consistent predictor of incident frailty, and VO2max is mechanistically central to physiologic reserve, but the available hard-outcome HRs use physical-activity (not CPET VO2max) exposure. Left unconvertible/qualitative rather than borrowing an activity HR onto a fitness scale. Direction is firmly protective. Tier C; reverse causation (subclinical decline lowers fitness) is a concern.","qualitative":true}},"modifiability":{"intervention":"Structured aerobic / endurance training, especially moderate-to-vigorous continuous exercise and high-intensity interval training.","effect_size":"Typically 10-25% increase in VO2max with 3-6 months of training; larger relative gains in deconditioned and older individuals, attenuated in already-fit and very old.","timeframe":"8-12 weeks for measurable gains; 6 months for substantial improvement.","evidence_type":"RCT meta-analysis","citation":"Numerous RCT meta-analyses of aerobic and HIIT training (e.g., Bacon 2013 PLoS One; Milanovic 2015 Sports Med) consistently show ~10-25% VO2max improvement.","rating":"high"}},{"id":"ventilatory_thresholds","name":"Ventilatory thresholds (VT1, VT2)","domain":"mitochondrial_crf","aliases":["ventilatory threshold","anaerobic threshold","gas exchange threshold","respiratory compensation point","VT1","VT2"],"profile":{"mechanism":"Ventilatory thresholds mark the exercise intensities at which ventilation rises disproportionately as metabolic acidosis develops (VT1 ~aerobic/gas-exchange threshold, VT2 ~respiratory compensation point). They index submaximal mitochondrial oxidative capacity and the workload sustainable without progressive acidosis, and they decline with age and deconditioning.","measurement":{"method":"Identified during cardiopulmonary exercise testing from ventilatory equivalents and gas-exchange slopes (V-slope method).","sample_type":"functional test","approx_cost_usd":"150-400"},"signal_quality":"moderate","signal_quality_note":"Threshold determination is somewhat operator- and method-dependent with inter-rater variability; physiologically meaningful but harder to standardize than VO2max.","confounders":["age","sex","training status","test protocol / ramp rate","rater subjectivity","medications affecting ventilation"],"testing_cadence":"baseline + annual (with CPET)"},"outcomes":{"all_cause_mortality":null,"cvd":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"low vs high anaerobic threshold in heart failure / preoperative populations","direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable summary HR; anaerobic-threshold prognosis reported heterogeneously across clinical CPET studies without a pooled estimate or SD","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Multiple clinical CPET studies in heart failure and preoperative risk stratification report anaerobic-threshold-based prognosis, but no single landmark meta-analysis with a clean HR.","study_type":"prospective-cohort","citation":"No single definitive citation; anaerobic threshold prognostic value summarized in CPET guideline statements (e.g., Guazzi 2016 EACPR/AHA scientific statement on CPET).","verification_status":"unverified","notes":"Anaerobic/ventilatory threshold predicts perioperative and heart-failure outcomes, but hard-outcome evidence in general aging populations is thin and largely subsumed by VO2max. No verified HR; effort to find a per-SD or per-unit population estimate was unsuccessful, so the continuous exposure is left unconvertible. Tier C, intermediate physiologic marker.","qualitative":true},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Aerobic endurance training, particularly threshold and tempo work.","effect_size":"Ventilatory thresholds shift to higher absolute and relative workloads with training, often improving more than VO2max in percentage terms.","timeframe":"6-12 weeks.","evidence_type":"RCT","citation":"Endurance training trials consistently show upward shifts in ventilatory/lactate thresholds (general exercise physiology literature).","rating":"high"}},{"id":"resting_metabolic_rate","name":"Resting metabolic rate","domain":"mitochondrial_crf","aliases":["RMR","basal metabolic rate","BMR","resting energy expenditure"],"profile":{"mechanism":"RMR is the energy expended at rest, dominated by organ and lean-tissue mitochondrial activity. Its relationship to aging is complex: low RMR is linked to longevity in cross-species comparisons, yet in humans higher RMR predicts mortality, an association largely confounded by fat mass and subclinical disease.","measurement":{"method":"Indirect calorimetry (ventilated hood) under fasted, rested conditions; predictive equations are common but less accurate.","sample_type":"in-office device","approx_cost_usd":"75-250"},"signal_quality":"noisy","signal_quality_note":"Strongly determined by lean and fat mass; once body composition is accounted for, residual RMR signal is small and easily confounded by recent food, sleep, temperature, thyroid status and illness.","confounders":["fat mass","lean mass","thyroid function","subclinical illness / inflammation","ambient temperature","recent food intake","menstrual phase","medications"],"testing_cadence":"not routinely tracked; baseline if metabolic assessment indicated"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"higher BMR/24h energy expenditure associated with increased mortality","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"direction reported but no consistent per-SD HR magnitude or usable SD published; cannot be standardized","conversion":null,"evidence_tier":"C","n":">3000","followup_years":40,"study":"Baltimore Longitudinal Study of Aging and Pima Indian cohorts: higher BMR independently predicted increased natural mortality.","study_type":"prospective-cohort","citation":"Jumpertz R, et al. Higher energy expenditure in humans predicts natural mortality. J Clin Endocrinol Metab. 2011;96(6):E972-E976; Ruggiero C, et al. High basal metabolic rate is a risk factor for mortality: the Baltimore Longitudinal Study of Aging. J Gerontol A Biol Sci Med Sci. 2008;63(7):698-706","verification_status":"approximate","notes":"Direction is paradoxical: higher RMR predicts higher mortality in human cohorts (BLSA, Pima), interpreted as a marker of subclinical disease/inflammation and accelerated aging. Speakman & Westerterp 2014 showed the low-RMR/longer-lifespan association largely disappears after adjusting for fat mass. Re-search confirmed no consistent per-SD HR magnitude is reported; the cell is genuinely thin and confounded. Left unconvertible, tier C.","qualitative":true},"cvd":null,"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Resistance training to increase lean mass; RMR otherwise tightly regulated and not a useful intervention target.","effect_size":"Small (a few percent) changes via lean-mass gain; adaptive thermogenesis lowers RMR with weight loss.","timeframe":"Months.","evidence_type":"observational","citation":"Body-composition and weight-change literature on RMR adaptation.","rating":"low"}},{"id":"substrate_utilization","name":"Substrate utilization (RER / maximal fat oxidation)","domain":"mitochondrial_crf","aliases":["respiratory exchange ratio","RER","RQ","maximal fat oxidation","MFO","FATmax","metabolic flexibility"],"profile":{"mechanism":"The respiratory exchange ratio and maximal fat oxidation reflect the balance between fat and carbohydrate combustion and the ability to switch fuels (metabolic flexibility). Impaired fat oxidation and blunted metabolic flexibility are features of insulin resistance and mitochondrial dysfunction, mechanistically tied to cardiometabolic aging.","measurement":{"method":"Indirect calorimetry at rest (RER) and during graded exercise to derive maximal fat oxidation rate and FATmax intensity.","sample_type":"in-office device","approx_cost_usd":"100-350"},"signal_quality":"noisy","signal_quality_note":"FATmax/MFO have well-documented reproducibility problems (test protocol, prior diet, glycogen status, day-to-day variability); RER is highly sensitive to recent carbohydrate intake.","confounders":["recent diet / glycogen status","fasting duration","exercise protocol","training status","fitness level","caffeine","time of day"],"testing_cadence":"not routinely tracked"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Endurance and FATmax-intensity exercise training; weight loss; low-carbohydrate dietary periodization.","effect_size":"Maximal fat oxidation and metabolic flexibility improve meaningfully with training; FATmax-intensity training programs reduce body fat, visceral fat and HOMA-IR.","timeframe":"6-12 weeks.","evidence_type":"RCT meta-analysis","citation":"Systematic review/meta-analysis of FATmax-intensity exercise training for cardiometabolic health in overweight/obesity (Sports Med / Med Sci Sports Exerc literature, 2024-2025).","rating":"moderate"}},{"id":"exercise_economy","name":"Exercise economy","domain":"mitochondrial_crf","aliases":["running economy","movement economy","oxygen cost of locomotion","metabolic cost of walking"],"profile":{"mechanism":"Exercise economy is the oxygen (energy) cost of locomotion at a fixed submaximal speed. Poorer walking economy means greater relative effort for daily tasks, contributes to fatigue and activity avoidance, and rises with age - a determinant of mobility decline and loss of independence.","measurement":{"method":"Indirect calorimetry during steady-state submaximal treadmill walking or running at standardized speeds.","sample_type":"functional test","approx_cost_usd":"100-300"},"signal_quality":"moderate","signal_quality_note":"Reasonably reproducible within a session, but absolute values depend on test speed, footwear, gait mechanics and familiarization; cross-study comparability is limited.","confounders":["test speed","body mass","gait mechanics / orthopedic status","footwear","training status","age"],"testing_cadence":"not routinely tracked"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":null,"dementia":null,"frailty":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"higher oxygen cost of walking associated with greater mobility decline / fatigue","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"association documented but no quantified hard-outcome HR or usable SD; cannot be standardized","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Baltimore Longitudinal Study of Aging and related work links a high energetic cost of walking to slower gait, fatigue and mobility limitation in older adults.","study_type":"prospective-cohort","citation":"Schrack JA, et al. The role of energetic cost in the age-related slowing of gait speed. J Am Geriatr Soc. 2012;60(10):1811-1816. PMID:23035768","verification_status":"unverified","notes":"Poor walking economy is associated with the mobility-limitation/frailty pathway, but re-search confirmed no verified hard-outcome HR exists. Left unconvertible, tier C. Largely a mechanistic/intermediate marker.","qualitative":true}},"modifiability":{"intervention":"Endurance training, strength and gait training, weight loss.","effect_size":"Walking/running economy improves modestly with training and weight reduction; gains are smaller and slower than VO2max changes.","timeframe":"Weeks to months.","evidence_type":"observational","citation":"Exercise physiology literature on economy adaptation; aging mobility studies.","rating":"moderate"}},{"id":"lactate_threshold","name":"Lactate threshold and lactate kinetics","domain":"mitochondrial_crf","aliases":["lactate threshold","LT1","LT2","onset of blood lactate accumulation","OBLA","maximal lactate steady state","lactate clearance"],"profile":{"mechanism":"The lactate threshold is the exercise intensity above which blood lactate accumulates faster than it can be cleared, reflecting the balance between glycolytic flux and mitochondrial oxidative capacity. A higher threshold and faster lactate clearance indicate better skeletal-muscle oxidative function, which declines with age and deconditioning.","measurement":{"method":"Serial capillary (fingertip/earlobe) blood lactate sampling during a graded exercise test; thresholds identified from the lactate-workload curve.","sample_type":"capillary blood","approx_cost_usd":"100-300"},"signal_quality":"moderate","signal_quality_note":"Lactate values are reproducible but threshold definitions vary widely (fixed 2/4 mmol/L vs individualized methods), and results depend on protocol, prior diet and glycogen status.","confounders":["test protocol / stage duration","prior diet and glycogen","training status","sampling site","hydration","ambient temperature"],"testing_cadence":"not routinely tracked; used in athletic monitoring"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Endurance training, especially threshold-intensity and high-volume aerobic training.","effect_size":"Lactate threshold shifts substantially to higher workloads with training; often the most trainable submaximal aerobic parameter.","timeframe":"6-12 weeks.","evidence_type":"RCT","citation":"Endurance-training literature consistently shows rightward shift of the lactate curve.","rating":"high"}},{"id":"grip_strength","name":"Grip strength","domain":"mitochondrial_crf","aliases":["handgrip strength","hand grip strength","muscle strength"],"profile":{"mechanism":"Grip strength is a simple, reliable proxy for total-body muscle strength and overall physiologic reserve. Low grip strength reflects sarcopenia, neuromuscular decline and systemic frailty, and is one of the strongest single-measure predictors of mortality and disability in aging.","measurement":{"method":"Maximal isometric force with a calibrated hand dynamometer (e.g., Jamar), best of multiple trials, typically dominant hand.","sample_type":"in-office device","approx_cost_usd":"20-80"},"signal_quality":"clean","signal_quality_note":"Highly reproducible with standardized protocol and calibrated dynamometer; main variability sources are posture, instructions and effort, all controllable.","confounders":["age","sex","body size / height","hand dominance","arthritis or hand injury","dynamometer type and protocol","reverse causation from subclinical disease"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1.16,"hr_metric":"per_unit","hr_unit_detail":"per 5 kg lower grip strength","direction":"risk","ci_low":1.13,"ci_high":1.2,"hr_per_sd":1.268,"hr_per_sd_ci":[1.216,1.3387],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 8 (Within-sex adult handgrip SD ~8 kg, from UK Biobank normative values (Dodds 2014 J Am Geriatr Soc / UK Biobank reference distributions) and the British normative pooled data (Dodds 2014 PLoS One).); k = SD/unit = 1.6","conversion":{"unit_value":5,"population_sd":8,"sd_source":"Within-sex adult handgrip SD ~8 kg, from UK Biobank normative values (Dodds 2014 J Am Geriatr Soc / UK Biobank reference distributions) and the British normative pooled data (Dodds 2014 PLoS One)."},"evidence_tier":"A","n":139691,"followup_years":4,"study":"Leong 2015, Lancet, PURE prospective cohort across 17 countries.","study_type":"prospective-cohort","citation":"Leong DP, et al. Prognostic value of grip strength: findings from the Prospective Urban Rural Epidemiology (PURE) study. Lancet. 2015;386(9990):266-273. doi:10.1016/S0140-6736(14)62000-6. PMID:25982160","verification_status":"verified","notes":"PURE: per 5 kg lower grip strength, all-cause mortality HR 1.16 (1.13-1.20). Closely matched by UK Biobank (Celis-Morales 2018 BMJ, n=502,293): per-5-kg HR men 1.16 (1.15-1.17), women 1.20 (1.17-1.23). Tier A given concordant very large cohorts. Grip strength outperformed systolic BP as a mortality predictor in PURE. Observational; partly reflects reverse causation."},"cvd":{"hr":1.17,"hr_metric":"per_unit","hr_unit_detail":"per 5 kg lower grip strength, cardiovascular mortality","direction":"risk","ci_low":1.11,"ci_high":1.24,"hr_per_sd":1.2856,"hr_per_sd_ci":[1.1817,1.4108],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 8 (Within-sex adult handgrip SD ~8 kg, UK Biobank normative values (Dodds 2014) and British pooled normative data.); k = SD/unit = 1.6","conversion":{"unit_value":5,"population_sd":8,"sd_source":"Within-sex adult handgrip SD ~8 kg, UK Biobank normative values (Dodds 2014) and British pooled normative data."},"evidence_tier":"A","n":139691,"followup_years":4,"study":"Leong 2015, Lancet, PURE prospective cohort across 17 countries.","study_type":"prospective-cohort","citation":"Leong DP, et al. Prognostic value of grip strength: findings from the Prospective Urban Rural Epidemiology (PURE) study. Lancet. 2015;386(9990):266-273. doi:10.1016/S0140-6736(14)62000-6. PMID:25982160","verification_status":"verified","notes":"PURE: CVD mortality HR 1.17 (1.11-1.24) per 5 kg lower; MI 1.07, stroke 1.09 per 5 kg lower. UK Biobank (Celis-Morales 2018) found CVD mortality HR 1.22 (men) and 1.19 (women) per 5 kg lower. Observational."},"cancer":{"hr":1.1,"hr_metric":"per_unit","hr_unit_detail":"per 5 kg lower grip strength, cancer mortality (men); 1.17 in women","direction":"risk","ci_low":1.07,"ci_high":1.13,"hr_per_sd":1.1647,"hr_per_sd_ci":[1.1143,1.216],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 8 (Within-sex adult handgrip SD ~8 kg, UK Biobank normative values (Dodds 2014).); k = SD/unit = 1.6","conversion":{"unit_value":5,"population_sd":8,"sd_source":"Within-sex adult handgrip SD ~8 kg, UK Biobank normative values (Dodds 2014)."},"evidence_tier":"B","n":502293,"followup_years":7.1,"study":"Celis-Morales 2018, BMJ, UK Biobank prospective cohort.","study_type":"prospective-cohort","citation":"Celis-Morales CA, et al. Associations of grip strength with cardiovascular, respiratory, and cancer outcomes and all cause mortality: prospective cohort study of half a million UK Biobank participants. BMJ. 2018;361:k1651. doi:10.1136/bmj.k1651. PMID:29739772","verification_status":"verified","notes":"Cancer mortality per 5 kg lower grip: men 1.10 (1.07-1.13), women 1.17 (1.13-1.21). Likely partly reverse causation (occult cancer reducing strength); association weaker than for CVD."},"dementia":{"hr":1.54,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower grip strength, incident dementia (pooled)","direction":"risk","ci_low":1.32,"ci_high":1.79,"hr_per_sd":1.54,"hr_per_sd_ci":[1.32,1.79],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"15 longitudinal cohorts","followup_years":null,"study":"Jia 2021, Front Aging Neurosci, systematic review/meta-analysis of 15 longitudinal cohort studies.","study_type":"meta-analysis","citation":"Jia S, et al. Grip strength and the risk of cognitive decline and dementia: a systematic review and meta-analysis of longitudinal cohort studies. Front Aging Neurosci. 2021;13:625551. doi:10.3389/fnagi.2021.625551. PMID:33613270","verification_status":"verified","notes":"Pooled HR per 1-SD lower grip strength: dementia 1.54 (1.32-1.79); cognitive decline 1.99 (1.71-2.32). This is a native per-SD pooled estimate (the earlier 'lowest vs highest category' label was incorrect). Observational; reverse causation possible as preclinical dementia reduces strength."},"frailty":{"hr":1.9,"hr_metric":"quartile","hr_unit_detail":"lowest vs highest grip strength quartile, incident ADL disability (men)","direction":"risk","ci_low":1.14,"ci_high":3.17,"hr_per_sd":1.2875,"hr_per_sd_ci":[1.0529,1.575],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":"~2000","followup_years":7,"study":"Al Snih 2004, Aging Clin Exp Res, Hispanic EPESE 7-year prospective cohort of non-disabled older men.","study_type":"prospective-cohort","citation":"Al Snih S, et al. Hand grip strength and incident ADL disability in elderly Mexican Americans over a seven-year period. Aging Clin Exp Res. 2004;16(6):481-486. PMID:15739601","verification_status":"approximate","notes":"Low grip strength is itself a core component of the Fried frailty phenotype, so it is partly definitional. HR 1.90 (1.14-3.17) for incident ADL disability, lowest vs highest quartile (men). Converted from a quartile contrast rather than left categorical because grip strength is a continuous exposure. Tier B; abundant consistent literature links low grip to incident frailty and disability."}},"modifiability":{"intervention":"Progressive resistance training, including grip- and forearm-specific loading.","effect_size":"Resistance training increases grip and overall strength by ~10-30% in older adults within months; among the most trainable functional markers.","timeframe":"8-12 weeks.","evidence_type":"RCT meta-analysis","citation":"Resistance-training RCT meta-analyses in older adults consistently show meaningful strength gains.","rating":"high"}},{"id":"lower_body_strength","name":"Lower-body strength / power relative to body mass","domain":"mitochondrial_crf","aliases":["leg press strength","sit-to-stand power","relative muscle power","lower-extremity strength","leg power"],"profile":{"mechanism":"Lower-body strength and power relative to body mass govern the ability to rise from a chair, climb stairs and recover balance. Power (force x velocity) declines faster than strength with age and is a strong determinant of mobility, fall risk and loss of independence.","measurement":{"method":"Leg-press 1-RM or isokinetic dynamometry; field surrogates include the 5- or 30-second sit-to-stand and sit-to-stand power estimated from chair-rise time, height and body mass.","sample_type":"functional test","approx_cost_usd":"0-150"},"signal_quality":"moderate","signal_quality_note":"Laboratory dynamometry is reproducible; field power estimates from chair-rise are practical but introduce estimation error and depend on technique and motivation.","confounders":["body mass","joint pain / orthopedic limitation","test technique","motivation / effort","age","sex"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1.57,"hr_metric":"categorical","hr_unit_detail":"low vs normal relative sit-to-stand power, all-cause mortality (men); 2.04 in women","direction":"risk","ci_low":1.26,"ci_high":1.97,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"~2000","followup_years":null,"study":"Toledo Study for Healthy Aging, prospective cohort of community-dwelling older adults.","study_type":"prospective-cohort","citation":"Alcazar J, et al. Low relative sit-to-stand power is associated with history of falls and fractures, prospective hospitalization, and all-cause mortality in older adults from the Toledo Study for Healthy Aging. J Sport Health Sci. 2024 (epub). doi:10.1016/j.jshs.2025.101034","verification_status":"approximate","notes":"Low relative sit-to-stand power: HR 1.57 (1.26-1.97) men, 2.04 (1.51-2.74) women for all-cause mortality. The 'low vs normal' contrast uses validated clinical cutoffs, not symmetric quantile groups, so it cannot be converted to per-SD with a fixed spread; kept categorical. Re-search did not yield a per-SD lower-body-power mortality HR in a general population. Follow-up duration not confirmed from abstract. Tier B. Observational."},"cvd":{"hr":0.86,"hr_metric":"categorical","hr_unit_detail":"higher vs lower knee-extension (lower-body) strength, cardiovascular/all-cause mortality","direction":"protective","ci_low":0.8,"ci_high":0.93,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"~1.9 million (pooled, 38 studies)","followup_years":null,"study":"Garcia-Hermoso 2018, Br J Sports Med, systematic review/meta-analysis of muscular strength and mortality (knee-extension strength subset).","study_type":"meta-analysis","citation":"Garcia-Hermoso A, et al. Muscular strength as a predictor of all-cause mortality in an apparently healthy population: a systematic review and meta-analysis of data from approximately 2 million men and women. Arch Phys Med Rehabil / Br J Sports Med 2018. PMID:29425700","verification_status":"approximate","notes":"Higher knee-extension (lower-body) strength: 14% lower mortality (HR 0.86, 0.80-0.93). The pooled estimate aggregates heterogeneous higher-vs-lower strength contrasts, so it is kept categorical rather than converted. CVD-specific events in general populations are less cleanly reported: in coronary-disease cohorts higher quadriceps strength predicted lower CV death (HR 0.66 per 10% body-weight increment). No general-population per-SD lower-body-strength incident-CVD HR was located. Observational."},"cancer":null,"dementia":null,"frailty":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"low vs normal relative leg/sit-to-stand power, incident falls and fractures","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"low vs normal power group (clinical cutoff); no verified incident-frailty HR available","conversion":null,"evidence_tier":"C","n":"~2000","followup_years":null,"study":"Toledo Study for Healthy Aging: low relative sit-to-stand power associated with history of falls/fractures and prospective hospitalization.","study_type":"prospective-cohort","citation":"Alcazar J, et al. J Sport Health Sci. 2024 (epub). doi:10.1016/j.jshs.2025.101034","verification_status":"unverified","notes":"Low lower-body power is strongly associated with falls, fractures and the mobility-disability/frailty pathway, but a verified incident-frailty HR is not available. Effect size left null; tier C.","qualitative":true}},"modifiability":{"intervention":"Progressive resistance training, especially high-velocity / power-oriented training and explosive sit-to-stand exercise.","effect_size":"Lower-body strength improves 25-100%+ and muscle power improves substantially in older adults with 8-12 weeks of resistance/power training; power-oriented training is more effective than slow heavy training for power gains.","timeframe":"8-12 weeks.","evidence_type":"RCT meta-analysis","citation":"Power- and resistance-training RCT meta-analyses in older adults.","rating":"high"},"comparability_tag":"Clinical cutpoint","comparability_note":"The available HRs contrast a clinically-defined low-strength group against normal — a threshold split of unknown SD width, neither a quantile nor a per-unit estimate, so it cannot be standardized."},{"id":"muscle_mass_almi","name":"Muscle mass (appendicular lean mass index)","domain":"mitochondrial_crf","aliases":["appendicular lean mass","ALM","ALMI","skeletal muscle mass index","lean body mass","sarcopenia"],"profile":{"mechanism":"Appendicular lean mass index (limb lean mass / height^2) quantifies skeletal-muscle quantity, the substrate for strength, metabolic glucose disposal and protein reserve. Low muscle mass (sarcopenia) reflects anabolic decline and predicts disability and mortality, though strength predicts outcomes more strongly than mass alone.","measurement":{"method":"Dual-energy X-ray absorptiometry (DEXA) appendicular lean mass; bioelectrical impedance is a lower-cost surrogate.","sample_type":"imaging","approx_cost_usd":"75-250"},"signal_quality":"moderate","signal_quality_note":"DEXA lean mass is reproducible (CV ~1-2%), but hydration status affects readings and lean mass includes non-muscle tissue; muscle quality/strength is not captured.","confounders":["body size / height normalization","hydration status","fat mass (obesity)","DEXA vs BIA method","age","sex","ethnicity"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":0.5,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD higher appendicular lean mass, all-cause mortality (prefrail/frail older adults)","direction":"protective","ci_low":0.27,"ci_high":0.92,"hr_per_sd":0.5,"hr_per_sd_ci":[0.27,0.92],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":1487,"followup_years":8.9,"study":"NHANES III prospective cohort of prefrail/frail older adults aged >=65 (Cawthon-type analysis of appendicular lean mass and mortality).","study_type":"prospective-cohort","citation":"Appendicular lean mass and mortality among prefrail and frail older adults. J Nutr Health Aging / NHANES III analysis. PMID:28244576. Each SD higher ALM HR 0.50 (0.27-0.92) in fully adjusted models.","verification_status":"approximate","notes":"Per-1-SD higher appendicular lean mass: all-cause mortality HR 0.50 (0.27-0.92) in fully adjusted models among prefrail/frail older adults (NHANES III, mean ALM 18.9 kg, SD 5.5 kg). The pooled meta-analytic categorical estimate (Liu 2023 PLoS One: low vs normal SMI by DXA HR 1.86, 1.26-2.74; by BIA 1.20, 1.07-1.33) is consistent in direction. Native per-SD figure used here; the prefrail/frail subgroup limits generalizability. Muscle mass alone is a weaker mortality predictor than grip strength. Observational, with reverse causation."},"cvd":{"hr":1.43,"hr_metric":"categorical","hr_unit_detail":"low vs normal muscle mass, incident cardiovascular events","direction":"risk","ci_low":1.23,"ci_high":1.68,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"~2.3 million (pooled, 100 longitudinal studies)","followup_years":null,"study":"Damluji/Veronese-type meta-analysis of longitudinal studies on sarcopenia, low muscle mass and cardiovascular outcomes.","study_type":"meta-analysis","citation":"Meta-analysis of sarcopenia and cardiovascular events/disease (100 longitudinal studies, ~2.3 million participants): low muscle mass and incident cardiovascular events aRR 1.43 (1.23-1.68); sarcopenia overall aRR 1.63 (1.30-2.04). Published 2023-2026 in the cardiology/sarcopenia literature.","verification_status":"approximate","notes":"Low muscle mass is associated with higher incident cardiovascular events (aRR 1.43, 1.23-1.68). The contrast is low-vs-normal by sarcopenia diagnostic cutoffs, so it is kept categorical rather than converted with a fixed quantile spread. A per-SD continuous ALMI-CVD HR in a general population was not located. Observational; muscle mass is a weaker independent CVD predictor than strength/fitness, and confounding by adiposity and frailty is substantial."},"cancer":{"hr":0.87,"hr_metric":"per_unit","hr_unit_detail":"per 20-percentile-point higher appendicular skeletal muscle index, cancer mortality","direction":"protective","ci_low":0.78,"ci_high":0.96,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"C","n":21938,"followup_years":10.9,"study":"NHANES (1999-2006, 2011-2018) prospective cohort linked to the 2018 mortality file; appendicular skeletal muscle index and cancer mortality.","study_type":"prospective-cohort","citation":"Low appendicular skeletal muscle mass is associated with the risk of mortality among adults in the United States. Sci Rep. 2025;15. doi:10.1038/s41598-025-94357-8. PMID:40121321","verification_status":"approximate","notes":"Higher appendicular skeletal muscle index was associated with lower cancer mortality: per 20-percentile-point increment HR 0.87 (0.78-0.96). Because the exposure is expressed as a percentile rank rather than in kg/m^2, it cannot be defensibly converted to per-SD; left unconvertible. This is cancer mortality (not incidence), in a general population. Tier C; reverse causation likely (occult cancer/cachexia lowers muscle mass)."},"dementia":{"hr":1.33,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower appendicular lean mass / BMI ratio, incident dementia (men)","direction":"risk","ci_low":1.07,"ci_high":1.65,"hr_per_sd":1.33,"hr_per_sd_ci":[1.07,1.65],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":2704,"followup_years":9.2,"study":"Health ABC Study, prospective cohort of community-dwelling older adults (1,290 men, 1,414 women).","study_type":"prospective-cohort","citation":"Hsu B, et al. Appendicular lean mass, grip strength, and the incidence of dementia among older adults in the Health ABC Study. J Gerontol A Biol Sci Med Sci. 2023;78(11):2070-2077. doi:10.1093/gerona/glac240. PMID:36548124","verification_status":"verified","notes":"Health ABC: per 1-SD lower appendicular-lean-mass/BMI ratio, incident dementia HR 1.33 (1.07-1.65) in MEN; the association was not significant in women (sex-specific result). Median 9.2-year follow-up; 28-29% developed dementia. A separate sarcopenia meta-analysis is concordant (incident AD HR ~1.50-1.57). Native per-SD estimate; the men-only signal limits generalizability. Observational; reverse causation possible as preclinical dementia reduces lean mass."},"frailty":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"low appendicular lean mass index, incident frailty / sarcopenia","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"low ALMI is a defining diagnostic criterion of sarcopenia/frailty, not an independent continuous predictor with a clean HR","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Low ALMI is a defining criterion of sarcopenia (EWGSOP2) and a component of physical frailty pathways.","study_type":"prospective-cohort","citation":"Cruz-Jentoft AJ, et al. Sarcopenia: revised European consensus on definition and diagnosis (EWGSOP2). Age Ageing. 2019;48(1):16-31. PMID:30312372","verification_status":"unverified","notes":"Low ALMI is partly definitional for sarcopenia/frailty rather than an independent predictor with a clean HR. Effect size left null; tier C. Strength and physical performance carry more independent prognostic weight than mass.","qualitative":true}},"modifiability":{"intervention":"Progressive resistance training, with adequate dietary protein; combined with anabolic stimulus in deficient states.","effect_size":"Resistance training increases appendicular lean mass by roughly 0.5-2 kg over 3-6 months in older adults; gains are modest in magnitude relative to strength gains.","timeframe":"12-24 weeks.","evidence_type":"RCT meta-analysis","citation":"Resistance-training RCT meta-analyses (e.g., Peterson 2011 Ageing Res Rev) show significant lean-mass gains in older adults.","rating":"moderate"},"comparability_tag":"Cutpoint / rank","comparability_note":"Muscle-mass HRs here use a sarcopenia diagnostic cutoff (CVD) and a percentile-rank exposure (cancer); neither carries the population SD needed to convert to a per-SD basis."},{"id":"gait_speed","name":"Gait speed","domain":"mitochondrial_crf","aliases":["walking speed","usual gait speed","habitual gait speed","4-meter walk"],"profile":{"mechanism":"Usual gait speed is an integrative 'vital sign' that summarizes the function of the cardiovascular, musculoskeletal, neurological and energetic systems. It declines with age, predicts survival and disability across populations, and is one of the most validated single functional measures in geriatrics.","measurement":{"method":"Time to walk a measured course (typically 4 m or 6 m) at usual pace, often the better of two trials; can also be measured over longer distances or with instrumented walkways.","sample_type":"functional test","approx_cost_usd":"0-50"},"signal_quality":"clean","signal_quality_note":"Highly reproducible and standardized; main variability is course length, static vs dynamic start and usual-pace instruction, all controllable.","confounders":["age","height / leg length","orthopedic and neurological conditions","course length and start protocol","footwear","test environment"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":0.88,"hr_metric":"per_unit","hr_unit_detail":"per 0.1 m/s higher usual gait speed","direction":"protective","ci_low":0.87,"ci_high":0.9,"hr_per_sd":0.7081,"hr_per_sd_ci":[0.6866,0.7524],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 0.1; population SD 0.27 (Studenski 2011 JAMA pooled analysis: mean usual gait speed 0.92 m/s, SD 0.27 m/s (n=34,485 community-dwelling older adults).); k = SD/unit = 2.7","conversion":{"unit_value":0.1,"population_sd":0.27,"sd_source":"Studenski 2011 JAMA pooled analysis: mean usual gait speed 0.92 m/s, SD 0.27 m/s (n=34,485 community-dwelling older adults)."},"evidence_tier":"A","n":34485,"followup_years":12,"study":"Studenski 2011, JAMA, pooled analysis of 9 cohort studies of community-dwelling older adults.","study_type":"pooled-cohort","citation":"Studenski S, et al. Gait speed and survival in older adults. JAMA. 2011;305(1):50-58. doi:10.1001/jama.2010.1923. PMID:21205966","verification_status":"verified","notes":"Pooled HR per 0.1 m/s higher gait speed 0.88 (0.87-0.90). The same paper provides the population SD (0.27 m/s) used for conversion. Follow-up ranged 6-21 years across 9 cohorts. Strong, graded, consistent association; gait speed predicted survival comparably to age and sex combined. Observational."},"cvd":{"hr":1.08,"hr_metric":"per_unit","hr_unit_detail":"per 0.1 m/s lower usual gait speed, incident cardiovascular disease","direction":"risk","ci_low":1.03,"ci_high":1.13,"hr_per_sd":1.231,"hr_per_sd_ci":[1.0831,1.391],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 0.1; population SD 0.27 (Studenski 2011 JAMA pooled analysis: mean usual gait speed 0.92 m/s, SD 0.27 m/s (n=34,485 community-dwelling older adults).); k = SD/unit = 2.7","conversion":{"unit_value":0.1,"population_sd":0.27,"sd_source":"Studenski 2011 JAMA pooled analysis: mean usual gait speed 0.92 m/s, SD 0.27 m/s (n=34,485 community-dwelling older adults)."},"evidence_tier":"B","n":101945,"followup_years":5.4,"study":"Veronese 2018, JAMDA, systematic review/meta-analysis of 48 prospective cohorts (13 cohorts for the CVD outcome).","study_type":"meta-analysis","citation":"Veronese N, et al. Association between gait speed with mortality, cardiovascular disease and cancer: a systematic review and meta-analysis of prospective cohort studies. J Am Med Dir Assoc. 2018;19(11):981-988.e7. doi:10.1016/j.jamda.2018.06.007. PMID:30056008","verification_status":"verified","notes":"Each 0.1 m/s slower gait speed: incident CVD HR 1.08 (1.03-1.13) across 13 cohorts (I2=81%). Same meta-analysis gives all-cause mortality HR 1.12 per 0.1 m/s. SD for conversion taken from Studenski 2011 (0.27 m/s), the same source used for the gait-speed mortality cell. Observational; partly reverse causation from subclinical CVD."},"cancer":{"hr":1,"hr_metric":"per_unit","hr_unit_detail":"per 0.1 m/s lower usual gait speed, cancer incidence/mortality","direction":"risk","ci_low":0.97,"ci_high":1.04,"hr_per_sd":1,"hr_per_sd_ci":[0.9211,1.1117],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 0.1; population SD 0.27 (Studenski 2011 JAMA pooled analysis: usual gait speed SD 0.27 m/s.); k = SD/unit = 2.7","conversion":{"unit_value":0.1,"population_sd":0.27,"sd_source":"Studenski 2011 JAMA pooled analysis: usual gait speed SD 0.27 m/s."},"evidence_tier":"B","n":101945,"followup_years":5.4,"study":"Veronese 2018, JAMDA, meta-analysis of prospective cohorts.","study_type":"meta-analysis","citation":"Veronese N, et al. J Am Med Dir Assoc. 2018;19(11):981-988.e7. doi:10.1016/j.jamda.2018.06.007. PMID:30056008","verification_status":"verified","notes":"Gait speed showed NO association with cancer (HR 1.00, 0.97-1.04 per 0.1 m/s; I2=15%, low heterogeneity). This is a genuine, well-powered null result, not missing data: unlike CVD and mortality, slow gait does not predict cancer. Retained as a real (null) cell so the heat map distinguishes 'tested, no effect' from 'no data'."},"dementia":{"hr":1.59,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD (0.204 m/s) lower usual gait speed, incident dementia","direction":"risk","ci_low":1.32,"ci_high":1.91,"hr_per_sd":1.59,"hr_per_sd_ci":[1.32,1.91],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~3500 (Three-City cohort)","followup_years":14,"study":"Three-City Study, prospective French population cohort: 1-SD lower gait speed associated with incident dementia.","study_type":"prospective-cohort","citation":"Dumurgier J, et al. Gait speed and decline in gait speed as predictors of incident dementia. J Gerontol A Biol Sci Med Sci. 2017;72(5):655-661. doi:10.1093/gerona/glw110. PMID:27302701. Per 1-SD (0.204 m/s) lower gait speed HR ~1.59.","verification_status":"approximate","notes":"Three-City Study: per 1-SD (0.204 m/s) lower baseline gait speed, incident dementia HR ~1.59 (CI approximate). Replaces the earlier Beauchet 2016 categorical pooled estimate (poor vs good gait performance, RR ~1.53) with a native per-SD figure; the Beauchet meta-analysis remains consistent. UK Biobank wrist-sensor data show ~32% lower dementia hazard per SD faster maximal gait speed. Observational; preclinical dementia slows gait (reverse causation)."},"frailty":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"slow gait speed as predictor of incident disability / frailty","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"slow gait speed is a defining Fried frailty phenotype criterion, partly definitional; no single clean independent HR","conversion":null,"evidence_tier":"B","n":"varies","followup_years":null,"study":"Slow gait speed is a core Fried frailty phenotype criterion and a strong predictor of incident mobility disability across cohorts.","study_type":"prospective-cohort","citation":"Fried LP, et al. Frailty in older adults: evidence for a phenotype. J Gerontol A Biol Sci Med Sci. 2001;56(3):M146-M156. PMID:11253156","verification_status":"unverified","notes":"Slow gait speed is partly definitional for the frailty phenotype; it also strongly predicts incident disability. No single clean independent HR extracted here. Tier B given extensive consistent literature; effect size left null.","qualitative":true}},"modifiability":{"intervention":"Multicomponent exercise (aerobic + resistance + balance/gait training); resistance and power training in deconditioned older adults.","effect_size":"Exercise interventions improve gait speed by roughly 0.05-0.10+ m/s in older adults; ~0.05 m/s is a clinically meaningful change.","timeframe":"12-24 weeks.","evidence_type":"RCT meta-analysis","citation":"Exercise-intervention RCT meta-analyses in older adults show significant gait-speed improvement.","rating":"moderate"}},{"id":"sit_to_stand","name":"Sit-to-stand (chair-rise test)","domain":"mitochondrial_crf","aliases":["chair-rise test","five-times sit-to-stand","5xSTS","30-second chair stand","sitting-rising test"],"profile":{"mechanism":"The chair-rise / sit-to-stand test measures lower-body strength, power and balance during a functionally essential task. Poor performance signals loss of mobility reserve, fall risk and frailty, and predicts mortality independent of conventional risk factors.","measurement":{"method":"Time for five chair rises (5xSTS), number of rises in 30 seconds, or the floor-based sitting-rising test scored 0-10.","sample_type":"functional test","approx_cost_usd":"0-25"},"signal_quality":"moderate","signal_quality_note":"Reproducible with standardized protocol; depends on chair height, arm use, technique and motivation, and different versions (timed, count, floor-based) are not interchangeable.","confounders":["chair height / arm use","joint pain and orthopedic limitation","test version","motivation / effort","age","balance impairment"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1.33,"hr_metric":"per_unit","hr_unit_detail":"per 1-point lower sitting-rising test score (0-10 scale), natural-cause mortality","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1.8727,"hr_per_sd_ci":null,"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 2.2 (Araujo 2025 Eur J Prev Cardiol: sitting-rising test score mean 7.3 +/- 2.2 (n=4,282 adults aged 46-75).); k = SD/unit = 2.2","conversion":{"unit_value":1,"population_sd":2.2,"sd_source":"Araujo 2025 Eur J Prev Cardiol: sitting-rising test score mean 7.3 +/- 2.2 (n=4,282 adults aged 46-75)."},"evidence_tier":"B","n":4282,"followup_years":12.3,"study":"Araujo 2025, Eur J Prev Cardiol, prospective cohort of adults 46-75 years performing the sitting-rising test.","study_type":"prospective-cohort","citation":"Araujo CG, et al. Sitting-rising test scores predict natural and cardiovascular causes of deaths in middle-aged and older men and women. Eur J Prev Cardiol. 2025. doi:10.1093/eurjpc/zwaf325","verification_status":"approximate","notes":"Per-1-point continuous estimate now used instead of the prior lowest-vs-highest categorical contrast (HR 3.84): each 1-point lower SRT score raised natural-mortality risk by 33% (age-adjusted HR 1.33). The paper reports the SRT-score SD (2.2), enabling conversion to per-SD. The native per-point figure is age-adjusted (the multivariate model was reported only for the 5-group categorical contrast), so the CI is not available at the per-point level - flagged approximate. Observational; SRT is an ordinal 0-10 composite."},"cvd":{"hr":1.31,"hr_metric":"per_unit","hr_unit_detail":"per 1-point lower sitting-rising test score (0-10 scale), cardiovascular mortality","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1.8113,"hr_per_sd_ci":null,"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 2.2 (Araujo 2025 Eur J Prev Cardiol: sitting-rising test score mean 7.3 +/- 2.2 (n=4,282 adults aged 46-75).); k = SD/unit = 2.2","conversion":{"unit_value":1,"population_sd":2.2,"sd_source":"Araujo 2025 Eur J Prev Cardiol: sitting-rising test score mean 7.3 +/- 2.2 (n=4,282 adults aged 46-75)."},"evidence_tier":"C","n":4282,"followup_years":12.3,"study":"Araujo 2025, Eur J Prev Cardiol, prospective cohort.","study_type":"prospective-cohort","citation":"Araujo CG, et al. Eur J Prev Cardiol. 2025. doi:10.1093/eurjpc/zwaf325","verification_status":"approximate","notes":"Per-1-point continuous estimate replaces the prior lowest-vs-highest categorical contrast (HR 6.05): each 1-point lower SRT score raised cardiovascular-mortality risk by 31% (age-adjusted HR 1.31). SRT-score SD 2.2 enables per-SD conversion. Per-point figure is age-adjusted and the CI is not available at this level; single cohort with relatively few CV deaths - kept tier C and flagged approximate. Observational."},"cancer":null,"dementia":null,"frailty":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"slow 5x sit-to-stand time as predictor of incident frailty / disability","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"chair-rise performance is embedded in the SPPB and frailty phenotype, partly definitional; no clean standalone incident-frailty HR","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Slow chair-rise time is a validated component of the Short Physical Performance Battery and predicts incident disability.","study_type":"prospective-cohort","citation":"Guralnik JM, et al. A short physical performance battery assessing lower extremity function. J Gerontol. 1994;49(2):M85-M94. PMID:8126356","verification_status":"unverified","notes":"Chair-rise performance is embedded in the SPPB and frailty assessments; it predicts incident disability but a clean standalone incident-frailty HR is not extracted here. Effect size left null; tier C.","qualitative":true}},"modifiability":{"intervention":"Progressive resistance and power training targeting the lower body; practiced sit-to-stand exercise.","effect_size":"Chair-rise time and repetitions improve substantially with 8-12 weeks of resistance/power training in older adults.","timeframe":"8-12 weeks.","evidence_type":"RCT meta-analysis","citation":"Resistance- and power-training RCT meta-analyses in older adults.","rating":"high"}},{"id":"vo2_kinetics","name":"VO2 kinetics (mean response time)","domain":"mitochondrial_crf","aliases":["oxygen uptake kinetics","VO2 mean response time","VO2 on-kinetics","VO2 recovery kinetics","tau"],"profile":{"mechanism":"VO2 kinetics describe how rapidly oxygen uptake rises at the onset of submaximal exercise (or recovers afterward). Faster kinetics indicate efficient oxygen delivery and mitochondrial oxidative responsiveness; sluggish kinetics reflect impaired microvascular and mitochondrial function and predict poorer functional mobility in older and chronically ill adults.","measurement":{"method":"Breath-by-breath gas analysis during constant-load submaximal exercise transitions or recovery, fitted to exponential models to derive mean response time / tau.","sample_type":"functional test","approx_cost_usd":"150-400"},"signal_quality":"noisy","signal_quality_note":"Breath-by-breath data are inherently noisy; reliable kinetic parameter estimation requires multiple transitions and signal averaging, and modeling choices affect results. Not standardized for routine use.","confounders":["work-rate domain (moderate vs heavy)","number of transitions averaged","modeling/curve-fitting method","fitness status","prior exercise (priming effect)","age"],"testing_cadence":"not routinely tracked; research/clinical-physiology use"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":null,"dementia":null,"frailty":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"slower VO2 kinetics associated with poorer functional mobility in impaired older adults","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"cross-sectional association only; no hard-outcome HR or usable SD published, cannot be standardized","conversion":null,"evidence_tier":"C","n":"small","followup_years":null,"study":"Cross-sectional and small cohort studies link slow submaximal VO2 on- and recovery-kinetics to functional mobility limitation and lower muscle strength in older adults.","study_type":"prospective-cohort","citation":"Bell C, et al. Oxygen-uptake (VO2) kinetics and functional mobility performance in impaired older adults. J Gerontol A Biol Sci Med Sci. 2003;58(1):M36-M40. PMID:12560409","verification_status":"unverified","notes":"Evidence is mechanistic/cross-sectional - slow VO2 kinetics relate to mobility limitation and muscle function in older and chronic-disease populations - but re-search confirmed no hard-outcome HR exists. Left unconvertible, tier C. Largely an intermediate physiologic marker.","qualitative":true}},"modifiability":{"intervention":"Endurance / aerobic training; high-intensity interval training.","effect_size":"VO2 on-kinetics speed up (shorter tau / mean response time) with aerobic training, particularly in older and deconditioned individuals.","timeframe":"6-12 weeks.","evidence_type":"RCT","citation":"Exercise-training studies show acceleration of VO2 kinetics with endurance training.","rating":"moderate"}},{"id":"heart_rate_recovery","name":"Heart rate recovery","domain":"mitochondrial_crf","aliases":["HRR","post-exercise heart rate recovery","heart rate recovery at 1 minute"],"profile":{"mechanism":"Heart rate recovery is the fall in heart rate in the first 1-2 minutes after peak exercise, driven mainly by parasympathetic (vagal) reactivation. Attenuated recovery indicates autonomic dysfunction, an independent marker of cardiovascular risk and mortality.","measurement":{"method":"Difference between peak heart rate and heart rate at 1 (or 2) minutes after a graded exercise test, with a standardized cool-down.","sample_type":"functional test","approx_cost_usd":"100-300"},"signal_quality":"moderate","signal_quality_note":"Reproducible when cool-down protocol (active vs passive recovery, posture) is standardized; protocol differences affect absolute values and abnormality cutoffs vary across studies.","confounders":["cool-down protocol (active vs passive)","body position during recovery","beta-blockers and rate-limiting drugs","fitness level","peak effort achieved","age"],"testing_cadence":"baseline + annual (with exercise testing)"},"outcomes":{"all_cause_mortality":{"hr":1.09,"hr_metric":"per_unit","hr_unit_detail":"per 10-bpm lower 1-minute heart rate recovery, all-cause mortality","direction":"risk","ci_low":1.01,"ci_high":1.19,"hr_per_sd":1.1089,"hr_per_sd_ci":[1.012,1.2321],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 12 (1-minute HRR population SD ~12 bpm, from primary-prevention treadmill-test cohorts (e.g. Cole 1999 NEJM-type distributions; median ~17, IQR-derived SD ~12 bpm).); k = SD/unit = 1.2","conversion":{"unit_value":10,"population_sd":12,"sd_source":"1-minute HRR population SD ~12 bpm, from primary-prevention treadmill-test cohorts (e.g. Cole 1999 NEJM-type distributions; median ~17, IQR-derived SD ~12 bpm)."},"evidence_tier":"A","n":41600,"followup_years":null,"study":"Qiu 2017, JAHA, meta-analysis of 9 prospective cohort studies.","study_type":"meta-analysis","citation":"Qiu S, et al. Heart rate recovery and risk of cardiovascular events and all-cause mortality: a meta-analysis of prospective cohort studies. J Am Heart Assoc. 2017;6(5):e005505. doi:10.1161/JAHA.117.005505. PMID:28487388","verification_status":"verified","notes":"Per 10-bpm lower HRR: all-cause mortality HR 1.09 (1.01-1.19). The continuous per-10-bpm estimate (rather than the attenuated-vs-fast categorical contrast HR 1.68, 1.51-1.88) is used so the cell can be standardized to per-SD. 9 studies, 2,082 deaths among 41,600 participants. Association independent of metabolic risk factors. Observational."},"cvd":{"hr":1.13,"hr_metric":"per_unit","hr_unit_detail":"per 10-bpm lower 1-minute heart rate recovery, cardiovascular events","direction":"risk","ci_low":1.05,"ci_high":1.21,"hr_per_sd":1.158,"hr_per_sd_ci":[1.0603,1.257],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 12 (1-minute HRR population SD ~12 bpm, primary-prevention treadmill-test cohorts.); k = SD/unit = 1.2","conversion":{"unit_value":10,"population_sd":12,"sd_source":"1-minute HRR population SD ~12 bpm, primary-prevention treadmill-test cohorts."},"evidence_tier":"B","n":34267,"followup_years":null,"study":"Qiu 2017, JAHA, meta-analysis of prospective cohort studies.","study_type":"meta-analysis","citation":"Qiu S, et al. J Am Heart Assoc. 2017;6(5):e005505. doi:10.1161/JAHA.117.005505. PMID:28487388","verification_status":"verified","notes":"Per 10-bpm lower HRR: cardiovascular events HR 1.13 (1.05-1.21). The continuous per-10-bpm estimate is used (categorical attenuated-vs-fast HR 1.69, 1.05-2.71) so the cell standardizes to per-SD. 5 studies, 1,061 events among 34,267 participants. Observational."},"cancer":null,"dementia":{"hr":0.9,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD higher heart-rate-recovery index after exercise, incident all-cause dementia","direction":"protective","ci_low":0.82,"ci_high":0.99,"hr_per_sd":0.9,"hr_per_sd_ci":[0.82,0.99],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":46348,"followup_years":12.6,"study":"UK Biobank prospective cohort; heart-rate response and recovery during a submaximal cycle exercise test and incident dementia.","study_type":"prospective-cohort","citation":"Heart rate response and recovery during exercise and dementia risk: a prospective UK Biobank study. Sci Rep. 2025;15. doi:10.1038/s41598-025-22299-2. PMID:41184419","verification_status":"verified","notes":"UK Biobank (n=46,348, median 12.6 y, 519 dementia cases): per 1-SD higher HRR index, incident all-cause dementia HR 0.90 (0.82-0.99) in the age/sex-adjusted model; with full risk-factor adjustment the per-SD HR was 0.72 (0.54-0.94). The recovery-ratio metric gave a concordant per-SD HR 0.90 (0.81-0.99). Native per-SD estimate; the less-adjusted Model 1 figure is used as the conservative comparable value. Associations with Alzheimer's and vascular dementia specifically were not significant. Observational."},"frailty":null},"modifiability":{"intervention":"Aerobic / endurance exercise training, which enhances vagal tone.","effect_size":"Heart rate recovery improves by several bpm with regular aerobic training; trained individuals show faster recovery.","timeframe":"8-12 weeks.","evidence_type":"RCT","citation":"Exercise-training trials demonstrate improved heart rate recovery with aerobic training.","rating":"moderate"}},{"id":"heart_rate_variability","name":"Heart rate variability (HRV)","domain":"mitochondrial_crf","aliases":["HRV","SDNN","RMSSD","vagal tone","autonomic balance"],"profile":{"mechanism":"Heart rate variability quantifies beat-to-beat variation in heart rate, indexing autonomic (mainly parasympathetic) regulation. Higher HRV reflects healthy vagal tone and physiologic adaptability; HRV declines with age and disease and lower values predict mortality and cardiovascular events.","measurement":{"method":"Time-domain (SDNN, RMSSD) and frequency-domain measures from ECG or photoplethysmography over short recordings (~5 min), 24-hour Holter, or consumer wearables.","sample_type":"wearable","approx_cost_usd":"0-300"},"signal_quality":"noisy","signal_quality_note":"HRV is highly state-dependent (posture, breathing, stress, sleep, caffeine, time of day) with large day-to-day variability; recording length and device differ across studies. Trends are more informative than single values.","confounders":["age","posture and breathing rate","physical activity and stress before recording","recording length","device / measurement method","medications (beta-blockers)","alcohol and caffeine","time of day / circadian phase"],"testing_cadence":"trend monitoring (e.g., daily wearable) or baseline + annual clinical recording"},"outcomes":{"all_cause_mortality":{"hr":1.56,"hr_metric":"quartile","hr_unit_detail":"lowest vs other quartiles of 5-minute RMSSD, all-cause mortality (healthy and patient populations)","direction":"risk","ci_low":1.32,"ci_high":1.85,"hr_per_sd":1.1913,"hr_per_sd_ci":[1.1155,1.274],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":38008,"followup_years":null,"study":"Jarczok 2022, Neurosci Biobehav Rev, systematic review/meta-analysis of HRV and mortality across healthy and patient populations (32 studies, 2 datasets).","study_type":"meta-analysis","citation":"Jarczok MN, et al. Heart rate variability in the prediction of mortality: a systematic review and meta-analysis of healthy and patient populations. Neurosci Biobehav Rev. 2022;143:104907. doi:10.1016/j.neubiorev.2022.104907. PMID:36243195","verification_status":"verified","notes":"Pooled HR 1.56 (1.32-1.85) for the lowest 5-minute RMSSD quartile vs other quartiles, across 38,008 participants in healthy and clinical populations. Converted to per-SD using an extreme-quartile approximation (HRV indices are log-normally distributed and analyzed log-transformed). Replaces the prior CVD-patient-only estimate (Fang 2020, low vs high HRV HR 2.12, 1.64-2.75) with a broader general-and-patient-population figure. Observational."},"cvd":{"hr":1.35,"hr_metric":"median_split","hr_unit_detail":"lowest vs highest level of SDNN, first cardiovascular event in populations without known CVD","direction":"risk","ci_low":1.1,"ci_high":1.67,"hr_per_sd":1.2063,"hr_per_sd_ci":[1.0614,1.3778],"comparability":"converted","hr_per_sd_basis":"median_split contrast; k = 1/1.6 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":"~21000 (pooled)","followup_years":null,"study":"Hillebrand 2013, Europace, meta-analysis and dose-response meta-regression in populations without known CVD.","study_type":"meta-analysis","citation":"Hillebrand S, et al. Heart rate variability and first cardiovascular event in populations without known cardiovascular disease: meta-analysis and dose-response meta-regression. Europace. 2013;15(5):742-749. doi:10.1093/europace/eus341. PMID:23425965","verification_status":"verified","notes":"Pooled RR 1.35 (1.10-1.67) comparing lowest vs highest SDNN level for a first cardiovascular event in populations without known CVD (the commonly cited '~40% higher risk'). Conservatively converted with an above/below-median separation; the original studies' grouping was heterogeneous (medians/tertiles), so this is an approximate conversion. Observational."},"cancer":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"lower HRV associated with shorter survival in cancer patients; no general-population cancer-incidence HR","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"evidence is prognostic (HRV measured in established-cancer patients predicting survival), not an incidence hazard in a cancer-free population; the two are not comparable, so no per-SD incidence HR can be assigned","conversion":null,"evidence_tier":"C","n":"varies (pooled prognostic studies)","followup_years":null,"study":"Systematic reviews/meta-analyses of HRV as a prognostic factor for survival in patients already diagnosed with cancer.","study_type":"meta-analysis","citation":"Zhou X, et al. Heart rate variability in the prediction of survival in patients with cancer: a systematic review and meta-analysis. J Psychosom Res. 2016;89:20-25. PMID:27663106. Higher SDNN protective for overall survival, HR ~0.59 (0.46-0.75).","verification_status":"approximate","notes":"HRV evidence in cancer is PROGNOSTIC - higher SDNN predicts longer survival in already-diagnosed cancer patients (HR ~0.59) - not predictive of cancer INCIDENCE in a cancer-free population. These are not comparable to the incidence-based cells used elsewhere in the heat map. No general-population HRV-to-cancer-incidence per-SD HR exists. Left unconvertible/qualitative; tier C. Reverse causation is severe (tumour burden lowers HRV).","qualitative":true},"dementia":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"lower vagally-mediated HRV associated with faster cognitive decline; no incident-dementia per-SD HR","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"available longitudinal evidence quantifies accelerated cognitive decline (effect on a continuous cognitive score), not incident-dementia hazard; no per-SD HR for incident dementia could be sourced","conversion":null,"evidence_tier":"C","n":2702,"followup_years":10,"study":"Whitehall II cohort: midlife vagally-mediated HRV (RMSSD, HF-HRV) and 10-year cognitive decline; plus narrative reviews of HRV and cognition.","study_type":"prospective-cohort","citation":"Britton A / Whitehall II analyses: Midlife heart rate variability and cognitive decline: a large longitudinal cohort study. 2024. PMID:39639946. Low RMSSD and HF-HRV were associated with cognitive decline ~3-3.5 years faster per decade.","verification_status":"approximate","notes":"Lower midlife vagally-mediated HRV predicts faster cognitive decline (low RMSSD: 0.07 SD faster 10-year decline), but the outcome is rate of cognitive decline, not an incident-dementia hazard. No verified per-SD HR for incident dementia was located. Left unconvertible/qualitative rather than borrowing a cognitive-decline effect onto a hazard scale. Direction (lower HRV -> worse) is consistent. Tier C.","qualitative":true},"frailty":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"lower HRV associated with frailty; cross-sectional/odds-ratio evidence, no incident-frailty per-SD HR","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"available evidence is cross-sectional (lower HRV in frail vs non-frail; odds ratios) with a 2025 meta-analysis finding non-significant pooled differences; no prospective per-SD incident-frailty hazard ratio could be sourced","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Cross-sectional studies and a 2025 three-level meta-analysis of HRV and frailty; lower time- and frequency-domain HRV in (pre)frail older adults, but pooled effects were not statistically significant.","study_type":"prospective-cohort","citation":"Parvaneh S, et al. Physiological complexity underlying heart rate dynamics and frailty status in community-dwelling older women. Gerontology 2010; and 2025 systematic review/three-level meta-analysis of HRV and frailty (non-significant pooled difference).","verification_status":"unverified","notes":"Lower HRV is associated with frailty cross-sectionally (e.g. lower heart-rate approximate entropy: OR ~1.99 for being frail), but a 2025 meta-analysis found pooled HRV differences between frail and non-frail groups non-significant, and no prospective per-SD incident-frailty hazard ratio exists. Left unconvertible/qualitative; tier C. Largely a correlate rather than a validated prospective predictor.","qualitative":true}},"modifiability":{"intervention":"Aerobic exercise training; secondarily slow-paced breathing / HRV-biofeedback and improved sleep and stress management.","effect_size":"Aerobic training produces modest increases in HRV (RMSSD/SDNN); biofeedback can acutely raise HRV but durable resting changes are smaller.","timeframe":"8-16 weeks.","evidence_type":"RCT meta-analysis","citation":"Meta-analyses of exercise training and of HRV-biofeedback show modest HRV improvements.","rating":"moderate"}},{"id":"hscrp","name":"hsCRP","domain":"inflammation","aliases":["high-sensitivity C-reactive protein","CRP","hs-CRP"],"profile":{"mechanism":"Acute-phase protein synthesized by the liver in response to IL-6; serves as a downstream integrator of systemic low-grade inflammation ('inflammaging'). Elevated hsCRP marks the chronic inflammatory state that accompanies atherosclerosis, metabolic dysfunction, and biological aging, though Mendelian randomization indicates it is a marker rather than a cause of disease.","measurement":{"method":"High-sensitivity immunoturbidimetric or immunonephelometric assay on a standard clinical chemistry analyzer.","sample_type":"venous blood","approx_cost_usd":"10-30"},"signal_quality":"moderate","signal_quality_note":"Analytically robust and well-standardized, but high within-person biological variability: levels spike acutely with infection, trauma, or recent exercise. Single measurements are noisy; serial measurements or values >10 mg/L should be excluded as acute reactions. Tertile/quartile stability over years is moderate.","confounders":["acute infection or recent illness","obesity and adiposity","smoking","estrogen / hormone therapy","recent vigorous exercise or trauma","chronic conditions (RA, periodontal disease)","statin and NSAID use"],"testing_cadence":"baseline + annual; repeat if >10 mg/L to exclude acute inflammation"},"outcomes":{"all_cause_mortality":{"hr":1.54,"hr_metric":"per_log_sd","hr_unit_detail":"Per 1 SD higher log-e CRP, non-vascular (non-cardiovascular) mortality, adjusted for conventional risk factors","direction":"risk","ci_low":1.4,"ci_high":1.68,"hr_per_sd":1.54,"hr_per_sd_ci":[1.4,1.68],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":160309,"followup_years":10,"study":"Emerging Risk Factors Collaboration 2010, Lancet, individual-participant meta-analysis of 54 prospective studies.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration. C-reactive protein concentration and risk of coronary heart disease, stroke, and mortality: an individual participant meta-analysis. Lancet. 2010;375(9709):132-140. doi:10.1016/S0140-6736(09)61717-7. PMID: 20031199.","verification_status":"verified","notes":"REFINED: replaces the earlier categorical Li 2017 pooled estimate with the ERFC native per-SD-of-log-CRP figure. ERFC reports non-vascular mortality RR 1.55 (1.41-1.69) age/sex-adjusted, 1.54 (1.40-1.68) after full risk-factor adjustment; vascular-mortality and all-cause associations are of broadly similar size. Strong predictive association but NOT causal -- the CRP CHD Genetics Collaboration MR found CRP-raising variants unrelated to disease."},"cvd":{"hr":1.37,"hr_metric":"per_log_sd","hr_unit_detail":"Per 1 SD higher log-e CRP, adjusted for conventional risk factors (coronary heart disease)","direction":"risk","ci_low":1.27,"ci_high":1.48,"hr_per_sd":1.37,"hr_per_sd_ci":[1.27,1.48],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":160309,"followup_years":10,"study":"Emerging Risk Factors Collaboration 2010, Lancet, individual-participant meta-analysis of 54 prospective studies.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration. C-reactive protein concentration and risk of coronary heart disease, stroke, and mortality: an individual participant meta-analysis. Lancet. 2010;375(9709):132-140. doi:10.1016/S0140-6736(09)61717-7. PMID: 20031199.","verification_status":"verified","notes":"HR is 1.63 (1.51-1.76) with age/sex adjustment only, attenuating to 1.37 after full risk-factor adjustment, indicating substantial confounding. CRITICAL: the CRP CHD Genetics Collaboration Mendelian randomization study (BMJ 2011;342:d548, ~194,000 participants) found CRP-raising genetic variants were NOT associated with coronary disease, concluding CRP concentration is unlikely to be even a modest causal factor. hsCRP is a strong RISK PREDICTOR but not a causal target -- this is where the field oversells."},"cancer":{"hr":1.105,"hr_metric":"per_unit","hr_unit_detail":"Per 1 natural-log unit higher CRP, overall cancer incidence (pooled prospective cohorts)","direction":"risk","ci_low":1.033,"ci_high":1.178,"hr_per_sd":1.1083,"hr_per_sd_ci":[1.034,1.1838],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 1.03 (SD of natural-log CRP ~1.0-1.1 in general adult populations (NHANES / ERFC-type distributions: median ~2 mg/L, IQR ~1-4.5 mg/L); ~1.03 used as a central estimate. Because the SD of ln(CRP) is close to 1, the per-log-unit and per-log-SD figures nearly coincide.); k = SD/unit = 1.03","conversion":{"unit_value":1,"population_sd":1.03,"log2_sd":null,"sd_source":"SD of natural-log CRP ~1.0-1.1 in general adult populations (NHANES / ERFC-type distributions: median ~2 mg/L, IQR ~1-4.5 mg/L); ~1.03 used as a central estimate. Because the SD of ln(CRP) is close to 1, the per-log-unit and per-log-SD figures nearly coincide."},"evidence_tier":"B","n":194796,"followup_years":null,"study":"Guo 2013, Asian Pacific J Cancer Prev, meta-analysis of 11 prospective cohort studies (11,459 cancer cases).","study_type":"meta-analysis","citation":"Guo YZ, Pan L, Du CJ, Ren DQ, Xie XM. Association between C-reactive protein and risk of cancer: a meta-analysis of prospective cohort studies. Asian Pac J Cancer Prev. 2013;14(1):243-248. doi:10.7314/apjcp.2013.14.1.243. PMID: 23534731.","verification_status":"verified","notes":"REFINED: replaces the earlier categorical Li 2017 cancer-mortality pooled estimate with a continuous per-ln-unit HR for cancer INCIDENCE (1.105, 1.033-1.178). Signal is driven by lung cancer (HR 1.31 per ln-unit); breast/prostate/colorectal associations were not significant. Converted via the SD of ln(CRP); since that SD is ~1, the per-log-SD figure is nearly identical to the native per-ln-unit HR. Mendelian randomization does NOT support a causal CRP-cancer link -- the association likely reflects reverse causation (preclinical tumor inflammation) and confounding (smoking). Predictive, not causal."},"dementia":{"hr":1.37,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher CRP, all-cause dementia","direction":"risk","ci_low":1.05,"ci_high":1.78,"hr_per_sd":1.37,"hr_per_sd_ci":[1.05,1.78],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled prospective cohorts","followup_years":null,"study":"Darweesh 2018, Alzheimer's & Dementia, meta-analysis of inflammatory markers and dementia risk.","study_type":"meta-analysis","citation":"Darweesh SKL et al. Inflammatory markers and the risk of dementia and Alzheimer's disease: a meta-analysis. Alzheimers Dement. 2018;14(11):1450-1459. doi:10.1016/j.jalz.2018.02.014.","verification_status":"approximate","notes":"CRP associated with all-cause dementia but NOT specifically with Alzheimer's disease in the same meta-analysis; signal appears driven by vascular dementia. Reverse causation (prodromal inflammation) is a concern given the long preclinical dementia phase."},"frailty":{"hr":1.27,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher CRP, incident frailty in women over 4 years (fully adjusted odds ratio)","direction":"risk","ci_low":0.96,"ci_high":1.69,"hr_per_sd":1.27,"hr_per_sd_ci":[0.96,1.69],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":1158,"followup_years":4,"study":"Gale 2013, English Longitudinal Study of Ageing, prospective cohort (women subset; 150 incident frailty cases).","study_type":"prospective-cohort","citation":"Gale CR et al. Inflammatory markers and incident frailty in men and women: the English Longitudinal Study of Ageing. Age (Dordr). 2013;35(6):2493-2501. doi:10.1007/s11357-013-9528-9. PMID: 23543263.","verification_status":"verified","notes":"REFINED: replaces the earlier Soysal log-unit estimate with a native per-SD figure. Fully-adjusted OR 1.27 (0.96-1.69) in women (borderline; age-adjusted OR was 1.69, 1.32-2.17); NO association in men (OR 0.93, 0.66-1.30). Soysal 2016 meta-analysis of 3 longitudinal studies likewise found CRP did not significantly predict incident frailty. Honest read: CRP tracks WITH frailty more than it forecasts it, and the prospective signal is sex-specific and weak."}},"modifiability":{"intervention":"Statin therapy, weight loss, and regular aerobic exercise; canakinumab/colchicine for residual inflammatory risk.","effect_size":"Rosuvastatin lowered hsCRP ~37% in JUPITER; diet-induced weight loss produces a comparable reduction (roughly proportional to kg lost); regular exercise lowers hsCRP by ~20-30%.","timeframe":"Weeks for statins; 3-6 months for weight loss and exercise.","evidence_type":"RCT","citation":"Ridker PM et al. JUPITER trial. N Engl J Med. 2008;359:2195-2207. POUNDS LOST trial (weight loss & hsCRP), Am J Clin Nutr 2012.","rating":"high"}},{"id":"il6","name":"IL-6","domain":"inflammation","aliases":["interleukin-6","IL6"],"profile":{"mechanism":"Pleiotropic pro-inflammatory cytokine and the principal driver of hepatic acute-phase protein synthesis (including CRP and fibrinogen). A central mediator of 'inflammaging'; unlike CRP, human genetic (IL6R) evidence supports a causal role in atherosclerotic disease, making the IL-6 pathway a validated therapeutic target.","measurement":{"method":"ELISA or high-sensitivity immunoassay (e.g., electrochemiluminescence); proteomic panels (Olink, SomaScan) also quantify it.","sample_type":"venous blood","approx_cost_usd":"30-90"},"signal_quality":"moderate","signal_quality_note":"Biologically meaningful but analytically more variable than CRP: short half-life, diurnal variation, sensitivity to recent exercise/infection, and assay-platform differences. Single measurements are noisy; cross-assay comparability is limited.","confounders":["acute infection / illness","obesity (adipose tissue secretes IL-6)","recent exercise","smoking","diurnal rhythm","assay platform variability","chronic inflammatory disease"],"testing_cadence":"baseline + annual; not yet routine in standard care"},"outcomes":{"all_cause_mortality":{"hr":1.48,"hr_metric":"per_log_sd","hr_unit_detail":"Per 1 SD higher log IL-6, all-cause mortality (adjusted)","direction":"risk","ci_low":1.33,"ci_high":1.64,"hr_per_sd":1.48,"hr_per_sd_ci":[1.33,1.64],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":1843,"followup_years":12,"study":"Lee S et al. 2012, Rancho Bernardo Study, general-population older-adult prospective cohort; concordant with Framingham immune-phenotype analysis.","study_type":"prospective-cohort","citation":"Lee S et al. Serum interleukin-6 concentrations and mortality in older adults: the Rancho Bernardo Study. PLoS One. 2012;7(4):e34218. doi:10.1371/journal.pone.0034218. PMID: 22509280. Corroborated by Framingham Heart Study immune-phenotype analysis 2024, PMID: 38867269.","verification_status":"verified","notes":"Multiple large cohorts (Rancho Bernardo HR ~1.48 per SD log IL-6; Framingham) converge on HR ~1.4-1.5 per SD; association persists after CRP adjustment, indicating IL-6 carries independent prognostic information. Tier A from consistency across cohorts. Native per-SD-of-log estimate -- IL-6 is right-skewed and analyzed log-transformed."},"cvd":{"hr":1.25,"hr_metric":"per_log_sd","hr_unit_detail":"Per 1 SD higher log IL-6, non-fatal MI / coronary heart disease (risk-factor adjusted; pooled cohort estimate)","direction":"risk","ci_low":1.19,"ci_high":1.32,"hr_per_sd":1.25,"hr_per_sd_ci":[1.19,1.32],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":">130000","followup_years":null,"study":"IL6R Mendelian Randomisation Analysis Consortium 2012, Lancet (causal); observational per-SD HR from Emerging Risk Factors Collaboration-type pooled cohort data.","study_type":"mendelian-randomization","citation":"IL6R Genetics Consortium / Sarwar N et al. The interleukin-6 receptor as a target for prevention of coronary heart disease: a mendelian randomisation analysis. Lancet. 2012;379(9822):1205-1213. doi:10.1016/S0140-6736(11)60110-X. PMID: 22421340.","verification_status":"approximate","notes":"IMPORTANT contrast with CRP: the IL6R variant (rs7529229, marking p.Asp358Ala) that mimics IL-6 signaling blockade was associated with LOWER coronary heart disease (per-allele OR 0.95, 0.93-0.97) in ~25,458 cases / 100,740 controls -- genetic evidence DOES support a causal role for IL-6 signaling. Observational per-SD HR is approximate (pooled cohort estimates ~1.2-1.3); causal validation is the key point. This anchors the canakinumab (CANTOS) and colchicine cardiovascular trials."},"cancer":{"hr":1.2,"hr_metric":"per_log_sd","hr_unit_detail":"Per 1 SD higher log IL-6, cancer mortality (approximate, older-adult cohort)","direction":"risk","ci_low":1.05,"ci_high":1.4,"hr_per_sd":1.2,"hr_per_sd_ci":[1.05,1.4],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":"older-adult cohorts","followup_years":null,"study":"Rancho Bernardo Study and similar elderly cohorts reporting IL-6 with cancer mortality.","study_type":"prospective-cohort","citation":"Lee S et al. Serum interleukin-6 concentrations and mortality in older adults: the Rancho Bernardo Study. PLoS One. 2012;7(4):e34218. PMID: 22509280.","verification_status":"unverified","notes":"IL-6 elevation associates with cancer mortality in observational cohorts, but no pooled meta-analytic estimate confirmed and reverse causation (tumor-secreted IL-6) is a major concern. Estimate is an order-of-magnitude approximation; treat as low-confidence."},"dementia":{"hr":1.32,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher IL-6, all-cause dementia","direction":"risk","ci_low":1.06,"ci_high":1.64,"hr_per_sd":1.32,"hr_per_sd_ci":[1.06,1.64],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled prospective cohorts","followup_years":null,"study":"Darweesh 2018, Alzheimer's & Dementia, meta-analysis of inflammatory markers and dementia risk.","study_type":"meta-analysis","citation":"Darweesh SKL et al. Inflammatory markers and the risk of dementia and Alzheimer's disease: a meta-analysis. Alzheimers Dement. 2018;14(11):1450-1459. doi:10.1016/j.jalz.2018.02.014.","verification_status":"verified","notes":"REFINED to the verified Darweesh pooled figure: IL-6 HR 1.32 (1.06-1.64) for all-cause dementia, but NOT associated with Alzheimer's disease alone (HR 1.06, 0.83-1.35) -- signal appears vascular. Reverse causation across the long dementia prodrome remains a caveat."},"frailty":{"hr":1.19,"hr_metric":"per_unit","hr_unit_detail":"Per 1 unit higher natural-log IL-6, incident frailty (longitudinal subset; OR reported as risk ratio)","direction":"risk","ci_low":0.87,"ci_high":1.62,"hr_per_sd":1.1394,"hr_per_sd_ci":[0.9008,1.4359],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.75 (SD of natural-log IL-6 ~0.75 in older-adult populations, derived from a log-normal fit to a representative older-adult distribution (linear mean ~2.0 pg/mL, SD ~1.74 pg/mL; CV ~0.87 implies SD of ln(IL-6) = sqrt(ln(1+CV^2)) ~0.75). Consistent with the 0.6-0.8 range seen across elderly cohorts. Approximate.); k = SD/unit = 0.75","conversion":{"unit_value":1,"population_sd":0.75,"log2_sd":null,"sd_source":"SD of natural-log IL-6 ~0.75 in older-adult populations, derived from a log-normal fit to a representative older-adult distribution (linear mean ~2.0 pg/mL, SD ~1.74 pg/mL; CV ~0.87 implies SD of ln(IL-6) = sqrt(ln(1+CV^2)) ~0.75). Consistent with the 0.6-0.8 range seen across elderly cohorts. Approximate."},"evidence_tier":"C","n":3402,"followup_years":null,"study":"Soysal 2016, Ageing Research Reviews, meta-analysis (3 longitudinal studies for incident frailty).","study_type":"meta-analysis","citation":"Soysal P et al. Inflammation and frailty in the elderly: a systematic review and meta-analysis. Ageing Res Rev. 2016;31:1-8. doi:10.1016/j.arr.2016.08.006. PMID: 27592340.","verification_status":"approximate","notes":"REFINED: previously unconvertible. The native HR is per 1 unit of ln(IL-6) with no SD reported in the source; converted using a population SD of ln(IL-6) ~0.75 derived from a log-normal fit to older-adult IL-6 distributions -- an approximate, externally-sourced SD, so verification_status is downgraded to approximate. Strong cross-sectional IL-6-frailty link, but the 3 longitudinal studies did NOT show IL-6 significantly predicting incident frailty (CI crosses 1). Related pooled analyses show IL-6 predicting incident mobility disability (HR ~1.26 per log unit)."}},"modifiability":{"intervention":"Direct pathway blockade (IL-6R antibody tocilizumab; IL-1beta antibody canakinumab; colchicine) lowers IL-6 axis activity; lifestyle (exercise, weight loss) produces smaller reductions.","effect_size":"Canakinumab (CANTOS) reduced hsCRP ~37% and IL-6 substantially with a 15% cut in major cardiovascular events; tocilizumab strongly suppresses CRP/fibrinogen. Exercise and weight loss lower IL-6 modestly (~10-25%).","timeframe":"Days to weeks for biologics; months for lifestyle change.","evidence_type":"RCT","citation":"Ridker PM et al. CANTOS trial (canakinumab). N Engl J Med. 2017;377:1119-1131. IL6R MR consortium, Lancet 2012.","rating":"high"}},{"id":"tnf_alpha","name":"TNF-alpha","domain":"inflammation","aliases":["tumor necrosis factor alpha","TNF-a","TNFa"],"profile":{"mechanism":"Pro-inflammatory cytokine central to innate immunity, apoptosis signaling, insulin resistance, and cachexia. Implicated in inflammaging and tissue catabolism; its soluble receptors (sTNFR1/sTNFR2) are more stable, prognostically informative analytes than free TNF-alpha itself.","measurement":{"method":"High-sensitivity ELISA or multiplex immunoassay; soluble TNF receptors (sTNFR1/2) often preferred for stability.","sample_type":"venous blood","approx_cost_usd":"30-90"},"signal_quality":"noisy","signal_quality_note":"Free circulating TNF-alpha is present at very low concentrations with a short half-life, marked diurnal variation, and poor assay reproducibility near the detection limit. Soluble receptors are far more reliable; most robust prognostic data come from sTNFR measurements rather than TNF-alpha itself.","confounders":["assay sensitivity limits and platform differences","diurnal variation","acute infection","obesity / adipose secretion","renal function (affects soluble receptor clearance)","smoking"],"testing_cadence":"research / specialist use; not routine"},"outcomes":{"all_cause_mortality":{"hr":1.34,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD (2.81 pg/mL) higher TNF-alpha, all-cause mortality in very old adults","direction":"risk","ci_low":1.12,"ci_high":1.6,"hr_per_sd":1.34,"hr_per_sd_ci":[1.12,1.6],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"centenarian / oldest-old cohort","followup_years":null,"study":"Bruunsgaard 2003, American Journal of Medicine, prospective study of TNF-alpha and mortality in centenarians.","study_type":"prospective-cohort","citation":"Bruunsgaard H et al. Elevated levels of tumor necrosis factor alpha and mortality in centenarians. Am J Med. 2003;115(4):278-283. doi:10.1016/S0002-9343(03)00329-2. PMID: 12967692.","verification_status":"approximate","notes":"REFINED: previously a null/qualitative cell. A genuine native per-SD HR exists, but only in a centenarian cohort -- a highly selected oldest-old population, so generalizability to general-population mortality is limited (hence Tier C). Free TNF-alpha is also analytically noisy near the detection limit. Soluble TNF receptors (sTNFR1) are the more robust analyte and consistently predict mortality (e.g., NOMAS Q4-vs-Q1 HR 1.8), but that is a distinct biomarker."},"cvd":{"hr":2.9,"hr_metric":"tertile","hr_unit_detail":"sTNFR1 tertile 3 vs tertile 1, death or new heart failure after acute MI (soluble TNF receptor, not free TNF-alpha)","direction":"risk","ci_low":1.9,"ci_high":3.8,"hr_per_sd":1.6297,"hr_per_sd_ci":[1.3424,1.8448],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"post-MI cohort","followup_years":null,"study":"Valgimigli 2005, Circulation, soluble TNF receptor-1 after acute myocardial infarction.","study_type":"prospective-cohort","citation":"Valgimigli M et al. Tumor necrosis factor-alpha receptor 1 is a major predictor of mortality and new-onset heart failure in patients with acute myocardial infarction. Circulation. 2005;111(7):863-870. PMID: 15699251.","verification_status":"approximate","notes":"Estimate is for the soluble TNF receptor (sTNFR1) in a post-MI population, NOT free TNF-alpha in primary prevention. Although a tertile contrast, it is flagged categorical (not converted) because the analyte/population mismatch makes a per-SD placement misleading. Strong prognostic marker in established CVD. Tier C reflects the mismatch."},"cancer":{"hr":1.32,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher soluble TNF receptor 1 (sTNFR1), cancer mortality (soluble TNF receptor, not free TNF-alpha)","direction":"risk","ci_low":1.11,"ci_high":1.57,"hr_per_sd":1.32,"hr_per_sd_ci":[1.11,1.57],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":775,"followup_years":8.1,"study":"Carlsson 2014, Atherosclerosis, ULSAM community cohort of elderly men.","study_type":"prospective-cohort","citation":"Carlsson AC, Juhlin CC, Larsson TE, et al. Soluble tumor necrosis factor receptor 1 (sTNFR1) is associated with increased total mortality due to cancer and cardiovascular causes -- findings from two community based cohorts of elderly. Atherosclerosis. 2014;237(1):236-242. doi:10.1016/j.atherosclerosis.2014.09.005. PMID: 25255422.","verification_status":"approximate","notes":"REFINED: previously a null cell. A genuine native per-SD HR exists (1.32, 1.11-1.57) but for the soluble receptor sTNFR1, NOT free TNF-alpha -- consistent with how the TNF-alpha/cvd cell handles the same analyte mismatch. sTNFR1 is the stable, prognostically informative analyte; free TNF-alpha is analytically noisy. Because of the analyte mismatch the figure is flagged out of the comparable per-SD scale rather than placed on it. Concordant evidence: circulating sTNFR2 associates with colorectal cancer risk (meta-analytic OR ~1.59). Single elderly-men cohort -- Tier C."},"dementia":{"hr":2.59,"hr_metric":"tertile","hr_unit_detail":"Top vs bottom tertile of PBMC spontaneous TNF-alpha production, incident Alzheimer's disease (PBMC production, not plasma concentration)","direction":"risk","ci_low":1.09,"ci_high":6.12,"hr_per_sd":1.5473,"hr_per_sd_ci":[1.0403,2.2956],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":691,"followup_years":null,"study":"Tan 2007, Neurology, Framingham Study, cognitively intact community-dwelling older adults (mean age 79).","study_type":"prospective-cohort","citation":"Tan ZS, Beiser AS, Vasan RS, et al. Inflammatory markers and the risk of Alzheimer disease: the Framingham Study. Neurology. 2007;68(22):1902-1908. doi:10.1212/01.wnl.0000263217.36439.da. PMID: 17536046.","verification_status":"approximate","notes":"REFINED: previously a null cell. Framingham reported TNF-alpha top-tertile HR 2.59 (1.09-6.12) for incident Alzheimer's disease. IMPORTANT analyte caveat: TNF-alpha was measured as SPONTANEOUS PRODUCTION by peripheral blood mononuclear cells, not circulating plasma concentration -- a related but distinct exposure (free plasma TNF-alpha is analytically noisy near the detection limit). Converted from a tertile contrast. Wide CI, single cohort, distinct analyte -- Tier C. The broader inflammatory-marker meta-analyses (Darweesh 2018) did not isolate a TNF-alpha plasma figure for dementia."},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Soysal 2016 meta-analysis reports cross-sectional TNF-alpha elevation in frail individuals; no significant longitudinal prediction.","study_type":"meta-analysis","citation":"Soysal P et al. Inflammation and frailty in the elderly. Ageing Res Rev. 2016;31:1-8. PMID: 27592340.","verification_status":"unverified","notes":"Searched specifically for an incident-frailty HR: TNF-alpha is cross-sectionally higher in frail vs robust older adults, but no verified longitudinal HR for incident frailty exists -- the inflammatory-marker meta-analyses found inflammatory parameters generally do not predict frailty onset, and free TNF-alpha is analytically noisy. Left without a numeric cell to avoid fabricated precision; honest emptiness.","qualitative":true}},"modifiability":{"intervention":"Anti-TNF biologics (etanercept, infliximab, adalimumab) in inflammatory disease; lifestyle (weight loss, exercise) for modest reductions in the general population.","effect_size":"Anti-TNF therapy strongly suppresses TNF signaling and, in observational meta-analysis of rheumatoid arthritis cohorts, was associated with reduced cardiovascular events (RR ~0.46); lifestyle change yields modest reductions.","timeframe":"Days to weeks for biologics; months for lifestyle.","evidence_type":"observational","citation":"Barnabe C et al. Systematic review and meta-analysis: anti-TNF therapy and cardiovascular events in rheumatoid arthritis. Arthritis Care Res. 2011;63(4):522-529. PMID: 20957658.","rating":"moderate"}},{"id":"glyca","name":"GlycA","domain":"inflammation","aliases":["glycoprotein acetyls","NMR glycoprotein acetylation signal","N-acetyl glycoprotein"],"profile":{"mechanism":"Composite NMR signal arising from N-acetyl methyl groups of glycosylated acute-phase proteins (alpha-1-acid glycoprotein, haptoglobin, alpha-1-antitrypsin, alpha-1-antichymotrypsin, transferrin). Integrates both protein abundance and glycosylation state, capturing a stable, time-averaged measure of chronic systemic inflammation that predicts long-term disease risk.","measurement":{"method":"Proton (1H) nuclear magnetic resonance spectroscopy of plasma/serum, typically as part of a multi-analyte NMR metabolomics panel.","sample_type":"venous blood","approx_cost_usd":"30-100"},"signal_quality":"clean","signal_quality_note":"Lower within-person biological variability than CRP because it averages several glycoproteins with longer half-lives; NMR quantification is highly reproducible. Less sensitive to transient acute spikes, making it a comparatively stable inflammation index. Newer marker with less standardization across labs.","confounders":["obesity / adiposity","smoking","acute infection (less than CRP)","metabolic syndrome and diabetes","NMR platform / lab differences","statin use"],"testing_cadence":"baseline + every few years; not yet routine clinical use"},"outcomes":{"all_cause_mortality":{"hr":1.74,"hr_metric":"quartile","hr_unit_detail":"Top vs bottom quartile of GlycA, pooled all-cause mortality across 7 cohorts","direction":"risk","ci_low":1.4,"ci_high":2.17,"hr_per_sd":1.2437,"hr_per_sd_ci":[1.1416,1.3566],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":63180,"followup_years":12.6,"study":"Connelly 2019, J Intern Med, meta-analysis of 7 population-based cohorts including the PREVEND study.","study_type":"meta-analysis","citation":"Connelly MA et al. GlycA, a novel pro-inflammatory glycoprotein biomarker, is associated with mortality: results from the PREVEND study and meta-analysis. J Intern Med. 2019;286(5):596-609. doi:10.1111/joim.12953. PMID: 31260573.","verification_status":"verified","notes":"Pooled RR 1.74 top vs bottom quartile across 7 cohorts (8,153 deaths). PREVEND primary HR 1.43 (1.09-1.87). Consistent with Women's Health Study per-SD HR ~1.14. Newer marker -- evidence base shallower than CRP/IL-6; Tier B. Converted from quartile contrast as no pooled native per-SD estimate is available."},"cvd":{"hr":1.64,"hr_metric":"quartile","hr_unit_detail":"Quartile 4 vs quartile 1 of GlycA, incident cardiovascular disease","direction":"risk","ci_low":1.39,"ci_high":1.93,"hr_per_sd":1.215,"hr_per_sd_ci":[1.1384,1.2955],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":27491,"followup_years":17,"study":"Akinkuolie 2014, Women's Health Study, prospective cohort of initially healthy women.","study_type":"prospective-cohort","citation":"Akinkuolie AO et al. A novel protein glycan biomarker and future cardiovascular disease events. J Am Heart Assoc. 2014;3(5):e001221. doi:10.1161/JAHA.114.001221. PMID: 25249300.","verification_status":"verified","notes":"Graded quartile relationship. Note: the PREVEND meta-analysis found GlycA was NOT independently associated with CARDIOVASCULAR mortality after full adjustment (nor was hsCRP) -- the incident-CVD signal partly attenuates with adjustment. No Mendelian randomization evidence; causality unestablished. Field should not yet treat GlycA as a causal target."},"cancer":{"hr":1.08,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher GlycA, cancer mortality at maximal follow-up","direction":"risk","ci_low":1.01,"ci_high":1.16,"hr_per_sd":1.08,"hr_per_sd_ci":[1.01,1.16],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":27524,"followup_years":20.5,"study":"Duprez / Otvos 2016, Women's Health Study, circulating N-linked glycoprotein acetyls and longitudinal mortality.","study_type":"prospective-cohort","citation":"Duprez DA et al. Circulating N-linked glycoprotein acetyls and longitudinal mortality risk. Circ Res. 2016;118(7):1146-1153. doi:10.1161/CIRCRESAHA.115.308078. PMID: 26951635.","verification_status":"verified","notes":"Modest association; stronger at 5 years (HR 1.23, 1.02-1.47) than at maximal follow-up, suggesting partial reverse causation from preclinical malignancy. A separate Women's Health Study analysis found GlycA predicts colorectal cancer incidence (HR 1.19 per SD, 1.06-1.35). Single-cohort, single-sex data -- Tier C."},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":118021,"followup_years":13.1,"study":"Harshfield 2023, Neurology, UK Biobank metabolomic profiles and incident stroke/dementia.","study_type":"prospective-cohort","citation":"Harshfield EL, Markus HS. Association of baseline metabolomic profiles with incident stroke and dementia and with imaging markers of cerebral small vessel disease. Neurology. 2023;101(5):e489-e501. doi:10.1212/WNL.0000000000207242.","verification_status":"verified","notes":"Searched specifically: the largest, best-controlled prospective analysis (UK Biobank, 118,021 participants, median 13.1y) found GlycA was NOT significantly associated with incident ALL-CAUSE dementia after adjustment for vascular risk factors. GlycA does predict incident STROKE and is reported to associate with vascular dementia, but no convertible, adjusted all-cause-dementia HR with CI was found. Left null rather than misrepresent a stroke/vascular-dementia signal as an all-cause-dementia HR -- honest emptiness.","qualitative":true},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Multicohort observational and Mendelian randomization analyses link GlycA to the Frailty Index.","study_type":"mendelian-randomization","citation":"Liu D et al. Unraveling the metabolic underpinnings of frailty using multicohort observational and Mendelian randomization analyses. Aging Cell. 2023. PMC10410014.","verification_status":"unverified","notes":"GlycA had the strongest positive association with the Frailty Index among NMR biomarkers (+1.40% Frailty Index per SD, 1.35-1.44), and MR supported a causal effect (beta +0.37% per SD). However, these are continuous Frailty-Index slope estimates, NOT a hazard ratio for incident frailty -- no convertible time-to-event HR was found, so the cell is left without a numeric HR rather than misrepresenting a slope as an HR.","qualitative":true}},"modifiability":{"intervention":"Weight loss, exercise, and statin therapy lower GlycA, paralleling effects on other acute-phase markers.","effect_size":"Statins and lifestyle interventions reduce GlycA modestly (roughly 5-15%); magnitude tracks reductions in adiposity and CRP.","timeframe":"Months.","evidence_type":"observational","citation":"Observational and secondary-analysis data (e.g., statin trials with NMR substudies); no dedicated large RCT with GlycA as primary endpoint.","rating":"moderate"}},{"id":"nlr","name":"Neutrophil:lymphocyte ratio (NLR)","domain":"inflammation","aliases":["NLR","neutrophil-to-lymphocyte ratio"],"profile":{"mechanism":"Ratio derived from a standard complete blood count; integrates the innate (neutrophil) and adaptive (lymphocyte) immune compartments. A high ratio reflects active inflammatory/stress responses with relative lymphopenia, a pattern associated with immunosenescence, physiologic stress, and adverse aging trajectories.","measurement":{"method":"Calculated from an automated complete blood count with differential (absolute neutrophil count divided by absolute lymphocyte count).","sample_type":"venous blood","approx_cost_usd":"5-20"},"signal_quality":"noisy","signal_quality_note":"Cheap and ubiquitous (derived from routine CBC), but highly non-specific and labile: shifts acutely with infection, physical/psychological stress, corticosteroids, and time of day. No standardized cut-points; tertile/quartile definitions vary widely across studies, limiting comparability.","confounders":["acute infection or illness","corticosteroid and other immunomodulatory drugs","physical / psychological stress","diurnal variation","smoking","absence of standardized thresholds","hematologic conditions"],"testing_cadence":"opportunistic -- available on any CBC; interpret with clinical context"},"outcomes":{"all_cause_mortality":{"hr":1.14,"hr_metric":"quartile","hr_unit_detail":"Per one-quartile increase in NLR, all-cause mortality (US general population)","direction":"risk","ci_low":1.1,"ci_high":1.17,"hr_per_sd":1.0529,"hr_per_sd_ci":[1.0382,1.0638],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":"NHANES 1999-2014 (>30000)","followup_years":null,"study":"NHANES 1999-2014 general-population analysis of NLR and mortality.","study_type":"prospective-cohort","citation":"Song M et al. Neutrophil-to-lymphocyte ratio and mortality in the United States general population. Sci Rep. 2021;11:464. doi:10.1038/s41598-020-79431-7.","verification_status":"verified","notes":"REFINED: replaces the loosely-defined Rotterdam per-unit estimate with the NHANES per-quartile figure, which has a defined contrast convertible by the standardization rules. Estimates vary widely by contrast across the literature (categorical high-vs-low ~1.43; Danish registry HR ~2.06 for NLR>=6) -- NLR unit definitions are inconsistent, a major limitation. Predictive only; NLR is a downstream readout of inflammation/stress."},"cvd":{"hr":1.04,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher NLR, incident cardiovascular disease (fully adjusted)","direction":"risk","ci_low":1.04,"ci_high":1.05,"hr_per_sd":1.04,"hr_per_sd_ci":[1.04,1.05],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":423701,"followup_years":13.4,"study":"Qin 2025, Cardiovascular Diabetology, UK Biobank prospective cohort (45,941 incident CVD events).","study_type":"prospective-cohort","citation":"Qin P, Ho FK, Celis-Morales CA, Pell JP. Association between systemic inflammation biomarkers and incident cardiovascular disease in 423,701 individuals: evidence from the UK Biobank cohort. Cardiovasc Diabetol. 2025;24:162. doi:10.1186/s12933-025-02721-9. PMID: 40234895.","verification_status":"verified","notes":"REFINED: replaces the earlier heterogeneous categorical Angkananard pooled OR with a native per-SD HR from a large, fully-adjusted UK Biobank cohort. HR 1.04 (1.04-1.05) per SD; the NLR-CVD relationship was linear. The per-SD effect is small but precisely estimated; categorical high-vs-low contrasts in the older meta-analytic literature look larger (~1.6) because they span a wider exposure range. Predictive, not causal -- Mendelian randomization of genetically-predicted NLR has not supported a causal CAD effect."},"cancer":{"hr":1.03,"hr_metric":"quartile","hr_unit_detail":"Per one-quartile increase in NLR, overall (any-site) incident cancer","direction":"risk","ci_low":1.02,"ci_high":1.04,"hr_per_sd":1.0117,"hr_per_sd_ci":[1.0078,1.0156],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":443540,"followup_years":6.9,"study":"Cook 2024, Cancer Epidemiol Biomarkers Prev, UK Biobank prospective cohort (22,747 incident cancers).","study_type":"prospective-cohort","citation":"Cook MB et al. White blood cell count, neutrophil-to-lymphocyte ratio, and incident cancer in the UK Biobank. Cancer Epidemiol Biomarkers Prev. 2024;33(6):821-829. doi:10.1158/1055-9965.EPI-23-1145.","verification_status":"verified","notes":"REFINED: replaces the earlier non-significant NHANES categorical cancer-MORTALITY estimate with a significant per-quartile HR for cancer INCIDENCE from a large UK Biobank cohort (HR 1.03, 1.02-1.04). Site-specific signals are stronger for kidney, colon, lung and soft-tissue cancers; the overall effect is small. Converted from the quartile metric for comparability (consistent with the NLR all-cause-mortality cell). Predictive; NLR is a downstream readout of inflammation/immunosenescence and possibly preclinical tumor inflammation."},"dementia":{"hr":1.16,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher NLR, incident all-cause dementia","direction":"risk","ci_low":1.11,"ci_high":1.2,"hr_per_sd":1.16,"hr_per_sd_ci":[1.11,1.2],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":361653,"followup_years":9,"study":"UK Biobank prospective cohort analysis of peripheral immunity and incident dementia (4,239 incident dementia cases).","study_type":"prospective-cohort","citation":"UK Biobank prospective cohort: neutrophil-to-lymphocyte ratio and incident dementia. Median follow-up ~9 years, 361,653 participants. (Peripheral immunity and risk of incident dementia, Mol Psychiatry / Transl Psychiatry 2022-2023 series.)","verification_status":"approximate","notes":"REFINED: previously a null cell. Large UK Biobank analysis gives a native per-SD HR 1.16 (1.11-1.20) for incident dementia. A separate biobank analysis reports a weaker Alzheimer's-specific signal (HR ~1.03 per SD), consistent with the cross-marker pattern that inflammation tracks vascular rather than Alzheimer dementia. Status approximate -- exact cohort report not line-verified."},"frailty":{"hr":2.06,"hr_metric":"quartile","hr_unit_detail":"NLR quartile 4 vs quartile 1, incident frailty over 3 years (multivariable-adjusted odds ratio)","direction":"risk","ci_low":1.18,"ci_high":3.59,"hr_per_sd":1.3291,"hr_per_sd_ci":[1.0673,1.654],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":1206,"followup_years":3,"study":"Xu 2022, Frontiers in Medicine, Chinese Longitudinal Healthy Longevity Survey, prospective cohort (164 incident frailty cases).","study_type":"prospective-cohort","citation":"Xu W, Liang Y, Lin Z. Association between neutrophil-lymphocyte ratio and frailty: the Chinese Longitudinal Healthy Longevity Survey. Front Med (Lausanne). 2022;8:783077. doi:10.3389/fmed.2021.783077. PMID: 35083244.","verification_status":"verified","notes":"REFINED: previously a null cell. Prospective CLHLS analysis of robust/pre-frail elders found NLR Q4 vs Q1 OR 2.06 (1.18-3.59) for incident frailty; dichotomized NLR>=3 gave OR 1.84 (1.14-2.97). Converted from the quartile contrast. Single-cohort, modest size (164 cases), 3-year follow-up -- Tier C. NLR is a downstream stress/inflammation readout, not a causal frailty driver."}},"modifiability":{"intervention":"No NLR-specific intervention; it falls with resolution of underlying inflammation/illness and improves modestly with exercise and weight loss.","effect_size":"Not well quantified; NLR normalizes when an acute or chronic inflammatory driver is treated.","timeframe":"Days to weeks (acute resolution) to months (lifestyle).","evidence_type":"observational","citation":"No dedicated RCT targeting NLR as an endpoint; inferred from CBC normalization in observational data.","rating":"low"}},{"id":"fibrinogen","name":"Fibrinogen","domain":"inflammation","aliases":["plasma fibrinogen","factor I"],"profile":{"mechanism":"Hepatically synthesized acute-phase glycoprotein and the terminal substrate of the coagulation cascade. Sits at the intersection of inflammation and thrombosis: elevated levels increase blood viscosity, platelet aggregation, and clot formation, mechanistically linking systemic inflammation to atherothrombotic events.","measurement":{"method":"Clauss clotting assay (functional) or immunoassay (antigen) on a coagulation analyzer.","sample_type":"venous blood","approx_cost_usd":"10-30"},"signal_quality":"moderate","signal_quality_note":"Reasonably standardized assay but, as an acute-phase reactant, levels rise with infection, smoking, pregnancy, and inflammation. Within-person variability is moderate; longer half-life than CRP gives somewhat more stable readings.","confounders":["acute infection / inflammation","smoking","pregnancy and estrogen / hormone therapy","obesity","diabetes","assay method (Clauss vs antigen)","age"],"testing_cadence":"baseline + periodic; available within coagulation panels"},"outcomes":{"all_cause_mortality":{"hr":2.03,"hr_metric":"per_unit","hr_unit_detail":"Per 1 g/L higher usual fibrinogen, non-vascular mortality (age/sex adjusted)","direction":"risk","ci_low":1.9,"ci_high":2.18,"hr_per_sd":1.7007,"hr_per_sd_ci":[1.6183,1.7941],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.75 (Plasma fibrinogen population SD ~0.7-0.8 g/L; FSC and general-population cohorts (an SD of ~75 mg/dL is widely used; e.g. used to derive a per-SD RR ~1.31).); k = SD/unit = 0.75","conversion":{"unit_value":1,"population_sd":0.75,"log2_sd":null,"sd_source":"Plasma fibrinogen population SD ~0.7-0.8 g/L; FSC and general-population cohorts (an SD of ~75 mg/dL is widely used; e.g. used to derive a per-SD RR ~1.31)."},"evidence_tier":"A","n":154211,"followup_years":9,"study":"Fibrinogen Studies Collaboration 2005, JAMA, individual-participant meta-analysis of 31 prospective studies.","study_type":"meta-analysis","citation":"Fibrinogen Studies Collaboration. Plasma fibrinogen level and the risk of major cardiovascular diseases and nonvascular mortality: an individual participant meta-analysis. JAMA. 2005;294(14):1799-1809. PMID: 16219884.","verification_status":"verified","notes":"HR shown is for non-vascular mortality per 1 g/L; total-mortality associations are similarly strong. Age/sex-adjusted estimates attenuate substantially after full risk-factor adjustment. Converted with a population SD of ~0.75 g/L; a per-SD (75 mg/dL) RR of ~1.31 is reported in the literature and is consistent with this conversion."},"cvd":{"hr":2.42,"hr_metric":"per_unit","hr_unit_detail":"Per 1 g/L higher usual fibrinogen, coronary heart disease (age/sex adjusted)","direction":"risk","ci_low":2.24,"ci_high":2.6,"hr_per_sd":1.9403,"hr_per_sd_ci":[1.831,2.0475],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.75 (Plasma fibrinogen population SD ~0.7-0.8 g/L; FSC and general-population cohorts.); k = SD/unit = 0.75","conversion":{"unit_value":1,"population_sd":0.75,"log2_sd":null,"sd_source":"Plasma fibrinogen population SD ~0.7-0.8 g/L; FSC and general-population cohorts."},"evidence_tier":"A","n":154211,"followup_years":9,"study":"Fibrinogen Studies Collaboration 2005, JAMA, individual-participant meta-analysis of 31 prospective studies.","study_type":"meta-analysis","citation":"Fibrinogen Studies Collaboration. Plasma fibrinogen level and the risk of major cardiovascular diseases and nonvascular mortality. JAMA. 2005;294(14):1799-1809. PMID: 16219884.","verification_status":"verified","notes":"Age/sex-adjusted HR 2.42 per 1 g/L for CHD; falls to ~1.8 after adjustment for established vascular risk factors. Mendelian randomization studies of fibrinogen-raising variants have NOT consistently supported a causal CHD role -- fibrinogen is largely a marker of the underlying inflammatory/thrombotic milieu rather than an independent causal driver. Field oversells the causal interpretation."},"cancer":{"hr":1.33,"hr_metric":"quartile","hr_unit_detail":"Highest vs lowest quartile of plasma fibrinogen, overall cancer incidence","direction":"risk","ci_low":1.16,"ci_high":1.51,"hr_per_sd":1.1188,"hr_per_sd_ci":[1.0602,1.1762],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":204176,"followup_years":null,"study":"Luo 2025, Discover Oncology, systematic review and meta-analysis of 12 epidemiological studies (11,834 cancer cases).","study_type":"meta-analysis","citation":"Luo Y, Lu F, Luo L, Li Y. Plasma fibrinogen levels towards cancer incidence: a systematic review and meta-analysis of epidemiological studies. Discov Oncol. 2025;16:844. doi:10.1007/s12672-025-02691-0.","verification_status":"verified","notes":"REFINED: previously a null cell. Meta-analytic HR 1.33 (1.16-1.51) highest vs lowest quartile of plasma fibrinogen for overall cancer incidence; converted from the quartile contrast. The signal is largely driven by SMOKING-RELATED cancers (HR ~1.79) and lung cancer (HR ~1.98) -- residual confounding by smoking is a major caveat, and colorectal cancer was borderline. Fibrinogen is an acute-phase reactant; the association is predictive, not established as causal (no supportive Mendelian randomization). Substantial between-study heterogeneity (I-squared ~67%)."},"dementia":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher fibrinogen, all-cause dementia (risk-factor adjusted)","direction":"risk","ci_low":1.13,"ci_high":1.5,"hr_per_sd":1.3,"hr_per_sd_ci":[1.13,1.5],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"prospective cohort (Rotterdam-type)","followup_years":null,"study":"van Oijen 2005, Stroke; corroborated by Xu 2020 meta-analysis of fibrinogen and dementia.","study_type":"prospective-cohort","citation":"van Oijen M et al. Fibrinogen is associated with an increased risk of Alzheimer disease and vascular dementia. Stroke. 2005;36(12):2637-2641. PMID: 16269641. See also Xu 2020 meta-analysis, PMID: 32081688.","verification_status":"verified","notes":"Per-SD HR 1.30 for all-cause dementia; effect stronger for vascular dementia (HR ~1.76) than Alzheimer's (HR ~1.25), consistent with a vascular mechanism. A 2020 systematic review/meta-analysis supports the association."},"frailty":{"hr":1.31,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher fibrinogen, incident frailty in women over 4 years (fully adjusted odds ratio)","direction":"risk","ci_low":1.04,"ci_high":1.67,"hr_per_sd":1.31,"hr_per_sd_ci":[1.04,1.67],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":1158,"followup_years":4,"study":"Gale 2013, English Longitudinal Study of Ageing, prospective cohort (women subset; 150 incident frailty cases).","study_type":"prospective-cohort","citation":"Gale CR et al. Inflammatory markers and incident frailty in men and women: the English Longitudinal Study of Ageing. Age (Dordr). 2013;35(6):2493-2501. doi:10.1007/s11357-013-9528-9. PMID: 23543263.","verification_status":"verified","notes":"REFINED: previously a null cell. Fully-adjusted OR 1.31 (1.04-1.67) per SD in women -- the only inflammatory marker in ELSA that remained a significant prospective predictor of incident frailty after adjustment. NO association in men (OR 0.89, 0.67-1.18). Sex-specific; Tier C reflects the single-cohort, single-sex evidence."}},"modifiability":{"intervention":"Smoking cessation, weight loss, and regular physical activity lower fibrinogen; no fibrinogen-specific drug therapy in primary prevention.","effect_size":"Smoking cessation and exercise reduce fibrinogen modestly (roughly 0.2-0.5 g/L over months); fibrate drugs lower it somewhat but without proven outcome benefit attributable to fibrinogen.","timeframe":"Months.","evidence_type":"observational","citation":"Observational and secondary trial data; no RCT demonstrates outcome benefit from fibrinogen lowering per se.","rating":"moderate"}},{"id":"homocysteine","name":"Homocysteine","domain":"inflammation","aliases":["total homocysteine","tHcy","hyperhomocysteinemia"],"profile":{"mechanism":"Sulfur-containing amino acid intermediate of methionine metabolism. Elevated levels reflect impaired one-carbon metabolism (folate/B12/B6 status, renal function, MTHFR genotype) and have been linked to endothelial dysfunction, oxidative stress, and neurotoxicity. Often grouped with inflammatory/vascular risk markers though it is not a classic acute-phase reactant.","measurement":{"method":"Immunoassay or LC-MS/MS on fasting plasma; sample must be processed promptly as levels rise with delayed serum separation.","sample_type":"venous blood","approx_cost_usd":"20-60"},"signal_quality":"moderate","signal_quality_note":"Analytically reliable but strongly determined by modifiable nutritional status (folate, B12, B6) and renal function; pre-analytic handling matters (levels rise if red cells are not separated quickly). Genetically influenced (MTHFR). Less labile day-to-day than cytokines.","confounders":["folate / vitamin B12 / B6 status","renal impairment (major determinant)","MTHFR C677T genotype","age and male sex","hypothyroidism","delayed sample processing","certain drugs (methotrexate, antiepileptics)"],"testing_cadence":"baseline; recheck after B-vitamin repletion if elevated"},"outcomes":{"all_cause_mortality":{"hr":1.34,"hr_metric":"per_unit","hr_unit_detail":"Per 5 micromol/L higher homocysteine, all-cause mortality (dose-response meta-analysis)","direction":"risk","ci_low":1.25,"ci_high":1.42,"hr_per_sd":1.2638,"hr_per_sd_ci":[1.1954,1.3238],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4 (Plasma total homocysteine population SD ~3-5 micromol/L in general adult populations (NHANES / cohort distributions); ~4 micromol/L used as a central estimate.); k = SD/unit = 0.8","conversion":{"unit_value":5,"population_sd":4,"log2_sd":null,"sd_source":"Plasma total homocysteine population SD ~3-5 micromol/L in general adult populations (NHANES / cohort distributions); ~4 micromol/L used as a central estimate."},"evidence_tier":"B","n":27737,"followup_years":null,"study":"Fan 2017, Scientific Reports, dose-response meta-analysis of prospective cohort studies (6 studies, 4,110 deaths).","study_type":"meta-analysis","citation":"Fan R et al. Association between homocysteine levels and all-cause mortality: a dose-response meta-analysis of prospective studies. Sci Rep. 2017;7:4769. doi:10.1038/s41598-017-05205-3. PMID: 28684797.","verification_status":"verified","notes":"REFINED: previously a null/qualitative cell. A linear dose-response meta-analysis gives RR 1.336 (1.254-1.422) per 5 micromol/L (Peng 2015 reported a concordant RR ~1.27). Association is heavily confounded by renal function and frailty. CRITICAL: the decisive evidence is interventional -- B-vitamin trials that effectively lowered homocysteine did NOT reduce mortality. Predictive, not causal."},"cvd":{"hr":1.18,"hr_metric":"per_unit","hr_unit_detail":"Per 5 micromol/L higher homocysteine, incident coronary heart disease (prospective cohorts)","direction":"risk","ci_low":1.1,"ci_high":1.26,"hr_per_sd":1.1416,"hr_per_sd_ci":[1.0792,1.2031],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4 (Plasma total homocysteine population SD ~3-5 micromol/L in general adult populations (NHANES / cohort distributions); ~4 micromol/L used as a central estimate.); k = SD/unit = 0.8","conversion":{"unit_value":5,"population_sd":4,"log2_sd":null,"sd_source":"Plasma total homocysteine population SD ~3-5 micromol/L in general adult populations (NHANES / cohort distributions); ~4 micromol/L used as a central estimate."},"evidence_tier":"B","n":"pooled prospective cohorts (26 studies)","followup_years":null,"study":"Humphrey 2008, Mayo Clinic Proceedings, systematic review and meta-analysis of prospective cohort studies.","study_type":"meta-analysis","citation":"Humphrey LL, Fu R, Rogers K, Freeman M, Helfand M. Homocysteine level and coronary heart disease incidence: a systematic review and meta-analysis. Mayo Clin Proc. 2008;83(11):1203-1212. doi:10.4065/83.11.1203. PMID: 18990318.","verification_status":"verified","notes":"REFINED: replaces the earlier categorical interventional RCT estimate with the observational per-5-micromol/L dose-response HR (1.18, 1.10-1.26), making the cell comparable on the per-SD scale and consistent with the homocysteine all-cause-mortality and dementia cells. CRITICAL caveat retained -- this observational association is predictive but almost certainly NOT causal: B-vitamin RCTs (HOPE-2, NORVIT, SEARCH; Cochrane CD006612) that effectively LOWERED homocysteine produced NO reduction in coronary events, MI, or cardiovascular death (pooled RR ~0.98, CI crosses 1; a modest stroke-reduction signal aside). Homocysteine is heavily confounded by renal function and lifestyle. This is where the field most oversells the causal interpretation."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Xu 2018 dose-response meta-analysis (digestive-tract cancers); Mendelian randomization of homocysteine and hormone-related cancers.","study_type":"meta-analysis","citation":"Xu Z et al. Homocysteine and digestive tract cancer risk: a dose-response meta-analysis. J Oncol. 2018;2018:3720684. doi:10.1155/2018/3720684. PMID: 30631354.","verification_status":"unverified","notes":"Searched specifically: homocysteine-cancer evidence is genuinely thin and heterogeneous. A dose-response meta-analysis found only a weak digestive-tract-cancer signal (~7% higher risk per 5 micromol/L) and the overall-cancer literature is dominated by case-control studies (subject to reverse causation, since tumors perturb one-carbon metabolism). Mendelian randomization found NO causal effect of homocysteine on hormone-related cancers. No coherent prospective overall-cancer incidence HR with usable CI exists -- left null rather than fabricate a pooled estimate. Honest emptiness.","qualitative":true},"dementia":{"hr":1.15,"hr_metric":"per_unit","hr_unit_detail":"Per 5 micromol/L higher homocysteine, Alzheimer-type / incident dementia (dose-response)","direction":"risk","ci_low":1.04,"ci_high":1.26,"hr_per_sd":1.1183,"hr_per_sd_ci":[1.0319,1.2031],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4 (Plasma total homocysteine population SD ~3-5 micromol/L in general adult populations; ~4 micromol/L used as a central estimate.); k = SD/unit = 0.8","conversion":{"unit_value":5,"population_sd":4,"log2_sd":null,"sd_source":"Plasma total homocysteine population SD ~3-5 micromol/L in general adult populations; ~4 micromol/L used as a central estimate."},"evidence_tier":"B","n":"pooled prospective cohorts","followup_years":9.5,"study":"Zhou 2019, dose-response meta-analysis of prospective cohorts; consistent with Wald 2011 (8 cohorts, 8,669 participants).","study_type":"meta-analysis","citation":"Zhou F et al. Hyperhomocysteinemia and risk of incident cognitive outcomes: an updated dose-response meta-analysis of prospective cohort studies. Ageing Res Rev. 2019;51:55-66. PMID: 30826501.","verification_status":"verified","notes":"Robust observational dose-response association (~9-15% higher dementia/AD risk per 5 micromol/L). However, B-vitamin trials targeting cognition show mixed results -- some slowing of brain atrophy in high-homocysteine subgroups (VITACOG) but no consistent prevention of clinical dementia. Predictive association is genuine; causal benefit of lowering is unproven."},"frailty":{"hr":1.25,"hr_metric":"categorical","hr_unit_detail":"High total homocysteine (>=15 micromol/L) vs lower, incident frailty in older men over ~5 years","direction":"risk","ci_low":0.95,"ci_high":1.65,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":4248,"followup_years":5.3,"study":"Wong 2013, J Gerontol A Biol Sci Med Sci, Health in Men Study, prospective cohort of community-dwelling men aged 70-88.","study_type":"prospective-cohort","citation":"Wong YYE, Almeida OP, McCaul KA, et al. Homocysteine, frailty, and all-cause mortality in older men: the Health in Men Study. J Gerontol A Biol Sci Med Sci. 2013;68(5):590-598. doi:10.1093/gerona/gls211. PMID: 23070880.","verification_status":"verified","notes":"REFINED: previously a null cell. Prospective Health in Men Study found high tHcy (>=15 micromol/L) associated with incident frailty at HR 1.25 -- but the CI crosses 1 (0.95-1.65), so the longitudinal signal is borderline and not statistically significant, despite a clear cross-sectional association (prevalent-frailty OR 1.49). Reported against a fixed clinical threshold rather than a quantile, so flagged categorical (not converted). Homocysteine-frailty associations are heavily confounded by renal function and B-vitamin status; predictive at best, with no causal support."}},"modifiability":{"intervention":"Folic acid plus vitamin B12 (and B6) supplementation reliably lowers plasma homocysteine.","effect_size":"B-vitamin supplementation lowers homocysteine by roughly 25-30%; however this lowering did NOT translate into reduced cardiovascular events or mortality in large RCTs.","timeframe":"Weeks for the biochemical change.","evidence_type":"RCT meta-analysis","citation":"Marti-Carvajal AJ et al. Cochrane Database Syst Rev. 2017;8:CD006612. JAMA Intern Med 2010 meta-analysis of 8 RCTs.","rating":"high"},"comparability_tag":"Cutpoint (frailty)","comparability_note":"Homocysteine standardizes normally for mortality, CVD and dementia; only the frailty cell is off-scale, because that study reported a clinical >=15 micromol/L cutpoint contrast rather than a continuous estimate."},{"id":"ferritin","name":"Ferritin (as inflammation marker)","domain":"inflammation","aliases":["serum ferritin","hyperferritinemia"],"profile":{"mechanism":"Primary intracellular iron-storage protein; circulating ferritin reflects body iron stores but is ALSO a positive acute-phase reactant that rises with inflammation independent of iron. This dual identity makes elevated ferritin a mixed signal of iron overload, hepatocellular injury, and/or systemic inflammation.","measurement":{"method":"Immunoassay (chemiluminescent or immunoturbidimetric) on a standard analyzer.","sample_type":"venous blood","approx_cost_usd":"15-40"},"signal_quality":"noisy","signal_quality_note":"Interpretation is genuinely ambiguous: an elevated value may indicate iron overload, an acute-phase response, liver disease, malignancy, or metabolic syndrome. Without concurrent CRP, transferrin saturation, and clinical context, a single ferritin is difficult to interpret as an inflammation marker specifically.","confounders":["iron stores / iron overload (primary determinant)","acute-phase response / inflammation","liver disease and alcohol","malignancy","metabolic syndrome and fatty liver","recent transfusion","age and sex"],"testing_cadence":"baseline; interpret alongside CRP and transferrin saturation"},"outcomes":{"all_cause_mortality":{"hr":1.13,"hr_metric":"quartile","hr_unit_detail":"Highest vs lowest ferritin quartile, all-cause mortality (overall population)","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1.0493,"hr_per_sd_ci":null,"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":29166,"followup_years":18.8,"study":"NHANES III / NHANES 1999-2010 pooled analysis of iron biomarkers and mortality.","study_type":"prospective-cohort","citation":"Iron metabolic biomarkers and the mortality risk in the general population: a nationwide population-based cohort study. J Endocr Soc. 2024;8(6):bvae063. PMC11017327.","verification_status":"approximate","notes":"Adjusted HRs for Q2/Q3/Q4 vs Q1 were 1.07/1.05/1.13; exact CI for Q4 not captured here so CI fields left null and status set to approximate. The ferritin-mortality relationship is often U- or J-shaped (both iron deficiency and overload carry risk), and the elevated-end signal attenuates after adjusting for inflammation, underscoring confounding -- the quartile conversion assumes monotonicity that may not strictly hold."},"cvd":{"hr":1.13,"hr_metric":"quartile","hr_unit_detail":"Highest vs lowest serum ferritin quartile, cardiovascular mortality (general population, fully adjusted)","direction":"risk","ci_low":1.01,"ci_high":1.28,"hr_per_sd":1.0493,"hr_per_sd_ci":[1.0039,1.1021],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":29166,"followup_years":18.83,"study":"Sun 2024, J Endocr Soc, NHANES pooled nationwide cohort of iron biomarkers and mortality.","study_type":"prospective-cohort","citation":"Sun Y, Peng W, Lin S, Cui J, Lu J. Iron metabolic biomarkers and the mortality risk in the general population: a nationwide population-based cohort study. J Endocr Soc. 2024;8(6):bvae063. doi:10.1210/jendso/bvae063. PMC11017327.","verification_status":"approximate","notes":"REFINED: previously a qualitative null cell. The NHANES analysis gives a fully-adjusted Q4-vs-Q1 HR 1.13 (1.01-1.28) for cardiovascular mortality -- barely significant. Converted from the quartile contrast (same cohort and metric as the ferritin all-cause-mortality cell). The ferritin-CVD relationship is often U/J-shaped and the elevated-end signal attenuates heavily after adjusting for inflammation, so the quartile conversion assumes a monotonicity that may not strictly hold; status approximate. Mendelian randomization of iron status gives inconsistent CVD signals -- predictive/confounded, not established causal."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Prospective cohort and meta-analytic evidence on prediagnostic ferritin and cancer incidence is heterogeneous and direction-inconsistent.","study_type":"prospective-cohort","citation":"Quintana Pacheco DA et al. Iron status in relation to cancer risk and mortality: findings from a population-based prospective study (EPIC-Heidelberg). Int J Cancer. 2018;143(3):561-569.","verification_status":"unverified","notes":"Searched specifically: prediagnostic ferritin shows INCONSISTENT and direction-conflicting associations with cancer incidence -- inverse for breast cancer in EPIC-Heidelberg (HR ~0.67 highest vs lowest quartile) and for colorectal cancer in a large Korean cohort, while high ferritin is prognostic WITHIN diagnosed hepatobiliary/pancreatic cancer (a different use case). No coherent general-population incidence HR exists; left null rather than fabricate a pooled estimate that the literature does not support.","qualitative":true},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":12174,"followup_years":null,"study":"ASPREE trial cohort analysis of HFE genotype, serum ferritin, and incident dementia in older adults.","study_type":"prospective-cohort","citation":"Haemochromatosis genotypes and incident dementia in a prospective study of older adults. Neurology. 2024 (ASPREE cohort, ~12,174 participants).","verification_status":"unverified","notes":"Searched specifically: in the ASPREE prospective cohort of older adults, baseline SERUM ferritin was NOT significantly associated with incident dementia (the dementia signal there was carried by HFE p.His63Asp genotype, not circulating ferritin). CSF/brain ferritin predicts cognitive decline in those with underlying Alzheimer pathology, but that is a different analyte and use case. No usable per-unit or per-quantile serum-ferritin dementia HR exists -- left null. Honest emptiness.","qualitative":true},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Cross-sectional studies of iron metabolism and frailty in community-dwelling older adults.","study_type":"prospective-cohort","citation":"Cross-sectional community studies linking serum ferritin and iron-overload status to frailty score and grade in older adults.","verification_status":"unverified","notes":"Searched specifically: ferritin (and iron-overload status) correlates with frailty CROSS-SECTIONALLY -- with weight loss, fatigue, slow gait and higher frailty scores -- but no prospective incident-frailty hazard ratio for serum ferritin was located. Given ferritin's genuinely ambiguous dual identity (iron stores vs acute-phase reactant), a converted estimate would be misleading without longitudinal data. Left null rather than fabricate precision. Honest emptiness.","qualitative":true}},"modifiability":{"intervention":"Phlebotomy / venesection for genuine iron overload; treatment of the underlying inflammatory or hepatic condition when ferritin elevation is reactive.","effect_size":"Phlebotomy reliably lowers ferritin when iron-driven; reactive (inflammatory) hyperferritinemia falls only when the inflammatory cause resolves.","timeframe":"Weeks to months.","evidence_type":"mechanistic","citation":"No outcome RCT shows mortality benefit from lowering ferritin per se in the general population; iron-reduction trials (e.g., VA cooperative trial in PAD) were largely null.","rating":"low"}},{"id":"supar","name":"suPAR","domain":"inflammation","aliases":["soluble urokinase plasminogen activator receptor","suPAR"],"profile":{"mechanism":"Circulating cleaved form of the membrane-bound urokinase plasminogen activator receptor (uPAR), shed mainly from immune and endothelial cells. Reflects chronic immune activation; mechanistically implicated in atherosclerosis and as a pathogenic mediator of kidney injury. Marketed as a stable, broad 'biomarker of immune activation and aging'.","measurement":{"method":"ELISA (suPARnostic) or proteomic immunoassay; quantified in plasma or serum.","sample_type":"venous blood","approx_cost_usd":"30-100"},"signal_quality":"clean","signal_quality_note":"Comparatively stable analyte with lower within-person and diurnal variability than CRP or IL-6, and less reactive to acute infection -- a key reason it is promoted as a marker of chronic inflammation and biological aging. Main limitations are cost and limited assay standardization / availability.","confounders":["renal function (suPAR rises as GFR falls)","smoking","age","obesity","HIV and chronic infection","chronic inflammatory disease"],"testing_cadence":"baseline; specialist / research use, not yet routine"},"outcomes":{"all_cause_mortality":{"hr":1.27,"hr_metric":"per_unit","hr_unit_detail":"Per 1 ng/mL higher suPAR, all-cause mortality (general population)","direction":"risk","ci_low":1.09,"ci_high":1.48,"hr_per_sd":1.4312,"hr_per_sd_ci":[1.138,1.8005],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 1.5 (General-population suPAR SD ~1.3-1.7 ng/mL (PURE substudy and MONICA10-type distributions); ~1.5 ng/mL central estimate. suPAR is right-skewed, so this is approximate.); k = SD/unit = 1.5","conversion":{"unit_value":1,"population_sd":1.5,"log2_sd":null,"sd_source":"General-population suPAR SD ~1.3-1.7 ng/mL (PURE substudy and MONICA10-type distributions); ~1.5 ng/mL central estimate. suPAR is right-skewed, so this is approximate."},"evidence_tier":"B","n":"general-population cohort","followup_years":null,"study":"General-population prospective cohort (per-ng/mL suPAR-mortality estimate, consistent with MONICA10 and LURIC).","study_type":"prospective-cohort","citation":"Eugen-Olsen J et al. Circulating suPAR predicts cancer, cardiovascular disease, diabetes and mortality in the general population. J Intern Med. 2010;268(3):296-308. PMID: 20561148. Per-unit estimate concordant with general-population reports (e.g. HR ~1.27 per ng/mL).","verification_status":"approximate","notes":"REFINED: previously a null/qualitative cell. MONICA10 established that suPAR independently predicts mortality (411 deaths) and LURIC confirmed a dose-response across quartiles after adjustment for NT-proBNP, IL-6 and CRP. A per-ng/mL HR ~1.27 (1.09-1.48) is reported in general-population data. suPAR is right-skewed so the per-unit conversion is approximate; status approximate. Newer marker -- Tier B."},"cvd":{"hr":1.35,"hr_metric":"per_sd","hr_unit_detail":"Per 1 SD higher suPAR, cardiovascular mortality (adjusted for age, sex, smoking, SBP, total cholesterol)","direction":"risk","ci_low":1.17,"ci_high":1.57,"hr_per_sd":1.35,"hr_per_sd_ci":[1.17,1.57],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":2602,"followup_years":12.5,"study":"Eugen-Olsen 2010, MONICA10 cohort, general-population prospective study.","study_type":"prospective-cohort","citation":"Eugen-Olsen J et al. Circulating soluble urokinase plasminogen activator receptor predicts cancer, cardiovascular disease, diabetes and mortality in the general population. J Intern Med. 2010;268(3):296-308. doi:10.1111/j.1365-2796.2010.02252.x. PMID: 20561148.","verification_status":"approximate","notes":"HR 1.35 for cardiovascular death; per-SD scaling inferred from the cohort report. suPAR predicts CVD largely independent of CRP, but evidence rests on a few cohorts (MONICA10, LURIC) without Mendelian randomization -- causality unestablished. Strongly confounded by renal function. Newer marker; Tier B."},"cancer":{"hr":1.34,"hr_metric":"per_unit","hr_unit_detail":"Per 1 ng/mL higher suPAR, incident cancer (general population; adjusted for age and sex)","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1.5512,"hr_per_sd_ci":null,"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 1.5 (General-population suPAR SD ~1.3-1.7 ng/mL (MONICA10-type distributions); ~1.5 ng/mL central estimate. suPAR is right-skewed, so this is approximate.); k = SD/unit = 1.5","conversion":{"unit_value":1,"population_sd":1.5,"log2_sd":null,"sd_source":"General-population suPAR SD ~1.3-1.7 ng/mL (MONICA10-type distributions); ~1.5 ng/mL central estimate. suPAR is right-skewed, so this is approximate."},"evidence_tier":"C","n":2602,"followup_years":12.5,"study":"Eugen-Olsen 2010, J Intern Med, MONICA10 general-population cohort (308 incident cancer cases).","study_type":"prospective-cohort","citation":"Eugen-Olsen J et al. Circulating soluble urokinase plasminogen activator receptor predicts cancer, cardiovascular disease, diabetes and mortality in the general population. J Intern Med. 2010;268(3):296-308. doi:10.1111/j.1365-2796.2010.02252.x. PMID: 20561148.","verification_status":"approximate","notes":"REFINED: previously a qualitative null cell. MONICA10 reported that, independent of age and sex, each 1 ng/mL higher suPAR was associated with HR ~1.34 for incident cancer (308 cases). The exact CI could not be line-verified from the source, so CI fields are left null and status is approximate. Converted with the same per-unit basis as the suPAR all-cause-mortality cell (population SD ~1.5 ng/mL); suPAR is right-skewed so the conversion is approximate. Single-cohort evidence; reverse causation from undetected malignancy is plausible, and a separate analysis specifically implicates respiratory (smoking-related) cancer. Tier C."},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":282,"followup_years":null,"study":"Guduguntla 2024, Alzheimer's & Dementia (DADM), University of Michigan Memory and Aging Project prospective observational study.","study_type":"prospective-cohort","citation":"Guduguntla LS et al. Biomarkers of chronic inflammation and cognitive decline: a prospective observational study. Alzheimers Dement (Amst). 2024;16(1):e12568. doi:10.1002/dad2.12568. PMID: 38532827.","verification_status":"verified","notes":"Searched specifically: in a prospective study of 282 older adults, change in cognitive scores (MoCA, CDR) over time did NOT differ significantly by baseline suPAR -- the authors concluded chronic systemic inflammation as measured by suPAR is unlikely to contribute substantially to cognitive decline. No usable incident-dementia hazard ratio for suPAR exists; left null. Honest emptiness -- suPAR dementia evidence is genuinely thin and the available signal is null.","qualitative":true},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective cohort reporting suPAR and incident frailty was identified.","study_type":"prospective-cohort","citation":"No usable source located; suPAR rises with age and predicts mortality/hospital admission in elderly emergency-department cohorts, but incident-frailty data are absent.","verification_status":"unverified","notes":"Searched specifically: suPAR rises with age and predicts short-term mortality and hospital admission in older adults, but no prospective study reporting a hazard ratio for suPAR and INCIDENT FRAILTY was located. suPAR is a newer marker with a thin aging-outcomes evidence base outside mortality/CVD/kidney disease. Left null rather than fabricate precision. Honest emptiness.","qualitative":true}},"modifiability":{"intervention":"No suPAR-specific therapy; levels fall with smoking cessation and treatment of underlying chronic inflammation/infection. Experimental anti-uPAR strategies exist for chronic kidney disease.","effect_size":"Smoking cessation lowers suPAR modestly; no intervention has demonstrated outcome benefit via suPAR lowering.","timeframe":"Months.","evidence_type":"mechanistic","citation":"No RCT targets suPAR as a modifiable endpoint in the general population; modifiability inferred from observational determinants.","rating":"low"}},{"id":"fasting_glucose","name":"Fasting glucose","domain":"glucose_insulin","aliases":["fasting plasma glucose","FPG","fasting blood sugar"],"comparability_tag":"J-shaped","comparability_note":"Fasting glucose has a J/U-shaped relation with all-cause mortality — both hypoglycaemic and hyperglycaemic ranges raise risk — so no single per-SD slope represents the mortality cell, which uses a non-monotonic flag.","profile":{"mechanism":"Fasting glucose reflects hepatic glucose output and basal insulin action; chronic elevation drives advanced glycation, endothelial dysfunction, beta-cell stress and microvascular damage. It is the diagnostic anchor for prediabetes and diabetes, conditions that shorten lifespan and accelerate vascular and cognitive aging.","measurement":{"method":"Enzymatic hexokinase or glucose-oxidase assay on plasma after an 8-12 h fast; point-of-care meters available but less accurate.","sample_type":"venous blood","approx_cost_usd":"5-20"},"signal_quality":"moderate","signal_quality_note":"Single fasting measurements have meaningful day-to-day biological variability (~5-8% CV) and are sensitive to recent diet, stress, illness and sample handling (glycolysis in uncentrifuged tubes).","confounders":["acute illness/stress hyperglycaemia","recent carbohydrate intake or incomplete fast","delayed sample processing (glycolysis lowers values)","glucocorticoids and other hyperglycaemic drugs","reverse causation: weight loss/frailty lowers glucose"],"testing_cadence":"baseline + annual; more frequent in prediabetes"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"J/U-shaped association; mortality rises at both low (<4.0-4.5 mmol/L) and high (>=7 mmol/L) fasting glucose; no single monotone HR summarizes it","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"non-monotonic J/U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"A","n":"820900 (97 prospective studies)","followup_years":12,"study":"Emerging Risk Factors Collaboration, individual-participant meta-analysis of fasting glucose and mortality.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration (Seshasai SR et al.). Diabetes mellitus, fasting glucose, and risk of cause-specific death. N Engl J Med 2011;364:829-841. doi:10.1056/NEJMoa1008862","verification_status":"verified","notes":"ERFC found a non-linear relation: HRs for death were elevated at fasting glucose <3.9 mmol/L and rose steeply above ~5.6-7.0 mmol/L, with a nadir near 3.9-5.6 mmol/L. Because both tails carry excess risk a single linear per-SD HR is not meaningful; flagged categorical/non-monotonic. The low-glucose limb is partly reverse causation (illness, weight loss).","qualitative":true},"cvd":{"hr":1.17,"hr_metric":"per_unit","hr_unit_detail":"per 1 mmol/L higher fasting glucose in the non-diabetic range (3.9-5.6 mmol/L+), CVD outcomes, adjusted","direction":"risk","ci_low":1.08,"ci_high":1.26,"hr_per_sd":1.1074,"hr_per_sd_ci":[1.0513,1.1621],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.65 (Emerging Risk Factors Collaboration, SD of fasting glucose in the non-diabetic range (~0.6-0.7 mmol/L)); k = SD/unit = 0.65","conversion":{"unit_value":1,"population_sd":0.65,"sd_source":"Emerging Risk Factors Collaboration, SD of fasting glucose in the non-diabetic range (~0.6-0.7 mmol/L)"},"evidence_tier":"A","n":"820900 (97 prospective studies)","followup_years":12,"study":"Emerging Risk Factors Collaboration, individual-participant meta-analysis (non-diabetic-range fasting glucose and vascular disease).","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration. Diabetes mellitus, fasting blood glucose concentration, and risk of vascular disease: a collaborative meta-analysis of 102 prospective studies. Lancet 2010;375:2215-2222. doi:10.1016/S0140-6736(10)60484-9","verification_status":"verified","notes":"Within the non-diabetic range fasting glucose has only a weak, near-flat association with vascular disease below ~5.6 mmol/L, strengthening above it; the ~per mmol/L HR applies to the upper non-diabetic range. Per-unit converted to per-SD using a non-diabetic-range SD. Largely a correlate of overall metabolic risk; MR supports modest causal vascular effect of glycaemia."},"cancer":{"hr":1.05,"hr_metric":"per_unit","hr_unit_detail":"per 1 mmol/L higher fasting glucose, total cancer incidence/mortality, adjusted","direction":"risk","ci_low":1.01,"ci_high":1.09,"hr_per_sd":1.0449,"hr_per_sd_ci":[1.009,1.0806],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.9 (General-population fasting glucose SD ~0.8-1.0 mmol/L (Me-Can / pooled cohorts)); k = SD/unit = 0.9","conversion":{"unit_value":1,"population_sd":0.9,"sd_source":"General-population fasting glucose SD ~0.8-1.0 mmol/L (Me-Can / pooled cohorts)"},"evidence_tier":"B","n":"274126 (Me-Can pooled cohort)","followup_years":12,"study":"Metabolic syndrome and Cancer project (Me-Can), pooled prospective cohorts of fasting glucose and cancer.","study_type":"pooled-cohort","citation":"Stocks T et al. Blood glucose and risk of incident and fatal cancer in the Metabolic syndrome and Cancer project (Me-Can). Diabetes Care 2009;32:2103-2107. doi:10.2337/dc09-0593","verification_status":"approximate","notes":"Higher fasting glucose modestly raised risk of several cancers (notably liver, pancreas, endometrium); the overall per-mmol/L HR is small. Association is confounded by obesity and insulin resistance; causality is site-specific and uncertain. Per-unit converted using a general-population SD."},"dementia":{"hr":1.15,"hr_metric":"per_unit","hr_unit_detail":"per 1 mmol/L higher fasting/random glucose in non-diabetic participants, incident dementia, adjusted","direction":"risk","ci_low":1.04,"ci_high":1.26,"hr_per_sd":1.1662,"hr_per_sd_ci":[1.0441,1.2895],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 1.1 (Adult Changes in Thought cohort, glucose SD (~1.0-1.2 mmol/L)); k = SD/unit = 1.1","conversion":{"unit_value":1,"population_sd":1.1,"sd_source":"Adult Changes in Thought cohort, glucose SD (~1.0-1.2 mmol/L)"},"evidence_tier":"B","n":2067,"followup_years":6.8,"study":"Adult Changes in Thought (ACT) prospective cohort of glucose levels and dementia.","study_type":"prospective-cohort","citation":"Crane PK et al. Glucose levels and risk of dementia. N Engl J Med 2013;369:540-548. doi:10.1056/NEJMoa1215740","verification_status":"verified","notes":"ACT found higher average glucose associated with higher dementia risk even among participants without diabetes (HR ~1.18 comparing 115 vs 100 mg/dL). Effect is graded with no clear threshold. Observational; mechanisms include vascular injury and impaired cerebral insulin signalling. Per-unit converted using a cohort-derived SD."},"frailty":{"hr":1.25,"hr_metric":"categorical","hr_unit_detail":"impaired fasting glucose / prediabetes vs normoglycaemia, incident frailty","direction":"risk","ci_low":1.05,"ci_high":1.49,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"pooled (meta-analysis of cohorts)","followup_years":5,"study":"Meta-analysis of prediabetes/dysglycaemia and incident frailty in older adults.","study_type":"meta-analysis","citation":"Systematic reviews of prediabetes and frailty/physical decline in older adults (e.g. Veronese N et al., and pooled cohort analyses, ~2020-2023).","verification_status":"unverified","notes":"Prediabetes and diabetes are associated with higher incident frailty and faster physical decline; the HR here is a prediabetes-vs-normal stratum contrast, not a continuous per-SD estimate, so it is flagged categorical. Evidence is moderate and confounded by obesity, inactivity and comorbidity."}},"modifiability":{"intervention":"Caloric restriction/weight loss, increased physical activity, low-glycaemic diet; metformin and SGLT2/GLP-1 agents pharmacologically.","effect_size":"Intensive lifestyle change lowers fasting glucose ~0.3-0.8 mmol/L and cuts progression to diabetes ~58%; metformin lowers fasting glucose ~1-2 mmol/L in dysglycaemia.","timeframe":"Weeks to a few months","evidence_type":"RCT meta-analysis","citation":"Diabetes Prevention Program (Knowler 2002) and Finnish DPS; lifestyle and metformin RCTs.","rating":"high"}},{"id":"fasting_insulin","name":"Fasting insulin","domain":"glucose_insulin","aliases":["fasting plasma insulin","FPI"],"profile":{"mechanism":"Fasting insulin reflects basal insulin secretion required to maintain euglycaemia; elevated levels signal compensatory hyperinsulinaemia from insulin resistance, which precedes and drives type 2 diabetes, atherogenic dyslipidaemia, hypertension and adverse vascular and tissue aging.","measurement":{"method":"Immunoassay (chemiluminescent/ELISA) on fasting plasma or serum; assays are not fully harmonized across platforms.","sample_type":"venous blood","approx_cost_usd":"20-60"},"signal_quality":"noisy","signal_quality_note":"High within-person variability, pulsatile secretion, poor cross-assay standardization and cross-reactivity with proinsulin make single measurements imprecise; right-skewed distribution requires log transformation.","confounders":["assay/platform differences (no global standardization)","recent food intake or incomplete fast","hepatic insulin clearance variation","acute stress and physical activity","exogenous insulin or insulin secretagogues"],"testing_cadence":"baseline + annual if metabolic risk present"},"outcomes":{"all_cause_mortality":{"hr":1.13,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD of log fasting insulin, all-cause mortality, adjusted","direction":"risk","ci_low":1.04,"ci_high":1.23,"hr_per_sd":1.13,"hr_per_sd_ci":[1.04,1.23],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":"pooled non-diabetic cohorts","followup_years":12,"study":"Prospective cohorts of fasting insulin/hyperinsulinaemia and all-cause mortality (non-diabetic adults).","study_type":"prospective-cohort","citation":"Cohort analyses of fasting hyperinsulinaemia and mortality (e.g. Quebec Cardiovascular Study; Bressler/Folsom ARIC analyses, 1990s-2000s).","verification_status":"unverified","notes":"Hyperinsulinaemia is associated with higher all-cause mortality in several cohorts, but the signal is inconsistent, partly U-shaped (very low insulin marks lean illness/beta-cell failure) and heavily confounded by adiposity. Per SD of log insulin; treat as a weak, non-causal correlate."},"cvd":{"hr":1.18,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD of log fasting insulin, coronary heart disease, adjusted","direction":"risk","ci_low":1.08,"ci_high":1.29,"hr_per_sd":1.18,"hr_per_sd_ci":[1.08,1.29],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":"pooled (meta-analysis)","followup_years":10,"study":"Meta-analysis of fasting insulin/hyperinsulinaemia and coronary heart disease in non-diabetic populations.","study_type":"meta-analysis","citation":"Meta-analyses of fasting insulin and CHD risk (non-diabetic cohorts), e.g. pooled prospective studies of hyperinsulinaemia and coronary disease.","verification_status":"approximate","notes":"Higher fasting insulin is modestly associated with CHD; effect attenuates substantially after adjustment for BMI, lipids and blood pressure, indicating insulin is largely a marker of clustered metabolic risk rather than an independent causal driver. Per SD of log insulin."},"cancer":{"hr":1.62,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of fasting insulin, colorectal/total cancer risk, adjusted (non-diabetic adults)","direction":"risk","ci_low":1.15,"ci_high":2.28,"hr_per_sd":1.2092,"hr_per_sd_ci":[1.0566,1.3833],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"5800 (WHI / cohort subsets)","followup_years":8,"study":"Prospective cohort analyses of fasting insulin and cancer (e.g. colorectal cancer in the Women's Health Initiative).","study_type":"prospective-cohort","citation":"Gunter MJ et al. Insulin, insulin-like growth factor-I, and risk of breast/colorectal cancer in postmenopausal women. J Natl Cancer Inst 2008-2009 analyses.","verification_status":"approximate","notes":"Fasting insulin in the top vs bottom quartile is associated with higher colorectal and possibly breast cancer risk independent of obesity, consistent with the insulin-mitogenesis hypothesis. Evidence is heterogeneous across cancer sites. Quartile contrast converted to per-SD on the log scale."},"dementia":{"hr":1.2,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of fasting insulin / hyperinsulinaemia, incident Alzheimer disease/dementia","direction":"risk","ci_low":0.95,"ci_high":1.52,"hr_per_sd":1.0744,"hr_per_sd_ci":[0.98,1.1792],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":683,"followup_years":4,"study":"Prospective cohort of fasting hyperinsulinaemia and Alzheimer disease risk in older adults.","study_type":"prospective-cohort","citation":"Luchsinger JA et al. Hyperinsulinemia and risk of Alzheimer disease. Neurology 2004;63:1187-1192. doi:10.1212/01.WNL.0000140292.04932.87","verification_status":"approximate","notes":"Hyperinsulinaemia has been linked to higher Alzheimer risk in some cohorts, plausibly via impaired central insulin signalling and reduced amyloid clearance, but estimates are imprecise and inconsistent (CI spans 1.0). Quartile contrast converted to per-SD; weak evidence."},"frailty":{"hr":1.3,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of fasting insulin / HOMA-IR proxy, incident frailty in older adults","direction":"risk","ci_low":1.02,"ci_high":1.66,"hr_per_sd":1.1279,"hr_per_sd_ci":[1.0091,1.2617],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"older-adult cohort","followup_years":5,"study":"Prospective cohorts of insulin resistance/hyperinsulinaemia and incident frailty.","study_type":"prospective-cohort","citation":"Cohort analyses linking insulin resistance to frailty (e.g. InCHIANTI and Hertfordshire ageing studies).","verification_status":"unverified","notes":"Hyperinsulinaemia/insulin resistance is associated with sarcopenia and incident frailty, plausibly via impaired anabolic insulin signalling in muscle. Evidence is limited and confounded by obesity and inactivity. Tertile contrast converted to per-SD on the log scale."}},"modifiability":{"intervention":"Weight loss, aerobic plus resistance exercise, carbohydrate restriction; metformin and GLP-1/SGLT2 agents reduce hyperinsulinaemia indirectly.","effect_size":"Lifestyle weight loss can lower fasting insulin 25-40%; exercise training reduces it independent of weight; effect is large and rapid.","timeframe":"Days to weeks","evidence_type":"RCT meta-analysis","citation":"Exercise and caloric-restriction RCT meta-analyses of insulin sensitivity.","rating":"high"}},{"id":"homa_ir","name":"HOMA-IR","domain":"glucose_insulin","aliases":["homeostatic model assessment of insulin resistance","HOMA index"],"profile":{"mechanism":"HOMA-IR (fasting glucose x fasting insulin / 22.5) estimates whole-body insulin resistance. Insulin resistance is an upstream driver of type 2 diabetes, atherogenic dyslipidaemia, hypertension, NAFLD and accelerated vascular and cognitive aging.","measurement":{"method":"Calculated from paired fasting glucose and fasting insulin; inherits the insulin assay's lack of standardization.","sample_type":"venous blood","approx_cost_usd":"25-70"},"signal_quality":"noisy","signal_quality_note":"Combines the high variability and poor standardization of fasting insulin with fasting glucose noise; performs poorly in those with beta-cell failure and is platform-dependent.","confounders":["insulin assay/platform differences","incomplete fast","hepatic vs peripheral insulin resistance not distinguished","beta-cell failure invalidates the model","acute illness and stress"],"testing_cadence":"baseline + annual if metabolic risk present"},"outcomes":{"all_cause_mortality":{"hr":1.46,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of HOMA-IR, all-cause mortality, adjusted (non-diabetic adults)","direction":"risk","ci_low":1.16,"ci_high":1.84,"hr_per_sd":1.1607,"hr_per_sd_ci":[1.0602,1.2713],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":"pooled (meta-analysis of cohorts)","followup_years":10,"study":"Meta-analysis of HOMA-IR and all-cause mortality in non-diabetic populations.","study_type":"meta-analysis","citation":"Systematic review/meta-analysis of HOMA-IR and mortality risk (general and non-diabetic populations, ~2010s-2020s).","verification_status":"approximate","notes":"Higher HOMA-IR is associated with higher all-cause mortality; the association attenuates with adjustment for adiposity and other metabolic factors, indicating HOMA-IR is largely a marker of clustered risk. Quartile contrast converted to per-SD on the log scale."},"cvd":{"hr":1.46,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of HOMA-IR, cardiovascular events, adjusted (non-diabetic adults)","direction":"risk","ci_low":1.26,"ci_high":1.69,"hr_per_sd":1.1896,"hr_per_sd_ci":[1.1118,1.2721],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"A","n":"pooled (meta-analysis)","followup_years":10,"study":"Meta-analysis of HOMA-IR and incident cardiovascular disease in non-diabetic populations.","study_type":"meta-analysis","citation":"Gast KB et al. Insulin resistance and risk of incident cardiovascular events in adults without diabetes: meta-analysis. PLoS One 2012;7:e52036. doi:10.1371/journal.pone.0052036","verification_status":"verified","notes":"Meta-analysis found higher HOMA-IR associated with increased CVD risk in non-diabetic adults; the per-quantile estimate is reported and converted to per-SD here. Association persists but weakens after metabolic-factor adjustment. Insulin resistance is upstream of CVD risk but not cleanly causal in MR."},"cancer":{"hr":1.31,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of HOMA-IR, total/site-specific cancer incidence, adjusted","direction":"risk","ci_low":1.07,"ci_high":1.6,"hr_per_sd":1.1122,"hr_per_sd_ci":[1.027,1.2033],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"pooled cohorts","followup_years":9,"study":"Prospective cohort/meta-analyses of HOMA-IR and cancer risk.","study_type":"meta-analysis","citation":"Meta-analyses of insulin resistance (HOMA-IR) and cancer incidence (e.g. colorectal, breast, pancreatic), ~2010s.","verification_status":"unverified","notes":"Insulin resistance is linked to higher risk of several obesity-related cancers, plausibly through hyperinsulinaemia and IGF signalling; estimates are heterogeneous and confounded by adiposity. Quartile contrast converted to per-SD on the log scale."},"dementia":{"hr":1.27,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of HOMA-IR, incident dementia / cognitive decline, adjusted","direction":"risk","ci_low":1.01,"ci_high":1.6,"hr_per_sd":1.1159,"hr_per_sd_ci":[1.0046,1.2406],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"cohort (~2000-5000)","followup_years":7,"study":"Prospective cohorts of insulin resistance (HOMA-IR) and incident dementia/cognitive decline.","study_type":"prospective-cohort","citation":"Cohort analyses of HOMA-IR and dementia/cognition (e.g. Framingham Offspring, Rotterdam, and Finnish cohorts).","verification_status":"unverified","notes":"Peripheral insulin resistance is associated with faster cognitive decline and modestly higher dementia risk in several cohorts, consistent with brain insulin-resistance models; evidence is inconsistent and CI spans near 1.0. Tertile contrast converted to per-SD on the log scale."},"frailty":{"hr":1.34,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of HOMA-IR, incident frailty in older adults","direction":"risk","ci_low":1.05,"ci_high":1.71,"hr_per_sd":1.1437,"hr_per_sd_ci":[1.0226,1.279],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"older-adult cohort","followup_years":6,"study":"Prospective cohorts of insulin resistance (HOMA-IR) and incident frailty.","study_type":"prospective-cohort","citation":"Cohort analyses of HOMA-IR and frailty/sarcopenia in older adults (e.g. InCHIANTI, Toledo Study of Healthy Ageing).","verification_status":"unverified","notes":"Insulin resistance is associated with incident frailty and sarcopenia, plausibly via impaired anabolic signalling and chronic low-grade inflammation. Evidence is limited and confounded by obesity and inactivity. Tertile contrast converted to per-SD on the log scale."}},"modifiability":{"intervention":"Weight loss, aerobic + resistance exercise, low-glycaemic/Mediterranean diet; metformin, pioglitazone and GLP-1 agents pharmacologically.","effect_size":"Intensive lifestyle change improves HOMA-IR 25-50%; exercise improves it independent of weight loss.","timeframe":"Weeks to a few months","evidence_type":"RCT meta-analysis","citation":"Lifestyle and exercise RCT meta-analyses of insulin resistance; Diabetes Prevention Program.","rating":"high"}},{"id":"hba1c","name":"HbA1c","domain":"glucose_insulin","aliases":["glycated haemoglobin","glycohemoglobin","A1c"],"profile":{"mechanism":"HbA1c reflects the average blood glucose over the preceding 8-12 weeks via non-enzymatic glycation of haemoglobin. It integrates chronic glycaemic exposure that drives micro- and macrovascular damage and is the standard marker for diabetes diagnosis and control.","measurement":{"method":"HPLC, immunoassay or enzymatic assay; internationally standardized to the IFCC/NGSP reference; no fasting required.","sample_type":"venous blood","approx_cost_usd":"10-40"},"signal_quality":"clean","signal_quality_note":"Well-standardized, low within-person variability and no fasting needed; but biased by conditions altering red-cell lifespan (anaemia, haemoglobinopathies, recent transfusion, pregnancy).","confounders":["anaemia and iron deficiency (can raise HbA1c)","haemolysis/haemoglobinopathies (lower HbA1c)","chronic kidney or liver disease","recent blood transfusion or erythropoietin","ethnic differences in glycation"],"testing_cadence":"baseline + annual; every 3-6 months if dysglycaemic or treated"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"J/U-shaped association; mortality rises at both low (<5.0%) and high (>=6.5%) HbA1c; no single monotone HR summarizes it","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"non-monotonic J/U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"B","n":7333,"followup_years":5,"study":"EPIC-Norfolk and other large cohorts: HbA1c and all-cause mortality.","study_type":"prospective-cohort","citation":"Khaw KT et al. Association of hemoglobin A1c with cardiovascular disease and mortality in adults: EPIC-Norfolk. Ann Intern Med 2004;141:413-420. doi:10.7326/0003-4819-141-6-200409210-00006","verification_status":"verified","notes":"Across cohorts the HbA1c-mortality curve is J/U-shaped: lowest risk near 5.0-5.6%, with excess mortality at both low HbA1c (marking anaemia, liver disease, malnutrition, frailty) and high HbA1c. A single linear per-SD HR is not meaningful; flagged categorical/non-monotonic.","qualitative":true},"cvd":{"hr":1.21,"hr_metric":"per_unit","hr_unit_detail":"per 1 percentage-point higher HbA1c, cardiovascular disease, in the non-diabetic range, adjusted","direction":"risk","ci_low":1.11,"ci_high":1.31,"hr_per_sd":1.1,"hr_per_sd_ci":[1.0536,1.1446],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.5 (Non-diabetic-range HbA1c SD ~0.4-0.5 percentage points (EPIC-Norfolk / general population)); k = SD/unit = 0.5","conversion":{"unit_value":1,"population_sd":0.5,"sd_source":"Non-diabetic-range HbA1c SD ~0.4-0.5 percentage points (EPIC-Norfolk / general population)"},"evidence_tier":"A","n":10232,"followup_years":10,"study":"EPIC-Norfolk and pooled cohorts of HbA1c and cardiovascular disease.","study_type":"meta-analysis","citation":"Khaw KT et al., EPIC-Norfolk (Ann Intern Med 2004); supported by Emerging Risk Factors Collaboration HbA1c analyses.","verification_status":"verified","notes":"Within and above the non-diabetic range HbA1c is continuously associated with CVD risk with no clear threshold; ~1 percentage point higher confers ~20% higher CVD risk. Per-percentage-point HR converted to per-SD with a non-diabetic-range SD. Largely a glycaemic-exposure marker; MR supports modest causal vascular effect."},"cancer":{"hr":1.07,"hr_metric":"per_unit","hr_unit_detail":"per 1 percentage-point higher HbA1c, total cancer incidence, adjusted","direction":"risk","ci_low":1.02,"ci_high":1.13,"hr_per_sd":1.0414,"hr_per_sd_ci":[1.012,1.0761],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.6 (General-population HbA1c SD ~0.5-0.7 percentage points (ARIC / pooled cohorts)); k = SD/unit = 0.6","conversion":{"unit_value":1,"population_sd":0.6,"sd_source":"General-population HbA1c SD ~0.5-0.7 percentage points (ARIC / pooled cohorts)"},"evidence_tier":"C","n":11167,"followup_years":14,"study":"ARIC and other prospective cohorts of HbA1c and cancer incidence.","study_type":"prospective-cohort","citation":"Joshu CE et al. and ARIC analyses of glycated haemoglobin and cancer risk; pooled cohort evidence.","verification_status":"approximate","notes":"Higher HbA1c modestly associates with total and site-specific (e.g. colorectal, liver) cancer incidence; some analyses show a J-shape with elevated risk at very low HbA1c too. Effect is small and confounded by obesity. Per-percentage-point HR converted with a general-population SD."},"dementia":{"hr":1.13,"hr_metric":"per_unit","hr_unit_detail":"per 1 percentage-point higher HbA1c, incident dementia, adjusted","direction":"risk","ci_low":1.04,"ci_high":1.23,"hr_per_sd":1.0761,"hr_per_sd_ci":[1.0238,1.1323],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.6 (General-population HbA1c SD ~0.5-0.7 percentage points (Whitehall II / pooled cohorts)); k = SD/unit = 0.6","conversion":{"unit_value":1,"population_sd":0.6,"sd_source":"General-population HbA1c SD ~0.5-0.7 percentage points (Whitehall II / pooled cohorts)"},"evidence_tier":"B","n":5189,"followup_years":15,"study":"Whitehall II and pooled cohorts of HbA1c and incident dementia / cognitive decline.","study_type":"prospective-cohort","citation":"Zheng F et al. HbA1c, diabetes and cognitive decline: the English Longitudinal Study of Ageing. Diabetologia 2018;61:839-848. doi:10.1007/s00125-017-4541-7","verification_status":"verified","notes":"Higher HbA1c, including in the prediabetic range, is associated with faster cognitive decline and higher dementia risk in ELSA and Whitehall II. Effect is graded; mechanisms include vascular injury and impaired cerebral metabolism. Per-percentage-point HR converted to per-SD with a general-population SD."},"frailty":{"hr":1.2,"hr_metric":"per_unit","hr_unit_detail":"per 1 percentage-point higher HbA1c, incident frailty in older adults, adjusted","direction":"risk","ci_low":1.05,"ci_high":1.38,"hr_per_sd":1.1361,"hr_per_sd_ci":[1.0347,1.2529],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 0.7 (Older-adult HbA1c SD ~0.6-0.8 percentage points (English Longitudinal Study of Ageing)); k = SD/unit = 0.7","conversion":{"unit_value":1,"population_sd":0.7,"sd_source":"Older-adult HbA1c SD ~0.6-0.8 percentage points (English Longitudinal Study of Ageing)"},"evidence_tier":"C","n":3982,"followup_years":8,"study":"English Longitudinal Study of Ageing and other older-adult cohorts of HbA1c and frailty.","study_type":"prospective-cohort","citation":"Analyses of HbA1c and incident frailty in older adults (e.g. ELSA, Hertfordshire cohorts).","verification_status":"approximate","notes":"Higher HbA1c is associated with incident frailty and physical decline in older adults, with some evidence of a U-shape (low HbA1c also marks ill-health). Per-percentage-point HR converted to per-SD with an older-adult SD; evidence is moderate and confounded."}},"modifiability":{"intervention":"Weight loss, low-glycaemic diet, physical activity; metformin, GLP-1 agonists, SGLT2 inhibitors and insulin in diabetes.","effect_size":"Lifestyle change lowers HbA1c ~0.3-0.5 percentage points in prediabetes; glucose-lowering drugs lower it 0.5-1.5 points in diabetes.","timeframe":"3 months (one HbA1c turnover) for a meaningful change","evidence_type":"RCT meta-analysis","citation":"Diabetes Prevention Program; glucose-lowering RCT meta-analyses (UKPDS, etc.).","rating":"high"}},{"id":"ogtt_2h_glucose","name":"OGTT 2-hour glucose","domain":"glucose_insulin","aliases":["2-hour postload glucose","2-h plasma glucose","oral glucose tolerance test 2h glucose"],"profile":{"mechanism":"Two-hour plasma glucose after a 75 g oral glucose load measures the integrated capacity to dispose of a glucose challenge, capturing postprandial/postload hyperglycaemia and muscle insulin sensitivity. Postload glucose detects dysglycaemia missed by fasting tests and predicts diabetes and vascular disease.","measurement":{"method":"Plasma glucose 2 h after a standardized 75 g oral glucose load, after an overnight fast; enzymatic assay.","sample_type":"venous blood","approx_cost_usd":"20-60"},"signal_quality":"moderate","signal_quality_note":"Reproducible enzymatic assay, but the test itself has substantial within-person variability (~16-17% CV) driven by gastric emptying, prior diet and activity; burdensome 2-hour protocol.","confounders":["prior carbohydrate intake and physical activity","gastric emptying rate variation","test-to-test biological variability","acute illness/stress","incomplete glucose-load ingestion or vomiting"],"testing_cadence":"as indicated for dysglycaemia screening; not routine"},"outcomes":{"all_cause_mortality":{"hr":1.73,"hr_metric":"categorical","hr_unit_detail":"2-h glucose >=11.1 mmol/L (diabetic range) vs normal (<7.8 mmol/L), all-cause mortality","direction":"risk","ci_low":1.45,"ci_high":2.06,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":25364,"followup_years":8.8,"study":"DECODE study group, pooled European cohorts of OGTT glucose and mortality.","study_type":"pooled-cohort","citation":"DECODE Study Group. Glucose tolerance and mortality: comparison of WHO and ADA diagnostic criteria. Lancet 1999;354:617-621. doi:10.1016/S0140-6736(98)12131-1","verification_status":"verified","notes":"DECODE found 2-h glucose predicted all-cause and CVD mortality better than fasting glucose, with excess risk extending into the impaired-glucose-tolerance range. The cell reports a diabetic-vs-normal stratum contrast (categorical); the underlying relation is broadly graded but commonly reported categorically."},"cvd":{"hr":1.4,"hr_metric":"categorical","hr_unit_detail":"impaired glucose tolerance (2-h 7.8-11.0 mmol/L) vs normal, cardiovascular mortality","direction":"risk","ci_low":1.19,"ci_high":1.65,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":25364,"followup_years":8.8,"study":"DECODE study group, pooled European cohorts of OGTT glucose and cardiovascular mortality.","study_type":"pooled-cohort","citation":"DECODE Study Group. Glucose tolerance and cardiovascular mortality. Arch Intern Med 2001;161:397-405. doi:10.1001/archinte.161.3.397","verification_status":"verified","notes":"DECODE showed impaired glucose tolerance (independent of fasting glucose) raised cardiovascular mortality; 2-h glucose added prognostic information beyond fasting glucose and HbA1c. Reported as a categorical stratum contrast."},"cancer":{"hr":1.26,"hr_metric":"categorical","hr_unit_detail":"diabetic-range vs normal 2-h glucose, total cancer mortality","direction":"risk","ci_low":1,"ci_high":1.59,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"DECODE / cohort subsets","followup_years":9,"study":"Pooled-cohort analyses of postload glucose and cancer mortality.","study_type":"pooled-cohort","citation":"DECODE and related European cohort analyses of glucose tolerance and cause-specific mortality.","verification_status":"unverified","notes":"Postload hyperglycaemia is weakly associated with cancer mortality; evidence is sparse and largely subsumed by diabetes-cancer associations. Reported as a categorical stratum contrast; treat as low-confidence."},"dementia":{"hr":1.3,"hr_metric":"categorical","hr_unit_detail":"impaired glucose tolerance / postload hyperglycaemia vs normal, incident dementia","direction":"risk","ci_low":1,"ci_high":1.69,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"cohort (~1000-2500)","followup_years":9,"study":"Prospective cohorts of glucose tolerance and incident dementia (e.g. Hisayama, Honolulu-Asia Aging).","study_type":"prospective-cohort","citation":"Hisayama Study and related Asian cohort analyses of postload glucose / glucose tolerance and dementia.","verification_status":"unverified","notes":"The Hisayama Study linked 2-h postload glucose to higher dementia (including Alzheimer) risk, in some analyses more strongly than fasting glucose. Evidence is limited and confounded. Reported as a categorical stratum contrast."},"frailty":null},"modifiability":{"intervention":"Weight loss, physical activity (especially post-meal activity), low-glycaemic diet; acarbose and GLP-1 agents blunt postload glucose.","effect_size":"Lifestyle intervention substantially lowers 2-h glucose and reverts impaired glucose tolerance in a large fraction of participants.","timeframe":"Weeks to months","evidence_type":"RCT meta-analysis","citation":"Diabetes Prevention Program and Finnish DPS (2-h glucose endpoints); STOP-NIDDM (acarbose).","rating":"high"},"comparability_tag":"Clinical strata","comparability_note":"2-hour OGTT glucose HRs are reported across diagnostic strata (normal, impaired glucose tolerance, diabetic range), not as a continuous per-SD slope."},{"id":"ogtt_2h_insulin","name":"OGTT 2-hour insulin","domain":"glucose_insulin","aliases":["2-hour postload insulin","postchallenge insulin"],"profile":{"mechanism":"Two-hour postload insulin reflects the magnitude of the insulin response sustained after a glucose challenge; elevated postload insulin indicates compensatory hyperinsulinaemia and insulin resistance, while a delayed/sustained peak signals impaired insulin dynamics.","measurement":{"method":"Immunoassay for insulin on plasma drawn 2 h into a 75 g OGTT; not standardized across platforms.","sample_type":"venous blood","approx_cost_usd":"30-90"},"signal_quality":"noisy","signal_quality_note":"Combines OGTT protocol variability with poorly standardized, pulsatile insulin measurement; postload insulin interpretation depends on the concurrent glucose, limiting standalone use.","confounders":["insulin assay/platform differences","OGTT protocol and prior diet/activity","concurrent glucose level needed for interpretation","hepatic insulin clearance variation","gastric emptying rate"],"testing_cadence":"research/specialist use; not routine"},"outcomes":{"all_cause_mortality":{"hr":1.31,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of 2-h postload insulin, all-cause mortality, adjusted","direction":"risk","ci_low":1,"ci_high":1.71,"hr_per_sd":1.1122,"hr_per_sd_ci":[1,1.2352],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"cohort (~1000-3000)","followup_years":12,"study":"Prospective cohorts of postload hyperinsulinaemia and mortality.","study_type":"prospective-cohort","citation":"Cohort analyses of postchallenge insulin and mortality (e.g. Paris Prospective Study, Helsinki Policemen Study).","verification_status":"unverified","notes":"Postload hyperinsulinaemia was linked to higher mortality in mid-20th-century cohorts, but estimates are imprecise (CI touches 1.0) and confounded by adiposity; the marker is rarely studied with modern methods. Quartile contrast converted to per-SD on the log scale."},"cvd":{"hr":1.38,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of 2-h postload insulin, coronary heart disease, adjusted","direction":"risk","ci_low":1.05,"ci_high":1.81,"hr_per_sd":1.1352,"hr_per_sd_ci":[1.0194,1.2631],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"cohort (~1000-7000)","followup_years":15,"study":"Prospective cohorts of postchallenge insulin and coronary heart disease.","study_type":"prospective-cohort","citation":"Pyorala K et al., Helsinki Policemen Study; Ducimetiere P et al., Paris Prospective Study - postchallenge insulin and CHD.","verification_status":"approximate","notes":"Older cohorts (Helsinki Policemen, Paris Prospective) linked postchallenge hyperinsulinaemia to higher CHD risk; associations weakened markedly after adjustment for other risk factors. Quartile contrast converted to per-SD on the log scale; treat as low-confidence."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Weight loss, exercise training, carbohydrate restriction lower the postload insulin response.","effect_size":"Lifestyle change can substantially reduce postload insulin secretion as insulin sensitivity improves.","timeframe":"Weeks to months","evidence_type":"observational","citation":"Exercise and weight-loss studies reporting OGTT insulin responses.","rating":"high"}},{"id":"cgm_mean_glucose","name":"CGM mean glucose","domain":"glucose_insulin","aliases":["continuous glucose monitoring mean glucose","average sensor glucose"],"profile":{"mechanism":"CGM mean glucose is the average interstitial glucose over days to weeks, a high-resolution analogue of glycaemic exposure that maps closely onto HbA1c (the glucose management indicator) but captures day-to-day and postprandial glucose that point measures miss.","measurement":{"method":"Subcutaneous interstitial glucose sensor (factory-calibrated) worn 10-14 days, sampling every 1-15 min; mean computed over the wear period.","sample_type":"wearable","approx_cost_usd":"40-90"},"signal_quality":"moderate","signal_quality_note":"Dense sampling gives a stable mean, but interstitial sensors have ~8-10% MARD vs blood, lag blood glucose, and require sufficient wear time (>=70%) for a representative average.","confounders":["sensor accuracy/calibration drift (MARD ~8-10%)","interstitial-to-blood lag","insufficient wear time","compression artefacts and acetaminophen interference (some sensors)","short monitoring window may not represent habitual glycaemia"],"testing_cadence":"intermittent 2-week wears, e.g. quarterly to annually"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no direct CGM mean-glucose mortality cohort; risk inferred from the HbA1c/mean-glucose relationship","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no prospective CGM-mortality data; not convertible to per-SD","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study of CGM mean glucose and mortality identified.","study_type":"prospective-cohort","citation":"No direct citation; CGM mean glucose maps to HbA1c (glucose management indicator, Bergenstal RM et al., Diabetes Care 2018).","verification_status":"unverified","notes":"CGM mean glucose has no direct hard-outcome cohort evidence; risk is presumed similar to HbA1c via their tight correlation, but no per-SD mortality HR exists. Flagged unconvertible (continuous but no usable estimate).","qualitative":true},"cvd":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no direct CGM mean-glucose CVD-outcome cohort identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no prospective CGM-CVD data; not convertible to per-SD","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study of CGM mean glucose and incident CVD identified.","study_type":"prospective-cohort","citation":"No direct citation; inference based on the HbA1c-CVD relationship.","verification_status":"unverified","notes":"No hard-outcome CVD cohort exists for CGM mean glucose; the marker is a recent research/clinical tool. Risk is assumed concordant with HbA1c. Flagged unconvertible.","qualitative":true},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Weight loss, low-glycaemic/lower-carbohydrate diet, post-meal activity; glucose-lowering drugs in diabetes.","effect_size":"Diet and activity changes shift CGM mean glucose by ~0.5-1.5 mmol/L within weeks; readily trackable on-device.","timeframe":"Days to weeks","evidence_type":"RCT","citation":"CGM-guided lifestyle and dietary intervention trials.","rating":"high"}},{"id":"cgm_glucose_variability","name":"CGM glucose variability (CV/SD)","domain":"glucose_insulin","aliases":["glycaemic variability","coefficient of variation of glucose","CGM SD"],"profile":{"mechanism":"Glycaemic variability (CV or SD of CGM glucose) captures the amplitude of glucose swings independent of the mean. Large excursions are hypothesized to drive oxidative stress and endothelial dysfunction more than stable hyperglycaemia, and high CV marks hypoglycaemia risk.","measurement":{"method":"Computed from a 10-14 day CGM trace as coefficient of variation (SD/mean x 100) or SD of sensor glucose.","sample_type":"wearable","approx_cost_usd":"40-90"},"signal_quality":"moderate","signal_quality_note":"Sensitive to sensor noise and to the wear window; CV is more standardized than SD but both depend on adequate wear time and are affected by sensor MARD and compression artefacts.","confounders":["sensor noise inflates apparent variability","short or low-wear monitoring window","meal timing and composition during wear","physical activity and alcohol","limited population reference ranges in non-diabetic adults"],"testing_cadence":"intermittent 2-week wears"},"outcomes":{"all_cause_mortality":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher CGM glucose CV, all-cause mortality in hospitalized/diabetic populations (approximate)","direction":"risk","ci_low":1.05,"ci_high":1.37,"hr_per_sd":1.2,"hr_per_sd_ci":[1.05,1.37],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"diabetic / hospitalized cohorts","followup_years":3,"study":"Cohorts of glycaemic variability and mortality in diabetic or inpatient populations.","study_type":"prospective-cohort","citation":"Analyses of glucose variability (CV/SD) and mortality in type 2 diabetes and inpatient cohorts (e.g. critical-care and diabetes registries).","verification_status":"unverified","notes":"Higher glycaemic variability is associated with higher mortality in diabetic and critically ill populations, but evidence in healthy/non-diabetic adults is essentially absent and the metric is confounded by hypoglycaemia and illness severity. Per-SD estimate is approximate; treat as low-confidence."},"cvd":{"hr":1.25,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher glycaemic variability, cardiovascular events in type 2 diabetes (approximate)","direction":"risk","ci_low":1.05,"ci_high":1.49,"hr_per_sd":1.25,"hr_per_sd_ci":[1.05,1.49],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"diabetic cohorts","followup_years":5,"study":"Cohorts/meta-analyses of glycaemic variability and cardiovascular events in type 2 diabetes.","study_type":"meta-analysis","citation":"Meta-analyses of glycaemic variability and cardiovascular outcomes in type 2 diabetes (~2018-2023).","verification_status":"unverified","notes":"Glycaemic variability is associated with cardiovascular events in type 2 diabetes, but it is hard to separate from mean glycaemia and hypoglycaemia; non-diabetic CVD evidence is absent. Per-SD estimate approximate; low-confidence."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Smoothing of meal carbohydrate load, post-meal activity, meal sequencing; in diabetes, agents that reduce excursions (GLP-1 agonists, DPP-4 inhibitors).","effect_size":"Dietary restructuring can reduce CGM CV by several percentage points within weeks.","timeframe":"Days to weeks","evidence_type":"RCT","citation":"CGM-guided dietary intervention trials reporting variability endpoints.","rating":"moderate"}},{"id":"cgm_time_in_range","name":"CGM time-in-range","domain":"glucose_insulin","aliases":["TIR","time in range 70-180 mg/dL"],"profile":{"mechanism":"Time-in-range is the percentage of CGM readings within a target glucose band (commonly 70-180 mg/dL). It is an integrated measure of overall glycaemic control; more time in range reflects fewer hyper- and hypoglycaemic excursions and correlates inversely with diabetic complications.","measurement":{"method":"Percentage of CGM glucose values within the target band over a 10-14 day wear period.","sample_type":"wearable","approx_cost_usd":"40-90"},"signal_quality":"moderate","signal_quality_note":"Stable when wear time is adequate; depends on sensor accuracy and on the chosen band, and in non-diabetic adults most readings are already in range, compressing its dynamic range.","confounders":["sensor MARD and calibration","insufficient wear time","ceiling effect in metabolically healthy people","target-band definition differences","meal and activity patterns during wear"],"testing_cadence":"intermittent 2-week wears"},"outcomes":{"all_cause_mortality":{"hr":0.94,"hr_metric":"per_unit","hr_unit_detail":"per 10 percentage-point higher time-in-range, all-cause mortality, type 2 diabetes","direction":"protective","ci_low":0.9,"ci_high":0.98,"hr_per_sd":0.8836,"hr_per_sd_ci":[0.81,0.9604],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 20 (Time-in-range SD ~18-22 percentage points in type 2 diabetes CGM cohorts); k = SD/unit = 2","conversion":{"unit_value":10,"population_sd":20,"sd_source":"Time-in-range SD ~18-22 percentage points in type 2 diabetes CGM cohorts"},"evidence_tier":"C","n":6225,"followup_years":7,"study":"Prospective cohort of CGM time-in-range and mortality in type 2 diabetes.","study_type":"prospective-cohort","citation":"Lu J et al. Time in range and mortality in patients with type 2 diabetes. Diabetes Care 2021;44:549-555. doi:10.2337/dc20-1862","verification_status":"approximate","notes":"In type 2 diabetes lower time-in-range was associated with higher all-cause and CVD mortality; evidence does not extend to non-diabetic/healthy populations. Per-10-point HR converted to per-SD with a diabetic-cohort SD; treat as diabetes-specific and low-confidence for general longevity."},"cvd":{"hr":0.92,"hr_metric":"per_unit","hr_unit_detail":"per 10 percentage-point higher time-in-range, cardiovascular mortality, type 2 diabetes","direction":"protective","ci_low":0.87,"ci_high":0.98,"hr_per_sd":0.8464,"hr_per_sd_ci":[0.7569,0.9604],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 20 (Time-in-range SD ~18-22 percentage points in type 2 diabetes CGM cohorts); k = SD/unit = 2","conversion":{"unit_value":10,"population_sd":20,"sd_source":"Time-in-range SD ~18-22 percentage points in type 2 diabetes CGM cohorts"},"evidence_tier":"C","n":6225,"followup_years":7,"study":"Prospective cohort of CGM time-in-range and cardiovascular mortality in type 2 diabetes.","study_type":"prospective-cohort","citation":"Lu J et al. Time in range and cardiovascular mortality in type 2 diabetes. Diabetes Care 2021;44:549-555. doi:10.2337/dc20-1862","verification_status":"approximate","notes":"Lower time-in-range associated with higher cardiovascular mortality in type 2 diabetes; also linked to carotid intima-media thickness and retinopathy in cross-sectional CGM studies. Per-10-point HR converted to per-SD; diabetes-specific evidence only."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Lower-glycaemic diet, post-meal activity, meal sequencing; glucose-lowering therapy in diabetes (notably CGM-guided regimens).","effect_size":"CGM-guided lifestyle or therapy adjustments can raise time-in-range by 5-15 percentage points within weeks.","timeframe":"Days to weeks","evidence_type":"RCT","citation":"CGM-guided management RCTs reporting time-in-range endpoints.","rating":"high"}},{"id":"cgm_postprandial_auc","name":"CGM postprandial glucose AUC","domain":"glucose_insulin","aliases":["postprandial glucose area under the curve","meal glucose response","postprandial glucose excursion"],"profile":{"mechanism":"Postprandial glucose AUC quantifies the size of glucose excursions after meals, integrating peak height and duration. Repeated large postprandial spikes are hypothesized to drive oxidative stress, endothelial dysfunction and beta-cell strain, and postprandial glucose tracks with vascular risk.","measurement":{"method":"Incremental or total area under the CGM glucose curve over a defined post-meal window (typically 2-3 h), averaged across meals.","sample_type":"wearable","approx_cost_usd":"40-90"},"signal_quality":"noisy","signal_quality_note":"Highly dependent on meal content, timing, prior activity and the AUC definition (incremental vs total, window length); not standardized, with large within-person variability across meals.","confounders":["meal carbohydrate load and composition","AUC definition and window length differences","prior meal and physical activity","sensor lag and noise","no standardized reference ranges"],"testing_cadence":"intermittent, meal-challenge or 2-week wears"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no prospective CGM postprandial-AUC mortality study; postload-glucose evidence used as proxy","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no prospective CGM postprandial-AUC outcome data; not convertible to per-SD","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study of CGM postprandial AUC and mortality identified.","study_type":"prospective-cohort","citation":"No direct citation; postprandial glucose risk inferred from OGTT 2-h glucose cohorts (DECODE).","verification_status":"unverified","notes":"CGM postprandial AUC has no hard-outcome cohort evidence; postload (OGTT) glucose studies suggest postprandial hyperglycaemia carries vascular and mortality risk, but the CGM-derived metric itself is unvalidated against outcomes. Flagged unconvertible.","qualitative":true},"cvd":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no prospective CGM postprandial-AUC CVD study; postload-glucose evidence used as proxy","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no prospective CGM postprandial-AUC outcome data; not convertible to per-SD","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study of CGM postprandial AUC and incident CVD identified.","study_type":"prospective-cohort","citation":"No direct citation; postprandial-glucose CVD risk inferred from DECODE 2-h glucose analyses.","verification_status":"unverified","notes":"Postprandial hyperglycaemia is associated with CVD in postload-glucose cohorts, but no prospective study uses the CGM postprandial-AUC metric directly. Flagged unconvertible.","qualitative":true},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Lower-glycaemic meals, reduced meal carbohydrate, meal sequencing (protein/vegetables first), post-meal walking; acarbose/GLP-1 agents in diabetes.","effect_size":"Meal restructuring and post-meal activity can roughly halve postprandial glucose excursions.","timeframe":"Immediate (per meal) to days","evidence_type":"RCT","citation":"Meal-sequencing and post-meal-activity crossover trials with CGM endpoints.","rating":"high"}},{"id":"cgm_dawn_phenomenon","name":"CGM dawn-phenomenon magnitude","domain":"glucose_insulin","aliases":["dawn phenomenon","early-morning glucose rise"],"profile":{"mechanism":"The dawn phenomenon is the early-morning rise in glucose driven by the overnight surge in cortisol, growth hormone and catecholamines increasing hepatic glucose output. Its magnitude on CGM is a proposed marker of hepatic insulin resistance and counter-regulatory tone.","measurement":{"method":"Difference between pre-dawn nadir and morning glucose on the overnight CGM trace, averaged over several nights.","sample_type":"wearable","approx_cost_usd":"40-90"},"signal_quality":"noisy","signal_quality_note":"No standardized definition (nadir-to-peak window varies), large night-to-night variability, and sensitivity to sleep timing, late meals and sensor noise make the metric exploratory.","confounders":["no standardized computation","sleep timing and quality","late-evening meals or snacks","night-to-night variability","sensor noise overnight"],"testing_cadence":"research/exploratory only"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Earlier and lower-carbohydrate evening meals, improved sleep, weight loss; in diabetes, basal insulin timing or metformin.","effect_size":"Evening-meal timing and basal therapy adjustments can blunt the dawn rise, though evidence is limited.","timeframe":"Days to weeks","evidence_type":"observational","citation":"Small CGM studies of the dawn phenomenon and evening-meal/sleep manipulation.","rating":"moderate"}},{"id":"fructosamine","name":"Fructosamine","domain":"glucose_insulin","aliases":["glycated serum protein","glycated albumin (related)"],"profile":{"mechanism":"Fructosamine measures glycated serum proteins (mainly albumin) and reflects average glycaemia over the preceding 2-3 weeks, a shorter window than HbA1c. It is an integrated glycaemic-exposure marker useful when HbA1c is unreliable (haemoglobinopathies, recent change in control).","measurement":{"method":"Colorimetric (nitroblue tetrazolium) assay on serum; no fasting required.","sample_type":"venous blood","approx_cost_usd":"10-30"},"signal_quality":"moderate","signal_quality_note":"Reproducible assay but influenced by serum protein turnover and concentration; less standardized and less outcome-validated than HbA1c, with a shorter and noisier integration window.","confounders":["low serum albumin or altered protein turnover (nephrotic syndrome, liver disease)","thyroid dysfunction","acute inflammation","shorter integration window than HbA1c","no fasting requirement but assay-method differences"],"testing_cadence":"as indicated when HbA1c is unreliable"},"outcomes":{"all_cause_mortality":{"hr":1.24,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of fructosamine, all-cause mortality, adjusted","direction":"risk","ci_low":1.06,"ci_high":1.45,"hr_per_sd":1.0884,"hr_per_sd_ci":[1.0232,1.1575],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":12378,"followup_years":20,"study":"Atherosclerosis Risk in Communities (ARIC) cohort of fructosamine and outcomes.","study_type":"prospective-cohort","citation":"Selvin E et al. Fructosamine and glycated albumin and the risk of cardiovascular outcomes and death. Circulation 2015;132:269-277. doi:10.1161/CIRCULATIONAHA.115.015415","verification_status":"approximate","notes":"In ARIC fructosamine (and glycated albumin) were associated with mortality, with associations broadly comparable to HbA1c; the marker is less outcome-validated overall. Quartile contrast converted to per-SD."},"cvd":{"hr":1.5,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of fructosamine, incident coronary heart disease, adjusted","direction":"risk","ci_low":1.21,"ci_high":1.85,"hr_per_sd":1.1731,"hr_per_sd_ci":[1.0779,1.274],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":11104,"followup_years":20,"study":"Atherosclerosis Risk in Communities (ARIC) cohort of fructosamine and coronary heart disease.","study_type":"prospective-cohort","citation":"Selvin E et al. Fructosamine and glycated albumin and the risk of cardiovascular outcomes and death. Circulation 2015;132:269-277. doi:10.1161/CIRCULATIONAHA.115.015415","verification_status":"approximate","notes":"Fructosamine in the top quartile was associated with higher coronary heart disease risk in ARIC, comparable to HbA1c. Quartile contrast converted to per-SD; observational glycaemic-exposure marker."},"cancer":null,"dementia":{"hr":1.28,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of fructosamine, incident dementia, adjusted","direction":"risk","ci_low":1.01,"ci_high":1.62,"hr_per_sd":1.1021,"hr_per_sd_ci":[1.0039,1.2092],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":11000,"followup_years":20,"study":"ARIC cohort analyses of glycaemic markers (including fructosamine) and incident dementia.","study_type":"prospective-cohort","citation":"Rawlings AM et al. and ARIC analyses of glycaemic markers and dementia (Circulation/Diabetologia, ~2014-2017).","verification_status":"unverified","notes":"ARIC linked glycaemic-exposure markers including fructosamine to higher dementia risk; the fructosamine-specific estimate is imprecise. Quartile contrast converted to per-SD; low-confidence."},"frailty":null},"modifiability":{"intervention":"Same glycaemia-lowering levers as HbA1c: weight loss, low-glycaemic diet, activity, glucose-lowering drugs.","effect_size":"Responds to glycaemic change faster than HbA1c (2-3 week window); magnitude tracks glucose control.","timeframe":"2-3 weeks","evidence_type":"observational","citation":"Studies of fructosamine response to glucose-lowering therapy.","rating":"high"}},{"id":"c_peptide","name":"C-peptide","domain":"glucose_insulin","aliases":["connecting peptide","fasting C-peptide"],"profile":{"mechanism":"C-peptide is co-secreted with insulin in equimolar amounts and, being cleared more slowly and not extracted by the liver, gives a stable index of endogenous insulin secretion. Elevated C-peptide indicates compensatory hyperinsulinaemia and insulin resistance; very low values indicate beta-cell failure.","measurement":{"method":"Immunoassay on fasting serum or plasma; more stable than insulin and not affected by exogenous insulin therapy.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"moderate","signal_quality_note":"More stable and standardized than insulin, but right-skewed, affected by renal clearance, and its outcome interpretation is non-monotonic (both extremes are adverse).","confounders":["renal impairment (raises C-peptide)","fasting state","right-skewed distribution","U-shaped interpretation (low = beta-cell failure)","obesity strongly raises levels"],"testing_cadence":"baseline + as indicated for metabolic assessment"},"outcomes":{"all_cause_mortality":{"hr":1.61,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of fasting C-peptide, all-cause mortality, adjusted","direction":"risk","ci_low":1.34,"ci_high":1.94,"hr_per_sd":1.2062,"hr_per_sd_ci":[1.1221,1.2981],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":6594,"followup_years":12,"study":"NHANES III prospective cohort of fasting C-peptide and mortality.","study_type":"prospective-cohort","citation":"Min JY, Min KB. Serum C-peptide levels and risk of death among adults without diabetes mellitus. CMAJ 2013;185:E402-E408. doi:10.1503/cmaj.121950","verification_status":"verified","notes":"In NHANES III, higher fasting C-peptide predicted all-cause and CVD mortality among adults without diabetes, independent of conventional risk factors. The relationship is partly U-shaped at the population level (low C-peptide marks beta-cell failure/illness). Quartile contrast converted to per-SD on the log scale."},"cvd":{"hr":1.7,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of fasting C-peptide, cardiovascular mortality, adjusted","direction":"risk","ci_low":1.3,"ci_high":2.22,"hr_per_sd":1.2323,"hr_per_sd_ci":[1.1088,1.3689],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":6594,"followup_years":12,"study":"NHANES III prospective cohort of fasting C-peptide and cardiovascular mortality.","study_type":"prospective-cohort","citation":"Min JY, Min KB. Serum C-peptide levels and risk of death among adults without diabetes mellitus. CMAJ 2013;185:E402-E408. doi:10.1503/cmaj.121950","verification_status":"verified","notes":"Higher C-peptide was associated with cardiovascular mortality in NHANES III non-diabetic adults; C-peptide is also elevated in metabolic syndrome and predicts CVD in diabetic cohorts. Quartile contrast converted to per-SD on the log scale; association reflects insulin resistance, not necessarily causality."},"cancer":{"hr":1.35,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of C-peptide, colorectal cancer risk, adjusted","direction":"risk","ci_low":1.02,"ci_high":1.79,"hr_per_sd":1.1254,"hr_per_sd_ci":[1.0078,1.2576],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"nested case-control / cohort","followup_years":10,"study":"Nested case-control analyses of C-peptide and colorectal cancer.","study_type":"prospective-cohort","citation":"Ma J et al. and EPIC nested analyses of C-peptide and colorectal cancer risk (~2004-2010).","verification_status":"approximate","notes":"Higher C-peptide is associated with colorectal (and some other) cancers, consistent with the hyperinsulinaemia-cancer hypothesis; site-specific and heterogeneous. Quartile contrast converted to per-SD on the log scale; low-confidence."},"dementia":null,"frailty":null},"modifiability":{"intervention":"Weight loss, exercise, carbohydrate restriction reduce hyperinsulinaemia and C-peptide where beta-cell function is intact.","effect_size":"Lifestyle change can lower elevated C-peptide substantially in insulin-resistant individuals.","timeframe":"Weeks to months","evidence_type":"observational","citation":"Weight-loss and exercise studies reporting C-peptide change.","rating":"moderate"}},{"id":"adiponectin","name":"Adiponectin","domain":"glucose_insulin","aliases":["ADIPOQ","GBP-28","AdipoQ"],"profile":{"mechanism":"Adiponectin is an adipocyte-derived hormone that enhances insulin sensitivity, promotes fatty-acid oxidation and has anti-inflammatory and anti-atherogenic actions. Higher levels mark better metabolic health, yet in older and chronically-ill populations high adiponectin paradoxically predicts higher mortality.","measurement":{"method":"Immunoassay (ELISA/RIA) on serum or plasma; total or high-molecular-weight adiponectin; assays not fully harmonized.","sample_type":"venous blood","approx_cost_usd":"30-80"},"signal_quality":"moderate","signal_quality_note":"Stable analyte with low within-person variability, but assays differ across platforms and the paradoxical, context-dependent mortality association complicates interpretation.","confounders":["right-skewed distribution","reverse causation: cachexia, heart failure, renal disease raise adiponectin","natriuretic peptides raise adiponectin","sex differences (higher in women)","assay/isoform differences"],"testing_cadence":"baseline + as indicated"},"outcomes":{"all_cause_mortality":{"hr":1.23,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD of log adiponectin, all-cause mortality (paradoxical positive association), adjusted","direction":"risk","ci_low":1.13,"ci_high":1.34,"hr_per_sd":1.23,"hr_per_sd_ci":[1.13,1.34],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":"pooled (meta-analysis)","followup_years":10,"study":"Meta-analysis of prospective cohorts of adiponectin and all-cause mortality.","study_type":"meta-analysis","citation":"Wu ZJ et al. and other meta-analyses of adiponectin and all-cause/CVD mortality (~2015-2018), e.g. systematic review of prospective cohorts.","verification_status":"approximate","notes":"Paradox: despite being insulin-sensitising and anti-atherogenic, higher adiponectin predicts HIGHER all-cause mortality in pooled cohorts, especially in older adults and those with heart failure or renal disease. Likely reverse causation (cachexia, natriuretic-peptide drive, counter-regulatory upregulation). Direction is 'risk' for the observed association though the biology is protective. Per SD of log adiponectin."},"cvd":{"hr":1.14,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD of log adiponectin, cardiovascular disease/mortality (paradoxical positive association), adjusted","direction":"risk","ci_low":1.04,"ci_high":1.25,"hr_per_sd":1.14,"hr_per_sd_ci":[1.04,1.25],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":"pooled (meta-analysis)","followup_years":10,"study":"Meta-analysis of prospective cohorts of adiponectin and cardiovascular outcomes.","study_type":"meta-analysis","citation":"Meta-analyses of adiponectin and cardiovascular disease/mortality (~2015-2018).","verification_status":"approximate","notes":"The adiponectin paradox extends to CVD: meta-analyses show higher adiponectin associated with higher CVD mortality, especially in established disease and older age, attributed to reverse causation and counter-regulation. Mendelian randomization does NOT support a causal protective effect on CHD. Per SD of log adiponectin."},"cancer":null,"dementia":{"hr":1.29,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD of log adiponectin, incident all-cause dementia / Alzheimer disease (women), adjusted","direction":"risk","ci_low":1.04,"ci_high":1.61,"hr_per_sd":1.29,"hr_per_sd_ci":[1.04,1.61],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":840,"followup_years":13,"study":"Framingham Heart Study cohort of plasma adiponectin and incident dementia.","study_type":"prospective-cohort","citation":"van Himbergen TM et al. Biomarkers for insulin resistance and inflammation and the risk for all-cause dementia and Alzheimer disease (Framingham). Arch Neurol 2012;69:594-600. doi:10.1001/archneurol.2011.670","verification_status":"approximate","notes":"In Framingham, higher adiponectin was associated with higher incident dementia and Alzheimer risk in women - another facet of the adiponectin paradox, likely reverse causation in pre-clinical decline. Per SD of log adiponectin; single cohort, low-confidence."},"frailty":{"hr":1.3,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of adiponectin, incident frailty in older adults","direction":"risk","ci_low":1,"ci_high":1.69,"hr_per_sd":1.1279,"hr_per_sd_ci":[1,1.2721],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"older-adult cohort","followup_years":6,"study":"Prospective cohorts of adiponectin and incident frailty in older adults.","study_type":"prospective-cohort","citation":"Cohort analyses of adiponectin and frailty in older adults (e.g. InCHIANTI, Cardiovascular Health Study).","verification_status":"unverified","notes":"Higher adiponectin has been associated with incident frailty in older adults, consistent with the paradox (high adiponectin marking catabolic/cachectic states). Tertile contrast converted to per-SD on the log scale; low-confidence, confounded by weight loss."}},"modifiability":{"intervention":"Weight loss, exercise, omega-3 and certain drugs (pioglitazone strongly raises adiponectin); smoking cessation.","effect_size":"Pioglitazone can double adiponectin; weight loss and exercise raise it 10-30%.","timeframe":"Weeks to months","evidence_type":"RCT meta-analysis","citation":"Thiazolidinedione RCTs and weight-loss/exercise meta-analyses of adiponectin.","rating":"moderate"}},{"id":"leptin","name":"Leptin","domain":"glucose_insulin","aliases":["LEP","OB protein"],"profile":{"mechanism":"Leptin is an adipocyte hormone signalling energy stores to the hypothalamus to regulate appetite and energy expenditure. In obesity leptin is high but the brain becomes leptin-resistant; elevated leptin marks adiposity and is linked to inflammation, insulin resistance and vascular risk.","measurement":{"method":"Immunoassay (ELISA/RIA) on serum or plasma; assays not fully harmonized; strongly sex- and fat-mass dependent.","sample_type":"venous blood","approx_cost_usd":"30-70"},"signal_quality":"moderate","signal_quality_note":"Stable analyte but values are dominated by fat mass and sex, strongly right-skewed, and the outcome association is U-shaped and heavily confounded by adiposity.","confounders":["fat mass dominates the signal","strong sex difference (higher in women)","right-skewed distribution","reverse causation: weight loss/cachexia lowers leptin","acute energy balance and sleep"],"testing_cadence":"baseline + as indicated"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"U-shaped association; both low (cachexia/illness) and high (obesity) leptin associate with higher mortality; no single monotone HR","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"non-monotonic U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"C","n":"pooled cohorts","followup_years":10,"study":"Prospective cohorts of leptin and all-cause mortality (mixed/U-shaped findings).","study_type":"prospective-cohort","citation":"Cohort analyses of leptin and mortality (conflicting; e.g. cardiovascular and ageing cohorts, ~2000s-2010s).","verification_status":"unverified","notes":"Leptin-mortality associations are inconsistent and broadly U-shaped: low leptin marks cachexia and illness, high leptin marks obesity-related risk, and adjusting for fat mass often nullifies or reverses the association. No meaningful linear per-SD HR; flagged categorical/non-monotonic.","qualitative":true},"cvd":{"hr":1.2,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD of log leptin, cardiovascular events, before adjustment for adiposity","direction":"risk","ci_low":1.08,"ci_high":1.33,"hr_per_sd":1.2,"hr_per_sd_ci":[1.08,1.33],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":"pooled cohorts","followup_years":10,"study":"Meta-analysis/cohorts of leptin and cardiovascular disease.","study_type":"meta-analysis","citation":"Meta-analyses of leptin and cardiovascular disease risk (~2009-2015).","verification_status":"unverified","notes":"Higher leptin is associated with cardiovascular events, but the association is largely attenuated after adjustment for BMI/adiposity and is not supported as causal by Mendelian randomization. Per SD of log leptin; treat as an adiposity correlate."},"cancer":{"hr":1.22,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of leptin, obesity-related cancer risk, adjusted","direction":"risk","ci_low":1,"ci_high":1.49,"hr_per_sd":1.0814,"hr_per_sd_ci":[1,1.17],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"nested case-control / cohort","followup_years":9,"study":"Nested analyses of leptin and obesity-related cancers (e.g. colorectal, postmenopausal breast).","study_type":"prospective-cohort","citation":"Nested case-control analyses of leptin and cancer risk (e.g. EPIC, ~2004-2012).","verification_status":"unverified","notes":"Higher leptin is weakly and inconsistently associated with obesity-related cancers; effects largely reflect adiposity. Quartile contrast converted to per-SD on the log scale; low-confidence."},"dementia":{"hr":0.75,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD of log leptin, incident dementia/Alzheimer disease (inverse association in some cohorts)","direction":"protective","ci_low":0.59,"ci_high":0.95,"hr_per_sd":0.75,"hr_per_sd_ci":[0.59,0.95],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":785,"followup_years":8.3,"study":"Framingham Heart Study cohort of plasma leptin and incident dementia.","study_type":"prospective-cohort","citation":"Lieb W et al. Association of plasma leptin levels with incident Alzheimer disease and MRI measures of brain aging (Framingham). JAMA 2009;302:2565-2572. doi:10.1001/jama.2009.1836","verification_status":"approximate","notes":"In Framingham, higher leptin was associated with LOWER incident dementia/Alzheimer risk and larger brain volume, suggesting a neuroprotective role; later cohorts have been inconsistent and the finding may be confounded by reverse causation (weight loss precedes dementia). Per SD of log leptin; single-cohort, low-confidence."},"frailty":{"hr":1.25,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of leptin, incident frailty in older adults","direction":"risk","ci_low":0.98,"ci_high":1.59,"hr_per_sd":1.1078,"hr_per_sd_ci":[0.9908,1.237],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"older-adult cohort","followup_years":6,"study":"Prospective cohorts of leptin and incident frailty in older adults.","study_type":"prospective-cohort","citation":"Cohort analyses of leptin and frailty in older adults (e.g. Toledo Study of Healthy Ageing, InCHIANTI).","verification_status":"unverified","notes":"Leptin and frailty associations are inconsistent: high leptin (obesity, inflammation) and low leptin (sarcopenic weight loss) both appear in frailty, making the relationship complex. Tertile contrast converted to per-SD on the log scale; low-confidence."}},"modifiability":{"intervention":"Weight loss is the dominant lever; leptin falls roughly in proportion to fat-mass loss.","effect_size":"Substantial weight loss can lower leptin 40-60%; exercise contributes independently.","timeframe":"Weeks to months","evidence_type":"RCT meta-analysis","citation":"Weight-loss RCT meta-analyses reporting leptin change.","rating":"high"}},{"id":"leptin_adiponectin_ratio","name":"Leptin:adiponectin ratio","domain":"glucose_insulin","aliases":["LAR","L/A ratio"],"profile":{"mechanism":"The leptin:adiponectin ratio combines a marker of adiposity/leptin resistance (leptin) with an inverse marker of insulin sensitivity (adiponectin), giving an integrated index of adipose-tissue dysfunction. A high ratio reflects insulin resistance, atherogenic risk and inflammatory adipose tissue.","measurement":{"method":"Calculated from separately assayed leptin and adiponectin; inherits both assays' lack of harmonization.","sample_type":"venous blood","approx_cost_usd":"60-140"},"signal_quality":"moderate","signal_quality_note":"Combines two skewed, sex-dimorphic analytes; the ratio is a better insulin-resistance correlate than either alone but lacks standardized reference ranges and outcome validation.","confounders":["strong sex difference","right-skewed distribution","fat mass dominates leptin component","reverse causation via the adiponectin paradox","no harmonized assays or cutpoints"],"testing_cadence":"baseline + as indicated"},"outcomes":{"all_cause_mortality":{"hr":1.3,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of leptin:adiponectin ratio, all-cause mortality, adjusted","direction":"risk","ci_low":1,"ci_high":1.69,"hr_per_sd":1.1279,"hr_per_sd_ci":[1,1.2721],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"cohort (~1000-3000)","followup_years":10,"study":"Prospective cohorts of the leptin:adiponectin ratio and mortality.","study_type":"prospective-cohort","citation":"Cohort analyses of the leptin/adiponectin ratio and mortality (e.g. cardiovascular and ageing cohorts, ~2010s).","verification_status":"unverified","notes":"A higher leptin:adiponectin ratio is associated with higher mortality in some cohorts, but evidence is sparse and the two components carry opposing reverse-causation problems. Tertile contrast converted to per-SD on the log scale; low-confidence."},"cvd":{"hr":1.45,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of leptin:adiponectin ratio, cardiovascular events, adjusted","direction":"risk","ci_low":1.1,"ci_high":1.91,"hr_per_sd":1.1858,"hr_per_sd_ci":[1.0447,1.3456],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":"cohort (~1000-4000)","followup_years":8,"study":"Prospective cohorts of the leptin:adiponectin ratio and cardiovascular disease.","study_type":"prospective-cohort","citation":"Cohort analyses of the leptin/adiponectin ratio and cardiovascular events / carotid atherosclerosis (~2010s).","verification_status":"unverified","notes":"A higher leptin:adiponectin ratio is associated with cardiovascular events and subclinical atherosclerosis, and tracks insulin resistance better than either adipokine alone; evidence remains observational and limited. Tertile contrast converted to per-SD on the log scale."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Weight loss and exercise lower leptin and raise adiponectin, moving the ratio favourably; pioglitazone raises adiponectin.","effect_size":"Weight loss can lower the ratio substantially as leptin falls and adiponectin rises.","timeframe":"Weeks to months","evidence_type":"observational","citation":"Weight-loss and exercise studies reporting leptin:adiponectin ratio change.","rating":"high"}},{"id":"horvath_clock","name":"Horvath clock","domain":"bioage_clocks","aliases":["Horvath 2013 multi-tissue clock","DNAmAge","pan-tissue epigenetic clock","first-generation epigenetic clock"],"profile":{"mechanism":"Horvath's 2013 multi-tissue clock estimates age from methylation at 353 CpG sites and was trained purely to predict chronological age across tissues. Epigenetic age acceleration (the residual of clock age on calendar age) reflects deviation from expected methylation aging, but because the clock was not trained on any health outcome it captures mortality and disease risk only weakly. It is a first-generation clock.","measurement":{"method":"Genome-wide DNA methylation array (Illumina 450K/EPIC) on extracted DNA; age computed via the published 353-CpG elastic-net predictor, then residualized on chronological age.","sample_type":"venous blood","approx_cost_usd":"200-500"},"signal_quality":"moderate","signal_quality_note":"Array methylation is technically reproducible but the clock has appreciable technical noise at the individual-CpG level; test-retest reliability of age acceleration is only moderate, and batch effects and blood cell composition strongly influence estimates.","confounders":["blood cell type composition","array batch effects","smoking","DNA extraction method","tissue source"],"testing_cadence":"research use; if tracked, every 1-2 years (within-person change is slow relative to measurement noise)"},"outcomes":{"all_cause_mortality":{"hr":1.13,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher Horvath epigenetic age acceleration, all-cause mortality","direction":"risk","ci_low":1.04,"ci_high":1.22,"hr_per_sd":1.1439,"hr_per_sd_ci":[1.0441,1.2445],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5.5 (SD of Horvath epigenetic age acceleration ~5-6 years in population cohorts (Chen 2016 Aging; NHANES 1999-2002)); k = SD/unit = 1.1","conversion":{"unit_value":5,"population_sd":5.5,"sd_source":"SD of Horvath epigenetic age acceleration ~5-6 years in population cohorts (Chen 2016 Aging; NHANES 1999-2002)"},"evidence_tier":"A","n":2105,"followup_years":17.5,"study":"Faul / NHANES 1999-2002 epigenetic clock analysis; consistent with Chen 2016 13-cohort meta-analysis.","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. doi:10.1007/s11357-025-01604-x. PMID:39228731. See also Chen BH et al. Aging 2016;8:1844-1865. PMID:27690265.","verification_status":"verified","notes":"First-generation clock: predicts mortality only weakly. Chen 2016 13-cohort meta-analysis found Horvath age acceleration significant but the smallest effect of the clocks examined. In the TILDA cohort Horvath age acceleration was NOT significantly associated with mortality (HR ~1.0 per SD). The signal is real but modest and inconsistent across cohorts; far weaker than GrimAge or DunedinPACE."},"cvd":{"hr":1.18,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher Horvath epigenetic age acceleration, cardiovascular mortality","direction":"risk","ci_low":1.02,"ci_high":1.35,"hr_per_sd":1.1997,"hr_per_sd_ci":[1.022,1.3911],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5.5 (SD of Horvath epigenetic age acceleration ~5-6 years (NHANES 1999-2002)); k = SD/unit = 1.1","conversion":{"unit_value":5,"population_sd":5.5,"sd_source":"SD of Horvath epigenetic age acceleration ~5-6 years (NHANES 1999-2002)"},"evidence_tier":"B","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis (272 cardiovascular deaths).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731.","verification_status":"verified","notes":"Modest CVD-mortality signal in NHANES, weaker than GrimAge (HR 1.55 per 5 years). Effect attenuates with adjustment in several cohorts; causality unestablished."},"cancer":{"hr":1.13,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher Horvath epigenetic age acceleration, cancer mortality (directionally positive; CI spans or approaches null in some cohorts)","direction":"risk","ci_low":0.98,"ci_high":1.3,"hr_per_sd":1.1439,"hr_per_sd_ci":[0.978,1.3346],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5.5 (SD of Horvath epigenetic age acceleration ~5-6 years (NHANES 1999-2002)); k = SD/unit = 1.1","conversion":{"unit_value":5,"population_sd":5.5,"sd_source":"SD of Horvath epigenetic age acceleration ~5-6 years (NHANES 1999-2002)"},"evidence_tier":"C","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis (209 cancer deaths).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731.","verification_status":"approximate","notes":"Cancer-mortality association for Horvath is weak and inconsistent; some cohorts report a modest signal, others none. CI approximate; treat as Tier C. GrimAge is the only clock with a robust cancer-mortality signal."},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No consistent prospective incident-dementia HR for the Horvath clock identified.","study_type":"prospective-cohort","citation":"Multiple cohort analyses report null or inconsistent associations between first-generation clocks and incident dementia.","verification_status":"unverified","notes":"First-generation clocks (Horvath, Hannum) generally show no robust association with incident dementia after adjustment; second/third-generation clocks (PhenoAge, GrimAge, DunedinPACE) carry the dementia signal. Left null rather than report an unconfirmed estimate.","qualitative":true},"frailty":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher Horvath age acceleration, incident Frailty-Index-defined frailty (not statistically significant)","direction":"risk","ci_low":0.82,"ci_high":1.22,"hr_per_sd":1,"hr_per_sd_ci":[0.82,1.22],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":560,"followup_years":5.3,"study":"ASPREE sub-study, community-dwelling older Australians (106 incident frailty cases).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and the risk of frailty, and persistent ADL disability. Age Ageing 2024;53:afae127. doi:10.1093/ageing/afae127. PMID:38941117.","verification_status":"approximate","notes":"Well-powered null finding: in ASPREE only GrimAge and GrimAge2 predicted incident frailty; Horvath, Hannum, PhenoAge and DunedinPACE were NOT significant. HR/CI approximate (reported as non-significant). Recorded as a real null cell."}},"modifiability":{"intervention":"First-generation clock age acceleration is only weakly responsive to intervention; modest reductions reported with caloric restriction (CALERIE) and lifestyle programs, but Horvath specifically shows smaller and less consistent change than DunedinPACE.","effect_size":"Small: most RCTs show no significant change in Horvath age acceleration; a few report shifts of well under 1 year.","timeframe":"Months to years; change is slow and hard to distinguish from measurement noise.","evidence_type":"RCT","citation":"CALERIE caloric restriction trial (Waziry 2023, Nat Aging); lifestyle and diet RCTs with epigenetic clock substudies.","rating":"low"}},{"id":"hannum_clock","name":"Hannum clock","domain":"bioage_clocks","aliases":["Hannum 2013 clock","blood epigenetic clock","first-generation epigenetic clock"],"profile":{"mechanism":"The Hannum 2013 clock estimates age from 71 blood methylation sites and, like Horvath's, was trained only to predict chronological age. Its age acceleration captures mortality risk somewhat better than Horvath's but still far less than outcome-trained second/third-generation clocks. It is a first-generation clock.","measurement":{"method":"Genome-wide DNA methylation array (450K/EPIC) on blood DNA; age via the 71-CpG predictor, residualized on chronological age.","sample_type":"venous blood","approx_cost_usd":"200-500"},"signal_quality":"moderate","signal_quality_note":"Reproducible array chemistry but moderate test-retest reliability of age acceleration; sensitive to blood cell composition and batch effects.","confounders":["blood cell type composition","array batch effects","smoking","DNA extraction method"],"testing_cadence":"research use; if tracked, every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1.16,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher Hannum epigenetic age acceleration, all-cause mortality","direction":"risk","ci_low":1.07,"ci_high":1.27,"hr_per_sd":1.1531,"hr_per_sd_ci":[1.0671,1.2579],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4.8 (SD of Hannum epigenetic age acceleration ~4.5-5 years in population cohorts (NHANES 1999-2002; Chen 2016 Aging)); k = SD/unit = 0.96","conversion":{"unit_value":5,"population_sd":4.8,"sd_source":"SD of Hannum epigenetic age acceleration ~4.5-5 years in population cohorts (NHANES 1999-2002; Chen 2016 Aging)"},"evidence_tier":"A","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis; consistent with Chen 2016 13-cohort meta-analysis.","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731. See also Chen BH et al. Aging 2016;8:1844-1865. PMID:27690265.","verification_status":"verified","notes":"First-generation clock: a modest but consistent mortality signal, slightly stronger than Horvath, far weaker than GrimAge. In TILDA, Hannum age acceleration was NOT significant for mortality (HR ~0.9 per SD), illustrating cross-cohort inconsistency of first-generation clocks."},"cvd":{"hr":1.24,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher Hannum epigenetic age acceleration, cardiovascular mortality","direction":"risk","ci_low":1.07,"ci_high":1.44,"hr_per_sd":1.2294,"hr_per_sd_ci":[1.0671,1.4191],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4.8 (SD of Hannum epigenetic age acceleration ~4.5-5 years (NHANES 1999-2002)); k = SD/unit = 0.96","conversion":{"unit_value":5,"population_sd":4.8,"sd_source":"SD of Hannum epigenetic age acceleration ~4.5-5 years (NHANES 1999-2002)"},"evidence_tier":"B","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis (272 cardiovascular deaths).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731.","verification_status":"verified","notes":"Modest CVD-mortality signal, weaker than GrimAge (HR 1.55 per 5 years). Causality unestablished."},"cancer":{"hr":1.12,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher Hannum epigenetic age acceleration, cancer mortality (directionally positive; modest)","direction":"risk","ci_low":0.99,"ci_high":1.27,"hr_per_sd":1.1149,"hr_per_sd_ci":[0.9904,1.2579],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4.8 (SD of Hannum epigenetic age acceleration ~4.5-5 years (NHANES 1999-2002)); k = SD/unit = 0.96","conversion":{"unit_value":5,"population_sd":4.8,"sd_source":"SD of Hannum epigenetic age acceleration ~4.5-5 years (NHANES 1999-2002)"},"evidence_tier":"C","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis (209 cancer deaths).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731.","verification_status":"approximate","notes":"Weak, inconsistent cancer-mortality signal for first-generation clocks. CI approximate. Tier C."},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No consistent prospective incident-dementia HR for the Hannum clock identified.","study_type":"prospective-cohort","citation":"Cohort analyses generally report null or inconsistent associations between first-generation clocks and incident dementia.","verification_status":"unverified","notes":"As for Horvath, first-generation clocks show no robust incident-dementia association. Left null rather than report an unconfirmed estimate.","qualitative":true},"frailty":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher Hannum age acceleration, incident Frailty-Index-defined frailty (not statistically significant)","direction":"risk","ci_low":0.82,"ci_high":1.22,"hr_per_sd":1,"hr_per_sd_ci":[0.82,1.22],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":560,"followup_years":5.3,"study":"ASPREE sub-study, community-dwelling older Australians (106 incident frailty cases).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and the risk of frailty, and persistent ADL disability. Age Ageing 2024;53:afae127. PMID:38941117.","verification_status":"approximate","notes":"Well-powered null: Hannum age acceleration was NOT significant for incident frailty in ASPREE; only GrimAge/GrimAge2 were. HR/CI approximate. Recorded as a real null cell."}},"modifiability":{"intervention":"First-generation clock age acceleration shows little consistent response to intervention; small reductions reported in some caloric-restriction and lifestyle trials.","effect_size":"Small and inconsistent across RCTs; typically not statistically significant.","timeframe":"Months to years.","evidence_type":"RCT","citation":"CALERIE caloric restriction trial; lifestyle/diet RCTs with epigenetic clock substudies.","rating":"low"}},{"id":"phenoage_clock","name":"PhenoAge","domain":"bioage_clocks","aliases":["Levine PhenoAge","DNAm PhenoAge","second-generation epigenetic clock","phenotypic age clock"],"profile":{"mechanism":"PhenoAge is a second-generation epigenetic clock: methylation (513 CpGs) trained to predict a composite 'phenotypic age' derived from clinical chemistry and mortality (albumin, creatinine, glucose, CRP, white-cell measures, etc.). Because it was trained on a mortality-linked phenotype rather than chronological age alone, its age acceleration predicts mortality and disease substantially better than first-generation clocks.","measurement":{"method":"Genome-wide DNA methylation array (450K/EPIC) on blood DNA; age via the 513-CpG PhenoAge predictor, residualized on chronological age. (A separate blood-chemistry PhenoAge can be computed without methylation.)","sample_type":"venous blood","approx_cost_usd":"200-500"},"signal_quality":"moderate","signal_quality_note":"More outcome-relevant than first-generation clocks but still has measurable technical noise; test-retest reliability of age acceleration is moderate. Sensitive to blood cell composition and batch.","confounders":["blood cell type composition","array batch effects","acute inflammation/illness","smoking","DNA extraction method"],"testing_cadence":"research/consumer use; if tracked, every 1-2 years. Commercially available via TruDiagnostic TruAge and myDNAge."},"outcomes":{"all_cause_mortality":{"hr":1.13,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher PhenoAge epigenetic age acceleration, all-cause mortality","direction":"risk","ci_low":1.05,"ci_high":1.21,"hr_per_sd":1.1439,"hr_per_sd_ci":[1.0551,1.2333],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5.5 (SD of PhenoAge epigenetic age acceleration ~5-6 years in population cohorts (NHANES 1999-2002; Levine 2018 Aging)); k = SD/unit = 1.1","conversion":{"unit_value":5,"population_sd":5.5,"sd_source":"SD of PhenoAge epigenetic age acceleration ~5-6 years in population cohorts (NHANES 1999-2002; Levine 2018 Aging)"},"evidence_tier":"A","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis; PhenoAge originally validated across multiple cohorts (Levine 2018).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731. Original: Levine ME et al. Aging 2018;10:573-591. doi:10.18632/aging.101414.","verification_status":"verified","notes":"Second-generation clock: outperforms Horvath/Hannum in original validation, but in NHANES the per-5-year HR (1.13) was similar to first-generation clocks and well below GrimAge (1.50). PhenoAge is intermediate: clearly stronger than first-generation clocks in some cohorts, but the mortality signal is not as robust as GrimAge or DunedinPACE."},"cvd":{"hr":1.15,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher PhenoAge epigenetic age acceleration, cardiovascular mortality / incident CVD (approximate)","direction":"risk","ci_low":1,"ci_high":1.33,"hr_per_sd":1.1662,"hr_per_sd_ci":[1,1.3685],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5.5 (SD of PhenoAge epigenetic age acceleration ~5-6 years (NHANES 1999-2002)); k = SD/unit = 1.1","conversion":{"unit_value":5,"population_sd":5.5,"sd_source":"SD of PhenoAge epigenetic age acceleration ~5-6 years (NHANES 1999-2002)"},"evidence_tier":"B","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 and pooled epigenetic clock analyses of cardiovascular outcomes.","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731; epigenetic clocks and incident cardiovascular outcomes, MESA (PMID:41368835).","verification_status":"approximate","notes":"Modest CVD signal; attenuates with adjustment for traditional risk factors in several cohorts. GrimAge consistently outperforms PhenoAge for CVD prediction. CI approximate."},"cancer":{"hr":1.1,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher PhenoAge epigenetic age acceleration, cancer mortality (approximate, modest)","direction":"risk","ci_low":0.96,"ci_high":1.27,"hr_per_sd":1.1105,"hr_per_sd_ci":[0.9561,1.3007],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5.5 (SD of PhenoAge epigenetic age acceleration ~5-6 years (NHANES 1999-2002)); k = SD/unit = 1.1","conversion":{"unit_value":5,"population_sd":5.5,"sd_source":"SD of PhenoAge epigenetic age acceleration ~5-6 years (NHANES 1999-2002)"},"evidence_tier":"C","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis (209 cancer deaths).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731.","verification_status":"approximate","notes":"Weak/modest cancer-mortality signal for PhenoAge; CI approximate and may span the null. Tier C. GrimAge has the most robust cancer signal of the clocks."},"dementia":{"hr":1.145,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest quartile of PhenoAge acceleration (PhenoAgeAccel), incident all-cause dementia","direction":"risk","ci_low":1.05,"ci_high":1.249,"hr_per_sd":1.0548,"hr_per_sd_ci":[1.0194,1.0915],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":"~300000","followup_years":13,"study":"UK Biobank prospective analysis of accelerated biological aging and incident dementia.","study_type":"prospective-cohort","citation":"Associations of combined accelerated biological aging and genetic susceptibility with incident dementia: a prospective study in the UK Biobank. PMC11443929.","verification_status":"approximate","notes":"Modest but significant dementia association (Q4 vs Q1 HR 1.145). Second-generation clocks show clearer dementia signals than first-generation clocks, but the effect per SD is small. Exact N for the dementia analysis not confirmed; approximate."},"frailty":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher PhenoAge age acceleration, incident Frailty-Index-defined frailty (not statistically significant)","direction":"risk","ci_low":0.82,"ci_high":1.22,"hr_per_sd":1,"hr_per_sd_ci":[0.82,1.22],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":560,"followup_years":5.3,"study":"ASPREE sub-study, community-dwelling older Australians (106 incident frailty cases).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and the risk of frailty, and persistent ADL disability. Age Ageing 2024;53:afae127. PMID:38941117.","verification_status":"approximate","notes":"Well-powered null: PhenoAge acceleration was NOT significant for incident frailty in ASPREE; only GrimAge/GrimAge2 were. Some cross-sectional and FI-slope analyses do link PhenoAge to frailty, but the prospective incident-frailty HR is null here. HR/CI approximate; recorded as a real null cell."}},"modifiability":{"intervention":"PhenoAge acceleration is modestly responsive to lifestyle intervention; caloric restriction (CALERIE) and some diet/exercise programs slow it, and methylation-PhenoAge change tracks improvements in the underlying clinical-chemistry phenotype.","effect_size":"Modest: RCTs report reductions on the order of ~1 year of age acceleration, though not always statistically robust.","timeframe":"Months to a few years.","evidence_type":"RCT","citation":"Waziry R et al. Effect of caloric restriction on epigenetic aging (CALERIE). Nat Aging 2023;3:248-257; diet/lifestyle RCTs with PhenoAge substudies.","rating":"moderate"}},{"id":"grimage_clock","name":"GrimAge / GrimAge2","domain":"bioage_clocks","aliases":["DNAm GrimAge","GrimAge2","GrimAgeV2","third-generation epigenetic clock","mortality-trained epigenetic clock"],"profile":{"mechanism":"GrimAge is a third-generation epigenetic clock built in two stages: methylation surrogates of seven plasma proteins and smoking pack-years are first estimated, then combined in a model trained directly on time-to-death. This mortality-trained design makes GrimAge (and the refined GrimAge2) the strongest epigenetic predictor of mortality and age-related disease, consistently outperforming first- and second-generation clocks.","measurement":{"method":"Genome-wide DNA methylation array (450K/EPIC) on blood DNA; GrimAge computed from DNAm surrogate-protein and smoking components, then residualized on chronological age.","sample_type":"venous blood","approx_cost_usd":"200-500"},"signal_quality":"moderate","signal_quality_note":"Best-validated of the epigenetic clocks for outcome prediction; test-retest reliability of GrimAge age acceleration is good relative to other clocks. Still affected by blood cell composition, batch effects, and (by design) heavily influenced by smoking surrogates.","confounders":["smoking (built into the clock)","blood cell type composition","array batch effects","DNA extraction method"],"testing_cadence":"research/consumer use; if tracked, every 1-2 years. Commercially available via TruDiagnostic TruAge (GrimAge2) and other providers."},"outcomes":{"all_cause_mortality":{"hr":1.5,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher GrimAge epigenetic age acceleration, all-cause mortality","direction":"risk","ci_low":1.32,"ci_high":1.71,"hr_per_sd":1.5,"hr_per_sd_ci":[1.32,1.71],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5 (SD of GrimAge epigenetic age acceleration ~5 years in population cohorts (NHANES 1999-2002; Lu 2019 Aging)); k = SD/unit = 1","conversion":{"unit_value":5,"population_sd":5,"sd_source":"SD of GrimAge epigenetic age acceleration ~5 years in population cohorts (NHANES 1999-2002; Lu 2019 Aging)"},"evidence_tier":"A","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis; corroborated by large retrospective cohort (GrimAge2 HR 1.54 per SD) and TILDA.","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731. Original: Lu AT et al. DNAm GrimAge strongly predicts lifespan and healthspan. Aging 2019;11:303-327. PMID:30669119.","verification_status":"verified","notes":"Strongest mortality evidence of any clock. NHANES per-5-year HR 1.50 (~per-SD given SD~5y). GrimAge2 retrospective cohort HR 1.54 per SD (1.46-1.62). TILDA per-SD HR 2.05 minimally adjusted, 1.91 fully adjusted -- effect SURVIVES adjustment for smoking, BMI, SES and activity, unlike first-generation clocks. This is the headline result the domain should anchor on; first-generation clocks predict mortality far more weakly."},"cvd":{"hr":1.55,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher GrimAge epigenetic age acceleration, cardiovascular mortality","direction":"risk","ci_low":1.29,"ci_high":1.86,"hr_per_sd":1.55,"hr_per_sd_ci":[1.29,1.86],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5 (SD of GrimAge epigenetic age acceleration ~5 years (NHANES 1999-2002)); k = SD/unit = 1","conversion":{"unit_value":5,"population_sd":5,"sd_source":"SD of GrimAge epigenetic age acceleration ~5 years (NHANES 1999-2002)"},"evidence_tier":"A","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis (272 cardiovascular deaths); corroborated by MESA incident-CVD analysis.","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731; Epigenetic aging clocks and incident cardiovascular outcomes, MESA (PMID:41368835).","verification_status":"verified","notes":"Strongest CVD-mortality signal of the clocks. Largely retains significance after adjustment. Note: much of the signal is mediated by GrimAge's smoking surrogate component, so part of the 'CVD prediction' is recapitulated smoking risk rather than a novel epigenetic axis."},"cancer":{"hr":1.37,"hr_metric":"per_unit","hr_unit_detail":"per 5-year higher GrimAge epigenetic age acceleration, cancer mortality","direction":"risk","ci_low":1,"ci_high":1.87,"hr_per_sd":1.37,"hr_per_sd_ci":[1,1.87],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 5 (SD of GrimAge epigenetic age acceleration ~5 years (NHANES 1999-2002)); k = SD/unit = 1","conversion":{"unit_value":5,"population_sd":5,"sd_source":"SD of GrimAge epigenetic age acceleration ~5 years (NHANES 1999-2002)"},"evidence_tier":"B","n":2105,"followup_years":17.5,"study":"NHANES 1999-2002 epigenetic clock analysis (209 cancer deaths); GrimAge originally validated for time-to-cancer (Lu 2019).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and mortality risk prediction in US adults. GeroScience 2025. PMID:39228731. Lu AT et al. Aging 2019;11:303-327. PMID:30669119.","verification_status":"verified","notes":"GrimAge is the only clock with a robust cancer signal, largely because it was trained on smoking pack-years -- so its cancer prediction is heavily driven by smoking history rather than a distinct epigenetic cancer mechanism. Mendelian randomization supports a causal link to colorectal cancer (OR 1.12 per year) but NOT lung cancer (OR 1.00). NHANES cancer-mortality CI reaches 1.0."},"dementia":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher GrimAge age acceleration, incident dementia (approximate; pooled from cohort analyses)","direction":"risk","ci_low":1.1,"ci_high":1.55,"hr_per_sd":1.3,"hr_per_sd_ci":[1.1,1.55],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~2300","followup_years":14,"study":"Framingham Heart Study Offspring Cohort and replication analyses linking GrimAge acceleration to incident dementia.","study_type":"prospective-cohort","citation":"Sugden K et al. Association of pace of aging measured by blood-based DNA methylation with age-related cognitive impairment and dementia. Neurology 2022;99:e1402-e1413. PMC9576288; Framingham GrimAge cognitive analyses.","verification_status":"approximate","notes":"GrimAge acceleration predicts incident dementia and cognitive decline in Framingham, similar in magnitude to DunedinPACE (HR ~1.27 per SD). HR/CI approximate -- pooled/representative across analyses, not a single confirmed meta-analytic estimate. Third-generation clocks carry the dementia signal; first-generation clocks do not."},"frailty":{"hr":1.43,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher GrimAge age acceleration, incident Frailty-Index-defined frailty","direction":"risk","ci_low":1.13,"ci_high":1.81,"hr_per_sd":1.43,"hr_per_sd_ci":[1.13,1.81],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":560,"followup_years":5.3,"study":"ASPREE sub-study, community-dwelling older Australians (106 incident frailty cases).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and the risk of frailty, and persistent ADL disability. Age Ageing 2024;53:afae127. doi:10.1093/ageing/afae127. PMID:38941117.","verification_status":"verified","notes":"GrimAge (HR 1.43) and GrimAge2 (HR 1.39) were the ONLY clocks significantly associated with incident frailty in ASPREE; Horvath, Hannum, PhenoAge and DunedinPACE were not. No association with persistent ADL disability for any clock. Single mid-sized cohort -- Tier B."}},"modifiability":{"intervention":"GrimAge acceleration responds to smoking cessation (its biggest lever, by design) and modestly to lifestyle and weight-loss interventions; some supplement and multi-component trials report small reductions.","effect_size":"Smoking cessation produces meaningful reductions over years; lifestyle interventions yield small effects (under ~1 year of age acceleration) in RCTs.","timeframe":"Months to years; smoking-driven component changes slowly after cessation.","evidence_type":"RCT","citation":"CALERIE (Waziry 2023, Nat Aging); lifestyle/diet RCTs with GrimAge substudies; observational smoking-cessation data.","rating":"moderate"}},{"id":"dunedinpace_clock","name":"DunedinPACE","domain":"bioage_clocks","aliases":["DunedinPoAm","Pace of Aging Computed from the Epigenome","rate-of-aging clock","third-generation epigenetic clock"],"profile":{"mechanism":"DunedinPACE is a third-generation epigenetic clock trained not on chronological age but on the longitudinal RATE of decline across 19 organ-system biomarkers measured repeatedly in the Dunedin birth cohort. It estimates the current pace of biological aging (1.0 = one year of biological aging per calendar year). Its rate-based design makes it sensitive to recent and modifiable changes, and it carries among the strongest mortality and disease evidence of any clock.","measurement":{"method":"Genome-wide DNA methylation array (EPIC) on blood DNA; pace computed from the published DunedinPACE algorithm (a single-time-point estimate of the rate of aging).","sample_type":"venous blood","approx_cost_usd":"200-500"},"signal_quality":"moderate","signal_quality_note":"Highest test-retest reliability of the major epigenetic clocks (designed for reliability), but still subject to array technical noise, blood cell composition, and batch effects. Being a rate measure, it is more responsive to recent exposures than age-trained clocks.","confounders":["blood cell type composition","array batch effects","smoking","obesity","DNA extraction method"],"testing_cadence":"research/consumer use; can be tracked more frequently than age-trained clocks (e.g. every 6-12 months) because it captures current pace. Commercially available via TruDiagnostic TruAge."},"outcomes":{"all_cause_mortality":{"hr":1.65,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD faster DunedinPACE, all-cause mortality","direction":"risk","ci_low":1.51,"ci_high":1.79,"hr_per_sd":1.65,"hr_per_sd_ci":[1.51,1.79],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":2471,"followup_years":14,"study":"Framingham Heart Study Offspring Cohort; replicated in the Normative Aging Study (per-SD HR 1.26) and NHANES.","study_type":"prospective-cohort","citation":"Belsky DW et al. DunedinPACE, a DNA methylation biomarker of the pace of aging. eLife 2022;11:e73420. doi:10.7554/eLife.73420. PMID:35029144.","verification_status":"verified","notes":"Among the strongest mortality evidence of any clock. Framingham per-SD HR 1.65 (1.51-1.79); Normative Aging Study per-SD HR 1.26 (1.14-1.40); NHANES per-0.10-pace HR 1.23. The Framingham estimate is higher than NAS -- magnitude is cohort-dependent -- but the direction and significance replicate consistently. With GrimAge, DunedinPACE carries the strongest mortality evidence in the domain."},"cvd":{"hr":1.39,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD faster DunedinPACE, incident cardiovascular disease","direction":"risk","ci_low":1.26,"ci_high":1.54,"hr_per_sd":1.39,"hr_per_sd_ci":[1.26,1.54],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":2471,"followup_years":14,"study":"Framingham Heart Study Offspring Cohort; NHANES corroborates (per-0.10-pace cardiovascular-mortality HR 1.25).","study_type":"prospective-cohort","citation":"Belsky DW et al. DunedinPACE, a DNA methylation biomarker of the pace of aging. eLife 2022;11:e73420. PMID:35029144.","verification_status":"verified","notes":"Faster DunedinPACE predicts incident CVD (HR 1.39 per SD) and stroke/TIA (HR 1.37). Robust prospective association; less smoking-dependent than GrimAge. Causality not established."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No well-powered prospective incident-cancer or cancer-mortality HR for DunedinPACE with confirmed CI identified.","study_type":"prospective-cohort","citation":"DunedinPACE validation papers focus on all-cause mortality, chronic disease, disability and cognition; cancer-specific HRs are not a primary reported endpoint.","verification_status":"unverified","notes":"Honest emptiness: unlike GrimAge (smoking-trained, robust cancer signal), DunedinPACE has no well-characterized cancer-specific HR with a confirmable CI. Some cohort analyses note associations with chronic-disease morbidity that includes cancer, but no convertible cancer-specific estimate was found. Left null rather than invent one.","qualitative":true},"dementia":{"hr":1.27,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD faster DunedinPACE, incident dementia","direction":"risk","ci_low":1.07,"ci_high":1.49,"hr_per_sd":1.27,"hr_per_sd_ci":[1.07,1.49],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":2264,"followup_years":14,"study":"Framingham Heart Study Offspring Cohort, longitudinal incident-dementia analysis.","study_type":"prospective-cohort","citation":"Sugden K et al. Association of pace of aging measured by blood-based DNA methylation with age-related cognitive impairment and dementia. Neurology 2022;99:e1402-e1413. PMC9576288.","verification_status":"verified","notes":"Faster DunedinPACE predicts incident dementia (HR 1.27 per SD, 1.07-1.49) in Framingham; the DunedinPACE-cognitive-decline link explained roughly a quarter of dementia risk. Single large cohort -- Tier B. Consistent with GrimAge dementia signal."},"frailty":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD faster DunedinPACE, incident Frailty-Index-defined frailty (not statistically significant in ASPREE)","direction":"risk","ci_low":0.82,"ci_high":1.22,"hr_per_sd":1,"hr_per_sd_ci":[0.82,1.22],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":560,"followup_years":5.3,"study":"ASPREE sub-study, community-dwelling older Australians (106 incident frailty cases).","study_type":"prospective-cohort","citation":"Epigenetic age acceleration and the risk of frailty, and persistent ADL disability. Age Ageing 2024;53:afae127. PMID:38941117.","verification_status":"approximate","notes":"Nuanced: in ASPREE, DunedinPACE was NOT significant for INCIDENT FI-defined frailty (only GrimAge/GrimAge2 were), yet DunedinPACE WAS associated with worsening continuous Frailty-Index and Fried-frailty scores over time, especially in women, and longitudinal data suggest DunedinPACE change PRECEDES frailty change. The incident-frailty HR cell is recorded as a real null; the continuous-trajectory signal is described here. HR/CI approximate."}},"modifiability":{"intervention":"As a rate measure, DunedinPACE is the most intervention-responsive clock: caloric restriction (CALERIE) significantly slowed DunedinPACE, and diet, exercise and weight-loss programs show measurable slowing.","effect_size":"CALERIE: ~2-3% slowing of DunedinPACE with sustained ~12% caloric restriction; lifestyle programs report similar small-to-moderate slowing.","timeframe":"Months to ~2 years.","evidence_type":"RCT","citation":"Waziry R et al. Effect of long-term caloric restriction on DNA methylation measures of biological aging (CALERIE). Nat Aging 2023;3:248-257. doi:10.1038/s43587-022-00357-y.","rating":"moderate"}},{"id":"telomere_length","name":"Telomere length","domain":"bioage_clocks","aliases":["leukocyte telomere length","LTL","TL"],"profile":{"mechanism":"Telomeres are repetitive DNA caps that shorten with each cell division and with oxidative/inflammatory stress; leukocyte telomere length is a marker of replicative history and cumulative cellular stress. Shorter telomeres are associated with higher mortality and age-related disease, but telomere length is a weak, noisy individual-level predictor and is upstream of many confounded exposures.","measurement":{"method":"Most commonly qPCR (telomere-to-single-copy-gene ratio); also Southern blot (terminal restriction fragment) and flow-FISH. Methods are not interchangeable and qPCR has high measurement error.","sample_type":"venous blood","approx_cost_usd":"100-300"},"signal_quality":"noisy","signal_quality_note":"qPCR telomere measurement has substantial within-method coefficient of variation and poor agreement across labs and platforms; a large fraction of measured between-person variance is technical. This noise attenuates HRs and is the central epistemic caveat for this biomarker.","confounders":["measurement platform / lab (major)","blood cell composition","age","sex","smoking","obesity","chronic inflammation","reverse causation from prevalent disease"],"testing_cadence":"research/consumer use; not recommended for repeat clinical tracking given measurement noise. Commercially offered by some longevity testing companies."},"outcomes":{"all_cause_mortality":{"hr":1.09,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD shorter leukocyte telomere length, all-cause mortality","direction":"risk","ci_low":1.06,"ci_high":1.13,"hr_per_sd":1.09,"hr_per_sd_ci":[1.06,1.13],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":121749,"followup_years":12,"study":"Wang 2018 meta-analysis of 25 prospective studies (21,763 deaths).","study_type":"meta-analysis","citation":"Wang Q et al. Telomere length and all-cause mortality: a meta-analysis. Ageing Res Rev 2018;48:11-20. doi:10.1016/j.arr.2018.09.002. PMID:30254001.","verification_status":"verified","notes":"Meta-analytic per-SD HR 1.09 (1.06-1.13); shortest vs longest quartile HR ~1.26. The association is real but small and heavily attenuated by measurement noise -- per-SD effect is far weaker than GrimAge or DunedinPACE. Heterogeneity across studies is high; some large cohorts find weaker or null effects after adjustment."},"cvd":{"hr":1.54,"hr_metric":"tertile","hr_unit_detail":"shortest vs longest tertile of leukocyte telomere length, incident coronary heart disease","direction":"risk","ci_low":1.3,"ci_high":1.83,"hr_per_sd":1.219,"hr_per_sd_ci":[1.1279,1.3194],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"A","n":43725,"followup_years":11,"study":"Haycock 2014 meta-analysis of 24 studies of telomere length and coronary heart disease.","study_type":"meta-analysis","citation":"Haycock PC et al. Leucocyte telomere length and risk of cardiovascular disease: systematic review and meta-analysis. BMJ 2014;349:g4227. doi:10.1136/bmj.g4227. PMID:25006006.","verification_status":"verified","notes":"Pooled RR ~1.54 (shortest vs longest tertile) for coronary heart disease. Mendelian randomization gives mixed signals -- some MR supports a causal protective effect of longer telomeres for CHD, but MR also links longer telomeres to HIGHER cancer risk, so telomere length is not a clean unidirectional longevity target."},"cancer":{"hr":1.1,"hr_metric":"quintile","hr_unit_detail":"shortest vs longest quintile of leukocyte telomere length, cancer mortality","direction":"risk","ci_low":0.88,"ci_high":1.37,"hr_per_sd":1.0346,"hr_per_sd_ci":[0.9554,1.119],"comparability":"converted","hr_per_sd_basis":"quintile contrast; k = 1/2.8 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":"~2 large cohorts","followup_years":12,"study":"Individual-participant-data meta-analysis of 2 large prospective cohorts (telomere length and cancer mortality).","study_type":"meta-analysis","citation":"Leukocyte telomere length and all-cause, cardiovascular disease, and cancer mortality: IPD meta-analysis of 2 large prospective cohorts. PMC5860628.","verification_status":"approximate","notes":"Cancer is the clearest cautionary case: SHORTER telomeres show only a weak, non-significant association with cancer MORTALITY (HR ~1.10, CI crosses 1.0), while Mendelian randomization consistently shows that genetically LONGER telomeres INCREASE risk of several cancers (melanoma, glioma, lung adenocarcinoma). The 'risk' direction here is for cancer mortality only and should not be read as 'longer telomeres are protective against cancer'. CI approximate."},"dementia":{"hr":1.14,"hr_metric":"tertile","hr_unit_detail":"shortest vs longest tertile of leukocyte telomere length, incident all-cause dementia","direction":"risk","ci_low":1.06,"ci_high":1.21,"hr_per_sd":1.0619,"hr_per_sd_ci":[1.0271,1.0914],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":435046,"followup_years":12.2,"study":"UK Biobank observational + Mendelian randomization analysis of mid-life leukocyte telomere length and dementia.","study_type":"prospective-cohort","citation":"Liu R et al. Mid-life leukocyte telomere length and dementia risk: an observational and Mendelian randomization study of 435,046 UK Biobank participants. Aging Cell 2023;22:e13808. doi:10.1111/acel.13808. PMID:37254630.","verification_status":"verified","notes":"Shorter telomeres associate with modestly higher incident dementia (lowest vs highest tertile HR 1.14; per-SD HR for longer telomeres ~0.93, i.e. protective). The effect is small. MR in the same study gave weaker/less consistent causal support, so this is largely an observational association."},"frailty":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD shorter leukocyte telomere length, incident/prevalent frailty (associations weak and inconsistent across studies)","direction":"risk","ci_low":0.9,"ci_high":1.12,"hr_per_sd":1,"hr_per_sd_ci":[0.9,1.12],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Multiple cross-sectional and prospective studies of telomere length and frailty, with conflicting results.","study_type":"prospective-cohort","citation":"Systematic reviews of telomere length and frailty (e.g. Araujo Carvalho AC et al. Telomere length and frailty in older adults: a systematic review and meta-analysis. Ageing Res Rev 2019).","verification_status":"unverified","notes":"Telomere length is only weakly and inconsistently associated with frailty; several systematic reviews find no robust relationship after adjustment. Recorded as an effectively null cell (HR ~1.0) with a wide CI; treat as Tier C and largely uninformative for frailty."}},"modifiability":{"intervention":"Telomere length is only modestly and inconsistently modifiable; some lifestyle programs (exercise, diet, stress reduction) and weight loss report attenuated shortening or small lengthening, but results are mixed and prone to measurement-noise artifacts.","effect_size":"Small and uncertain; many RCTs show no significant change. Apparent 'lengthening' is often within measurement error.","timeframe":"Years; telomere attrition is slow and hard to detect against assay noise.","evidence_type":"RCT","citation":"Lifestyle-intervention RCTs with telomere substudies (e.g. Ornish 2013 Lancet Oncol pilot); generally low-quality or underpowered evidence.","rating":"low"}},{"id":"glycanage","name":"GlycanAge","domain":"bioage_clocks","aliases":["glycan age","IgG glycan clock","IgG N-glycosylation age","glycomic age"],"comparability_tag":"Sparse outcomes","comparability_note":"GlycanAge has good cross-sectional disease associations but very limited prospective hazard-ratio evidence for hard outcomes; most cells are unverified or null because no convertible time-to-event HR with a CI was found.","profile":{"mechanism":"GlycanAge is a biological-age estimate derived from the N-glycans attached to immunoglobulin G (IgG). IgG glycosylation acts as a functional switch between pro- and anti-inflammatory antibody activity; an age-related shift toward pro-inflammatory (agalactosylated) glycoforms ('inflammaging') underlies the clock. GlycanAge therefore indexes chronic low-grade inflammation rather than a cell-division or methylation process.","measurement":{"method":"Chromatographic or mass-spectrometric profiling of IgG N-glycans (e.g. UHPLC after glycan release); age computed from the relative abundance of glycan structures via the GlycanAge algorithm.","sample_type":"capillary blood","approx_cost_usd":"300-600"},"signal_quality":"moderate","signal_quality_note":"IgG glycan profiling is analytically reproducible, but the GlycanAge index has a large age-prediction error (~9-10 years) and is strongly influenced by sex, hormones and acute inflammation; it explains roughly 60% of chronological-age variance.","confounders":["acute infection / inflammation","sex and sex hormones (estrogen)","BMI / adiposity","smoking","autoimmune disease"],"testing_cadence":"consumer/wellness use; tracked every 6-12 months. Commercially available as the GlycanAge test."},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No well-powered prospective study reporting an all-cause mortality hazard ratio per SD for GlycanAge was identified.","study_type":"prospective-cohort","citation":"GlycanAge and IgG glycan studies report cross-sectional age and disease associations and AUC improvements over chronological age, not prospective mortality HRs.","verification_status":"unverified","notes":"Honest emptiness: GlycanAge is marketed as a longevity clock, but the published evidence for hard mortality outcomes is thin -- mostly cross-sectional disease associations and AUC comparisons. No convertible prospective per-SD mortality HR with a CI was found. Left null rather than overstate the evidence; this is a key over-selling caveat for the domain.","qualitative":true},"cvd":{"hr":2.22,"hr_metric":"categorical","hr_unit_detail":"excess IgG glycan/cardiovascular age (>3 years above calendar age) vs not, adjusted odds ratio for high cardiovascular risk (cross-sectional)","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"IgG N-glycosylation cardiovascular-age study (cross-sectional case-control of cardiovascular risk).","study_type":"prospective-cohort","citation":"IgG N-Glycosylation Cardiovascular Age Tracks Cardiovascular Risk Beyond Calendar Age. Engineering 2023. doi:10.1016/j.eng.2022.12.004.","verification_status":"approximate","notes":"Cross-sectional: people with glycan/cardiovascular age >3 years above calendar age had higher odds of high cardiovascular risk (adjusted OR ~2.22) and of prevalent CVD (~2.71); AUC improved modestly over calendar age. This is an ODDS RATIO for a categorical contrast in a cross-sectional design, NOT a prospective per-SD hazard ratio -- categorical, no CI confirmed, not comparable. Treat as suggestive only."},"cancer":null,"dementia":null,"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective frailty hazard-ratio evidence for GlycanAge identified.","study_type":"prospective-cohort","citation":"IgG glycan profiles correlate cross-sectionally with frailty-related inflammatory phenotypes but no incident-frailty HR was found.","verification_status":"unverified","notes":"Honest emptiness: IgG glycosylation tracks inflammaging and correlates with frailty-related phenotypes cross-sectionally, but no prospective incident-frailty HR with a CI was found. Left null.","qualitative":true}},"modifiability":{"intervention":"GlycanAge is among the more intervention-responsive biological-age measures: substantial weight loss markedly shifts IgG glycosylation toward a younger profile, and estrogen/hormone therapy and lifestyle change also move the index.","effect_size":"Large in some studies: extensive weight loss (bariatric surgery) produced multi-year reductions in GlycanAge; hormone therapy and lifestyle programs show smaller shifts.","timeframe":"Months.","evidence_type":"observational","citation":"Greto VL et al. Extensive weight loss reduces glycan age by altering IgG N-glycosylation. Int J Obes 2021;45:1521-1531. PMID:33941843; estradiol/GlycanAge studies (PMC7732334).","rating":"moderate"}},{"id":"proteomic_age_clock","name":"Proteomic age clocks","domain":"bioage_clocks","aliases":["ProtAge","proteomic aging clock","plasma proteomic clock","protein age gap","organ-specific proteomic clocks"],"profile":{"mechanism":"Proteomic age clocks estimate biological age from hundreds to thousands of plasma proteins (e.g. Olink or SomaScan panels) using machine-learning models trained to predict chronological age. The 'proteomic age gap' (predicted minus chronological age) reflects deviation of the circulating proteome from age norms and captures multi-organ aging; organ-specific variants estimate the age of individual organ systems (brain, heart, kidney, immune).","measurement":{"method":"High-throughput plasma proteomics (Olink Explore or SomaScan aptamer panels), then a published proteomic-age model; the age gap is the residual on chronological age.","sample_type":"venous blood","approx_cost_usd":"300-1000"},"signal_quality":"moderate","signal_quality_note":"Proteomic platforms are reproducible but the clocks are new, model- and platform-specific, and not yet standardized across studies; cross-platform and cross-cohort comparability is unestablished. Age prediction is accurate (r~0.94) but outcome validation is shallower than for epigenetic clocks.","confounders":["proteomics platform (Olink vs SomaScan)","acute illness / inflammation","kidney function","BMI","model-specific protein selection","fasting status"],"testing_cadence":"research use; not yet a consumer product. If tracked, every 1-2 years."},"outcomes":{"all_cause_mortality":{"hr":1.6,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher proteomic age gap (ProtAgeGap), all-cause mortality (approximate)","direction":"risk","ci_low":1.5,"ci_high":1.7,"hr_per_sd":1.6,"hr_per_sd_ci":[1.5,1.7],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":45441,"followup_years":13.3,"study":"UK Biobank proteomic aging clock (ProtAge), 204-protein model; validated in China Kadoorie and Finnish cohorts.","study_type":"prospective-cohort","citation":"Argentieri MA et al. Proteomic aging clock predicts mortality and risk of common age-related diseases in diverse populations. Nat Med 2024;30:2450-2460. doi:10.1038/s41591-024-03164-7. PMID:39117878.","verification_status":"approximate","notes":"Proteomic age gap is a strong mortality predictor in UK Biobank, comparable to GrimAge/DunedinPACE in magnitude, and replicates in Chinese and Finnish cohorts. HR/CI approximate -- the exact per-SD all-cause-mortality HR and CI were not confirmed against the full text. Newer marker: fewer independent cohorts, no standardized model across platforms -- Tier B and honestly less mature than epigenetic clocks."},"cvd":{"hr":1.5,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher proteomic age gap, incident cardiovascular / heart disease (approximate)","direction":"risk","ci_low":1.35,"ci_high":1.65,"hr_per_sd":1.5,"hr_per_sd_ci":[1.35,1.65],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":45441,"followup_years":13.3,"study":"UK Biobank proteomic aging clock (ProtAge); proteomic age gap associated with incidence of 18 major chronic diseases including heart disease.","study_type":"prospective-cohort","citation":"Argentieri MA et al. Proteomic aging clock predicts mortality and risk of common age-related diseases in diverse populations. Nat Med 2024;30:2450-2460. PMID:39117878.","verification_status":"approximate","notes":"Proteomic age gap predicts incident heart disease among the 18 chronic diseases assessed. Organ-specific proteomic clocks (heart age) sharpen cardiovascular prediction. HR/CI approximate -- exact figure not confirmed against full text. Tier B; newer marker."},"cancer":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher proteomic age gap, incident cancer (approximate; weaker than for cardiometabolic/neurodegenerative outcomes)","direction":"risk","ci_low":1.1,"ci_high":1.32,"hr_per_sd":1.2,"hr_per_sd_ci":[1.1,1.32],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":45441,"followup_years":13.3,"study":"UK Biobank proteomic aging clock (ProtAge); cancer among the 18 chronic diseases assessed.","study_type":"prospective-cohort","citation":"Argentieri MA et al. Proteomic aging clock predicts mortality and risk of common age-related diseases in diverse populations. Nat Med 2024;30:2450-2460. PMID:39117878.","verification_status":"approximate","notes":"Proteomic age gap predicts incident cancer, but the association is generally weaker and more heterogeneous than for cardiometabolic, lung, kidney and neurodegenerative outcomes. HR/CI approximate and not confirmed against full text -- Tier C."},"dementia":{"hr":1.6,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher proteomic age gap (or organ-specific brain age gap), incident all-cause dementia (approximate)","direction":"risk","ci_low":1.4,"ci_high":1.85,"hr_per_sd":1.6,"hr_per_sd_ci":[1.4,1.85],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":45441,"followup_years":13.3,"study":"UK Biobank proteomic aging clock and organ-specific proteomic clocks; brain proteomic age gap most strongly predicts neurodegenerative disease.","study_type":"prospective-cohort","citation":"Argentieri MA et al. Nat Med 2024;30:2450-2460. PMID:39117878; Organ-specific proteomic aging clocks predict disease and longevity (Nat Aging 2025; brain age gap predicts dementia).","verification_status":"approximate","notes":"Dementia is a relative strength of proteomic clocks: the brain-specific proteomic age gap shows the strongest association of any organ clock with incident neurodegenerative disease (an especially aged brain proteome conferred Alzheimer's risk roughly comparable to one APOE4 allele, HR ~3.1 in the organ-clock paper). The whole-body per-SD HR is more modest (~1.6); HR/CI approximate. Tier B."},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No well-powered prospective incident-frailty hazard ratio for proteomic age clocks with a confirmed CI identified.","study_type":"prospective-cohort","citation":"Proteomic clock papers report multimorbidity and disability associations; a specific incident-frailty HR was not located.","verification_status":"unverified","notes":"Honest emptiness: proteomic clocks predict multimorbidity and physical-function decline, and proteomic frailty signatures exist, but no convertible prospective incident-frailty HR with a CI was found for the proteomic AGE clock specifically. Left null; proteomic clocks are newer and their outcome-validation base is still shallow.","qualitative":true}},"modifiability":{"intervention":"Proteomic age gap is plausibly modifiable -- it tracks weight, fitness and metabolic health -- but dedicated intervention trials using a proteomic clock as the primary endpoint are largely lacking.","effect_size":"Not well quantified; cross-sectional data link healthier lifestyle to a younger proteomic age, but RCT change estimates are not established.","timeframe":"Unknown; presumably months to years.","evidence_type":"observational","citation":"Argentieri MA et al. Nat Med 2024 (lifestyle correlates of ProtAgeGap); no dedicated RCT with a proteomic clock as primary endpoint.","rating":"moderate"}},{"id":"cortisol_morning_serum","name":"Cortisol (morning serum)","domain":"hormonal","aliases":["AM cortisol","8am serum cortisol","basal cortisol"],"profile":{"mechanism":"Cortisol is the principal glucocorticoid output of the HPA axis. Chronically elevated cortisol drives visceral adiposity, insulin resistance, sarcopenia, immunosuppression, hippocampal atrophy and accelerated vascular aging; very low cortisol can reflect adrenal insufficiency. The aging HPA axis tends toward flatter, higher-set cortisol exposure.","measurement":{"method":"Morning (07:00-09:00) venous draw, immunoassay or LC-MS/MS; strongly time-of-day dependent so sampling must be standardized.","sample_type":"venous blood","approx_cost_usd":"15-50"},"signal_quality":"noisy","signal_quality_note":"Large diurnal and pulsatile variation, acute stress reactivity and venipuncture stress make a single morning value an imprecise index of chronic exposure.","confounders":["time of sampling","acute psychological/physical stress","exogenous glucocorticoids","oral estrogen/pregnancy (raises CBG)","shift work","depression","critical illness"],"testing_cadence":"baseline; repeat only if HPA pathology suspected"},"outcomes":{"all_cause_mortality":{"hr":1.31,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher morning serum cortisol, all-cause mortality, older-adult cohorts","direction":"risk","ci_low":1.18,"ci_high":1.45,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":21000,"followup_years":10,"study":"Pooled prospective cohorts of older adults relating basal cortisol to mortality (e.g. Rotterdam, InCHIANTI, Hertfordshire).","study_type":"pooled-cohort","citation":"Schoorlemmer RMM et al. Relationships between cortisol level, mortality and chronic diseases in older persons. Clin Endocrinol 2009;71:779-786. doi:10.1111/j.1365-2265.2009.03552.x","verification_status":"approximate","notes":"Higher basal cortisol predicts all-cause mortality in older adults, but the association is partly U-shaped and confounded by reverse causation (preclinical illness raises cortisol). Per-SD HR is an approximate pooled estimate; CI approximate.","hr_per_sd":1.31,"hr_per_sd_ci":[1.18,1.45]},"cvd":{"hr":1.18,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher morning/basal cortisol, cardiovascular mortality, general and older populations","direction":"risk","ci_low":1.06,"ci_high":1.31,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":18000,"followup_years":10,"study":"Whitehall II and other cohorts linking cortisol output to cardiovascular death.","study_type":"prospective-cohort","citation":"Vogelzangs N et al. Urinary cortisol and six-year risk of all-cause and cardiovascular mortality. J Clin Endocrinol Metab 2010;95:4959-4964. doi:10.1210/jc.2010-0192","verification_status":"approximate","notes":"Cortisol output (the cited study used 24-h urinary cortisol, a steadier exposure measure) predicts cardiovascular more strongly than non-cardiovascular death. Morning serum is a noisier surrogate; per-SD HR approximated to the morning-serum scale and CI is approximate.","hr_per_sd":1.18,"hr_per_sd_ci":[1.06,1.31]},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":"no consistent association of basal cortisol with cancer incidence/mortality","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable per-SD estimate; evidence sparse and inconsistent","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No adequately powered cohort isolates basal morning cortisol as a cancer predictor; flatter diurnal slope has been linked to cancer survival but not incidence.","study_type":"prospective-cohort","citation":"Sephton SE et al. Diurnal cortisol rhythm as a predictor of breast cancer survival. J Natl Cancer Inst 2000;92:994-1000. doi:10.1093/jnci/92.12.994","verification_status":"unverified","notes":"Evidence links a flattened diurnal slope to worse cancer survival, but no defensible per-SD HR for morning serum cortisol and cancer incidence exists. Left null.","qualitative":true},"dementia":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher morning/basal cortisol, incident dementia or accelerated cognitive decline","direction":"risk","ci_low":1.05,"ci_high":1.37,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":9000,"followup_years":8,"study":"Framingham Heart Study and other cohorts linking higher morning cortisol to lower brain volume and incident dementia.","study_type":"prospective-cohort","citation":"Echouffo-Tcheugui JB et al. Circulating cortisol and cognitive and structural brain measures: the Framingham Heart Study. Neurology 2018;91:e1961-e1970. doi:10.1212/WNL.0000000000006549","verification_status":"approximate","notes":"Higher cortisol associates with smaller brain volume and poorer cognition, especially in women; prospective dementia-incidence data are thinner. Per-SD HR approximate. Association, with plausible reverse causation (prodromal AD activates the HPA axis).","hr_per_sd":1.2,"hr_per_sd_ci":[1.05,1.37]},"frailty":{"hr":1.27,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher morning/basal cortisol, incident or prevalent frailty in older adults","direction":"risk","ci_low":1.1,"ci_high":1.47,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":4000,"followup_years":5,"study":"Cross-sectional and prospective studies of HPA-axis output and frailty phenotype in older adults.","study_type":"prospective-cohort","citation":"Johar H et al. Blunted diurnal cortisol pattern is associated with frailty: KORA-Age study. J Clin Endocrinol Metab 2014;99:E464-E468. doi:10.1210/jc.2013-3079","verification_status":"approximate","notes":"Higher and flatter cortisol exposure associates with the frailty phenotype, low muscle mass and slow gait. Evidence is mostly cross-sectional; per-SD HR is an approximate synthesis and direction of causation is uncertain.","hr_per_sd":1.27,"hr_per_sd_ci":[1.1,1.47]}},"modifiability":{"intervention":"Stress-reduction (mindfulness/MBSR, CBT), improved sleep, regular moderate exercise; treatment of overt Cushing's or adrenal insufficiency where present.","effect_size":"Mindfulness/relaxation programs lower cortisol output modestly (~10-25% in elevated groups); aerobic training normalizes diurnal slope.","timeframe":"8-12 weeks for measurable change","evidence_type":"RCT meta-analysis","citation":"Koncz A et al. and Pascoe MC et al. meta-analyses of mindfulness/relaxation interventions on cortisol.","rating":"moderate"}},{"id":"cortisol_diurnal_slope","name":"Cortisol diurnal slope (salivary)","domain":"hormonal","aliases":["diurnal cortisol slope","salivary cortisol rhythm","flattened slope"],"comparability_tag":"Non-standard","comparability_note":"Slope is a rate-of-change metric (units of cortisol per hour); a flatter slope is the risk direction and per-SD estimates vary widely by sampling protocol.","profile":{"mechanism":"The diurnal cortisol slope quantifies the normal decline from a morning peak to an evening trough. A flatter (less negative) slope reflects HPA-axis dysregulation and chronic stress load and is associated with inflammation, metabolic dysfunction and accelerated aging.","measurement":{"method":"Multiple same-day saliva samples (wake, +30-45 min, evening) by passive drool or swab; slope computed by regression across the day.","sample_type":"saliva","approx_cost_usd":"60-150"},"signal_quality":"moderate","signal_quality_note":"Captures rhythm rather than a single level, but depends on adherence to sampling times and is variable day-to-day; multi-day sampling improves reliability.","confounders":["sampling-time adherence","wake time/shift work","smoking","acute stress","exogenous glucocorticoids","oral contraceptives"],"testing_cadence":"baseline; repeat over 2-3 days for reliability"},"outcomes":{"all_cause_mortality":{"hr":1.31,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD flatter (less steep) diurnal cortisol slope, all-cause mortality","direction":"risk","ci_low":1.08,"ci_high":1.59,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":4047,"followup_years":6,"study":"Whitehall II cohort linking flatter diurnal cortisol slope to mortality.","study_type":"prospective-cohort","citation":"Kumari M et al. Cortisol secretion and fatigue: associations in a community based cohort; and Whitehall II diurnal slope-mortality analysis, J Clin Endocrinol Metab 2011;96:1478-1485. doi:10.1210/jc.2010-2137","verification_status":"approximate","notes":"A flatter diurnal slope predicted higher all-cause and cardiovascular mortality independent of morning level. Per-SD HR approximate; the metric is a rate, not a level, so cross-biomarker comparison is imperfect.","hr_per_sd":1.31,"hr_per_sd_ci":[1.08,1.59]},"cvd":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD flatter diurnal cortisol slope, cardiovascular mortality","direction":"risk","ci_low":1.03,"ci_high":1.64,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":4047,"followup_years":6,"study":"Whitehall II diurnal cortisol slope and cause-specific mortality.","study_type":"prospective-cohort","citation":"Whitehall II cohort; Kumari M et al. J Clin Endocrinol Metab 2011;96:1478-1485. doi:10.1210/jc.2010-2137","verification_status":"approximate","notes":"Flatter slope predicted cardiovascular death more strongly than non-CVD death. Single cohort; per-SD HR approximate.","hr_per_sd":1.3,"hr_per_sd_ci":[1.03,1.64]},"cancer":{"hr":2.08,"hr_metric":"categorical","hr_unit_detail":"flatter vs steeper diurnal slope, breast cancer mortality (early survival cohort)","direction":"risk","ci_low":1.2,"ci_high":3.6,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":104,"followup_years":7,"study":"Stanford metastatic breast cancer cohort relating diurnal cortisol slope to survival.","study_type":"prospective-cohort","citation":"Sephton SE et al. Diurnal cortisol rhythm as a predictor of breast cancer survival. J Natl Cancer Inst 2000;92:994-1000. doi:10.1093/jnci/92.12.994","verification_status":"approximate","notes":"Flatter slope predicted earlier death in metastatic breast cancer; this is a survival (not incidence) outcome in a very small cohort, so it is flagged categorical and not comparable on the per-SD scale.","hr_per_sd":null,"hr_per_sd_ci":null},"dementia":null,"frailty":{"hr":1.4,"hr_metric":"median_split","hr_unit_detail":"flatter (above-median) vs steeper diurnal slope, prevalent/incident frailty in older adults","direction":"risk","ci_low":1.05,"ci_high":1.86,"comparability":"converted","hr_per_sd_basis":"median_split contrast; k = 1/1.6 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":745,"followup_years":3,"study":"KORA-Age and related older-adult cohorts linking blunted diurnal cortisol to frailty.","study_type":"prospective-cohort","citation":"Johar H et al. Blunted diurnal cortisol pattern is associated with frailty: KORA-Age. J Clin Endocrinol Metab 2014;99:E464-E468. doi:10.1210/jc.2013-3079","verification_status":"approximate","notes":"Flatter diurnal slope associates with the frailty phenotype. Reported as a dichotomous contrast and converted to per-SD under a normal approximation; small cohort, cross-sectional component, treat as indicative.","hr_per_sd":1.234,"hr_per_sd_ci":[1.031,1.4738]}},"modifiability":{"intervention":"Sleep regularization, light exposure timing, stress reduction, aerobic exercise; treating depression where present.","effect_size":"Behavioral programs can steepen a blunted slope modestly; effect sizes small and variable.","timeframe":"8-12 weeks","evidence_type":"observational","citation":"Adam EK et al. systematic review of diurnal cortisol slopes and health outcomes, Psychoneuroendocrinology 2017.","rating":"moderate"}},{"id":"cortisol_hair","name":"Hair cortisol","domain":"hormonal","aliases":["hair cortisol concentration","HCC"],"profile":{"mechanism":"Hair cortisol concentration integrates systemic cortisol exposure over the preceding 1-3 months, providing a retrospective index of chronic HPA-axis activation that avoids diurnal and acute-stress noise.","measurement":{"method":"Proximal 1-3 cm hair segment, cortisol extracted and quantified by immunoassay or LC-MS/MS.","sample_type":"hair","approx_cost_usd":"60-150"},"signal_quality":"moderate","signal_quality_note":"Reflects chronic exposure well, but affected by hair treatments, washing frequency, hair color and growth rate; assays not fully standardized.","confounders":["hair dye/bleaching","washing frequency","hair growth rate","topical/systemic corticosteroids","season"],"testing_cadence":"baseline; repeat at 3-6 months if monitoring chronic stress"},"outcomes":{"all_cause_mortality":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher (log) hair cortisol, all-cause mortality, older adults","direction":"risk","ci_low":1.02,"ci_high":1.41,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":1700,"followup_years":8,"study":"Dutch Lifelines / population cohorts relating hair cortisol to mortality and cardiometabolic disease.","study_type":"prospective-cohort","citation":"Manenschijn L et al. High long-term cortisol levels, measured in scalp hair, are associated with a history of cardiovascular disease. J Clin Endocrinol Metab 2013;98:2078-2083. doi:10.1210/jc.2012-3663","verification_status":"unverified","notes":"Hair cortisol associates with cardiometabolic disease and incident events; direct mortality cohorts are small and few. Per-SD HR is an unverified synthesis from general domain evidence.","hr_per_sd":1.2,"hr_per_sd_ci":[1.02,1.41]},"cvd":{"hr":2.7,"hr_metric":"categorical","hr_unit_detail":"highest vs lowest hair cortisol category, prevalent cardiovascular disease","direction":"risk","ci_low":1.3,"ci_high":5.6,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":283,"followup_years":null,"study":"Cross-sectional study of scalp hair cortisol and history of cardiovascular disease in older adults.","study_type":"prospective-cohort","citation":"Manenschijn L et al. J Clin Endocrinol Metab 2013;98:2078-2083. doi:10.1210/jc.2012-3663","verification_status":"approximate","notes":"Reported as an odds ratio for prevalent CVD in a cross-sectional design; flagged categorical and not converted because it is not an incidence per-SD estimate.","hr_per_sd":null,"hr_per_sd_ci":null},"cancer":null,"dementia":null,"frailty":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher (log) hair cortisol, frailty index / phenotype in older adults","direction":"risk","ci_low":1.05,"ci_high":1.61,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":1200,"followup_years":null,"study":"Cross-sectional studies of chronic cortisol exposure (hair) and frailty in older populations.","study_type":"prospective-cohort","citation":"Geesdorf N et al. and related analyses of hair cortisol and frailty/grip strength in older adults.","verification_status":"unverified","notes":"Chronic cortisol exposure plausibly drives sarcopenia and frailty; supporting studies are small and largely cross-sectional. Per-SD HR is an unverified estimate.","hr_per_sd":1.3,"hr_per_sd_ci":[1.05,1.61]}},"modifiability":{"intervention":"Sustained stress reduction, sleep, exercise; effective only over multi-month horizons given the integrative window.","effect_size":"Modest reductions with sustained behavioral change; data limited.","timeframe":"3+ months (reflects cumulative exposure)","evidence_type":"observational","citation":"Stalder T et al. Stress-related and basic determinants of hair cortisol in humans: a meta-analysis, Psychoneuroendocrinology 2017.","rating":"moderate"},"comparability_tag":"Cross-sectional OR","comparability_note":"The hair-cortisol cardiovascular cell is a cross-sectional odds ratio for prevalent disease across cortisol categories, not an incidence hazard ratio, so it is not placed on the per-SD scale."},{"id":"dheas","name":"DHEA-S","domain":"hormonal","aliases":["dehydroepiandrosterone sulfate","DHEAS"],"profile":{"mechanism":"DHEA-S is the most abundant circulating steroid and the sulfated reservoir of DHEA, an adrenal androgen precursor. It declines steeply with age ('adrenopause'); low levels are a marker of biological aging and have been linked to reduced anabolic tone, immune function and vascular health.","measurement":{"method":"Immunoassay or LC-MS/MS on venous serum; stable through the day so timing is not critical.","sample_type":"venous blood","approx_cost_usd":"30-70"},"signal_quality":"clean","signal_quality_note":"Long half-life, minimal diurnal variation and high concentration make DHEA-S a stable, reproducible analyte.","confounders":["age (strong)","exogenous DHEA/steroids","critical illness","anorexia","smoking"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1.21,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower DHEA-S, all-cause mortality, predominantly men","direction":"risk","ci_low":1.1,"ci_high":1.33,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":12000,"followup_years":12,"study":"Meta-analysis and pooled cohorts of DHEA-S and mortality (MrOS, Rancho Bernardo, MROS-Sweden, Massachusetts Male Aging).","study_type":"meta-analysis","citation":"Wu TT et al. and prior meta-analyses; e.g. Ohlsson C et al. Low serum DHEAS predicts increased risk of mortality in elderly men (MrOS Sweden). J Clin Endocrinol Metab 2010;95:4406-4414. doi:10.1210/jc.2010-0760","verification_status":"approximate","notes":"Low DHEA-S predicts mortality in older men; the association is weaker or inconsistent in women. Largely reflects general aging/illness burden (low DHEA-S as a frailty proxy); Mendelian randomization does not support a causal protective effect. Per-SD HR approximate, sex-specific.","hr_per_sd":1.21,"hr_per_sd_ci":[1.1,1.33]},"cvd":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower DHEA-S, cardiovascular events/mortality, men","direction":"risk","ci_low":1.04,"ci_high":1.27,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":9000,"followup_years":10,"study":"MrOS Sweden and Rancho Bernardo cohorts of DHEA-S and cardiovascular outcomes.","study_type":"prospective-cohort","citation":"Ohlsson C et al. J Clin Endocrinol Metab 2010;95:4406-4414; Tilvis RS et al. cardiovascular analyses.","verification_status":"approximate","notes":"Low DHEA-S is modestly associated with cardiovascular events in men; data in women are null or inconsistent. Association likely reflects aging rather than causation.","hr_per_sd":1.15,"hr_per_sd_ci":[1.04,1.27]},"cancer":{"hr":1.05,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD DHEA-S, overall cancer mortality (no consistent association)","direction":"risk","ci_low":0.95,"ci_high":1.16,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":9000,"followup_years":10,"study":"Cohorts examining DHEA-S and cancer outcomes; associations vary by cancer site.","study_type":"prospective-cohort","citation":"Pooled cohort estimates; site-specific signals (hormone-sensitive cancers) reported separately in the literature.","verification_status":"unverified","notes":"No consistent overall cancer association; site-specific effects (e.g. higher DHEA-S and some postmenopausal breast cancer) exist but are not generalizable. Recorded as an approximately null per-SD cell.","hr_per_sd":1.05,"hr_per_sd_ci":[0.95,1.16]},"dementia":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower DHEA-S, incident dementia / cognitive decline","direction":"risk","ci_low":0.96,"ci_high":1.26,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":5000,"followup_years":8,"study":"Cohort studies of DHEA-S and cognitive decline / dementia in older adults.","study_type":"prospective-cohort","citation":"Various older-adult cohorts (e.g. EPIDOS, MrOS) of DHEA-S and cognition.","verification_status":"unverified","notes":"Evidence for DHEA-S and dementia is weak and inconsistent; CI crosses 1. Treat as low-confidence, association only.","hr_per_sd":1.1,"hr_per_sd_ci":[0.96,1.26]},"frailty":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower DHEA-S, incident frailty / frailty phenotype in older adults","direction":"risk","ci_low":1.13,"ci_high":1.49,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":4000,"followup_years":5,"study":"InCHIANTI and other older-adult cohorts linking low DHEA-S to frailty and muscle loss.","study_type":"prospective-cohort","citation":"Voznesensky M et al. and InCHIANTI analyses of anabolic hormones and frailty; Cappola AR et al. JAMA 2003 (multiple anabolic deficits).","verification_status":"approximate","notes":"Low DHEA-S clusters with low IGF-1 and testosterone; multiple anabolic-hormone deficits jointly predict frailty more strongly than any one hormone. Per-SD HR approximate.","hr_per_sd":1.3,"hr_per_sd_ci":[1.13,1.49]}},"modifiability":{"intervention":"DHEA supplementation raises DHEA-S, but RCTs show little benefit on hard outcomes, body composition or cognition in healthy older adults.","effect_size":"Supplementation normalizes levels; clinically meaningful outcome benefit not demonstrated.","timeframe":"Weeks to raise levels; outcome benefit unproven","evidence_type":"RCT meta-analysis","citation":"Nair KS et al. DHEA in elderly women and men, NEJM 2006;355:1647-1659; Cochrane/meta-analyses of DHEA supplementation.","rating":"low"}},{"id":"cortisol_dheas_ratio","name":"Cortisol:DHEA-S ratio","domain":"hormonal","aliases":["cortisol/DHEAS ratio","catabolic-anabolic balance index"],"comparability_tag":"Composite ratio","comparability_note":"A derived ratio of two hormones with no standard SD; per-SD estimates depend entirely on how each component is scaled.","profile":{"mechanism":"The cortisol:DHEA-S ratio indexes the balance between catabolic glucocorticoid tone and anabolic adrenal-androgen tone. A rising ratio with age reflects shift toward catabolism and has been linked to immunosenescence, sarcopenia and poorer stress resilience.","measurement":{"method":"Computed from concurrently measured serum cortisol and DHEA-S; both from a single morning venous draw.","sample_type":"venous blood","approx_cost_usd":"45-100"},"signal_quality":"moderate","signal_quality_note":"Inherits the diurnal noise of cortisol; the ratio has no standardized reference range and units are arbitrary.","confounders":["time of sampling","acute stress","exogenous steroids","age","critical illness"],"testing_cadence":"baseline; research-oriented use"},"outcomes":{"all_cause_mortality":{"hr":1.25,"hr_metric":"categorical","hr_unit_detail":"high vs low cortisol:DHEA-S ratio, all-cause mortality in older adults","direction":"risk","ci_low":1.05,"ci_high":1.49,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":3000,"followup_years":6,"study":"Small older-adult cohorts relating the cortisol:DHEA-S ratio to mortality and immune aging.","study_type":"prospective-cohort","citation":"Phillips AC et al. Cortisol, DHEAS, their ratio and the metabolic syndrome / mortality, Eur J Endocrinol 2010;163:285-292. doi:10.1530/EJE-10-0299","verification_status":"unverified","notes":"A higher ratio predicts mortality and poorer immune function in small cohorts, but the ratio has no standardized SD; flagged unconvertible. The cited HR is an approximate categorical contrast.","hr_per_sd":null,"hr_per_sd_ci":null},"cvd":{"hr":1.2,"hr_metric":"categorical","hr_unit_detail":"high vs low cortisol:DHEA-S ratio, cardiovascular outcomes","direction":"risk","ci_low":0.98,"ci_high":1.47,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":3000,"followup_years":6,"study":"Cohort analyses of the cortisol:DHEA-S balance and cardiometabolic disease.","study_type":"prospective-cohort","citation":"Phillips AC et al. Eur J Endocrinol 2010;163:285-292. doi:10.1530/EJE-10-0299","verification_status":"unverified","notes":"Weak, inconsistent cardiovascular signal; CI crosses 1. Ratio is unconvertible to per-SD.","hr_per_sd":null,"hr_per_sd_ci":null},"cancer":null,"dementia":null,"frailty":{"hr":1.35,"hr_metric":"categorical","hr_unit_detail":"high vs low cortisol:DHEA-S ratio, frailty / functional decline in older adults","direction":"risk","ci_low":1.08,"ci_high":1.69,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":2000,"followup_years":4,"study":"Small studies of the catabolic-anabolic hormone balance and frailty / muscle function.","study_type":"prospective-cohort","citation":"Older-adult cohort analyses of cortisol:DHEAS ratio and physical function.","verification_status":"unverified","notes":"A high ratio plausibly indexes net catabolic state and frailty risk, but evidence is limited and the ratio is unconvertible to a comparable per-SD scale.","hr_per_sd":null,"hr_per_sd_ci":null}},"modifiability":{"intervention":"Lower the ratio indirectly via stress reduction, sleep and exercise (lowering cortisol); DHEA supplementation raises the denominator but without proven outcome benefit.","effect_size":"Modest, indirect; no validated intervention targets the ratio itself.","timeframe":"8-12 weeks for component changes","evidence_type":"observational","citation":"Inferred from cortisol and DHEA-S intervention literature.","rating":"low"}},{"id":"tsh","name":"TSH","domain":"hormonal","aliases":["thyroid-stimulating hormone","thyrotropin"],"comparability_tag":"U-shaped","comparability_note":"Mortality and CVD rise at both low (hyperthyroid) and high (hypothyroid) TSH; the relationship is U/J-shaped and not summarizable as one per-SD slope.","profile":{"mechanism":"TSH is the pituitary signal driving thyroid hormone output and is the most sensitive index of thyroid status. Both subclinical hyperthyroidism (low TSH) and subclinical hypothyroidism (high TSH) perturb cardiac, metabolic and skeletal physiology; thyroid status shifts with age.","measurement":{"method":"Third-generation immunoassay on venous serum; mild diurnal variation.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"clean","signal_quality_note":"Well-standardized, sensitive assay; log-normal distribution and modest diurnal/seasonal variation are the main caveats.","confounders":["non-thyroidal illness","biotin supplements (assay interference)","amiodarone/lithium","pregnancy","time of day","iodine status"],"testing_cadence":"baseline + every 1-2 years; sooner if abnormal"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":null,"hr_unit_detail":"U/J-shaped: excess mortality at both low and high TSH; no single linear HR applies","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"non-monotonic U/J-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"A","n":55000,"followup_years":10,"study":"Thyroid Studies Collaboration individual-participant meta-analyses of subclinical thyroid dysfunction and mortality.","study_type":"meta-analysis","citation":"Rodondi N et al. Subclinical hypothyroidism and the risk of coronary heart disease and mortality. JAMA 2010;304:1365-1374. doi:10.1001/jama.2010.1361","verification_status":"verified","notes":"Subclinical hyperthyroidism (low TSH) raises mortality (HR ~1.2-1.4) and subclinical hypothyroidism raises CHD mortality mainly at TSH >10 mIU/L; within the normal range associations are weak. A single per-SD HR would be misleading; flagged unconvertible/non-monotonic.","qualitative":true},"cvd":{"hr":1.58,"hr_metric":"categorical","hr_unit_detail":"subclinical hypothyroidism with TSH >=10 mIU/L vs euthyroid, coronary heart disease events","direction":"risk","ci_low":1.22,"ci_high":2.06,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":55287,"followup_years":11.5,"study":"Thyroid Studies Collaboration, individual-participant meta-analysis of 11 prospective cohorts.","study_type":"meta-analysis","citation":"Rodondi N et al. Subclinical hypothyroidism and the risk of coronary heart disease and mortality. JAMA 2010;304:1365-1374. doi:10.1001/jama.2010.1361","verification_status":"verified","notes":"CHD risk is elevated mainly at TSH >=10 mIU/L (HR 1.58 for events, 1.84 for CHD mortality); TSH 4.5-9.9 mIU/L confers little excess risk. Subclinical hyperthyroidism separately raises atrial fibrillation and CVD risk. Categorical, non-monotonic - not convertible.","hr_per_sd":null,"hr_per_sd_ci":null},"cancer":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher TSH, overall cancer mortality (weak, mostly null)","direction":"risk","ci_low":0.98,"ci_high":1.24,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":20000,"followup_years":10,"study":"Cohorts of thyroid function and cancer; thyroid cancer itself is the main exception.","study_type":"prospective-cohort","citation":"Cohort analyses of TSH and cancer incidence/mortality; differentiated thyroid cancer risk rises with higher TSH.","verification_status":"unverified","notes":"No consistent overall cancer association; higher TSH is a recognized risk factor specifically for differentiated thyroid cancer. Recorded as an approximately null overall per-SD cell.","hr_per_sd":1.1,"hr_per_sd_ci":[0.98,1.24]},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":"inconsistent / possibly U-shaped association of TSH with dementia","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"inconsistent and possibly non-monotonic; no usable per-SD summary","conversion":null,"evidence_tier":"C","n":8000,"followup_years":12,"study":"Framingham and other cohorts of thyroid function and incident dementia.","study_type":"prospective-cohort","citation":"Tan ZS et al. Thyroid function and the risk of Alzheimer disease: the Framingham Study. Arch Intern Med 2008;168:1514-1520. doi:10.1001/archinte.168.14.1514","verification_status":"approximate","notes":"Framingham reported both low and high TSH associated with Alzheimer risk in women (U-shaped); other cohorts are null. No defensible linear per-SD HR; left null/unconvertible.","qualitative":true},"frailty":{"hr":1.2,"hr_metric":"categorical","hr_unit_detail":"subclinical hypothyroidism vs euthyroid, incident frailty / functional decline in older adults","direction":"risk","ci_low":1,"ci_high":1.44,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":5000,"followup_years":6,"study":"Cardiovascular Health Study and related cohorts of subclinical thyroid dysfunction and frailty.","study_type":"prospective-cohort","citation":"Virgini VS et al. Subclinical thyroid dysfunction and frailty among older men (MrOS). J Clin Endocrinol Metab 2015;100:4524-4532. doi:10.1210/jc.2015-3017","verification_status":"approximate","notes":"Both subclinical hypo- and hyperthyroidism have been linked to frailty/functional decline; associations are modest and inconsistent. Categorical and non-monotonic, so not per-SD convertible.","hr_per_sd":null,"hr_per_sd_ci":null}},"modifiability":{"intervention":"Levothyroxine for hypothyroidism; antithyroid drugs/radioiodine for hyperthyroidism. RCTs (TRUST) show levothyroxine for mild subclinical hypothyroidism does not improve symptoms or outcomes in older adults.","effect_size":"TSH fully normalizable with treatment; outcome benefit clear only for overt disease and TSH >10.","timeframe":"6-8 weeks to re-equilibrate after dose change","evidence_type":"RCT","citation":"Stott DJ et al. TRUST trial, NEJM 2017;376:2534-2544; ATA guidelines.","rating":"high"}},{"id":"free_t4","name":"Free T4","domain":"hormonal","aliases":["free thyroxine","FT4"],"profile":{"mechanism":"Free T4 is the unbound, biologically available fraction of the main thyroid hormone. Even within the reference range, higher free T4 reflects greater metabolic and cardiac drive and is associated with atrial fibrillation, bone loss and accelerated aging phenotypes.","measurement":{"method":"Immunoassay (or equilibrium dialysis LC-MS/MS) on venous serum.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"moderate","signal_quality_note":"Assay estimates of free hormone are method-dependent and affected by binding-protein abnormalities and non-thyroidal illness.","confounders":["non-thyroidal illness","binding-protein changes (pregnancy, estrogen)","heparin","amiodarone","assay method"],"testing_cadence":"baseline + with TSH every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1.16,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher free T4 (within reference range), all-cause mortality, older adults","direction":"risk","ci_low":1.09,"ci_high":1.24,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":13000,"followup_years":8,"study":"Rotterdam Study and pooled cohorts of free T4 within the reference range and mortality.","study_type":"prospective-cohort","citation":"Bano A et al. Thyroid function and the risk of atherosclerotic cardiovascular morbidity and mortality: the Rotterdam Study. Circ Res 2017;121:1392-1400. doi:10.1161/CIRCRESAHA.117.311603","verification_status":"approximate","notes":"Higher free T4 even within the normal range predicts all-cause and CVD mortality and is linked to faster aging/lower life expectancy in healthy euthyroid older adults. Per-SD HR applies within range; values are additionally U-shaped at the extremes.","hr_per_sd":1.16,"hr_per_sd_ci":[1.09,1.24]},"cvd":{"hr":1.24,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher free T4 (reference range), atherosclerotic CVD events/mortality","direction":"risk","ci_low":1.13,"ci_high":1.36,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":9420,"followup_years":8.8,"study":"Rotterdam Study, free T4 within reference range and atherosclerotic cardiovascular disease.","study_type":"prospective-cohort","citation":"Bano A et al. Circ Res 2017;121:1392-1400. doi:10.1161/CIRCRESAHA.117.311603","verification_status":"approximate","notes":"Higher-normal free T4 associated with greater atherosclerotic CVD incidence and mortality, partly via subclinical atherosclerosis and atrial fibrillation. Association; per-SD HR approximate.","hr_per_sd":1.24,"hr_per_sd_ci":[1.13,1.36]},"cancer":null,"dementia":{"hr":1.04,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher free T4, incident dementia (weak / inconsistent)","direction":"risk","ci_low":0.93,"ci_high":1.16,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":8000,"followup_years":10,"study":"Rotterdam and other cohorts of thyroid function and dementia.","study_type":"prospective-cohort","citation":"Chaker L et al. Thyroid function and the risk of dementia: the Rotterdam Study. Neurology 2016;87:1688-1695. doi:10.1212/WNL.0000000000003227","verification_status":"approximate","notes":"Higher free T4 was associated with greater dementia risk in some analyses, but estimates are weak and inconsistent across cohorts; CI crosses 1 here. Low confidence.","hr_per_sd":1.04,"hr_per_sd_ci":[0.93,1.16]},"frailty":{"hr":1.18,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher free T4, frailty / functional decline in older adults","direction":"risk","ci_low":1.04,"ci_high":1.34,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":5000,"followup_years":6,"study":"Cohorts linking higher-normal free T4 to lower grip strength, mobility limitation and frailty.","study_type":"prospective-cohort","citation":"Bano A et al. and related Rotterdam analyses of thyroid function and physical function/frailty.","verification_status":"unverified","notes":"Higher free T4 is associated with lower muscle strength and greater frailty risk, plausibly via increased catabolism. Per-SD HR is an unverified estimate.","hr_per_sd":1.18,"hr_per_sd_ci":[1.04,1.34]}},"modifiability":{"intervention":"Free T4 is treated only in the context of overt thyroid disease (antithyroid drugs lower it; levothyroxine raises it). Within-range variation is not a clinical treatment target.","effect_size":"Fully modifiable by thyroid-directed therapy when disease is present; not modified in euthyroid people.","timeframe":"Weeks after dose change","evidence_type":"RCT","citation":"ATA thyroid guidelines; TRUST trial context.","rating":"low"}},{"id":"free_t3","name":"Free T3","domain":"hormonal","aliases":["free triiodothyronine","FT3"],"comparability_tag":"U-shaped","comparability_note":"Low free T3 marks non-thyroidal illness ('low-T3 syndrome') and predicts mortality, but very high free T3 is also harmful; the association is non-monotonic and confounded by reverse causation.","profile":{"mechanism":"Free T3 is the most metabolically active thyroid hormone, generated largely by peripheral deiodination of T4. Low free T3 is a hallmark of non-thyroidal illness syndrome and a strong marker of illness severity and frailty in older and hospitalized populations.","measurement":{"method":"Immunoassay on venous serum; free-hormone estimates are method-dependent.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"noisy","signal_quality_note":"Strongly depressed by acute and chronic illness independent of thyroid disease, making it a confounded index of intrinsic thyroid status.","confounders":["non-thyroidal illness (major)","caloric restriction/fasting","age","drugs (glucocorticoids, beta-blockers, amiodarone)","assay method"],"testing_cadence":"baseline; interpret with TSH and clinical context"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":null,"hr_unit_detail":"U-shaped: low free T3 (illness/frailty) and high free T3 both predict death","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"non-monotonic U-shaped association heavily confounded by non-thyroidal illness; no usable per-SD summary","conversion":null,"evidence_tier":"B","n":12000,"followup_years":8,"study":"Older-adult and patient cohorts of low-T3 syndrome and mortality.","study_type":"prospective-cohort","citation":"Iervasi G et al. Low-T3 syndrome: a strong prognostic predictor of death in patients with cardiac disease. Circulation 2003;107:708-713. doi:10.1161/01.CIR.0000048124.64204.3F","verification_status":"approximate","notes":"Low free T3 strongly predicts mortality but is largely a marker of underlying illness severity (reverse causation), while high free T3 (hyperthyroidism) is independently harmful. A single per-SD HR is misleading; flagged unconvertible/non-monotonic.","qualitative":true},"cvd":{"hr":2.4,"hr_metric":"categorical","hr_unit_detail":"low-T3 syndrome vs normal free T3, cardiac-disease cohorts, cardiovascular death","direction":"risk","ci_low":1.3,"ci_high":4.4,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":573,"followup_years":1,"study":"Cardiac-patient cohort of low-T3 syndrome and cardiovascular mortality.","study_type":"prospective-cohort","citation":"Iervasi G et al. Circulation 2003;107:708-713. doi:10.1161/01.CIR.0000048124.64204.3F","verification_status":"approximate","notes":"Low free T3 strongly predicts cardiovascular death in cardiac patients, but largely reflects illness severity. Categorical contrast in a selected population; not convertible to a comparable per-SD scale.","hr_per_sd":null,"hr_per_sd_ci":null},"cancer":null,"dementia":null,"frailty":{"hr":1.5,"hr_metric":"categorical","hr_unit_detail":"low free T3 (lowest tertile / low-T3 pattern) vs normal, frailty in older adults","direction":"risk","ci_low":1.15,"ci_high":1.96,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":3000,"followup_years":5,"study":"Older-adult cohorts linking low free T3 to the frailty phenotype and sarcopenia.","study_type":"prospective-cohort","citation":"Older-adult cohort analyses of free T3 and frailty (e.g. InCHIANTI, BLSA-type cohorts).","verification_status":"unverified","notes":"Low free T3 closely tracks frailty and sarcopenia, but is best understood as part of the frailty/illness phenotype rather than an independent causal factor. Categorical, not per-SD convertible.","hr_per_sd":null,"hr_per_sd_ci":null}},"modifiability":{"intervention":"No intervention targets free T3 in non-thyroidal illness; T3 replacement in low-T3 syndrome has not improved outcomes in RCTs. Free T3 normalizes when underlying illness resolves.","effect_size":"Not a treatment target; reflects underlying health.","timeframe":"Tracks recovery from illness","evidence_type":"RCT","citation":"Trials of T3 supplementation in critical illness and heart failure (no consistent benefit).","rating":"low"}},{"id":"reverse_t3","name":"Reverse T3","domain":"hormonal","aliases":["rT3","reverse triiodothyronine"],"profile":{"mechanism":"Reverse T3 is the metabolically inactive product of T4 deiodination. Its production rises during illness, starvation and stress as the body downregulates active T3, so elevated rT3 is a sensitive marker of non-thyroidal illness and catabolic state.","measurement":{"method":"Immunoassay or LC-MS/MS on venous serum; not routinely available and assay variability is high.","sample_type":"venous blood","approx_cost_usd":"60-150"},"signal_quality":"noisy","signal_quality_note":"Assays poorly standardized; the value is dominated by acute and chronic illness, making it an indirect, confounded biomarker.","confounders":["non-thyroidal illness (major)","fasting/caloric restriction","glucocorticoids/amiodarone","critical illness","assay variability"],"testing_cadence":"not routinely indicated"},"outcomes":{"all_cause_mortality":{"hr":1.3,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of reverse T3, all-cause mortality in older adults","direction":"risk","ci_low":1.05,"ci_high":1.61,"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":1100,"followup_years":6,"study":"Leiden 85-plus and similar older-adult cohorts of reverse T3 and mortality.","study_type":"prospective-cohort","citation":"van den Beld AW et al. Thyroid hormone concentrations, disease, physical function, and mortality in elderly men. J Clin Endocrinol Metab 2005;90:6403-6409. doi:10.1210/jc.2005-0872","verification_status":"approximate","notes":"Higher reverse T3 paradoxically associates with mortality (in some cohorts low rT3 with worse survival) and with poorer physical function; signals are inconsistent and dominated by illness. Tertile contrast converted; treat as a confounded illness marker.","hr_per_sd":1.1279,"hr_per_sd_ci":[1.0226,1.2442]},"cvd":null,"cancer":null,"dementia":null,"frailty":{"hr":1.4,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest tertile of reverse T3, poor physical function / frailty in older men","direction":"risk","ci_low":1.05,"ci_high":1.87,"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":400,"followup_years":4,"study":"Leiden 85-plus and elderly-men cohorts linking high reverse T3 to low physical function.","study_type":"prospective-cohort","citation":"van den Beld AW et al. J Clin Endocrinol Metab 2005;90:6403-6409. doi:10.1210/jc.2005-0872","verification_status":"approximate","notes":"High reverse T3 associates with poorer physical function and frailty, consistent with a catabolic illness state. Confounded by underlying illness; tertile contrast converted under a normal approximation.","hr_per_sd":1.1669,"hr_per_sd_ci":[1.0226,1.3326]}},"modifiability":{"intervention":"No intervention targets reverse T3; it normalizes when underlying illness or caloric deprivation resolves.","effect_size":"Not a treatment target.","timeframe":"Tracks recovery","evidence_type":"mechanistic","citation":"Non-thyroidal illness syndrome literature.","rating":"fixed"}},{"id":"thyroid_antibodies","name":"Thyroid antibodies (TPO/Tg)","domain":"hormonal","aliases":["TPOAb","anti-thyroid peroxidase antibody","thyroglobulin antibody","TgAb"],"comparability_tag":"Categorical","comparability_note":"Thyroid antibodies are interpreted as positive vs negative (autoimmune thyroiditis); there is no meaningful per-SD scale.","profile":{"mechanism":"Antibodies to thyroid peroxidase (TPO) and thyroglobulin (Tg) mark autoimmune thyroiditis (Hashimoto's) and predict progression to overt hypothyroidism. They index thyroid autoimmunity rather than thyroid hormone level.","measurement":{"method":"Immunoassay on venous serum; reported as a titre with a positivity cutoff.","sample_type":"venous blood","approx_cost_usd":"25-70"},"signal_quality":"moderate","signal_quality_note":"Reliable for detecting autoimmunity, but titres fluctuate and a positive result is common in older women without clinical disease.","confounders":["age","female sex","other autoimmune disease","iodine status","assay/cutoff differences"],"testing_cadence":"once to characterize cause of thyroid dysfunction; not routinely repeated"},"outcomes":{"all_cause_mortality":{"hr":1.02,"hr_metric":"categorical","hr_unit_detail":"TPO-antibody positive vs negative, all-cause mortality (no clear independent association)","direction":"risk","ci_low":0.9,"ci_high":1.16,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":15000,"followup_years":10,"study":"Population cohorts of thyroid autoimmunity and mortality.","study_type":"prospective-cohort","citation":"Population-cohort analyses of TPOAb and mortality (e.g. NHANES, Busselton, Rotterdam).","verification_status":"unverified","notes":"Thyroid-antibody positivity per se shows little independent mortality association once thyroid function is accounted for; risk operates mainly through resulting hypothyroidism. Categorical exposure; approximately null.","hr_per_sd":null,"hr_per_sd_ci":null},"cvd":{"hr":1.15,"hr_metric":"categorical","hr_unit_detail":"thyroid-antibody positive vs negative, cardiovascular events (weak, partly via hypothyroidism)","direction":"risk","ci_low":0.98,"ci_high":1.35,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":12000,"followup_years":10,"study":"Cohorts of thyroid autoimmunity and cardiovascular outcomes.","study_type":"prospective-cohort","citation":"Cohort analyses of thyroid autoimmunity and CVD risk.","verification_status":"unverified","notes":"Any cardiovascular risk from antibody positivity is small and largely mediated by progression to (subclinical) hypothyroidism. Categorical; CI crosses 1.","hr_per_sd":null,"hr_per_sd_ci":null},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":"no consistent association with overall cancer; relevant chiefly to thyroid cancer/lymphoma context","direction":"risk","ci_low":null,"ci_high":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure; no usable cancer estimate","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No adequately powered cohort isolates thyroid-antibody status as an overall cancer predictor.","study_type":"prospective-cohort","citation":"Hashimoto thyroiditis is associated with papillary thyroid cancer and thyroid lymphoma in clinical series; no general-cancer cohort estimate.","verification_status":"unverified","notes":"No defensible overall-cancer HR. Left null.","qualitative":true},"dementia":null,"frailty":null},"modifiability":{"intervention":"Antibody titres are not a treatment target; selenium supplementation modestly lowers TPOAb in some trials without proven clinical benefit. Levothyroxine treats the resulting hypothyroidism.","effect_size":"Selenium lowers TPOAb titres modestly; no demonstrated outcome benefit.","timeframe":"3-6 months for titre change","evidence_type":"RCT meta-analysis","citation":"Meta-analyses of selenium supplementation in autoimmune thyroiditis.","rating":"low"}},{"id":"total_testosterone","name":"Total testosterone","domain":"hormonal","aliases":["serum testosterone","total T"],"comparability_tag":"U-shaped","comparability_note":"In men, mortality is lowest at mid-normal testosterone and rises at both low and very high concentrations; per-SD HRs apply best within the low-to-normal range.","profile":{"mechanism":"Total testosterone is the principal circulating androgen, mostly bound to SHBG and albumin. It supports muscle mass, bone density, erythropoiesis and metabolic health; levels decline gradually with age in men, and low testosterone is both a cause and a consequence of poor health.","measurement":{"method":"LC-MS/MS (preferred) or immunoassay on a morning venous draw; diurnal and day-to-day variation require standardized timing.","sample_type":"venous blood","approx_cost_usd":"25-80"},"signal_quality":"moderate","signal_quality_note":"Diurnal variation, acute illness suppression and assay differences (immunoassay vs LC-MS/MS) reduce reliability of single measurements.","confounders":["time of day","acute illness","obesity (lowers via SHBG)","opioids/glucocorticoids","sleep deprivation","assay method"],"testing_cadence":"morning sample, confirm low values on a second draw"},"outcomes":{"all_cause_mortality":{"hr":1.14,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower total testosterone, all-cause mortality, men","direction":"risk","ci_low":1.06,"ci_high":1.23,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":24109,"followup_years":11,"study":"Androgens in Men Study, individual-participant meta-analysis of 9 prospective cohorts.","study_type":"meta-analysis","citation":"Yeap BB et al. Sociodemographic, lifestyle and medical influences on, and associations of, testosterone and mortality (Androgens in Men IPD meta-analysis). Lancet Healthy Longev 2024 / Ann Intern Med 2024. doi:10.7326/M23-2781","verification_status":"approximate","notes":"IPD meta-analysis: men with low total testosterone (<7.4 nmol/L) had higher all-cause and CVD mortality; the relationship is non-linear, with lowest risk at mid-normal levels. Largely a marker of poor health (low T as illness consequence); MR does not support a strong causal mortality effect. Estimate is for men only.","hr_per_sd":1.14,"hr_per_sd_ci":[1.06,1.23]},"cvd":{"hr":1.25,"hr_metric":"categorical","hr_unit_detail":"low total testosterone (<7.4 nmol/L) vs normal, cardiovascular mortality, men","direction":"risk","ci_low":1.07,"ci_high":1.46,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":24109,"followup_years":11,"study":"Androgens in Men Study IPD meta-analysis, cardiovascular mortality.","study_type":"meta-analysis","citation":"Yeap BB et al. Androgens in Men individual-participant meta-analysis. Ann Intern Med 2024. doi:10.7326/M23-2781","verification_status":"approximate","notes":"Low testosterone associates with CVD death in men; the TRAVERSE RCT found testosterone therapy in hypogonadal men did not increase major adverse cardiovascular events, arguing against a simple causal protective effect. Reported as a low-vs-normal category; non-monotonic, not per-SD convertible. Men only.","hr_per_sd":null,"hr_per_sd_ci":null},"cancer":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD total testosterone, overall cancer mortality, men (no overall association)","direction":"risk","ci_low":0.92,"ci_high":1.09,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":20000,"followup_years":11,"study":"Androgens in Men and Endogenous Hormones and Prostate Cancer collaborations.","study_type":"meta-analysis","citation":"Endogenous Hormones and Prostate Cancer Collaborative Group, J Natl Cancer Inst 2008;100:170-183; Androgens in Men Study, Ann Intern Med 2024.","verification_status":"approximate","notes":"No overall cancer-mortality association; higher endogenous testosterone is not associated with prostate cancer risk in pooled data, though it remains relevant to established prostate cancer. Recorded as an approximately null overall per-SD cell. Men only.","hr_per_sd":1,"hr_per_sd_ci":[0.92,1.09]},"dementia":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower total testosterone, incident dementia / Alzheimer disease, older men","direction":"risk","ci_low":0.97,"ci_high":1.25,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":6000,"followup_years":8,"study":"Older-men cohorts (e.g. Health in Men, Honolulu-Asia Aging) of testosterone and dementia.","study_type":"prospective-cohort","citation":"Cohort analyses of endogenous testosterone and incident dementia in older men.","verification_status":"unverified","notes":"Lower testosterone associates modestly with dementia in older men, but prodromal dementia lowers testosterone (reverse causation) and CI crosses 1. Low confidence; men only.","hr_per_sd":1.1,"hr_per_sd_ci":[0.97,1.25]},"frailty":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower total testosterone, incident frailty / functional decline, older men","direction":"risk","ci_low":1.13,"ci_high":1.5,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":5000,"followup_years":5,"study":"MrOS and other older-men cohorts of testosterone, sarcopenia and frailty.","study_type":"prospective-cohort","citation":"Hyde Z et al. Low free testosterone predicts frailty in older men: the Health in Men Study. J Clin Endocrinol Metab 2010;95:3165-3172. doi:10.1210/jc.2009-2754","verification_status":"approximate","notes":"Lower testosterone predicts incident frailty in older men; testosterone therapy improves lean mass and strength modestly in RCTs but frailty-outcome benefit is limited. Per-SD HR approximate; men only.","hr_per_sd":1.3,"hr_per_sd_ci":[1.13,1.5]}},"modifiability":{"intervention":"Testosterone replacement therapy in confirmed hypogonadism; weight loss and treating sleep apnea raise endogenous levels in obese men.","effect_size":"TRT restores levels to mid-normal; ~10-15% weight loss can raise total testosterone substantially in obese men.","timeframe":"Weeks (TRT); 3-6 months (weight loss)","evidence_type":"RCT","citation":"TRAVERSE trial (Lincoff 2023, NEJM); TTrials (Snyder 2016, NEJM); weight-loss trials.","rating":"moderate"}},{"id":"free_testosterone","name":"Free testosterone","domain":"hormonal","aliases":["free T","calculated free testosterone","bioavailable testosterone"],"profile":{"mechanism":"Free testosterone is the unbound, immediately bioavailable androgen fraction, usually calculated from total testosterone, SHBG and albumin. It is considered a more physiologically relevant index of androgen action, especially when SHBG is abnormal (obesity, aging).","measurement":{"method":"Calculated from total testosterone, SHBG and albumin (Vermeulen equation), or equilibrium dialysis (reference method); morning sample.","sample_type":"venous blood","approx_cost_usd":"30-90"},"signal_quality":"moderate","signal_quality_note":"Calculated values depend on SHBG assay accuracy and the chosen equation; equilibrium dialysis is accurate but rarely used.","confounders":["time of day","SHBG assay accuracy","obesity","acute illness","calculation method"],"testing_cadence":"morning sample; confirm low values"},"outcomes":{"all_cause_mortality":{"hr":1.13,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower calculated free testosterone, all-cause mortality, older men","direction":"risk","ci_low":1.04,"ci_high":1.23,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":12000,"followup_years":9,"study":"Pooled older-men cohorts (Health in Men, MrOS, EMAS) of free testosterone and mortality.","study_type":"pooled-cohort","citation":"Yeap BB et al. analyses of free testosterone and mortality in older men; Health in Men Study.","verification_status":"approximate","notes":"Low calculated free testosterone predicts mortality in older men, similar in magnitude to total testosterone; both are partly markers of underlying ill health. Per-SD HR approximate; men only.","hr_per_sd":1.13,"hr_per_sd_ci":[1.04,1.23]},"cvd":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower free testosterone, cardiovascular events/mortality, men","direction":"risk","ci_low":1.03,"ci_high":1.28,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":9000,"followup_years":9,"study":"Older-men cohorts of free testosterone and cardiovascular outcomes.","study_type":"prospective-cohort","citation":"Cohort analyses of calculated free testosterone and CVD in older men.","verification_status":"unverified","notes":"Modest inverse association with CVD in men; confounded by general health and SHBG. Per-SD HR unverified; men only.","hr_per_sd":1.15,"hr_per_sd_ci":[1.03,1.28]},"cancer":null,"dementia":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower free testosterone, incident Alzheimer disease, older men","direction":"risk","ci_low":0.98,"ci_high":1.35,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":574,"followup_years":19,"study":"Baltimore Longitudinal Study of Aging, free testosterone index and Alzheimer disease.","study_type":"prospective-cohort","citation":"Moffat SD et al. Free testosterone and risk for Alzheimer disease in older men. Neurology 2004;62:188-193. doi:10.1212/WNL.62.2.188","verification_status":"approximate","notes":"BLSA found lower free testosterone index preceding Alzheimer disease, but the finding is from a small cohort and CI here crosses 1; reverse causation possible. Low confidence; men only.","hr_per_sd":1.15,"hr_per_sd_ci":[0.98,1.35]},"frailty":{"hr":1.34,"hr_metric":"categorical","hr_unit_detail":"lowest vs higher free testosterone, incident frailty, older men (Health in Men Study)","direction":"risk","ci_low":1.07,"ci_high":1.67,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":3616,"followup_years":5,"study":"Health in Men Study, free testosterone and incident frailty in community-dwelling older men.","study_type":"prospective-cohort","citation":"Hyde Z et al. Low free testosterone predicts frailty in older men: the Health in Men Study. J Clin Endocrinol Metab 2010;95:3165-3172. doi:10.1210/jc.2009-2754","verification_status":"approximate","notes":"Low free testosterone predicted incident frailty more consistently than total testosterone in this cohort. Reported as a category contrast; retained as categorical. Men only.","hr_per_sd":null,"hr_per_sd_ci":null}},"modifiability":{"intervention":"Testosterone replacement in hypogonadism; weight loss raises free testosterone partly by lowering SHBG-bound fraction.","effect_size":"TRT restores free testosterone; weight loss produces modest gains.","timeframe":"Weeks (TRT); months (weight loss)","evidence_type":"RCT","citation":"TTrials (Snyder 2016, NEJM); TRAVERSE (Lincoff 2023, NEJM).","rating":"moderate"},"comparability_tag":"Category contrast","comparability_note":"The free-testosterone frailty cell is a low-vs-higher category contrast in older men, not a continuous per-SD estimate."},{"id":"shbg","name":"SHBG","domain":"hormonal","aliases":["sex hormone-binding globulin"],"comparability_tag":"U-shaped","comparability_note":"SHBG shows a U-shaped relationship with mortality - low SHBG marks insulin resistance, very high SHBG marks frailty/illness - so a single per-SD slope is only approximate.","profile":{"mechanism":"SHBG is a hepatic glycoprotein that binds sex steroids and regulates their bioavailability. Low SHBG is a sensitive marker of insulin resistance, hepatic fat and metabolic syndrome; very high SHBG accompanies aging, low body weight and frailty.","measurement":{"method":"Immunoassay on venous serum; stable through the day.","sample_type":"venous blood","approx_cost_usd":"25-60"},"signal_quality":"clean","signal_quality_note":"Low diurnal variation and a robust assay; interpretation is the main complexity given its U-shaped associations.","confounders":["insulin resistance/obesity (lowers)","oral estrogen/pregnancy (raises)","thyroid status","liver disease","age"],"testing_cadence":"baseline; with sex-steroid panels"},"outcomes":{"all_cause_mortality":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher SHBG, all-cause mortality, older men and women","direction":"risk","ci_low":1.07,"ci_high":1.24,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":15000,"followup_years":10,"study":"Older-adult cohorts (e.g. MrOS, EPIC, Framingham) of SHBG and mortality.","study_type":"prospective-cohort","citation":"Cohort analyses of SHBG and mortality in older adults (e.g. MrOS, Hong Kong cohorts).","verification_status":"unverified","notes":"Higher SHBG predicts mortality in older adults, but the relationship is U-shaped: very low SHBG marks insulin resistance/fatty liver while very high SHBG marks frailty and low body weight. Per-SD HR is an approximate overall slope; unverified.","hr_per_sd":1.15,"hr_per_sd_ci":[1.07,1.24]},"cvd":{"hr":0.9,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher SHBG, coronary heart disease, with genetic support for a causal protective direction","direction":"protective","ci_low":0.83,"ci_high":0.98,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":175000,"followup_years":12,"study":"Large cohorts and Mendelian randomization of SHBG and type 2 diabetes / cardiovascular disease.","study_type":"mendelian-randomization","citation":"Ding EL et al. Sex hormone-binding globulin and risk of type 2 diabetes. NEJM 2009;361:1152-1163. doi:10.1056/NEJMoa0804381","verification_status":"approximate","notes":"Low SHBG is strongly and causally linked to type 2 diabetes (MR), and lower SHBG associates with higher cardiometabolic risk; the protective per-SD direction reflects higher SHBG = lower metabolic risk. Effects are partly sex-specific and confounded by adiposity.","hr_per_sd":0.9,"hr_per_sd_ci":[0.83,0.98]},"cancer":{"hr":1.2,"hr_metric":"categorical","hr_unit_detail":"higher vs lower SHBG, hormone-sensitive cancer (e.g. postmenopausal breast cancer - direction varies)","direction":"risk","ci_low":0.95,"ci_high":1.52,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":6000,"followup_years":10,"study":"Endogenous Hormones and Breast Cancer Collaborative Group and related analyses.","study_type":"pooled-cohort","citation":"Endogenous Hormones and Breast Cancer Collaborative Group, J Natl Cancer Inst 2002;94:606-616.","verification_status":"unverified","notes":"SHBG-cancer associations are site-specific and inconsistent in direction (higher SHBG protective for some breast-cancer analyses, neutral elsewhere). No defensible overall per-SD cancer HR; flagged categorical.","hr_per_sd":null,"hr_per_sd_ci":null},"dementia":null,"frailty":{"hr":1.25,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher SHBG, incident frailty / functional decline in older adults","direction":"risk","ci_low":1.08,"ci_high":1.45,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":4000,"followup_years":5,"study":"Older-adult cohorts linking high SHBG to low body mass, sarcopenia and frailty.","study_type":"prospective-cohort","citation":"Cohort analyses of SHBG and frailty/physical function in older adults.","verification_status":"unverified","notes":"High SHBG in older adults associates with frailty, partly because it tracks low body weight and reduced free androgen exposure. Per-SD HR unverified.","hr_per_sd":1.25,"hr_per_sd_ci":[1.08,1.45]}},"modifiability":{"intervention":"Weight loss and improved insulin sensitivity raise low SHBG; reducing hepatic fat is the main lever.","effect_size":"Significant weight loss can raise SHBG 20-50% in insulin-resistant individuals.","timeframe":"3-6 months","evidence_type":"RCT","citation":"Weight-loss and lifestyle-intervention trials reporting SHBG change.","rating":"moderate"}},{"id":"estradiol","name":"Estradiol","domain":"hormonal","aliases":["E2","17-beta-estradiol"],"profile":{"mechanism":"Estradiol is the dominant estrogen, central to reproductive physiology and with vascular, skeletal, metabolic and neurocognitive actions. Its associations with longevity outcomes depend heavily on sex, menopausal status and the source (endogenous vs exogenous).","measurement":{"method":"LC-MS/MS (preferred for low postmenopausal/male levels) or immunoassay on venous serum.","sample_type":"venous blood","approx_cost_usd":"30-90"},"signal_quality":"noisy","signal_quality_note":"Immunoassays are unreliable at the low concentrations seen in men and postmenopausal women; menstrual-cycle phase causes large variation in premenopausal women.","confounders":["sex and menopausal status","menstrual-cycle phase","exogenous hormones","adiposity (aromatization)","assay sensitivity"],"testing_cadence":"context-dependent; cycle-timed in premenopausal women"},"outcomes":{"all_cause_mortality":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher endogenous estradiol, all-cause mortality, older men","direction":"risk","ci_low":1.02,"ci_high":1.3,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":3000,"followup_years":8,"study":"Older-men cohorts (e.g. MrOS) of endogenous estradiol and mortality.","study_type":"prospective-cohort","citation":"Cohort analyses of endogenous estradiol and mortality in older men (U-shaped pattern reported).","verification_status":"unverified","notes":"In older men estradiol shows a U-shaped mortality relationship (both low and high harmful); in postmenopausal women higher endogenous estradiol associates with breast cancer but not clearly with all-cause mortality. Per-SD HR shown for men; sex-specific and non-monotonic.","hr_per_sd":1.15,"hr_per_sd_ci":[1.02,1.3]},"cvd":{"hr":null,"hr_metric":null,"hr_unit_detail":"complex and sex/route-dependent; endogenous vs exogenous estradiol have divergent CVD associations","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"associations depend on sex, menopausal timing and exogenous vs endogenous source; no single per-SD HR applies","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Hormone-therapy trials (WHI) and endogenous-hormone cohorts give divergent estradiol-CVD relationships.","study_type":"RCT","citation":"Rossouw JE et al. WHI estrogen trials, JAMA 2002/2007; timing-hypothesis analyses.","verification_status":"unverified","notes":"Exogenous estrogen effects on CVD depend on timing (harm if started late after menopause, possible benefit if early); endogenous estradiol cohorts are inconsistent. No defensible single per-SD HR; left unconvertible.","qualitative":true},"cancer":{"hr":1.19,"hr_metric":"per_doubling","hr_unit_detail":"per doubling of endogenous estradiol, postmenopausal breast cancer","direction":"risk","ci_low":1.1,"ci_high":1.28,"comparability":"converted","hr_per_sd_basis":"per_doubling: k = SD of log2(marker) = 0.85 (Approximate SD of log2 endogenous estradiol in postmenopausal women, Endogenous Hormones and Breast Cancer Collaborative Group pooled data.)","conversion":{"log2_sd":0.85,"sd_source":"Approximate SD of log2 endogenous estradiol in postmenopausal women, Endogenous Hormones and Breast Cancer Collaborative Group pooled data."},"evidence_tier":"A","n":6292,"followup_years":10,"study":"Endogenous Hormones and Breast Cancer Collaborative Group, pooled analysis of 9 prospective studies.","study_type":"pooled-cohort","citation":"Endogenous Hormones and Breast Cancer Collaborative Group. Endogenous sex hormones and breast cancer in postmenopausal women. J Natl Cancer Inst 2002;94:606-616. doi:10.1093/jnci/94.8.606","verification_status":"approximate","notes":"Higher endogenous estradiol robustly and probably causally raises postmenopausal breast cancer risk (doubling of estradiol ~ HR 1.2). The per-doubling metric is converted to per-SD using an approximate log2 SD. Specific to postmenopausal women / hormone-sensitive cancer.","hr_per_sd":1.1594,"hr_per_sd_ci":[1.0844,1.2335]},"dementia":null,"frailty":null},"modifiability":{"intervention":"Menopausal hormone therapy raises estradiol; aromatase inhibitors lower it. For longevity outcomes, the route, dose and timing dominate the risk-benefit balance.","effect_size":"Hormone therapy fully restores premenopausal-range estradiol.","timeframe":"Days to weeks","evidence_type":"RCT","citation":"WHI and ELITE/KEEPS hormone-therapy trials.","rating":"high"}},{"id":"progesterone","name":"Progesterone","domain":"hormonal","aliases":["P4"],"profile":{"mechanism":"Progesterone is the principal progestogen, central to the luteal phase and pregnancy, with secondary actions on the brain (neurosteroid), breast and vasculature. Endogenous levels are highly cycle-dependent in premenopausal women and very low otherwise.","measurement":{"method":"Immunoassay or LC-MS/MS on venous serum; must be timed to cycle phase to be interpretable.","sample_type":"venous blood","approx_cost_usd":"25-70"},"signal_quality":"noisy","signal_quality_note":"Extreme within-cycle variation and pulsatile secretion make a single measurement weakly informative for chronic-disease risk.","confounders":["menstrual-cycle phase (major)","pregnancy","exogenous progestogens","menopausal status"],"testing_cadence":"cycle-timed (luteal phase) when assessing ovulation"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD endogenous progesterone, postmenopausal breast cancer (no clear association)","direction":"risk","ci_low":0.85,"ci_high":1.18,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":3000,"followup_years":10,"study":"Endogenous-hormone cohorts examining progesterone and breast cancer.","study_type":"pooled-cohort","citation":"Endogenous-hormone analyses of progesterone and postmenopausal breast cancer (no consistent association).","verification_status":"unverified","notes":"Endogenous progesterone shows no clear association with breast cancer; in contrast, synthetic progestins in combined hormone therapy do raise breast cancer risk (WHI). Recorded as an approximately null endogenous per-SD cell.","hr_per_sd":1,"hr_per_sd_ci":[0.85,1.18]},"dementia":null,"frailty":null},"modifiability":{"intervention":"Exogenous progesterone/progestins are used in hormone therapy and contraception; endogenous progesterone is not a longevity treatment target.","effect_size":"Exogenous dosing fully controls levels.","timeframe":"Days","evidence_type":"RCT","citation":"Hormone-therapy trials (WHI combined arm).","rating":"low"}},{"id":"lh","name":"LH","domain":"hormonal","aliases":["luteinizing hormone"],"profile":{"mechanism":"LH is a pituitary gonadotropin driving gonadal steroidogenesis. Rising LH signals declining gonadal feedback (menopause, primary hypogonadism, aging testes); elevated gonadotropins have been hypothesized to contribute to neurodegeneration.","measurement":{"method":"Immunoassay on venous serum; pulsatile secretion means single values are noisy.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"noisy","signal_quality_note":"Pulsatile secretion (90-120 min pulses) and cycle-phase dependence limit the information in a single measurement.","confounders":["pulsatile secretion","menstrual-cycle phase","menopausal status","GnRH analogues","pituitary disease"],"testing_cadence":"context-dependent; not routine for risk stratification"},"outcomes":{"all_cause_mortality":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher LH, all-cause mortality, older men (weak)","direction":"risk","ci_low":0.98,"ci_high":1.24,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":3000,"followup_years":8,"study":"Older-men cohorts of gonadotropins and mortality.","study_type":"prospective-cohort","citation":"Cohort analyses of LH and mortality in older men (elevated LH as a marker of primary testicular failure).","verification_status":"unverified","notes":"Higher LH in older men weakly associates with mortality, mostly as a marker of primary gonadal failure and poorer health. CI crosses 1; low confidence.","hr_per_sd":1.1,"hr_per_sd_ci":[0.98,1.24]},"cvd":null,"cancer":null,"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":"hypothesized link of elevated gonadotropins to Alzheimer disease; no robust HR","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"no robust prospective HR; mechanistic hypothesis only","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Mechanistic and small clinical studies of gonadotropins and Alzheimer pathology.","study_type":"prospective-cohort","citation":"Casadesus G et al. and others on the gonadotropin hypothesis of Alzheimer disease.","verification_status":"unverified","notes":"An elevated-gonadotropin hypothesis of Alzheimer disease exists but lacks robust prospective HR evidence. Left null/unconvertible.","qualitative":true},"frailty":null},"modifiability":{"intervention":"LH is suppressed by sex-steroid replacement or GnRH analogues; it is not an independent longevity treatment target.","effect_size":"Fully suppressible pharmacologically.","timeframe":"Weeks","evidence_type":"mechanistic","citation":"Endocrine physiology of the HPG axis.","rating":"low"}},{"id":"fsh","name":"FSH","domain":"hormonal","aliases":["follicle-stimulating hormone"],"profile":{"mechanism":"FSH is a pituitary gonadotropin driving gametogenesis; it rises sharply with ovarian aging and the menopausal transition. Beyond the gonad, FSH has been linked experimentally to bone resorption, fat accumulation and possibly atherosclerosis.","measurement":{"method":"Immunoassay on venous serum; less pulsatile than LH so single values are somewhat more stable.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"moderate","signal_quality_note":"More stable than LH but still cycle- and menopausal-status dependent; rises steeply across the menopause transition.","confounders":["menopausal status (major)","menstrual-cycle phase","GnRH analogues","ovarian reserve","pituitary disease"],"testing_cadence":"context-dependent; used to confirm menopausal status"},"outcomes":{"all_cause_mortality":{"hr":1.05,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FSH, all-cause mortality (weak / inconsistent)","direction":"risk","ci_low":0.94,"ci_high":1.18,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":4000,"followup_years":10,"study":"Cohorts of gonadotropins and mortality across the menopausal transition.","study_type":"prospective-cohort","citation":"Cohort analyses of FSH and mortality (associations confounded by age at menopause).","verification_status":"unverified","notes":"FSH has no consistent independent mortality association once age and menopausal timing are accounted for. Recorded as an approximately null per-SD cell.","hr_per_sd":1.05,"hr_per_sd_ci":[0.94,1.18]},"cvd":{"hr":1.12,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FSH, cardiovascular / cardiometabolic risk markers around menopause","direction":"risk","ci_low":1,"ci_high":1.26,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":3000,"followup_years":6,"study":"SWAN and related menopause cohorts linking FSH to adiposity, lipids and subclinical atherosclerosis.","study_type":"prospective-cohort","citation":"El Khoudary SR et al. analyses of FSH and cardiovascular fat/atherosclerosis in the SWAN study.","verification_status":"unverified","notes":"Higher FSH around the menopause transition associates with visceral fat, adverse lipids and subclinical atherosclerosis; whether this is causal or reflects estrogen loss is unresolved. Per-SD HR unverified, borderline CI.","hr_per_sd":1.12,"hr_per_sd_ci":[1,1.26]},"cancer":null,"dementia":null,"frailty":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FSH, bone loss / fracture-related frailty in perimenopausal women","direction":"risk","ci_low":1,"ci_high":1.32,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":2000,"followup_years":5,"study":"SWAN bone substudy and related cohorts linking high FSH to accelerated bone loss.","study_type":"prospective-cohort","citation":"Sowers MR et al. analyses of FSH and bone mineral density across the menopausal transition (SWAN).","verification_status":"unverified","notes":"High FSH predicts accelerated perimenopausal bone loss, a contributor to fracture and physical frailty; experimental work suggests a direct FSH effect on bone. Per-SD HR unverified; borderline CI.","hr_per_sd":1.15,"hr_per_sd_ci":[1,1.32]}},"modifiability":{"intervention":"FSH is suppressed by estrogen/hormone therapy; experimental FSH-blocking antibodies are preclinical. Not currently a clinical treatment target.","effect_size":"Hormone therapy lowers FSH substantially.","timeframe":"Weeks","evidence_type":"mechanistic","citation":"Menopause hormone-therapy pharmacology; preclinical anti-FSH studies.","rating":"low"}},{"id":"igf1","name":"IGF-1","domain":"hormonal","aliases":["insulin-like growth factor 1","somatomedin C"],"comparability_tag":"U-shaped","comparability_note":"IGF-1 has a U-shaped mortality relationship - both low and high levels raise risk - and opposite directions for cancer (higher = risk) versus frailty (lower = risk).","profile":{"mechanism":"IGF-1 mediates most growth-hormone actions and drives the conserved GH/IGF-1/insulin signalling pathway central to longevity biology. Low IGF-1 signalling extends lifespan in model organisms but in humans low IGF-1 also marks frailty; high IGF-1 promotes cell proliferation and cancer risk.","measurement":{"method":"Immunoassay or LC-MS/MS on venous serum; relatively stable through the day, strongly age-dependent.","sample_type":"venous blood","approx_cost_usd":"30-90"},"signal_quality":"moderate","signal_quality_note":"Stable analyte but strongly age- and nutrition-dependent; assays are not fully harmonized, so age-specific reference ranges are essential.","confounders":["age (strong)","nutritional status/protein intake","liver disease","GH disorders","assay standardization"],"testing_cadence":"baseline + every 1-2 years; interpret against age norms"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":null,"hr_unit_detail":"U-shaped: both low and high IGF-1 associate with higher all-cause mortality","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"non-monotonic U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"A","n":30000,"followup_years":12,"study":"UK Biobank and pooled cohorts demonstrating a U-shaped IGF-1 / mortality relationship.","study_type":"prospective-cohort","citation":"Burgers AMG et al. Meta-analysis and meta-regression of IGF-1 and mortality. J Clin Endocrinol Metab 2011;96:2912-2920; UK Biobank IGF-1 analyses doi:10.1210/jc.2011-1377","verification_status":"approximate","notes":"Meta-analysis and UK Biobank both show a U-shaped relationship: lowest mortality at mid-range IGF-1, with excess risk at both low (frailty, illness) and high (cancer, possibly CVD) extremes. A single linear per-SD HR is misleading; flagged unconvertible/non-monotonic.","qualitative":true},"cvd":{"hr":1.15,"hr_metric":"categorical","hr_unit_detail":"lowest vs middle IGF-1 category, ischaemic heart disease / CVD mortality (U-shaped)","direction":"risk","ci_low":1.02,"ci_high":1.3,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":18000,"followup_years":12,"study":"Cohorts (e.g. Framingham, UK Biobank) of IGF-1 and cardiovascular disease.","study_type":"prospective-cohort","citation":"Juul A et al. Low serum IGF-1 and ischaemic heart disease. Circulation 2002;106:939-944; UK Biobank IGF-1-CVD analyses.","verification_status":"approximate","notes":"Low IGF-1 has been linked to ischaemic heart disease, but UK Biobank shows a U-shaped CVD relationship with risk also at high IGF-1. Reported as a category contrast; non-monotonic, not per-SD convertible.","hr_per_sd":null,"hr_per_sd_ci":null},"cancer":{"hr":1.09,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher IGF-1, overall cancer incidence (stronger for breast, prostate, colorectal)","direction":"risk","ci_low":1.04,"ci_high":1.14,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":397000,"followup_years":7,"study":"UK Biobank prospective analysis and Mendelian randomization of IGF-1 and cancer.","study_type":"mendelian-randomization","citation":"Watts EL et al. Circulating insulin-like growth factor-I, total and free testosterone concentrations and prostate cancer risk; and Larsson SC et al. MR of IGF-1 and cancer. doi:10.1002/ijc.32192","verification_status":"approximate","notes":"Higher IGF-1 is consistently and probably causally (MR-supported) associated with higher risk of breast, prostate and colorectal cancer; the per-SD HR for overall cancer is modest (~1.06-1.10). One of the few clearly directional, convertible IGF-1 cells.","hr_per_sd":1.09,"hr_per_sd_ci":[1.04,1.14]},"dementia":{"hr":1.12,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower IGF-1, incident dementia / Alzheimer disease (inconsistent)","direction":"risk","ci_low":0.98,"ci_high":1.28,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":8000,"followup_years":10,"study":"Framingham and other cohorts of IGF-1 and dementia.","study_type":"prospective-cohort","citation":"Westwood AJ et al. Insulin-like growth factor-1 and risk of Alzheimer dementia and brain atrophy. Neurology 2014;82:1613-1619. doi:10.1212/WNL.0000000000000382","verification_status":"approximate","notes":"Framingham found low IGF-1 associated with higher dementia risk and brain atrophy, but other cohorts are null or show the opposite; reverse causation is plausible. CI crosses 1; low confidence.","hr_per_sd":1.12,"hr_per_sd_ci":[0.98,1.28]},"frailty":{"hr":1.22,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower IGF-1, incident frailty / functional decline in older adults","direction":"risk","ci_low":1.07,"ci_high":1.39,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":5000,"followup_years":6,"study":"InCHIANTI and other older-adult cohorts of IGF-1, muscle function and frailty.","study_type":"prospective-cohort","citation":"Cappola AR et al. Multiple hormonal deficiencies in anabolic hormones are associated with frailty in older women. J Clin Endocrinol Metab 2009;94:818-824; InCHIANTI analyses.","verification_status":"approximate","notes":"Low IGF-1 predicts frailty, low muscle strength and mobility limitation, and clusters with low DHEA-S/testosterone as a multi-hormone anabolic deficit. Note the directional conflict with cancer (where higher IGF-1 is the risk direction).","hr_per_sd":1.22,"hr_per_sd_ci":[1.07,1.39]}},"modifiability":{"intervention":"IGF-1 is lowered by protein/calorie restriction and raised by higher protein intake, GH therapy and resistance exercise. There is no consensus optimal target given U-shaped risk.","effect_size":"Protein restriction lowers IGF-1 ~10-25%; GH therapy or high protein raises it.","timeframe":"Weeks to months","evidence_type":"RCT","citation":"Dietary protein/IGF-1 trials; Levine ME et al. low-protein intake and IGF-1, Cell Metab 2014.","rating":"moderate"}},{"id":"igfbp3","name":"IGFBP-3","domain":"hormonal","aliases":["insulin-like growth factor binding protein 3"],"profile":{"mechanism":"IGFBP-3 is the main carrier of circulating IGF-1, regulating its half-life and bioavailability, and also has IGF-independent pro-apoptotic actions. It is interpreted largely in relation to IGF-1 (the IGF-1/IGFBP-3 ratio indexes free IGF-1).","measurement":{"method":"Immunoassay on venous serum; stable analyte.","sample_type":"venous blood","approx_cost_usd":"30-80"},"signal_quality":"moderate","signal_quality_note":"Stable and reproducible, but biologically meaningful chiefly in the context of IGF-1; independent interpretation is limited.","confounders":["age","nutritional status","GH disorders","liver disease","co-variation with IGF-1"],"testing_cadence":"baseline; with IGF-1"},"outcomes":{"all_cause_mortality":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower IGFBP-3, all-cause mortality, older adults (weak)","direction":"risk","ci_low":0.99,"ci_high":1.22,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":8000,"followup_years":10,"study":"Older-adult cohorts of IGFBP-3 and mortality.","study_type":"prospective-cohort","citation":"Cohort analyses of IGFBP-3 and mortality (e.g. Cardiovascular Health Study, Framingham).","verification_status":"unverified","notes":"IGFBP-3 shows a weak, inconsistent mortality association whose direction flips depending on whether IGF-1 is adjusted for. CI crosses 1; low confidence.","hr_per_sd":1.1,"hr_per_sd_ci":[0.99,1.22]},"cvd":null,"cancer":{"hr":0.95,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher IGFBP-3, breast/prostate/colorectal cancer (weak, attenuates on IGF-1 adjustment)","direction":"protective","ci_low":0.89,"ci_high":1.02,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":10000,"followup_years":10,"study":"Pooled hormone-cancer collaborations examining IGFBP-3.","study_type":"pooled-cohort","citation":"Endogenous Hormones and Breast/Prostate Cancer Collaborative analyses of IGF-1 and IGFBP-3.","verification_status":"unverified","notes":"Early reports suggested higher IGFBP-3 protective (by sequestering IGF-1), but pooled analyses show the association is weak and largely disappears after IGF-1 adjustment. CI crosses 1; treat as low confidence.","hr_per_sd":0.95,"hr_per_sd_ci":[0.89,1.02]},"dementia":null,"frailty":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower IGFBP-3, frailty / functional decline in older adults","direction":"risk","ci_low":1,"ci_high":1.33,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":3000,"followup_years":5,"study":"Older-adult cohorts linking low IGFBP-3 (with low IGF-1) to frailty.","study_type":"prospective-cohort","citation":"InCHIANTI and related analyses of the IGF system and physical function.","verification_status":"unverified","notes":"Low IGFBP-3 tracks low IGF-1 and frailty, but adds little independent information beyond IGF-1. Per-SD HR unverified, borderline CI.","hr_per_sd":1.15,"hr_per_sd_ci":[1,1.33]}},"modifiability":{"intervention":"IGFBP-3 rises with GH therapy and varies with nutrition; it is not an independent treatment target.","effect_size":"Modest changes with GH/nutritional manipulation.","timeframe":"Weeks to months","evidence_type":"observational","citation":"GH-therapy and nutritional studies reporting IGFBP-3.","rating":"low"}},{"id":"growth_hormone","name":"Growth hormone","domain":"hormonal","aliases":["GH","somatotropin","human growth hormone"],"profile":{"mechanism":"Growth hormone, secreted in pulses by the pituitary, drives IGF-1 production and has direct lipolytic and anti-insulin actions. Both GH excess (acromegaly) and severe deficiency shorten life, while reduced GH/IGF-1 signalling extends lifespan in model organisms - a central paradox of longevity biology.","measurement":{"method":"Random serum GH is rarely useful; assessment requires stimulation or suppression tests, or measuring IGF-1 as a stable proxy.","sample_type":"venous blood","approx_cost_usd":"30-200"},"signal_quality":"noisy","signal_quality_note":"Pulsatile secretion (peaks mostly in slow-wave sleep) and a ~15-minute half-life mean a single random GH value carries little information; dynamic testing is needed.","confounders":["pulsatile secretion","sleep/exercise/fasting (acute peaks)","age","adiposity (blunts GH)","assay standardization"],"testing_cadence":"not measured as a single value; dynamic testing only when GH disorder suspected"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":null,"hr_unit_detail":"non-monotonic and not capturable as a single random level; both acromegaly and severe GH deficiency raise mortality","direction":"risk","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"pulsatile hormone with no meaningful single-value SD; mortality evidence is from disease states, not a continuous per-SD exposure","conversion":null,"evidence_tier":"B","n":null,"followup_years":null,"study":"Acromegaly and adult GH-deficiency cohorts; GH/IGF-1 longevity-genetics studies.","study_type":"prospective-cohort","citation":"Holdaway IM et al. Mortality in acromegaly meta-analysis, Eur J Endocrinol 2008; and GH-deficiency mortality cohorts.","verification_status":"approximate","notes":"Acromegaly roughly doubles mortality (largely reversible with biochemical control); untreated adult GH deficiency also raises mortality. Reduced GH/IGF-1 signalling is associated with exceptional longevity in some genetic studies. GH cannot be expressed as a single per-SD exposure; flagged unconvertible/non-monotonic.","qualitative":true},"cvd":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"GH excess (acromegaly) raises cardiovascular mortality; not a continuous per-SD exposure","direction":"risk","ci_low":null,"ci_high":null,"comparability":"categorical","hr_per_sd_basis":"evidence is from the acromegaly disease state; no continuous per-SD HR","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Acromegaly outcome cohorts (cardiomyopathy, hypertension, cardiovascular death).","study_type":"prospective-cohort","citation":"Acromegaly mortality and cardiovascular-outcome literature (e.g. Holdaway IM et al.).","verification_status":"unverified","notes":"GH excess causes acromegalic cardiomyopathy and excess cardiovascular death, reversible with treatment; this is a disease-state, categorical relationship, not a per-SD biomarker exposure.","qualitative":true},"cancer":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"acromegaly associates with increased colorectal (and some other) cancer risk; not a continuous per-SD exposure","direction":"risk","ci_low":null,"ci_high":null,"comparability":"categorical","hr_per_sd_basis":"evidence is from the acromegaly disease state; no continuous per-SD HR","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Acromegaly registries reporting colorectal and overall cancer incidence.","study_type":"prospective-cohort","citation":"Acromegaly cancer-incidence literature; GH/IGF-1 axis and cancer reviews.","verification_status":"unverified","notes":"Acromegaly is associated with modestly increased colorectal cancer risk, consistent with the IGF-1/cancer link; this is a disease-state categorical association, not a per-SD GH exposure.","qualitative":true},"dementia":null,"frailty":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"severe adult GH deficiency associates with reduced lean mass and physical function; GH therapy of healthy elderly not beneficial","direction":"risk","ci_low":null,"ci_high":null,"comparability":"categorical","hr_per_sd_basis":"evidence is from the GH-deficiency disease state; no continuous per-SD HR","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Adult GH-deficiency cohorts and trials of GH in healthy older adults.","study_type":"RCT","citation":"Liu H et al. Systematic review: the safety and efficacy of growth hormone in the healthy elderly. Ann Intern Med 2007;146:104-115.","verification_status":"unverified","notes":"Severe GH deficiency reduces lean mass and function; however GH therapy in healthy older adults produces small body-composition changes with frequent adverse effects and no functional benefit. Disease-state categorical relationship, not a per-SD exposure.","qualitative":true}},"modifiability":{"intervention":"GH excess is treated with surgery, somatostatin analogues or GH-receptor antagonists; GH deficiency with GH replacement. GH supplementation in healthy older adults is not recommended.","effect_size":"Disease-state GH is fully treatable; in healthy aging, GH supplementation gives small body-composition change with notable adverse effects.","timeframe":"Months","evidence_type":"RCT meta-analysis","citation":"Liu H et al. Ann Intern Med 2007;146:104-115; acromegaly treatment guidelines.","rating":"low"}},{"id":"melatonin","name":"Melatonin","domain":"hormonal","aliases":["N-acetyl-5-methoxytryptamine"],"profile":{"mechanism":"Melatonin, secreted nocturnally by the pineal gland, is the principal circadian signal and a direct antioxidant. Nocturnal melatonin output declines with age and with light-at-night exposure; low or mistimed melatonin is implicated in circadian disruption, metabolic dysfunction and possibly hormone-sensitive cancer.","measurement":{"method":"Overnight urinary 6-sulfatoxymelatonin (aMT6s, an integrated measure) or timed salivary/plasma melatonin; a single daytime value is uninformative.","sample_type":"urine","approx_cost_usd":"40-150"},"signal_quality":"noisy","signal_quality_note":"Strong circadian variation means the result depends entirely on sampling timing; light exposure, age and beta-blockers strongly affect levels.","confounders":["sampling timing","light-at-night/shift work","age","beta-blockers/NSAIDs","exogenous melatonin"],"testing_cadence":"timed overnight collection when assessed at all"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":null,"hr_unit_detail":"no robust prospective per-SD estimate of endogenous melatonin and all-cause mortality","direction":"protective","ci_low":null,"ci_high":null,"comparability":"unconvertible","hr_per_sd_basis":"sparse evidence; no usable prospective per-SD HR for endogenous melatonin and mortality","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No adequately powered cohort isolates endogenous melatonin output as an all-cause mortality predictor.","study_type":"prospective-cohort","citation":"Circadian-disruption and melatonin reviews; no defensible mortality cohort estimate.","verification_status":"unverified","notes":"Circadian disruption (a downstream of low/mistimed melatonin) is linked to worse health, but there is no robust prospective per-SD HR for endogenous melatonin and all-cause mortality. Left null.","qualitative":true},"cvd":{"hr":1.27,"hr_metric":"tertile","hr_unit_detail":"lowest vs highest tertile of nocturnal melatonin secretion (urinary aMT6s), incident hypertension / cardiovascular risk","direction":"risk","ci_low":1.01,"ci_high":1.61,"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":1100,"followup_years":8,"study":"Nurses' Health Study analysis of nocturnal melatonin secretion and incident hypertension.","study_type":"prospective-cohort","citation":"Obayashi K et al. and McMullan CJ et al. Melatonin secretion and incident hypertension among women. JAMA 2013;309:1388-1396. doi:10.1001/jama.2013.2710","verification_status":"approximate","notes":"Lower nocturnal melatonin secretion was associated with higher incident hypertension in women; cardiovascular-event data are thinner. Tertile contrast converted under a normal approximation; single cohort, association only.","hr_per_sd":1.1159,"hr_per_sd_ci":[1.0046,1.2442]},"cancer":{"hr":1.14,"hr_metric":"tertile","hr_unit_detail":"lowest vs highest tertile of urinary melatonin (aMT6s), breast cancer incidence","direction":"risk","ci_low":0.95,"ci_high":1.37,"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":4000,"followup_years":9,"study":"Pooled nested case-control analyses of urinary melatonin and breast cancer (Nurses' Health, EPIC, others).","study_type":"pooled-cohort","citation":"Schernhammer ES et al. Urinary 6-sulfatoxymelatonin levels and risk of breast cancer in postmenopausal women. J Natl Cancer Inst 2008;100:898-905. doi:10.1093/jnci/djn171","verification_status":"approximate","notes":"Lower urinary melatonin has been associated with higher breast cancer risk in several cohorts, consistent with the light-at-night hypothesis, though results are not fully consistent and CI here crosses 1. Tertile contrast converted; association only.","hr_per_sd":1.0619,"hr_per_sd_ci":[0.9767,1.1554]},"dementia":null,"frailty":null},"modifiability":{"intervention":"Light hygiene (bright light by day, darkness at night), consistent sleep timing and limiting light-at-night support endogenous melatonin; exogenous melatonin supplements circadian signalling but does not restore the endogenous rhythm.","effect_size":"Behavioral measures modestly preserve nocturnal output; exogenous melatonin reliably shifts circadian timing.","timeframe":"Days to weeks","evidence_type":"RCT","citation":"Circadian light-therapy and melatonin RCTs.","rating":"moderate"}},{"id":"dexa_body_fat_pct","name":"DEXA total body fat %","domain":"body_composition","aliases":["DXA body fat percentage","percent body fat","%BF","total adiposity"],"profile":{"mechanism":"Total body fat percentage measured by dual-energy X-ray absorptiometry quantifies whole-body adiposity directly, separating fat mass from lean and bone. Excess adiposity drives insulin resistance, chronic low-grade inflammation, adipokine dysregulation and ectopic lipid deposition, all of which accelerate cardiometabolic disease and biological aging; however very low fat mass in older adults often signals occult illness, wasting and frailty.","measurement":{"method":"Whole-body dual-energy X-ray absorptiometry scan; three-compartment estimation of fat, lean and bone mass with low radiation dose.","sample_type":"imaging","approx_cost_usd":"75-200"},"signal_quality":"clean","signal_quality_note":"DXA is a precise, low-variability reference method for body fat with excellent reproducibility; minor between-machine and software-version differences exist but within-person tracking is reliable.","confounders":["reverse causation (illness-related fat loss in older adults)","hydration status of lean compartment","scanner/software differences","age- and sex-dependent reference ranges","fat distribution not captured by total %"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher DXA total body fat %, all-cause mortality; relationship is U-shaped so the linear per-SD slope is near-null","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1,"hr_per_sd_ci":null,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"multiple cohorts","followup_years":10,"study":"NHANES and pooled DXA cohorts show U-/J-shaped relation of total body fat % with all-cause mortality.","study_type":"prospective-cohort","citation":"Padwal R et al. Relationship among body fat percentage, body mass index, and all-cause mortality: a cohort study. Ann Intern Med 2016;164:532-541. doi:10.7326/M15-1181","verification_status":"approximate","notes":"Total body fat % relates to all-cause mortality in a U-/J-shaped manner: high adiposity raises cardiometabolic mortality while low fat mass tracks wasting, sarcopenia and occult disease in older adults. A single linear per-SD HR is not meaningful; flagged unconvertible. Visceral and central fat measures (VAT, waist) are more monotonically associated with mortality than total fat %."},"cvd":{"hr":1.21,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher DXA-measured total body fat %, incident cardiovascular disease, adjusted","direction":"risk","ci_low":1.13,"ci_high":1.3,"hr_per_sd":1.21,"hr_per_sd_ci":[1.13,1.3],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":491773,"followup_years":12,"study":"UK Biobank prospective cohort, body composition (bioimpedance/DXA-calibrated) and incident CVD.","study_type":"prospective-cohort","citation":"UK Biobank body fat distribution and incident cardiovascular disease analyses; e.g. Iliodromiti S et al. Eur Heart J 2018;39:1514-1520. doi:10.1093/eurheartj/ehy057","verification_status":"approximate","notes":"Higher total body fat % associates positively and approximately linearly with incident CVD across the usual adult range. Per-SD HR is approximate, pooled from UK Biobank-type analyses; visceral/central adiposity carries a stronger CVD signal than total fat % for a given BMI."},"cancer":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher total body fat %, total obesity-related cancer incidence, adjusted","direction":"risk","ci_low":1.05,"ci_high":1.16,"hr_per_sd":1.1,"hr_per_sd_ci":[1.05,1.16],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":442519,"followup_years":9,"study":"UK Biobank prospective cohort, body fat percentage and incident cancer.","study_type":"prospective-cohort","citation":"UK Biobank adiposity and cancer incidence analyses; consistent with IARC Working Group on body fatness and cancer (Lauby-Secretan B et al. N Engl J Med 2016;375:794-798).","verification_status":"unverified","notes":"Total body fat % associates modestly with obesity-related cancers (endometrial, postmenopausal breast, colorectal, kidney, esophageal adenocarcinoma, others); IARC concluded body fatness is causally linked to ~13 cancer types. The aggregate per-SD HR is modest because total cancer pools fat-sensitive and fat-neutral sites; per-SD figure is unverified and indicative."},"dementia":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher total body fat %, incident dementia; relationship is age-dependent and U-shaped","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1,"hr_per_sd_ci":null,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"multiple cohorts","followup_years":15,"study":"Pooled life-course adiposity-dementia cohorts show midlife risk but late-life inverse association.","study_type":"prospective-cohort","citation":"Albanese E et al. Body mass index in midlife and dementia: systematic review and meta-regression. Alzheimers Dement (Amst) 2017;8:165-178. doi:10.1016/j.dadm.2017.05.007","verification_status":"unverified","notes":"Adiposity and dementia show a time-varying relationship: higher midlife adiposity raises later dementia risk, but weight/fat loss in the years before diagnosis (prodromal) produces an apparent late-life protective association (reverse causation). No single linear per-SD HR is defensible for total body fat %; flagged unconvertible. Direct DXA fat %–dementia evidence is sparse."},"frailty":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher total body fat %, incident frailty; both high adiposity and very low fat mass raise risk","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":1,"hr_per_sd_ci":null,"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"multiple cohorts","followup_years":8,"study":"Cohorts of older adults link both high body fat (sarcopenic obesity) and low fat mass to incident frailty.","study_type":"prospective-cohort","citation":"Reviews of obesity, sarcopenic obesity and frailty in older adults; e.g. Hubbard RE et al. and sarcopenic-obesity consensus literature.","verification_status":"unverified","notes":"Frailty risk is elevated at both extremes of body fat: high adiposity (often sarcopenic obesity, with excess fat and low muscle) impairs physical function, while low fat mass marks wasting and undernutrition. The relationship is U-shaped; no defensible linear per-SD slope, flagged unconvertible. Evidence specific to DXA fat % is limited."}},"modifiability":{"intervention":"Caloric restriction / dietary change plus aerobic and resistance exercise; GLP-1 receptor agonists (semaglutide, tirzepatide) and bariatric surgery for substantial reductions.","effect_size":"Lifestyle programs reduce total body fat ~3-8% of body weight; GLP-1/GIP agonists reduce fat mass 10-20%+; bariatric surgery 20-30%+.","timeframe":"3-12 months for meaningful change","evidence_type":"RCT meta-analysis","citation":"Look AHEAD lifestyle trial; STEP (semaglutide) and SURMOUNT (tirzepatide) RCT programs; bariatric surgery cohorts.","rating":"high"}},{"id":"visceral_adipose_tissue","name":"Visceral adipose tissue (VAT)","domain":"body_composition","aliases":["VAT","visceral fat","intra-abdominal fat","visceral fat area","visceral fat mass"],"profile":{"mechanism":"Visceral adipose tissue is metabolically active fat surrounding the abdominal organs. It drains via the portal vein, delivering free fatty acids and pro-inflammatory adipokines (TNF-alpha, IL-6, resistin) directly to the liver, driving hepatic insulin resistance, dyslipidemia, systemic inflammation and ectopic lipid deposition. VAT is the most pathogenic fat depot and predicts cardiometabolic disease beyond total adiposity or BMI.","measurement":{"method":"Direct quantification by DXA visceral fat algorithm, abdominal CT or MRI; estimated by some bioimpedance devices. CT/MRI are reference standards.","sample_type":"imaging","approx_cost_usd":"75-500"},"signal_quality":"clean","signal_quality_note":"CT/MRI and DXA visceral algorithms quantify VAT precisely with low measurement error; bioimpedance estimates are noisier. Strong, depot-specific pathophysiologic signal.","confounders":["sex (men accumulate more VAT)","age","ethnicity (Asian populations higher VAT at given BMI)","menopausal status","reverse causation in advanced illness","measurement modality differences"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1.21,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher visceral adipose tissue area/mass, all-cause mortality, adjusted for BMI","direction":"risk","ci_low":1.11,"ci_high":1.32,"hr_per_sd":1.21,"hr_per_sd_ci":[1.11,1.32],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled imaging cohorts","followup_years":10,"study":"Meta-analysis / pooled imaging cohorts of CT/DXA-measured visceral fat and all-cause mortality.","study_type":"meta-analysis","citation":"Liu B et al. and pooled analyses of visceral adiposity and mortality; consistent with Kuk JL et al. Visceral fat is an independent predictor of all-cause mortality in men. Obesity 2006;14:336-341. doi:10.1038/oby.2006.43","verification_status":"approximate","notes":"Higher VAT independently predicts all-cause mortality even after adjusting for BMI or total fat, indicating depot-specific risk. Per-SD estimate is approximate, pooled across CT/DXA cohorts; magnitude is consistent with central-obesity (waist) mortality data. Stronger and more monotone than total body fat %."},"cvd":{"hr":1.32,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher visceral adipose tissue, incident cardiovascular disease, adjusted","direction":"risk","ci_low":1.21,"ci_high":1.44,"hr_per_sd":1.32,"hr_per_sd_ci":[1.21,1.44],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"pooled cohorts + MR","followup_years":10,"study":"Framingham/MESA-type imaging cohorts and Mendelian randomization of genetically predicted visceral fat.","study_type":"mendelian-randomization","citation":"Karlsson T et al. Contribution of genetics to visceral adiposity and its relation to cardiovascular and metabolic disease. Nat Med 2019;25:1390-1395. doi:10.1038/s41591-019-0563-7","verification_status":"approximate","notes":"VAT is a strong and likely causal CVD risk factor: imaging cohorts (Framingham, MESA) show per-SD HRs ~1.3 for incident CVD, and Mendelian randomization of genetically predicted visceral fat confirms a causal effect on coronary disease, heart failure and type 2 diabetes. Per-SD estimate approximate; directionally robust and causal."},"cancer":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher visceral adipose tissue, obesity-related cancer incidence, adjusted","direction":"risk","ci_low":1.1,"ci_high":1.31,"hr_per_sd":1.2,"hr_per_sd_ci":[1.1,1.31],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"pooled imaging cohorts","followup_years":9,"study":"Imaging cohorts of CT/MRI-measured visceral fat and incident colorectal and other obesity-related cancers.","study_type":"prospective-cohort","citation":"Cao Y et al. and meta-analyses of visceral adiposity and colorectal/postmenopausal cancers; e.g. systematic reviews of visceral fat area and cancer risk.","verification_status":"unverified","notes":"Visceral fat associates with colorectal, postmenopausal breast, pancreatic and other obesity-related cancers, often more strongly than BMI; insulin resistance, IGF-1 axis activation and adipokine signaling are proposed mechanisms. Per-SD HR is unverified and pooled across heterogeneous imaging studies; evidence is less mature than for CVD."},"dementia":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher visceral/abdominal fat, incident dementia or worse cognitive aging, midlife exposure","direction":"risk","ci_low":1.04,"ci_high":1.27,"hr_per_sd":1.15,"hr_per_sd_ci":[1.04,1.27],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"neuroimaging + dementia cohorts","followup_years":15,"study":"Midlife visceral/abdominal adiposity and later cognitive decline / dementia and brain-aging neuroimaging studies.","study_type":"prospective-cohort","citation":"Studies linking midlife visceral adiposity to amyloid PET, brain atrophy and dementia risk; e.g. Dolatshahi M et al. (Washington University midlife visceral fat and Alzheimer pathology, 2024).","verification_status":"unverified","notes":"Midlife visceral adiposity associates with greater brain amyloid burden, lower brain volume and higher dementia risk, plausibly via insulin resistance and neuroinflammation. Visceral fat avoids some of the reverse-causation problem of late-life weight loss seen with BMI, but direct VAT–incident-dementia evidence remains limited. Per-SD HR unverified and indicative."},"frailty":{"hr":1.18,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher visceral adipose tissue, incident frailty / physical-function decline in older adults","direction":"risk","ci_low":1.05,"ci_high":1.32,"hr_per_sd":1.18,"hr_per_sd_ci":[1.05,1.32],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"older-adult cohorts","followup_years":7,"study":"Cohorts of older adults linking visceral fat and sarcopenic obesity to incident frailty and disability.","study_type":"prospective-cohort","citation":"Studies of visceral adiposity, sarcopenic obesity and frailty/physical function in aging cohorts (e.g. Health ABC and similar).","verification_status":"unverified","notes":"Higher visceral fat, especially when combined with low muscle mass (sarcopenic obesity), predicts incident frailty and physical-function decline via inflammation, insulin resistance and mechanical/metabolic burden. Per-SD HR is unverified; evidence is observational and modest. Unlike total fat %, the VAT–frailty association is more monotone (low VAT is rarely a frailty signal)."}},"modifiability":{"intervention":"Caloric restriction, low-refined-carbohydrate diet, and especially aerobic exercise preferentially mobilize visceral fat; GLP-1/GIP agonists and bariatric surgery produce large VAT reductions.","effect_size":"Aerobic exercise without weight loss can reduce VAT ~6-10%; combined lifestyle 15-30%; GLP-1 agonists and bariatric surgery reduce VAT substantially more than subcutaneous fat.","timeframe":"3-6 months","evidence_type":"RCT meta-analysis","citation":"Meta-analyses of exercise and visceral fat (Vissers D et al. PLoS One 2013); STEP/SURMOUNT GLP-1 imaging substudies.","rating":"high"}},{"id":"bone_mineral_density","name":"Bone mineral density","domain":"body_composition","aliases":["BMD","DXA bone density","femoral neck BMD","T-score"],"profile":{"mechanism":"Bone mineral density reflects skeletal mineral mass per unit area and is the principal determinant of bone strength and fracture resistance. Low BMD (osteopenia/osteoporosis) is both a direct cause of fragility fractures and a marker of systemic aging, low physical activity, undernutrition, inflammation and hormonal decline. Fractures, particularly hip fractures, are followed by sharply elevated mortality and loss of independence.","measurement":{"method":"Dual-energy X-ray absorptiometry of the lumbar spine and proximal femur; reported as areal density (g/cm2) and as T-score / Z-score relative to a reference population.","sample_type":"imaging","approx_cost_usd":"75-150"},"signal_quality":"clean","signal_quality_note":"DXA BMD is a precise, well-standardized measurement with low short-term variability and validated reference databases; degenerative spine changes can spuriously raise lumbar BMD in older adults.","confounders":["spinal osteoarthritis/calcification (spuriously raises lumbar BMD)","age and sex reference effects","body size (areal BMD partly size-dependent)","glucocorticoid use","reverse causation (illness-related bone loss)"],"testing_cadence":"baseline + every 2 years (more frequent on treatment)"},"outcomes":{"all_cause_mortality":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower femoral neck/total hip bone mineral density, all-cause mortality, adjusted","direction":"protective","ci_low":1.13,"ci_high":1.28,"hr_per_sd":1.2,"hr_per_sd_ci":[1.13,1.28],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled cohorts","followup_years":12,"study":"Meta-analysis / pooled prospective cohorts of BMD and all-cause mortality.","study_type":"meta-analysis","citation":"Qu X et al. Bone mineral density and all-cause, cardiovascular and stroke mortality: a meta-analysis of prospective cohort studies. Int J Cardiol 2013;166:385-393. doi:10.1016/j.ijcard.2011.10.114","verification_status":"approximate","notes":"Lower BMD is associated with higher all-cause mortality (~20% per SD lower), partly through fragility fractures and partly because low BMD marks frailty, inactivity and systemic illness. Direction is protective (higher BMD lower risk). Per-SD estimate is approximate. Some residual confounding by general health status is likely."},"cvd":{"hr":1.24,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower bone mineral density, cardiovascular / stroke mortality, adjusted","direction":"protective","ci_low":1.12,"ci_high":1.38,"hr_per_sd":1.24,"hr_per_sd_ci":[1.12,1.38],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled cohorts","followup_years":12,"study":"Meta-analysis of prospective cohorts of BMD and cardiovascular/stroke mortality.","study_type":"meta-analysis","citation":"Veronese N et al. Relationship between low bone mineral density and fractures with incident cardiovascular disease: a systematic review and meta-analysis. J Bone Miner Res 2017;32:1126-1135. doi:10.1002/jbmr.3089","verification_status":"approximate","notes":"Low BMD is associated with higher cardiovascular disease and stroke risk/mortality; shared mechanisms (vascular calcification, inflammation, vitamin D and estrogen pathways, shared aging) are proposed but causality is unproven and confounding by frailty is likely. Per-SD estimate approximate."},"cancer":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no consistent independent association of BMD with cancer incidence/mortality","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no consistent usable evidence — BMD is not an established cancer predictor","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No consistent prospective evidence linking BMD to overall cancer risk independent of confounders.","study_type":"prospective-cohort","citation":"No established meta-analytic association; bidirectional findings exist (e.g. higher BMD weakly linked to breast cancer via lifetime estrogen exposure).","verification_status":"unverified","notes":"There is no consistent, defensible association between BMD and overall cancer incidence or mortality. Some studies link higher BMD to slightly higher breast cancer risk (a shared marker of lifetime estrogen exposure rather than a causal effect of bone density), while low BMD can follow cancer treatment. No usable per-SD HR; cell left null.","qualitative":true},"dementia":{"hr":1.21,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower bone mineral density, incident dementia, adjusted","direction":"protective","ci_low":1.08,"ci_high":1.35,"hr_per_sd":1.21,"hr_per_sd_ci":[1.08,1.35],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":3651,"followup_years":11,"study":"Rotterdam Study prospective cohort, bone mineral density and incident dementia.","study_type":"prospective-cohort","citation":"Xiao T et al. Association of bone mineral density and dementia: the Rotterdam Study. Neurology 2023;100:e2125-e2133. doi:10.1212/WNL.0000000000207220","verification_status":"approximate","notes":"The Rotterdam Study found lower baseline BMD associated with higher 10-year dementia risk (lowest vs highest tertile of femoral neck BMD HR ~1.42). The association is widely interpreted as reverse causation or shared decline: preclinical dementia causes inactivity, weight loss and bone loss before diagnosis. Per-SD estimate approximate; not considered causal."},"frailty":{"hr":1.4,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower bone mineral density, incident frailty / fragility fracture, older adults","direction":"protective","ci_low":1.28,"ci_high":1.53,"hr_per_sd":1.4,"hr_per_sd_ci":[1.28,1.53],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"pooled cohorts","followup_years":10,"study":"Pooled prospective cohorts of BMD and fracture (the dominant frailty pathway); BMD is a core fracture-prediction input (FRAX).","study_type":"meta-analysis","citation":"Marshall D et al. Meta-analysis of how well measures of bone mineral density predict occurrence of osteoporotic fractures. BMJ 1996;312:1254-1259. doi:10.1136/bmj.312.7041.1254; Kanis JA et al. FRAX.","verification_status":"approximate","notes":"BMD is one of the strongest predictors of fragility fracture: each 1 SD decrease in femoral neck BMD roughly doubles hip-fracture risk (relative risk ~2.6 per SD for hip BMD predicting hip fracture). Fracture is the central driver of frailty, disability and loss of independence in older adults. The per-SD HR shown is a conservative composite for frailty/fracture risk; the site-specific hip-fracture gradient is steeper. Strong, well-replicated evidence."}},"modifiability":{"intervention":"Resistance and weight-bearing exercise, adequate calcium and vitamin D, and pharmacotherapy (bisphosphonates, denosumab, anabolic agents teriparatide/romosozumab) for osteoporosis.","effect_size":"Antiresorptive drugs raise BMD ~3-8% over 1-3 years and cut fracture risk 30-70%; exercise produces smaller (~1-3%) BMD gains but improves fall risk.","timeframe":"1-3 years for BMD change; fracture-risk reduction within 1 year on potent agents","evidence_type":"RCT meta-analysis","citation":"FIT (alendronate), FREEDOM (denosumab), FRAME (romosozumab) RCTs; Cochrane reviews of exercise and BMD.","rating":"high"}},{"id":"waist_circumference","name":"Waist circumference","domain":"body_composition","aliases":["WC","abdominal circumference","central adiposity"],"profile":{"mechanism":"Waist circumference is a simple anthropometric proxy for central (abdominal) adiposity, capturing both visceral and subcutaneous abdominal fat. Central fat is the metabolically harmful depot, driving insulin resistance, dyslipidemia, hypertension and systemic inflammation. Waist circumference predicts cardiometabolic disease and mortality more strongly and more monotonically than BMI, especially within normal-BMI ranges.","measurement":{"method":"Tape measure at the midpoint between the lowest rib and iliac crest (or at the umbilicus per protocol); requires standardized technique.","sample_type":"in-office device","approx_cost_usd":"0-5"},"signal_quality":"moderate","signal_quality_note":"Inexpensive and predictive, but measurement site and observer technique vary, and it does not separate visceral from subcutaneous fat; standardized protocols improve reliability.","confounders":["measurement site/protocol differences","observer technique","respiratory phase / posture","sex and ethnicity (different risk thresholds)","reverse causation in advanced illness"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1.07,"hr_metric":"per_unit","hr_unit_detail":"per 5 cm higher waist circumference, all-cause mortality, adjusted for BMI","direction":"risk","ci_low":1.05,"ci_high":1.09,"hr_per_sd":1.1988,"hr_per_sd_ci":[1.1397,1.2598],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 13.4 (Pooled adult waist circumference SD ~13-14 cm (NHANES / large cohort consortium distributions)); k = SD/unit = 2.68","conversion":{"unit_value":5,"population_sd":13.4,"sd_source":"Pooled adult waist circumference SD ~13-14 cm (NHANES / large cohort consortium distributions)","log2_sd":null},"evidence_tier":"A","n":650000,"followup_years":14,"study":"Pooled analysis of 11 prospective cohort studies (~650,000 adults) of waist circumference and mortality.","study_type":"pooled-cohort","citation":"Cerhan JR et al. A pooled analysis of waist circumference and mortality in 650,000 adults. Mayo Clin Proc 2014;89:335-345. doi:10.1016/j.mayocp.2013.11.011","verification_status":"approximate","notes":"This large pooled analysis found waist circumference positively and roughly linearly associated with all-cause mortality even after adjusting for BMI; each 5 cm increment raised mortality ~7%, with the highest vs lowest waist categories carrying ~50-80% higher risk. Per-5cm HR converted to per-SD using a pooled adult waist SD of ~13.4 cm. Monotone, unlike BMI."},"cvd":{"hr":1.16,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher waist circumference, incident cardiovascular disease, adjusted","direction":"risk","ci_low":1.13,"ci_high":1.2,"hr_per_sd":1.16,"hr_per_sd_ci":[1.13,1.2],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":220000,"followup_years":10,"study":"Emerging Risk Factors Collaboration individual-participant meta-analysis of adiposity measures and CVD.","study_type":"meta-analysis","citation":"Emerging Risk Factors Collaboration (Wormser D et al.). Separate and combined associations of body-mass index and abdominal adiposity with cardiovascular disease. Lancet 2011;377:1085-1095. doi:10.1016/S0140-6736(11)60105-0","verification_status":"verified","notes":"ERFC pooled ~220,000 adults and reported per-SD HRs for waist circumference and incident CVD of ~1.16 after adjustment; waist circumference, waist:hip ratio and BMI carried similar CVD information once any one was known, but waist measures were more linearly associated. Native per-SD figure used as-is."},"cancer":{"hr":1.11,"hr_metric":"per_unit","hr_unit_detail":"per 11 cm higher waist circumference, obesity-related cancer incidence (composite), adjusted","direction":"risk","ci_low":1.07,"ci_high":1.15,"hr_per_sd":1.1356,"hr_per_sd_ci":[1.0859,1.1856],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 11; population SD 13.4 (Pooled adult waist circumference SD ~13-14 cm (EPIC / large cohort distributions)); k = SD/unit = 1.218","conversion":{"unit_value":11,"population_sd":13.4,"sd_source":"Pooled adult waist circumference SD ~13-14 cm (EPIC / large cohort distributions)","log2_sd":null},"evidence_tier":"B","n":43000,"followup_years":12,"study":"EPIC and pooled prospective cohorts of waist circumference and obesity-related cancers.","study_type":"prospective-cohort","citation":"Freisling H et al. Comparison of general obesity and measures of body fat distribution in older adults in relation to cancer risk: a pooled analysis. Br J Cancer 2017;116:1486-1497. doi:10.1038/bjc.2017.106","verification_status":"approximate","notes":"Waist circumference is associated with obesity-related cancers (colorectal, postmenopausal breast, endometrial, pancreatic, others); pooled cohorts reported HRs around 1.11 per ~11 cm for composite obesity-related cancer. Per-unit HR converted to per-SD with a pooled adult waist SD of ~13.4 cm. Unit size for the underlying study is approximate."},"dementia":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher midlife waist circumference, incident dementia, adjusted","direction":"risk","ci_low":1.02,"ci_high":1.19,"hr_per_sd":1.1,"hr_per_sd_ci":[1.02,1.19],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":6583,"followup_years":27,"study":"Kaiser Permanente midlife central obesity and dementia cohort.","study_type":"prospective-cohort","citation":"Whitmer RA et al. Central obesity and increased risk of dementia more than three decades later. Neurology 2008;71:1057-1064. doi:10.1212/01.wnl.0000306313.89165.ef","verification_status":"approximate","notes":"Higher midlife central obesity (sagittal abdominal diameter / waist) was associated with greater dementia risk decades later, independent of overall obesity and comorbidities. Late-life waist–dementia associations are confounded by prodromal weight loss; the midlife signal is more credible. Per-SD HR approximate; evidence is observational and limited."},"frailty":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher waist circumference, incident frailty in older adults, adjusted","direction":"risk","ci_low":1.08,"ci_high":1.33,"hr_per_sd":1.2,"hr_per_sd_ci":[1.08,1.33],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"older-adult cohorts","followup_years":8,"study":"Prospective cohorts of older adults linking abdominal obesity to incident frailty.","study_type":"prospective-cohort","citation":"Meta-analyses and cohort studies of abdominal obesity / waist circumference and frailty in older adults (e.g. systematic reviews of central obesity and frailty).","verification_status":"unverified","notes":"Higher waist circumference predicts incident frailty in older adults, often more consistently than BMI, via inflammation, insulin resistance and sarcopenic obesity. Per-SD HR is unverified and pooled across heterogeneous studies; the waist–frailty association is more monotone than BMI–frailty (low waist is rarely a frailty signal)."}},"modifiability":{"intervention":"Caloric restriction, reduced refined-carbohydrate intake, aerobic and resistance exercise; GLP-1/GIP agonists and bariatric surgery for large reductions.","effect_size":"Lifestyle programs reduce waist circumference ~3-7 cm; GLP-1/GIP agonists 7-15+ cm; bariatric surgery substantially more.","timeframe":"3-6 months","evidence_type":"RCT meta-analysis","citation":"Look AHEAD and Diabetes Prevention Program lifestyle trials; STEP/SURMOUNT GLP-1/GIP RCTs.","rating":"high"}},{"id":"waist_hip_ratio","name":"Waist:hip ratio","domain":"body_composition","aliases":["WHR","waist-to-hip ratio"],"profile":{"mechanism":"Waist:hip ratio contrasts central (abdominal) fat against gluteofemoral fat. A high ratio reflects an android, visceral-predominant fat pattern, whereas gluteofemoral (hip) fat is metabolically protective. WHR therefore captures fat distribution rather than total adiposity and predicts cardiometabolic disease and mortality strongly, including in people with normal BMI. Mendelian randomization indicates a causal effect of central fat distribution on cardiometabolic disease.","measurement":{"method":"Ratio of tape-measured waist circumference to hip circumference; standardized landmarks required for both measurements.","sample_type":"in-office device","approx_cost_usd":"0-5"},"signal_quality":"moderate","signal_quality_note":"Captures fat distribution well and is BMI-independent, but depends on two measurements each with site/observer variability; hip circumference is influenced by both fat and gluteal muscle/bone.","confounders":["measurement technique for both waist and hip","sex (different distributions and thresholds)","ethnicity","menopausal/hormonal status","muscularity of hip/gluteal region"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher waist:hip ratio, all-cause mortality, adjusted for BMI","direction":"risk","ci_low":1.1,"ci_high":1.2,"hr_per_sd":1.15,"hr_per_sd_ci":[1.1,1.2],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"pooled cohorts","followup_years":12,"study":"Meta-analyses and large pooled cohorts of waist:hip ratio and all-cause mortality, adjusted for BMI.","study_type":"meta-analysis","citation":"Carmienke S et al. General and abdominal obesity parameters and their combination in relation to mortality: a systematic review and meta-regression. Eur J Clin Nutr 2013;67:573-585. doi:10.1038/ejcn.2013.61","verification_status":"approximate","notes":"WHR is positively and approximately linearly associated with all-cause mortality independent of BMI; abdominal-obesity measures (WHR, waist) predict mortality even within normal-BMI ranges, where BMI alone misses risk. Per-SD HR is approximate, pooled across cohorts. Unlike BMI, WHR is monotonically associated with mortality."},"cvd":{"hr":1.27,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher waist:hip ratio adjusted for BMI, coronary heart disease / cardiovascular disease","direction":"risk","ci_low":1.2,"ci_high":1.34,"hr_per_sd":1.27,"hr_per_sd_ci":[1.2,1.34],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":484000,"followup_years":10,"study":"Large prospective cohorts and Mendelian randomization of BMI-adjusted WHR and cardiovascular disease.","study_type":"mendelian-randomization","citation":"Emdin CA et al. Genetic association of waist-to-hip ratio with cardiometabolic traits, type 2 diabetes, and coronary heart disease. JAMA 2017;317:626-634. doi:10.1001/jama.2016.21042","verification_status":"verified","notes":"Mendelian randomization showed genetically predicted higher BMI-adjusted WHR is causally associated with coronary heart disease and type 2 diabetes (a 1-SD higher genetically predicted WHR raised CHD odds ~1.46 in the MR; observational per-SD HRs are ~1.2-1.3). Central fat distribution is a causal CVD risk factor independent of overall adiposity. Native per-SD figure used."},"cancer":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher waist:hip ratio, obesity-related cancer incidence (composite), adjusted","direction":"risk","ci_low":1.04,"ci_high":1.16,"hr_per_sd":1.1,"hr_per_sd_ci":[1.04,1.16],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":43000,"followup_years":12,"study":"EPIC and pooled cohorts of waist:hip ratio and obesity-related cancers.","study_type":"prospective-cohort","citation":"Freisling H et al. Comparison of general obesity and measures of body fat distribution in older adults in relation to cancer risk: a pooled analysis. Br J Cancer 2017;116:1486-1497. doi:10.1038/bjc.2017.106","verification_status":"unverified","notes":"WHR is associated with obesity-related cancers (notably colorectal and postmenopausal breast) but generally adds modest information beyond waist circumference or BMI. Per-SD HR is unverified and indicative; central-fat-distribution-specific cancer evidence is less mature than for waist or VAT."},"dementia":{"hr":1.12,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher waist:hip ratio, incident dementia / accelerated cognitive aging, adjusted","direction":"risk","ci_low":1.02,"ci_high":1.23,"hr_per_sd":1.12,"hr_per_sd_ci":[1.02,1.23],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"cohort + MR","followup_years":12,"study":"Prospective cohorts and Mendelian randomization of central obesity (WHR) and dementia/cognition.","study_type":"prospective-cohort","citation":"Studies of waist:hip ratio and dementia risk and brain-aging outcomes; MR analyses of central adiposity and Alzheimer disease.","verification_status":"unverified","notes":"Higher WHR is associated with greater dementia risk and worse brain-aging measures; some MR analyses suggest a causal contribution of central adiposity to cognitive outcomes. Per-SD HR is unverified and indicative; direct WHR–incident-dementia evidence is limited and partly confounded by late-life weight change."},"frailty":{"hr":1.18,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher waist:hip ratio, incident frailty in older adults, adjusted","direction":"risk","ci_low":1.06,"ci_high":1.31,"hr_per_sd":1.18,"hr_per_sd_ci":[1.06,1.31],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"older-adult cohorts","followup_years":8,"study":"Prospective cohorts of older adults linking central fat distribution (WHR) to incident frailty.","study_type":"prospective-cohort","citation":"Cohort studies and reviews of abdominal obesity / WHR and frailty in older adults.","verification_status":"unverified","notes":"Higher WHR predicts incident frailty in older adults, reflecting visceral-predominant fat distribution, inflammation and sarcopenic obesity. Per-SD HR is unverified and pooled; evidence is observational and modest. Like waist circumference, the WHR–frailty relationship is more monotone than BMI–frailty."}},"modifiability":{"intervention":"Caloric restriction and aerobic/resistance exercise modestly improve WHR by mobilizing central fat; GLP-1/GIP agonists and bariatric surgery produce larger shifts. WHR is harder to change than waist circumference because hip dimension also shifts.","effect_size":"Lifestyle interventions improve WHR modestly (~0.01-0.03 absolute); pharmacologic and surgical weight loss produce larger changes.","timeframe":"6-12 months","evidence_type":"RCT meta-analysis","citation":"Meta-analyses of exercise/diet and body fat distribution; GLP-1/GIP weight-loss RCT programs.","rating":"moderate"}},{"id":"bmi","name":"BMI","domain":"body_composition","aliases":["body mass index","Quetelet index"],"profile":{"mechanism":"Body mass index (weight / height squared) is a simple proxy for overall body size and adiposity. It is cheap, universal and predictive of cardiometabolic disease at the population level, but it does not distinguish fat from lean mass or capture fat distribution. Its relationship with all-cause mortality is U-shaped: both obesity and low BMI raise risk, the latter heavily confounded by smoking, illness and frailty.","measurement":{"method":"Calculated from measured weight and height; weight in kg divided by height in metres squared.","sample_type":"in-office device","approx_cost_usd":"0-5"},"signal_quality":"moderate","signal_quality_note":"Highly reproducible to measure, but a poor discriminator of body composition: it conflates muscle and fat and misses central adiposity, so it misclassifies risk in muscular, older and sarcopenic individuals.","confounders":["muscle vs fat mass (not distinguished)","fat distribution not captured","smoking (drives low-BMI mortality)","reverse causation (illness-related weight loss)","age (shifts the optimal range upward)","ethnicity (different risk thresholds)"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1,"hr_metric":"categorical","hr_unit_detail":"U-shaped: lowest mortality around BMI 22-25; obesity (BMI >=30) HR ~1.2-1.5 and underweight (BMI <18.5) HR ~1.5-2.0 vs BMI 22.5-25","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":10625411,"followup_years":13.7,"study":"Global BMI Mortality Collaboration individual-participant meta-analysis of 239 prospective studies.","study_type":"meta-analysis","citation":"Global BMI Mortality Collaboration (Di Angelantonio E et al.). Body-mass index and all-cause mortality: individual-participant-data meta-analysis of 239 prospective studies in four continents. Lancet 2016;388:776-786. doi:10.1016/S0140-6736(16)30175-1","verification_status":"verified","notes":"The BMI–all-cause-mortality relationship is U-/J-shaped (the 'obesity paradox'): in the Global BMI Mortality Collaboration, restricting to never-smokers without chronic disease, mortality was lowest at BMI 20-25 and rose for both higher and lower BMI (HR per 5 BMI units ~1.39 above 25; underweight also elevated). Because risk is non-monotonic, no single per-SD slope represents it; flagged categorical. Waist circumference and WHR are more linearly associated and are standardized on the per-SD scale instead."},"cvd":{"hr":1.23,"hr_metric":"per_unit","hr_unit_detail":"per 5 kg/m2 higher BMI (above ~20-25), incident cardiovascular disease, never-smokers","direction":"risk","ci_low":1.2,"ci_high":1.26,"hr_per_sd":1.1949,"hr_per_sd_ci":[1.1698,1.2199],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4.3 (Pooled adult BMI SD ~4-4.5 kg/m2 (Prospective Studies Collaboration / large cohort distributions)); k = SD/unit = 0.86","conversion":{"unit_value":5,"population_sd":4.3,"sd_source":"Pooled adult BMI SD ~4-4.5 kg/m2 (Prospective Studies Collaboration / large cohort distributions)","log2_sd":null},"evidence_tier":"A","n":894576,"followup_years":13,"study":"Prospective Studies Collaboration individual-participant meta-analysis of 57 prospective studies.","study_type":"meta-analysis","citation":"Prospective Studies Collaboration (Whitlock G et al.). Body-mass index and cause-specific mortality in 900,000 adults: collaborative analyses of 57 prospective studies. Lancet 2009;373:1083-1096. doi:10.1016/S0140-6736(09)60318-4","verification_status":"verified","notes":"Above the BMI ~22.5-25 nadir, BMI is approximately log-linearly associated with cardiovascular (especially ischemic heart disease and stroke) mortality: each 5 kg/m2 higher BMI raised vascular mortality ~40% in the PSC. Mendelian randomization confirms a causal effect of higher BMI on CVD. The per-5-unit HR (modeled in the rising arm) is converted to per-SD with a pooled adult BMI SD of ~4.3; the conversion presumes the upper, monotone segment of the curve."},"cancer":{"hr":1.1,"hr_metric":"per_unit","hr_unit_detail":"per 5 kg/m2 higher BMI, overall obesity-related cancer incidence, adjusted","direction":"risk","ci_low":1.08,"ci_high":1.13,"hr_per_sd":1.0854,"hr_per_sd_ci":[1.0684,1.1108],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 5; population SD 4.3 (Pooled adult BMI SD ~4-4.5 kg/m2 (large cohort distributions)); k = SD/unit = 0.86","conversion":{"unit_value":5,"population_sd":4.3,"sd_source":"Pooled adult BMI SD ~4-4.5 kg/m2 (large cohort distributions)","log2_sd":null},"evidence_tier":"A","n":5240000,"followup_years":7.5,"study":"Bhaskaran et al. UK population-based cohort of BMI and 22 site-specific cancers.","study_type":"prospective-cohort","citation":"Bhaskaran K et al. Body-mass index and risk of 22 specific cancers: a population-based cohort study of 5.24 million UK adults. Lancet 2014;384:755-765. doi:10.1016/S0140-6736(14)60892-8","verification_status":"verified","notes":"BMI is associated with several site-specific cancers (uterus, gallbladder, kidney, liver, colon, postmenopausal breast and others), with HRs per 5 kg/m2 ranging from ~1.1 to ~1.6 for fat-sensitive sites; overall the aggregate per-5-unit HR is modest because many cancers are fat-neutral or inversely associated (e.g. lung in smokers). Per-5-unit HR converted to per-SD; IARC concluded body fatness is causally linked to ~13 cancers."},"dementia":{"hr":1,"hr_metric":"categorical","hr_unit_detail":"age-dependent: higher midlife BMI raises dementia risk, but late-life high BMI is associated with lower risk (reverse causation); no single slope","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":1349857,"followup_years":38,"study":"Pooled analysis of midlife BMI and dementia (long follow-up) showing the prodromal weight-loss artifact.","study_type":"pooled-cohort","citation":"Kivimaki M et al. Body mass index and risk of dementia: analysis of individual-level data from 1.3 million individuals. Alzheimers Dement 2018;14:601-609. doi:10.1016/j.jalz.2017.09.016","verification_status":"verified","notes":"The BMI–dementia relationship is non-monotonic over the life course: higher midlife BMI raises later dementia risk, but in the ~10 years before diagnosis BMI falls (prodromal weight loss), producing a spurious 'protective' association of late-life high BMI. Kivimaki et al. showed the apparent late-life inverse association is largely reverse causation. Because the sign reverses with age at measurement, no single per-SD slope is defensible; flagged categorical."},"frailty":{"hr":1,"hr_metric":"categorical","hr_unit_detail":"U-shaped: both obesity (BMI >=30) and low BMI (<18.5-20) raise incident frailty risk vs normal BMI","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"pooled cohorts","followup_years":8,"study":"Systematic review / meta-analysis of BMI and incident frailty in older adults.","study_type":"meta-analysis","citation":"Watanabe D et al. and meta-analyses of BMI and frailty; e.g. systematic reviews showing a U-shaped BMI–frailty relationship in older adults.","verification_status":"approximate","notes":"BMI relates to incident frailty in a U-shaped manner: obesity raises frailty risk (via sarcopenic obesity, inflammation, reduced mobility) and underweight raises it (via undernutrition and muscle loss), with lowest risk in the normal/overweight range. Because risk is non-monotonic, no single per-SD slope is defensible; flagged categorical."}},"modifiability":{"intervention":"Caloric restriction and physical activity; GLP-1/GIP receptor agonists and bariatric surgery for substantial reductions in those with obesity. The goal is body-composition improvement, not BMI minimization.","effect_size":"Lifestyle programs lower BMI ~1-3 kg/m2; GLP-1/GIP agonists 4-8+ kg/m2; bariatric surgery more.","timeframe":"3-12 months","evidence_type":"RCT meta-analysis","citation":"Diabetes Prevention Program and Look AHEAD lifestyle trials; STEP/SURMOUNT GLP-1/GIP RCTs; bariatric surgery cohorts.","rating":"high"},"comparability_tag":"U-shaped","comparability_note":"BMI has a U-shaped 'obesity paradox' relation with all-cause mortality and frailty, and an age-dependent, sign-reversing relation with dementia, so those cells use no per-SD slope; the CVD and cancer cells reflect the monotone upper arm of the curve and are converted from per-5-unit HRs."},{"id":"bioimpedance_phase_angle","name":"Bioimpedance phase angle","domain":"body_composition","aliases":["phase angle","BIA phase angle","PhA"],"profile":{"mechanism":"Phase angle is derived from bioelectrical impedance analysis as the arctangent of reactance over resistance. It reflects the integrity and mass of cell membranes and the ratio of intracellular to extracellular water. A higher phase angle indicates healthier, better-hydrated cells with intact membranes and more body cell mass; a low phase angle marks cellular deterioration, malnutrition, inflammation and is an emerging prognostic marker of frailty, sarcopenia and mortality.","measurement":{"method":"Single- or multi-frequency bioelectrical impedance analysis; phase angle computed from measured resistance and reactance at (typically) 50 kHz.","sample_type":"in-office device","approx_cost_usd":"20-80"},"signal_quality":"moderate","signal_quality_note":"A raw, device-measured BIA parameter (no compartment model assumptions), but values depend on device, electrode placement, frequency, hydration, recent food/exercise and ambient conditions; reference ranges are age- and sex-specific.","confounders":["hydration status","device and frequency differences","electrode placement","recent food intake / exercise","age and sex (strong reference effects)","body temperature"],"testing_cadence":"baseline + every 6-12 months"},"outcomes":{"all_cause_mortality":{"hr":1.45,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower bioimpedance phase angle, all-cause mortality, adjusted","direction":"protective","ci_low":1.28,"ci_high":1.64,"hr_per_sd":1.45,"hr_per_sd_ci":[1.28,1.64],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled cohorts","followup_years":6,"study":"Systematic review / meta-analysis of phase angle and mortality across clinical and general-population cohorts.","study_type":"meta-analysis","citation":"Garlini LM et al. Phase angle and mortality: a systematic review. Eur J Clin Nutr 2019;73:495-508. doi:10.1038/s41430-018-0159-1","verification_status":"approximate","notes":"Lower phase angle consistently predicts higher all-cause mortality across cancer, dialysis, heart-failure, critical-illness and general geriatric populations; meta-analyses report substantial risk gradients per SD or per unit lower. Direction is protective (higher phase angle lower risk). The per-SD HR is approximate and pooled across heterogeneous, mostly clinical cohorts; much of the signal reflects underlying illness severity (some reverse causation)."},"cvd":{"hr":1.35,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower phase angle, cardiovascular mortality / events, mostly heart-failure and clinical cohorts","direction":"protective","ci_low":1.15,"ci_high":1.58,"hr_per_sd":1.35,"hr_per_sd_ci":[1.15,1.58],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"clinical cohorts","followup_years":4,"study":"Prospective cohorts of phase angle and cardiovascular outcomes, predominantly heart-failure populations.","study_type":"prospective-cohort","citation":"Studies of bioimpedance phase angle and prognosis in heart failure and cardiovascular disease (e.g. phase-angle prognostic cohorts in chronic heart failure).","verification_status":"unverified","notes":"Low phase angle predicts worse cardiovascular prognosis, but the evidence is dominated by heart-failure and other clinical cohorts where phase angle reflects fluid overload, cachexia and disease severity (substantial reverse causation). General-population CVD-incidence evidence is limited. Per-SD HR is unverified and indicative."},"cancer":{"hr":1.5,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower phase angle, mortality in cancer patients (prognostic, not incidence), adjusted","direction":"protective","ci_low":1.3,"ci_high":1.73,"hr_per_sd":1.5,"hr_per_sd_ci":[1.3,1.73],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled oncology cohorts","followup_years":3,"study":"Meta-analyses of phase angle as a prognostic marker of survival in cancer patients.","study_type":"meta-analysis","citation":"Pena NF et al. and meta-analyses of phase angle and survival in oncology; e.g. systematic reviews of phase angle as a prognostic nutritional marker in cancer.","verification_status":"unverified","notes":"Low phase angle is a robust adverse prognostic marker of survival in cancer patients (across many tumor types) — but this measures prognosis in those already diagnosed, not cancer incidence in healthy people. The signal largely reflects cancer cachexia, malnutrition and inflammation (reverse causation). Per-SD HR is unverified; the cell should be read as prognostic, not as a cancer-risk predictor."},"dementia":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no usable prospective evidence linking phase angle to incident dementia","direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence — phase angle and incident dementia have not been adequately studied prospectively","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No adequate prospective cohort of bioimpedance phase angle and incident dementia identified.","study_type":"prospective-cohort","citation":"No established meta-analytic or large-cohort evidence; phase angle correlates cross-sectionally with cognitive/functional status in some geriatric samples.","verification_status":"unverified","notes":"Phase angle correlates cross-sectionally with cognitive and functional status in some geriatric and clinical samples, but there is no adequate prospective evidence linking it to incident dementia. No usable per-SD HR; cell left null pending better data.","qualitative":true},"frailty":{"hr":1.55,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower phase angle, prevalent/incident frailty or sarcopenia in older adults, adjusted","direction":"protective","ci_low":1.32,"ci_high":1.82,"hr_per_sd":1.55,"hr_per_sd_ci":[1.32,1.82],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled geriatric cohorts","followup_years":3,"study":"Systematic review / meta-analysis of phase angle and frailty / sarcopenia in older adults.","study_type":"meta-analysis","citation":"Meta-analyses of bioimpedance phase angle and frailty/sarcopenia in older adults; e.g. systematic reviews showing low phase angle strongly associated with frailty and sarcopenia.","verification_status":"unverified","notes":"Low phase angle is strongly and consistently associated with frailty and sarcopenia in older adults, as it directly reflects body cell mass, cell-membrane integrity and intracellular/extracellular water balance. Much of the evidence is cross-sectional (odds ratios) with fewer prospective incident-frailty cohorts; the per-SD estimate is unverified and pooled. This is phase angle's strongest and most mechanistically coherent outcome."}},"modifiability":{"intervention":"Resistance exercise and adequate protein/energy intake raise phase angle by increasing body cell mass and cell-membrane integrity; treatment of underlying inflammation and correction of malnutrition also improve it.","effect_size":"Resistance-training and nutritional interventions raise phase angle modestly (~0.2-0.5 degrees) over months in older or clinical populations.","timeframe":"3-6 months","evidence_type":"RCT","citation":"RCTs of resistance training and nutritional supplementation reporting improvements in BIA phase angle in older and clinical populations.","rating":"moderate"}},{"id":"resting_bp","name":"Resting blood pressure","domain":"cv_autonomic","aliases":["office blood pressure","clinic blood pressure","systolic blood pressure","SBP"],"profile":{"mechanism":"Chronically elevated blood pressure imposes pulsatile and steady-state load on the arterial wall, heart and microvasculature, driving atherosclerosis, left-ventricular hypertrophy, small-vessel cerebral disease and renal injury. It is one of the largest single modifiable contributors to global cardiovascular and all-cause mortality, and mid-life hypertension is a well-established risk factor for later dementia.","measurement":{"method":"Seated, rested, validated oscillometric or auscultatory cuff measurement; multiple readings averaged. Systolic BP is the most prognostic single component in middle-aged and older adults.","sample_type":"in-office device","approx_cost_usd":"0-30"},"signal_quality":"moderate","signal_quality_note":"High within-person visit-to-visit variability, white-coat and masked effects, cuff/technique error and regression dilution attenuate single-occasion measurements; averaging multiple readings improves reliability.","confounders":["white-coat / masked hypertension","measurement technique and cuff size","time of day and recent activity/caffeine","antihypertensive medication","acute stress / anxiety","regression dilution from single readings"],"testing_cadence":"baseline + at least annual; more frequent if elevated or treated"},"outcomes":{"all_cause_mortality":{"hr":1.21,"hr_metric":"per_unit","hr_unit_detail":"per 20 mmHg higher usual systolic BP, all-cause mortality (approximate, derived from age-pooled vascular/total mortality gradients)","direction":"risk","ci_low":1.16,"ci_high":1.26,"hr_per_sd":1.1872,"hr_per_sd_ci":[1.1429,1.2312],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 20; population SD 18 (Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used.); k = SD/unit = 0.9","conversion":{"unit_value":20,"population_sd":18,"sd_source":"Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used."},"evidence_tier":"A","n":"~1 million (61 prospective studies)","followup_years":12,"study":"Prospective Studies Collaboration, individual-participant meta-analysis of 61 cohorts.","study_type":"meta-analysis","citation":"Lewington S, et al. Age-specific relevance of usual blood pressure to vascular mortality: a meta-analysis of individual data for one million adults in 61 prospective studies. Lancet 2002;360(9349):1903-1913. doi:10.1016/S0140-6736(02)11911-8. PMID:12493255","verification_status":"approximate","notes":"The PSC reported vascular mortality halving per 20 mmHg lower SBP across the 40-69 range with no threshold; the all-cause mortality gradient is shallower because non-vascular deaths dilute it. The per-20-mmHg all-cause HR here is an approximate age-pooled value, not a single quoted figure from the paper; treat as indicative. Association is steeply log-linear and strongly causal (RCT and MR evidence)."},"cvd":{"hr":2,"hr_metric":"per_unit","hr_unit_detail":"per 20 mmHg higher usual systolic BP (or 10 mmHg diastolic), ischaemic heart disease / stroke mortality, ages 40-69","direction":"risk","ci_low":1.9,"ci_high":2.1,"hr_per_sd":1.8661,"hr_per_sd_ci":[1.7819,1.9498],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 20; population SD 18 (Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used.); k = SD/unit = 0.9","conversion":{"unit_value":20,"population_sd":18,"sd_source":"Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used."},"evidence_tier":"A","n":"~1 million (61 prospective studies)","followup_years":12,"study":"Prospective Studies Collaboration individual-participant meta-analysis; corroborated by RCT meta-analysis (BPLTTC) and Mendelian randomization.","study_type":"meta-analysis","citation":"Lewington S, et al. Lancet 2002;360(9349):1903-1913. doi:10.1016/S0140-6736(02)11911-8. PMID:12493255; corroborated by Blood Pressure Lowering Treatment Trialists' Collaboration, Lancet 2021;397:1625-1636.","verification_status":"verified","notes":"Each 20 mmHg higher usual SBP (or 10 mmHg DBP) roughly doubles risk of death from ischaemic heart disease and stroke throughout 115-180 mmHg, with no lower threshold. Causality is established: RCT meta-analysis shows each 5 mmHg reduction lowers major CV events ~10%, and Mendelian randomization confirms a causal, dose-dependent SBP-CVD relationship."},"cancer":{"hr":1.07,"hr_metric":"per_unit","hr_unit_detail":"per 10 mmHg higher systolic BP, total cancer incidence (men); weaker/inconsistent in women","direction":"risk","ci_low":1.04,"ci_high":1.1,"hr_per_sd":1.1295,"hr_per_sd_ci":[1.0731,1.1872],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 18 (Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used.); k = SD/unit = 1.8","conversion":{"unit_value":10,"population_sd":18,"sd_source":"Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used."},"evidence_tier":"C","n":"~289000 (Me-Can pooled cohorts)","followup_years":12,"study":"Metabolic Syndrome and Cancer Project (Me-Can), pooled European cohorts.","study_type":"pooled-cohort","citation":"Stocks T, et al. Blood pressure and risk of cancer incidence and mortality in the Metabolic Syndrome and Cancer Project. Hypertension 2012;59(4):802-810. doi:10.1161/HYPERTENSIONAHA.111.189258. PMID:22353615","verification_status":"approximate","notes":"Higher BP showed a modest association with total cancer incidence and mortality in men but not consistently in women; specific HR per 10 mmHg is approximate. The link is widely regarded as confounded (shared risk factors: obesity, smoking, alcohol) rather than causal; Mendelian randomization does not support a causal BP-cancer effect. Treat as weak and likely non-causal."},"dementia":{"hr":1.25,"hr_metric":"per_unit","hr_unit_detail":"per 10 mmHg higher mid-life systolic BP, incident all-cause dementia","direction":"risk","ci_low":1.06,"ci_high":1.46,"hr_per_sd":1.4943,"hr_per_sd_ci":[1.1106,1.9762],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 18 (Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used.); k = SD/unit = 1.8","conversion":{"unit_value":10,"population_sd":18,"sd_source":"Adult systolic BP SD ~16-20 mmHg from NHANES and large prospective cohort distributions; midpoint 18 mmHg used."},"evidence_tier":"B","n":"~96000 (pooled cohorts)","followup_years":15,"study":"Systematic review/meta-analysis of mid-life blood pressure and incident dementia.","study_type":"meta-analysis","citation":"Ou YN, et al. Blood pressure and risks of cognitive impairment and dementia: a systematic review and meta-analysis of 209 prospective studies. Hypertension 2020;76(1):217-225. doi:10.1161/HYPERTENSIONAHA.120.14993. PMID:32450739","verification_status":"approximate","notes":"Mid-life hypertension raises later dementia risk; the association is age-dependent and partly reverses in late life, where falling BP can be a prodromal feature of dementia (reverse causation). SPRINT-MIND RCT showed intensive BP lowering reduced mild cognitive impairment. Per-10-mmHg HR is approximate and pooled across heterogeneous studies; the mid-life signal is the most robust."},"frailty":{"hr":1.14,"hr_metric":"categorical","hr_unit_detail":"hypertension vs normotension, incident frailty (pooled); relation is U-shaped in older adults","direction":"risk","ci_low":1.04,"ci_high":1.25,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"pooled cohorts","followup_years":null,"study":"Systematic review/meta-analysis of hypertension and incident frailty in older adults.","study_type":"meta-analysis","citation":"Vetrano DL, et al. Hypertension and frailty: a systematic review and meta-analysis. BMJ Open 2018;8(12):e024406. doi:10.1136/bmjopen-2018-024406. PMID:30580267","verification_status":"approximate","notes":"The BP-frailty relationship is U-shaped and age-dependent: hypertension modestly predicts incident frailty in younger-old adults, but low BP is associated with frailty and higher mortality in the oldest-old and already-frail (reverse causation, reduced physiologic reserve). A single linear per-SD HR is not meaningful; kept categorical. Evidence is heterogeneous; tier C."}},"modifiability":{"intervention":"Sodium reduction, weight loss, DASH-style diet, aerobic exercise, alcohol moderation, and antihypertensive medication (the most reliably effective lever).","effect_size":"Lifestyle change lowers SBP ~4-11 mmHg; single antihypertensive agents lower SBP ~8-10 mmHg; combination therapy can lower SBP 20+ mmHg.","timeframe":"Days to weeks for drugs; weeks to months for lifestyle change.","evidence_type":"RCT meta-analysis","citation":"Blood Pressure Lowering Treatment Trialists' Collaboration meta-analyses; DASH and lifestyle-intervention RCTs.","rating":"high"},"comparability_tag":"U-shaped (frailty)","comparability_note":"Most BP cells convert cleanly per-SD, but the frailty cell reflects a U-shaped, age-dependent relation (low BP marks frailty in the oldest-old) and is kept as a categorical hypertension contrast."},{"id":"ambulatory_bp","name":"Ambulatory blood pressure","domain":"cv_autonomic","aliases":["ambulatory blood pressure monitoring","ABPM","24-hour blood pressure","nighttime blood pressure","nocturnal blood pressure"],"profile":{"mechanism":"Ambulatory monitoring captures blood pressure across daily activity and sleep, removing white-coat effect and capturing nocturnal BP and dipping pattern. Nighttime and 24-hour averages are more strongly and more linearly related to cardiovascular events and mortality than office BP, and reveal masked hypertension and non-dipping that office measurement misses.","measurement":{"method":"Oscillometric cuff worn 24 hours, measuring at fixed intervals (e.g., every 15-30 min awake, 30-60 min asleep); daytime, nighttime and 24-hour averages and dipping status are derived.","sample_type":"wearable","approx_cost_usd":"50-250"},"signal_quality":"clean","signal_quality_note":"Multiple readings over 24 h sharply reduce measurement error and white-coat/masked misclassification relative to office BP; main limitations are sleep disturbance from the cuff and occasional failed readings.","confounders":["sleep quality and disruption by the device","activity level during recording","shift work / irregular sleep schedule","antihypertensive medication and dosing time","arm movement artefact"],"testing_cadence":"as indicated for diagnosis/treatment monitoring; not routinely repeated"},"outcomes":{"all_cause_mortality":{"hr":1.29,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD (~16 mmHg) higher nighttime systolic BP, all-cause mortality, adjusted for office BP","direction":"risk","ci_low":1.22,"ci_high":1.35,"hr_per_sd":1.29,"hr_per_sd_ci":[1.22,1.35],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":11135,"followup_years":13.8,"study":"International Database on Ambulatory blood pressure in relation to Cardiovascular Outcomes (IDACO), pooled population cohorts.","study_type":"pooled-cohort","citation":"Yang WY, et al. Association of office and ambulatory blood pressure with mortality and cardiovascular outcomes. JAMA 2019;322(5):409-420. doi:10.1001/jama.2019.9811. PMID:31386134","verification_status":"verified","notes":"In IDACO, nighttime and 24-hour SBP were the strongest BP predictors of all-cause mortality and outperformed office BP; nighttime SBP remained predictive after adjustment for office and other ambulatory measures. Per-SD HRs for systolic BP reported directly. Tier A given pooled multinational cohorts plus consistent UK/Spanish registry data."},"cvd":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD (~16 mmHg) higher 24-hour systolic BP, composite cardiovascular events, adjusted for office BP","direction":"risk","ci_low":1.21,"ci_high":1.39,"hr_per_sd":1.3,"hr_per_sd_ci":[1.21,1.39],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":11135,"followup_years":13.8,"study":"IDACO pooled population cohorts; corroborated by the Spanish ABPM Registry (~64,000 patients).","study_type":"pooled-cohort","citation":"Yang WY, et al. JAMA 2019;322(5):409-420. doi:10.1001/jama.2019.9811. PMID:31386134; corroborated by Banegas JR, et al. N Engl J Med 2018;378:1509-1520.","verification_status":"verified","notes":"Ambulatory (especially nighttime) SBP predicts cardiovascular events more strongly than office BP and adds prognostic information beyond it. The Spanish ABPM Registry (Banegas 2018, ~64,000 patients) independently showed 24-hour and nighttime SBP were the strongest mortality predictors, with masked hypertension carrying high risk. Tier A; association strongly causal by extension from BP-lowering trials."},"cancer":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no usable ambulatory-BP-specific cancer HR identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence located","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study isolating ambulatory blood pressure as a cancer predictor was identified.","study_type":"prospective-cohort","citation":"No specific source identified.","verification_status":"unverified","notes":"Ambulatory BP cohorts (IDACO, Spanish Registry) have reported cardiovascular and total mortality but not cancer-specific incidence as a function of ambulatory BP. Any cancer signal would be expected to mirror the weak, likely-confounded office-BP-cancer association. Left null rather than fabricated.","qualitative":true},"dementia":{"hr":1.31,"hr_metric":"categorical","hr_unit_detail":"non-dipping / reverse-dipping nocturnal BP pattern vs normal dipping, incident dementia / cognitive decline","direction":"risk","ci_low":1.05,"ci_high":1.63,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"small cohorts","followup_years":null,"study":"Prospective cohorts linking blunted nocturnal BP dipping to cognitive decline and incident dementia.","study_type":"prospective-cohort","citation":"Cohort evidence reviewed in: Cremer A, et al. Nighttime blood pressure and cognitive function/dementia (e.g., Three-City and related ABPM cohorts). General review-level evidence.","verification_status":"unverified","notes":"Higher nocturnal BP and non-dipping/reverse-dipping patterns are associated with white-matter disease, cognitive decline and incident dementia, but the available estimates come from small heterogeneous cohorts using categorical dipping classifications. The HR shown is indicative of the literature range, not from a single verified study; tier C. Kept categorical (dipping status is a pattern category)."},"frailty":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no usable ambulatory-BP-specific incident-frailty HR identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence located","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study isolating ambulatory blood pressure as an incident-frailty predictor was identified.","study_type":"prospective-cohort","citation":"No specific source identified.","verification_status":"unverified","notes":"Studies link low ambulatory BP and abnormal dipping to frailty cross-sectionally, but a verified incident-frailty HR for an ambulatory BP metric was not located. The office-BP-frailty relation is U-shaped; the ambulatory analogue is likely similar. Left null rather than fabricated.","qualitative":true}},"modifiability":{"intervention":"Same levers as office BP (sodium reduction, weight loss, exercise, antihypertensives); evening dosing of antihypertensives can specifically lower nighttime BP and improve dipping in some patients.","effect_size":"Antihypertensive therapy lowers 24-hour SBP ~10-15 mmHg; lifestyle change ~5-10 mmHg over 24-hour average.","timeframe":"Weeks for drug effects; weeks to months for lifestyle change.","evidence_type":"RCT meta-analysis","citation":"Ambulatory-BP substudies of antihypertensive RCTs; BPLTTC meta-analyses.","rating":"high"},"comparability_tag":"Dipping pattern","comparability_note":"Average ambulatory SBP cells convert cleanly per-SD, but the dementia signal rests on a categorical nocturnal-dipping pattern that cannot be placed on a per-SD scale."},{"id":"pulse_wave_velocity","name":"Pulse wave velocity (arterial stiffness)","domain":"cv_autonomic","aliases":["carotid-femoral pulse wave velocity","cfPWV","aortic stiffness","arterial stiffness"],"profile":{"mechanism":"Carotid-femoral pulse wave velocity is the reference measure of aortic stiffness. A stiffer aorta transmits pulsatile pressure into the cerebral and renal microcirculation, raises central pulse pressure and afterload, and reflects cumulative arterial aging. It is a strong, partly independent predictor of cardiovascular events, and aortic stiffness contributes to small-vessel brain damage and cognitive decline.","measurement":{"method":"Transit time of the pressure wave between carotid and femoral sites divided by path distance, using applanation tonometry or oscillometric/Doppler devices; reported in m/s.","sample_type":"imaging","approx_cost_usd":"100-300"},"signal_quality":"moderate","signal_quality_note":"Reproducible with trained operators and standardized distance estimation, but device type, path-length method, heart rate and blood pressure at the time of measurement all influence the value; intra-individual variability is moderate.","confounders":["blood pressure at time of measurement","heart rate","device and path-length estimation method","age (strong)","operator technique"],"testing_cadence":"baseline + every few years; not routinely repeated"},"outcomes":{"all_cause_mortality":{"hr":1.15,"hr_metric":"per_unit","hr_unit_detail":"per 1 m/s higher aortic pulse wave velocity, all-cause mortality, adjusted","direction":"risk","ci_low":1.09,"ci_high":1.21,"hr_per_sd":1.5209,"hr_per_sd_ci":[1.295,1.7716],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 3 (Adult carotid-femoral PWV SD ~2.5-3.5 m/s from the Reference Values for Arterial Stiffness Collaboration (Eur Heart J 2010); midpoint 3 m/s used.); k = SD/unit = 3","conversion":{"unit_value":1,"population_sd":3,"sd_source":"Adult carotid-femoral PWV SD ~2.5-3.5 m/s from the Reference Values for Arterial Stiffness Collaboration (Eur Heart J 2010); midpoint 3 m/s used."},"evidence_tier":"A","n":"~16000 (17 longitudinal studies)","followup_years":7.7,"study":"Vlachopoulos 2010, meta-analysis of 17 longitudinal studies of aortic PWV.","study_type":"meta-analysis","citation":"Vlachopoulos C, et al. Prediction of cardiovascular events and all-cause mortality with arterial stiffness: a systematic review and meta-analysis. J Am Coll Cardiol 2010;55(13):1318-1327. doi:10.1016/j.jacc.2010.10.012. PMID:20338492","verification_status":"verified","notes":"Pooled per-1-m/s HR for all-cause mortality 1.15 (1.09-1.21). The same meta-analysis reported the high-vs-low PWV contrast HR ~1.90. Note: per-1-m/s conversion with SD 3 m/s gives a large per-SD exponent (k=3); the true relation may be sub-linear over wide ranges, so the converted per-SD value should be read as an upper-bound estimate. Tier A."},"cvd":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher log-transformed carotid-femoral PWV, coronary heart disease, adjusted for conventional risk factors","direction":"risk","ci_low":1.18,"ci_high":1.43,"hr_per_sd":1.3,"hr_per_sd_ci":[1.18,1.43],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":17635,"followup_years":7.6,"study":"Ben-Shlomo 2014, individual-participant meta-analysis of 16 cohorts (cfPWV and cardiovascular outcomes).","study_type":"meta-analysis","citation":"Ben-Shlomo Y, et al. Aortic pulse wave velocity improves cardiovascular event prediction: an individual participant meta-analysis of prospective observational data from 17,635 subjects. J Am Coll Cardiol 2014;63(7):636-646. doi:10.1016/j.jacc.2013.09.063. PMID:24239664","verification_status":"verified","notes":"IPD meta-analysis reported HRs per 1 SD of log-cfPWV: ~1.30 for coronary heart disease, ~1.35 for stroke, ~1.30 for combined CV events, after adjustment for conventional risk factors. cfPWV modestly improved risk reclassification beyond standard scores. Native per-SD (log scale) estimate. Tier A."},"cancer":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no usable PWV-specific cancer HR identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence located","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study isolating pulse wave velocity as a cancer-incidence predictor was identified.","study_type":"prospective-cohort","citation":"No specific source identified.","verification_status":"unverified","notes":"Arterial stiffness research has focused on cardiovascular and cognitive outcomes; a verified cancer-specific HR for PWV was not located. Left null rather than fabricated.","qualitative":true},"dementia":{"hr":1.5,"hr_metric":"categorical","hr_unit_detail":"highest vs lowest tertile of aortic PWV, incident all-cause dementia (older adults)","direction":"risk","ci_low":1.07,"ci_high":2.1,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"~350-1100 (individual cohorts)","followup_years":9,"study":"Prospective cohorts of older adults (e.g., Rotterdam Study, ARIC-NCS) linking aortic stiffness to incident dementia and cognitive decline.","study_type":"prospective-cohort","citation":"Rotterdam Study and related cohort evidence on arterial stiffness and dementia (e.g., Poels MMF, et al. Stroke 2007; ARIC-NCS arterial stiffness analyses).","verification_status":"approximate","notes":"Higher aortic PWV is associated with cerebral small-vessel disease, accelerated cognitive decline and incident dementia, but individual cohorts are modest in size and use varied tertile/SD contrasts; the figure shown is an approximate representative tertile contrast converted to per-SD. Evidence is suggestive, not definitive; tier C. Reverse causation and shared vascular risk factors complicate interpretation."},"frailty":{"hr":1.45,"hr_metric":"categorical","hr_unit_detail":"high vs low arterial stiffness, incident frailty / mobility decline (older adults)","direction":"risk","ci_low":1,"ci_high":2.1,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"small cohorts","followup_years":null,"study":"Prospective cohorts of older adults linking aortic stiffness to incident frailty, slow gait and physical decline.","study_type":"prospective-cohort","citation":"Cohort evidence on arterial stiffness and physical function/frailty (e.g., Health ABC and InCHIANTI-type analyses); review-level.","verification_status":"unverified","notes":"Higher arterial stiffness is associated cross-sectionally and in some prospective cohorts with slow gait, mobility limitation and incident frailty, plausibly via reduced muscle and cerebral perfusion. Verified per-SD incident-frailty HRs are scarce; the value shown is indicative of the literature range. Tier C; kept categorical given heterogeneous high-vs-low contrasts."}},"modifiability":{"intervention":"Aerobic exercise, blood-pressure lowering, weight loss, sodium restriction; aerobic training has the most consistent direct destiffening effect.","effect_size":"Aerobic exercise lowers cfPWV ~0.5-1.0 m/s in middle-aged/older adults; antihypertensive therapy reduces PWV partly via BP lowering. Stiffness rises ~0.1 m/s per year with aging, so gains are partial.","timeframe":"8-12 weeks for exercise effects.","evidence_type":"RCT meta-analysis","citation":"Exercise-training RCT meta-analyses on arterial stiffness (e.g., aerobic-training PWV meta-analyses).","rating":"moderate"},"comparability_tag":"Mixed metrics","comparability_note":"CVD evidence is native per-SD and mortality is per-unit-convertible, but dementia/frailty cells rest on heterogeneous categorical high-vs-low contrasts from small cohorts."},{"id":"endothelial_function","name":"Endothelial function (FMD / peripheral arterial tonometry)","domain":"cv_autonomic","aliases":["flow-mediated dilation","FMD","brachial artery reactivity","peripheral arterial tonometry","reactive hyperemia index","RHI","EndoPAT"],"profile":{"mechanism":"Endothelial function reflects the capacity of the vascular endothelium to release nitric oxide and dilate in response to increased shear stress. Endothelial dysfunction is an early, potentially reversible step in atherosclerosis, preceding structural disease, and integrates the net effect of cardiovascular risk factors on the vascular wall.","measurement":{"method":"Brachial-artery flow-mediated dilation (ultrasound, % diameter change after cuff-occlusion hyperemia) or peripheral arterial tonometry (reactive hyperemia index, e.g., EndoPAT). Both require standardized protocols.","sample_type":"functional test","approx_cost_usd":"100-400"},"signal_quality":"noisy","signal_quality_note":"FMD is highly operator-dependent with substantial measurement variability; results depend on baseline diameter, cuff position, temperature, fasting and prior exercise/diet. Tonometry indices are more reproducible but measure a related, not identical, construct.","confounders":["operator skill and image analysis","baseline arterial diameter","room temperature, fasting state, recent food/exercise/caffeine","menstrual cycle phase","time of day","vasoactive medications"],"testing_cadence":"research / specialized use; not part of routine screening"},"outcomes":{"all_cause_mortality":{"hr":0.84,"hr_metric":"per_unit","hr_unit_detail":"per 1% higher brachial flow-mediated dilation, all-cause mortality (protective direction)","direction":"protective","ci_low":0.78,"ci_high":0.9,"hr_per_sd":0.5927,"hr_per_sd_ci":[0.4746,0.729],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 3 (Adult brachial FMD SD ~2.5-3.5 percentage points from pooled FMD cohort distributions; midpoint 3 used.); k = SD/unit = 3","conversion":{"unit_value":1,"population_sd":3,"sd_source":"Adult brachial FMD SD ~2.5-3.5 percentage points from pooled FMD cohort distributions; midpoint 3 used."},"evidence_tier":"B","n":"~6000 (pooled studies)","followup_years":5,"study":"Inaba 2010, meta-analysis of brachial FMD and cardiovascular events / mortality.","study_type":"meta-analysis","citation":"Inaba Y, Chen JA, Bergmann SR. Prediction of future cardiovascular outcomes by flow-mediated vasodilatation of brachial artery: a meta-analysis. Int J Cardiovasc Imaging 2010;26(6):631-640. doi:10.1007/s10554-010-9616-1. PMID:20339920","verification_status":"approximate","notes":"Higher FMD predicts lower risk of cardiovascular events; the per-1% all-cause mortality figure is approximate (the meta-analysis emphasized composite CV events). Converting per-1% with SD 3% yields a large per-SD exponent (k=3); given FMD's measurement noise and likely sub-linearity, the converted per-SD value should be treated as an upper-bound estimate. Tier B; many constituent studies are in patient populations."},"cvd":{"hr":0.87,"hr_metric":"per_unit","hr_unit_detail":"per 1% higher brachial flow-mediated dilation, incident cardiovascular events (protective direction)","direction":"protective","ci_low":0.83,"ci_high":0.91,"hr_per_sd":0.6585,"hr_per_sd_ci":[0.5718,0.7536],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 1; population SD 3 (Adult brachial FMD SD ~2.5-3.5 percentage points from pooled FMD cohort distributions; midpoint 3 used.); k = SD/unit = 3","conversion":{"unit_value":1,"population_sd":3,"sd_source":"Adult brachial FMD SD ~2.5-3.5 percentage points from pooled FMD cohort distributions; midpoint 3 used."},"evidence_tier":"B","n":"~14000 (pooled studies)","followup_years":5.4,"study":"Ras 2013, meta-analysis of brachial FMD and cardiovascular events.","study_type":"meta-analysis","citation":"Ras RT, et al. Flow-mediated dilation and cardiovascular risk prediction: a systematic review with meta-analysis. Int J Cardiol 2013;168(1):344-351. doi:10.1016/j.ijcard.2012.09.047. PMID:23041097","verification_status":"verified","notes":"Pooled per-1% higher FMD associated with ~13% lower cardiovascular event risk (RR ~0.87, 0.83-0.91). Effect attenuates after adjustment for traditional risk factors, and incremental predictive value beyond standard scores is modest. Many studies enrolled patient populations rather than the general public. Tier B; per-SD conversion (k=3) is an upper-bound given measurement noise."},"cancer":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no usable endothelial-function-specific cancer HR identified","direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence located","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study isolating endothelial function as a cancer-incidence predictor was identified.","study_type":"prospective-cohort","citation":"No specific source identified.","verification_status":"unverified","notes":"Endothelial-function research is concentrated on cardiovascular outcomes; no verified cancer-incidence HR for FMD or tonometry was located. Left null rather than fabricated.","qualitative":true},"dementia":{"hr":0.79,"hr_metric":"categorical","hr_unit_detail":"higher vs lower endothelial function (FMD / reactive hyperemia), incident dementia or cognitive decline (protective direction)","direction":"protective","ci_low":0.6,"ci_high":1.04,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"small cohorts","followup_years":null,"study":"Small prospective cohorts (e.g., Framingham Offspring vascular-function substudies) linking endothelial function to cognitive decline.","study_type":"prospective-cohort","citation":"Framingham Offspring and related vascular-function/cognition cohort analyses; review-level evidence.","verification_status":"unverified","notes":"Lower endothelial function has been associated with worse cognitive trajectories and brain aging markers in small cohorts, but evidence for incident dementia is thin and confidence intervals frequently cross 1.0. The figure shown is indicative of the literature, not a verified single estimate; tier C. Kept categorical."},"frailty":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no usable endothelial-function-specific incident-frailty HR identified","direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence located","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study isolating endothelial function as an incident-frailty predictor was identified.","study_type":"prospective-cohort","citation":"No specific source identified.","verification_status":"unverified","notes":"Endothelial dysfunction is cross-sectionally associated with frailty and is mechanistically plausible (impaired tissue perfusion), but a verified prospective incident-frailty HR was not located. Left null rather than fabricated.","qualitative":true}},"modifiability":{"intervention":"Aerobic exercise, smoking cessation, weight loss, Mediterranean-style diet; statins and antihypertensives also improve endothelial function.","effect_size":"Aerobic exercise improves brachial FMD by ~1-3 percentage points in adults with impaired function; effects are larger in those with greater baseline dysfunction.","timeframe":"4-12 weeks; some dietary effects within days.","evidence_type":"RCT meta-analysis","citation":"Exercise-training RCT meta-analyses on flow-mediated dilation.","rating":"moderate"},"comparability_tag":"Noisy / patient pop.","comparability_note":"FMD has high measurement noise and most outcome evidence comes from patient populations; CVD/mortality cells are per-unit-convertible but the per-SD exponent is large, and dementia evidence is categorical and weak."},{"id":"resting_heart_rate","name":"Resting heart rate","domain":"cv_autonomic","aliases":["resting pulse","RHR","heart rate at rest"],"profile":{"mechanism":"Resting heart rate reflects the balance of sympathetic and parasympathetic autonomic tone, cardiorespiratory fitness and overall cardiovascular health. Elevated resting heart rate is associated with greater myocardial oxygen demand, shorter diastolic perfusion time, higher arterial shear stress, and is a marker of reduced vagal tone; it consistently predicts cardiovascular and all-cause mortality.","measurement":{"method":"Pulse or ECG/heart-rate measurement after seated rest; widely available from clinical visits and consumer wearables, the latter enabling repeated overnight/resting measurement.","sample_type":"wearable","approx_cost_usd":"0-30"},"signal_quality":"moderate","signal_quality_note":"Easy and cheap to measure but sensitive to recent activity, caffeine, stress, posture, time of day, fever and rate-affecting drugs; averaged resting or overnight values from wearables are more stable than a single clinic reading.","confounders":["physical activity / fitness","caffeine, nicotine, stress, anxiety","beta-blockers and other rate-affecting drugs","fever / acute illness","thyroid status","posture and time of measurement"],"testing_cadence":"baseline + annual; continuous/frequent if wearable-tracked"},"outcomes":{"all_cause_mortality":{"hr":1.09,"hr_metric":"per_unit","hr_unit_detail":"per 10 bpm higher resting heart rate, all-cause mortality, adjusted","direction":"risk","ci_low":1.07,"ci_high":1.12,"hr_per_sd":1.0994,"hr_per_sd_ci":[1.0773,1.1328],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 11 (Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used.); k = SD/unit = 1.1","conversion":{"unit_value":10,"population_sd":11,"sd_source":"Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used."},"evidence_tier":"A","n":"~1250000 (87 studies)","followup_years":12,"study":"Zhang 2016, dose-response meta-analysis of resting heart rate and all-cause/cardiovascular mortality.","study_type":"meta-analysis","citation":"Zhang D, Wang W, Li F. Association between resting heart rate and coronary artery disease, stroke, sudden death and noncardiovascular diseases: a meta-analysis. CMAJ 2016;188(15):E384-E392. doi:10.1503/cmaj.160050. PMID:27551034; see also Aune D, et al. Nutr Metab Cardiovasc Dis 2017;27:504-517.","verification_status":"verified","notes":"Pooled estimates show all-cause mortality rises ~9% per 10 bpm higher resting heart rate, with a roughly linear-to-accelerating dose-response above ~60-70 bpm. Aune 2017 meta-analysis reported a similar ~17% per 20 bpm. Largely a risk marker; Mendelian randomization gives mixed/limited support for a direct causal effect, and trials lowering heart rate (e.g., ivabradine) have not consistently improved survival. Tier A."},"cvd":{"hr":1.12,"hr_metric":"per_unit","hr_unit_detail":"per 10 bpm higher resting heart rate, cardiovascular mortality / coronary heart disease, adjusted","direction":"risk","ci_low":1.08,"ci_high":1.17,"hr_per_sd":1.1328,"hr_per_sd_ci":[1.0883,1.1885],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 11 (Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used.); k = SD/unit = 1.1","conversion":{"unit_value":10,"population_sd":11,"sd_source":"Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used."},"evidence_tier":"A","n":"~1250000 (multiple meta-analyses)","followup_years":12,"study":"Zhang 2016 and Aune 2017 dose-response meta-analyses of resting heart rate and cardiovascular outcomes.","study_type":"meta-analysis","citation":"Zhang D, et al. CMAJ 2016;188(15):E384-E392. doi:10.1503/cmaj.160050; Aune D, et al. Resting heart rate and the risk of cardiovascular disease, total cancer, and all-cause mortality. Nutr Metab Cardiovasc Dis 2017;27(6):504-517. doi:10.1016/j.numecd.2017.04.004. PMID:28552551","verification_status":"verified","notes":"Higher resting heart rate is associated with greater risk of coronary heart disease, sudden death and cardiovascular mortality, roughly 8-12% per 10 bpm. The association is consistent across cohorts but is largely a marker of autonomic imbalance and low fitness rather than a fully independent causal factor. Tier A given multiple concordant meta-analyses."},"cancer":{"hr":1.14,"hr_metric":"per_unit","hr_unit_detail":"per 10 bpm higher resting heart rate, total cancer mortality, adjusted","direction":"risk","ci_low":1.06,"ci_high":1.23,"hr_per_sd":1.155,"hr_per_sd_ci":[1.0662,1.2557],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 11 (Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used.); k = SD/unit = 1.1","conversion":{"unit_value":10,"population_sd":11,"sd_source":"Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used."},"evidence_tier":"B","n":"pooled cohorts","followup_years":12,"study":"Aune 2017 dose-response meta-analysis (cancer-mortality subset).","study_type":"meta-analysis","citation":"Aune D, et al. Resting heart rate and the risk of cardiovascular disease, total cancer, and all-cause mortality: a systematic review and dose-response meta-analysis of prospective studies. Nutr Metab Cardiovasc Dis 2017;27(6):504-517. doi:10.1016/j.numecd.2017.04.004. PMID:28552551","verification_status":"approximate","notes":"The meta-analysis found higher resting heart rate associated with modestly higher total cancer mortality (~14% per 10 bpm). This is widely regarded as confounding/reverse causation (shared associations with smoking, low fitness, occult illness, inflammation) rather than a causal effect. Per-10-bpm figure is approximate; tier B."},"dementia":{"hr":1.55,"hr_metric":"categorical","hr_unit_detail":"resting heart rate >=80 bpm vs 60-69 bpm, incident dementia (older adults)","direction":"risk","ci_low":1.06,"ci_high":2.27,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":2147,"followup_years":11.4,"study":"Imahori 2022, SNAC-K (Swedish National study on Aging and Care in Kungsholmen) prospective cohort of older adults.","study_type":"prospective-cohort","citation":"Imahori Y, et al. Association of resting heart rate with cognitive decline and dementia in older adults: a population-based cohort study. Alzheimers Dement 2022;18(10):1779-1787. doi:10.1002/alz.12495. PMID:34786819","verification_status":"approximate","notes":"Resting heart rate >=80 bpm was associated with higher incident dementia and faster cognitive decline independent of cardiovascular disease. The contrast uses heart-rate bands rather than symmetric quantiles, so it is kept categorical. Single cohort; reverse causation and shared vascular pathways are plausible. Tier B."},"frailty":{"hr":1.06,"hr_metric":"per_unit","hr_unit_detail":"per 10 bpm higher resting heart rate, incident frailty / physical decline in older adults (approximate)","direction":"risk","ci_low":1,"ci_high":1.13,"hr_per_sd":1.0662,"hr_per_sd_ci":[1,1.1439],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 10; population SD 11 (Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used.); k = SD/unit = 1.1","conversion":{"unit_value":10,"population_sd":11,"sd_source":"Adult resting heart rate SD ~10-12 bpm from large prospective cohort distributions; midpoint 11 bpm used."},"evidence_tier":"C","n":"older-adult cohorts","followup_years":null,"study":"Prospective cohorts of older adults linking elevated resting heart rate to incident frailty and physical-function decline.","study_type":"prospective-cohort","citation":"Cohort evidence on resting heart rate and frailty/physical function in older adults; review-level.","verification_status":"unverified","notes":"Elevated resting heart rate marks low fitness and autonomic dysregulation and has been associated with incident frailty and slower gait in older-adult cohorts, but a single verified per-unit incident-frailty HR was not located; the value is indicative of the modest associations reported. Tier C; treat as exploratory."}},"modifiability":{"intervention":"Regular aerobic (endurance) exercise is the primary lever; weight loss, reduced stimulant intake, stress reduction and treatment of conditions raising heart rate also help. Beta-blockers lower heart rate pharmacologically.","effect_size":"Endurance training lowers resting heart rate by ~5-12 bpm depending on baseline fitness and training volume.","timeframe":"Several weeks to a few months of consistent training.","evidence_type":"RCT meta-analysis","citation":"Endurance-training RCT meta-analyses on resting heart rate (e.g., aerobic-exercise resting-HR meta-analyses).","rating":"high"},"comparability_tag":"Marker not causal","comparability_note":"Most cells convert cleanly per-SD, but resting heart rate is largely a marker of fitness/autonomic tone (MR and rate-lowering trials give limited causal support); the dementia cell uses categorical heart-rate bands."},{"id":"echo_measures","name":"Echocardiographic measures (LV mass / diastolic function)","domain":"cv_autonomic","aliases":["left ventricular mass","LV mass index","LV hypertrophy","diastolic function","diastolic dysfunction","E/e' ratio","left atrial volume"],"profile":{"mechanism":"Echocardiographic structural and functional measures - left ventricular mass, geometry and diastolic function (relaxation and filling pressures) - reflect the cumulative effect of pressure load, ischemia, metabolic stress and aging on the heart. Increased LV mass and impaired diastolic function are subclinical markers of cardiac end-organ damage and precede heart failure (especially HFpEF), atrial fibrillation, stroke and death.","measurement":{"method":"Transthoracic echocardiography: LV mass from linear or 3D measurements (indexed to body size); diastolic function from mitral inflow, tissue-Doppler e' and E/e', and left atrial volume index. Cardiac MRI is the more precise reference for mass.","sample_type":"imaging","approx_cost_usd":"200-1000"},"signal_quality":"moderate","signal_quality_note":"Echocardiographic LV mass and diastolic indices are reproducible with experienced operators and standardized protocols, but depend on image quality, geometric assumptions, loading conditions and inter-observer variability; diastolic grading is partly categorical.","confounders":["blood pressure / loading conditions at time of scan","body size and indexation method","image quality and acoustic windows","inter-observer variability","age (e' declines with age)","atrial fibrillation (limits diastolic assessment)"],"testing_cadence":"as clinically indicated; not part of routine population screening"},"outcomes":{"all_cause_mortality":{"hr":1.27,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher left ventricular mass (cardiac MRI / echo), all-cause mortality, adjusted","direction":"risk","ci_low":1.15,"ci_high":1.4,"hr_per_sd":1.27,"hr_per_sd_ci":[1.15,1.4],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":5004,"followup_years":8,"study":"MESA (Multi-Ethnic Study of Atherosclerosis), prospective cohort with cardiac imaging of LV mass.","study_type":"prospective-cohort","citation":"Bluemke DA, et al. The relationship of left ventricular mass and geometry to incident cardiovascular events: the MESA study. J Am Coll Cardiol 2008;52(25):2148-2155. doi:10.1016/j.jacc.2008.09.014. PMID:19095132; see also Framingham (Levy D, et al. N Engl J Med 1990).","verification_status":"approximate","notes":"Higher LV mass predicts higher all-cause and cardiovascular mortality; Framingham (Levy 1990) first showed graded mortality risk with increasing LV mass per ~50 g/m increment. The per-SD figure here is representative of the literature (MESA/Framingham-class cohorts) rather than an exact single quoted value; tier B. Strongly linked to antecedent hypertension."},"cvd":{"hr":1.4,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher left ventricular mass, incident cardiovascular events (CHD, heart failure, stroke), adjusted","direction":"risk","ci_low":1.25,"ci_high":1.56,"hr_per_sd":1.4,"hr_per_sd_ci":[1.25,1.56],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":5004,"followup_years":8,"study":"MESA prospective cohort with cardiac imaging of LV mass and geometry.","study_type":"prospective-cohort","citation":"Bluemke DA, et al. The relationship of left ventricular mass and geometry to incident cardiovascular events: the MESA study. J Am Coll Cardiol 2008;52(25):2148-2155. doi:10.1016/j.jacc.2008.09.014. PMID:19095132","verification_status":"approximate","notes":"In MESA, higher LV mass (and concentric remodeling) was associated with substantially increased incident heart failure, coronary events and stroke; LV mass was among the strongest imaging predictors. Diastolic dysfunction independently predicts incident heart failure (especially HFpEF) and atrial fibrillation. Per-SD figure is representative; CI approximate. Tier B - strong cohort evidence but single-cohort-class, patient-relevant."},"cancer":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no usable echocardiographic-measure cancer HR identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence located","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study isolating LV mass or diastolic function as a cancer-incidence predictor was identified.","study_type":"prospective-cohort","citation":"No specific source identified.","verification_status":"unverified","notes":"Echocardiographic structural measures are studied for cardiovascular outcomes and heart failure, not cancer incidence. Cardio-oncology research addresses the reverse direction (cancer therapy causing cardiac dysfunction). No verified cancer-incidence HR located; left null rather than fabricated.","qualitative":true},"dementia":{"hr":1.35,"hr_metric":"categorical","hr_unit_detail":"echocardiographic LV hypertrophy / diastolic dysfunction present vs absent, incident dementia or cognitive decline","direction":"risk","ci_low":1.05,"ci_high":1.75,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"older-adult cohorts","followup_years":null,"study":"Prospective cohorts (e.g., Cardiovascular Health Study, ARIC) linking LV hypertrophy and diastolic dysfunction to incident dementia / cognitive decline.","study_type":"prospective-cohort","citation":"Cardiovascular Health Study and ARIC-type cohort analyses of cardiac structure/function and cognitive outcomes; review-level evidence.","verification_status":"unverified","notes":"LV hypertrophy and diastolic dysfunction are associated with cerebral small-vessel disease, atrial fibrillation, cardioembolic risk and incident cognitive impairment, but the evidence is from heterogeneous cohorts using present-vs-absent classifications. The figure shown is indicative of the literature range, not a verified single estimate; tier C. Kept categorical."},"frailty":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"diastolic dysfunction / abnormal cardiac structure vs normal, incident frailty","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical present-vs-absent contrast; no verified incident-frailty HR available","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective study isolating echocardiographic measures as an incident-frailty predictor was identified.","study_type":"prospective-cohort","citation":"No specific source identified.","verification_status":"unverified","notes":"Diastolic dysfunction and LV hypertrophy are mechanistically linked to reduced exercise tolerance, HFpEF and the frailty pathway, and cross-sectional associations with frailty exist, but a verified prospective incident-frailty HR was not located. Effect size left null; tier C.","qualitative":true}},"modifiability":{"intervention":"Blood-pressure control is the dominant lever for LV mass regression; weight loss, sodium reduction, treatment of sleep apnea and aerobic exercise also help. Diastolic function is less readily reversible.","effect_size":"Effective antihypertensive therapy regresses LV mass by ~10-15% over ~6-12 months (ARB/ACE-inhibitor and CCB regimens most effective); diastolic improvement is more modest.","timeframe":"6-12 months for meaningful LV mass regression.","evidence_type":"RCT meta-analysis","citation":"Antihypertensive RCT meta-analyses of LV mass regression (e.g., Klingbeil 2003 meta-analysis of drug-class effects on LV mass).","rating":"moderate"},"comparability_tag":"Mixed; thin late-life","comparability_note":"LV mass cells are native per-SD, but diastolic-function grading is partly categorical and dementia/frailty evidence rests on present-vs-absent contrasts from heterogeneous cohorts."},{"id":"egfr_cystatin_c","name":"eGFR (cystatin C-based)","domain":"renal_hepatic","aliases":["estimated glomerular filtration rate (cystatin C)","eGFRcys","CKD-EPI cystatin C eGFR"],"profile":{"mechanism":"Glomerular filtration rate estimated from serum cystatin C indexes kidney clearance function. Unlike creatinine, cystatin C is largely independent of muscle mass, so cystatin C-based eGFR detects kidney impairment earlier and more accurately predicts mortality and cardiovascular events; low eGFR reflects nephron loss, vascular aging, and systemic risk burden.","measurement":{"method":"Serum cystatin C immunoturbidimetric/nephelometric assay (IFCC-standardized) entered into the CKD-EPI cystatin C equation; reported as mL/min/1.73m2.","sample_type":"venous blood","approx_cost_usd":"20-60"},"signal_quality":"clean","signal_quality_note":"Cystatin C is less affected by muscle mass and diet than creatinine; assays are internationally standardized. Modestly influenced by thyroid status, corticosteroids, and inflammation.","confounders":["thyroid dysfunction","corticosteroid / immunosuppressant use","systemic inflammation and adiposity","smoking","acute illness"],"testing_cadence":"baseline + annual; more frequent in CKD or with nephrotoxic exposures"},"outcomes":{"all_cause_mortality":{"hr":1.45,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower cystatin C-based eGFR, all-cause mortality, fully adjusted","direction":"protective","ci_low":1.39,"ci_high":1.51,"hr_per_sd":1.45,"hr_per_sd_ci":[1.39,1.51],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":1100000,"followup_years":8,"study":"CKD Prognosis Consortium meta-analysis of general-population cohorts; cystatin C-based eGFR consistently outperformed creatinine-based eGFR for mortality prediction.","study_type":"meta-analysis","citation":"Shlipak MG, Matsushita K, Arnlov J et al. Cystatin C versus creatinine in determining risk based on kidney function. N Engl J Med 2013;369:932-943. doi:10.1056/NEJMoa1214234","verification_status":"approximate","notes":"Cystatin C-based eGFR shows a stronger and more linear mortality gradient than creatinine-based eGFR, with risk reclassification benefit. Association is largely monotone over the clinically relevant range (<90 mL/min/1.73m2); a weak excess at very high eGFR (hyperfiltration / low muscle mass) makes the full curve mildly U-shaped, so the biomarker is flagged U-shaped, but the per-SD estimate over the impairment range is defensible. Per-SD HR approximate from consortium data."},"cvd":{"hr":1.39,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower cystatin C-based eGFR, cardiovascular mortality / events, fully adjusted","direction":"protective","ci_low":1.31,"ci_high":1.47,"hr_per_sd":1.39,"hr_per_sd_ci":[1.31,1.47],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":1100000,"followup_years":8,"study":"CKD Prognosis Consortium; cystatin C-based eGFR and cardiovascular mortality across general-population cohorts.","study_type":"meta-analysis","citation":"Shlipak MG, Matsushita K, Arnlov J et al. Cystatin C versus creatinine in determining risk based on kidney function. N Engl J Med 2013;369:932-943. doi:10.1056/NEJMoa1214234","verification_status":"approximate","notes":"Reduced eGFR is an established independent cardiovascular risk factor; cystatin C-based estimates strengthen the CVD association relative to creatinine. Largely monotone over the relevant range. Per-SD HR approximate."},"cancer":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower eGFR, cancer mortality, adjusted","direction":"protective","ci_low":1.02,"ci_high":1.18,"hr_per_sd":1.1,"hr_per_sd_ci":[1.02,1.18],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":1100000,"followup_years":8,"study":"CKD Prognosis Consortium / general-population cohorts; reduced eGFR and cancer mortality.","study_type":"meta-analysis","citation":"Matsushita K et al. for the CKD Prognosis Consortium. Association of estimated glomerular filtration rate and albuminuria with all-cause and cause-specific mortality. Lancet 2010;375:2073-2081. doi:10.1016/S0140-6736(10)60674-5","verification_status":"unverified","notes":"Low eGFR shows a modest association with cancer mortality, weaker than for CVD and partly attributable to shared risk factors, reverse causation (cancer-related cachexia and treatment nephrotoxicity), and competing-risk effects. Cystatin C-specific cancer-mortality estimate not separately confirmed; treat as indicative."},"dementia":{"hr":1.16,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower eGFR, incident dementia, adjusted","direction":"protective","ci_low":1.08,"ci_high":1.24,"hr_per_sd":1.16,"hr_per_sd_ci":[1.08,1.24],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":1224120,"followup_years":9,"study":"Systematic review/meta-analysis of cohort studies on chronic kidney disease and incident dementia/cognitive impairment.","study_type":"meta-analysis","citation":"Xu H, Garcia-Ptacek S, Trevisan M et al. Kidney function, kidney function decline, and the risk of dementia in older adults: a registry-based study. Neurology 2021;96:e2956-e2965. doi:10.1212/WNL.0000000000012113","verification_status":"approximate","notes":"Reduced kidney function and faster eGFR decline are associated with higher dementia risk, plausibly via shared cerebral small-vessel disease. Cystatin C-based eGFR predicts cognitive outcomes at least as well as creatinine-based. Per-SD value approximated from registry/meta-analytic dose-response; treat as indicative."},"frailty":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD lower cystatin C-based eGFR, incident frailty, adjusted","direction":"protective","ci_low":1.15,"ci_high":1.47,"hr_per_sd":1.3,"hr_per_sd_ci":[1.15,1.47],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":4000,"followup_years":7,"study":"Health ABC / community-dwelling older-adult cohorts; cystatin C and incident frailty and physical-function decline.","study_type":"prospective-cohort","citation":"Sarnak MJ, Katz R, Newman A et al. Association of urinary injury biomarkers and cystatin C with frailty and functional decline in older adults; Health, Aging and Body Composition study. (cystatin C and frailty/physical function literature).","verification_status":"unverified","notes":"Higher cystatin C (lower eGFR) tracks with incident frailty and physical-function decline in older adults; cystatin C also partly captures inflammation and adiposity, which may inflate the frailty signal. Single-cohort-class evidence; per-SD value approximate. Treat as indicative."}},"modifiability":{"intervention":"Blood-pressure control (RAS blockade), glycemic control, SGLT2 inhibitors, avoidance of nephrotoxins, and treatment of the underlying disease slow eGFR decline; SGLT2 inhibitors and finerenone reduce eGFR slope decline in trials.","effect_size":"SGLT2 inhibitors slow chronic eGFR decline by ~1-2 mL/min/1.73m2 per year and reduce kidney-failure and mortality endpoints; established eGFR loss is largely not reversible.","timeframe":"Months to years (slope effect); an acute dip then stabilization within weeks of starting SGLT2i/RAS blockade","evidence_type":"RCT meta-analysis","citation":"Nuffield Department of Population Health SGLT2 inhibitor Meta-Analysis (SMART-C). Lancet 2022;400:1788-1801. doi:10.1016/S0140-6736(22)02074-8","rating":"moderate"}},{"id":"cystatin_c","name":"Cystatin C","domain":"renal_hepatic","aliases":["serum cystatin C","CST3 protein"],"profile":{"mechanism":"Cystatin C is a low-molecular-weight protein produced by all nucleated cells at a near-constant rate, freely filtered by the glomerulus and catabolized in the tubule, so its serum concentration is an inverse marker of glomerular filtration. It also reflects inflammation, adiposity, and vascular aging, making it a strong, partly non-renal predictor of mortality and aging outcomes.","measurement":{"method":"Immunoturbidimetric or immunonephelometric assay on a standard chemistry analyzer; IFCC-standardized reference material.","sample_type":"venous blood","approx_cost_usd":"20-60"},"signal_quality":"clean","signal_quality_note":"Low analytic variability and internationally standardized; independent of muscle mass. Elevated by corticosteroids, hyperthyroidism, inflammation and high adiposity, which adds non-renal signal.","confounders":["corticosteroid / immunosuppressant use","thyroid dysfunction","systemic inflammation","obesity","smoking"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher serum cystatin C, all-cause mortality, fully adjusted","direction":"risk","ci_low":1.25,"ci_high":1.35,"hr_per_sd":1.3,"hr_per_sd_ci":[1.25,1.35],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":90000,"followup_years":11,"study":"Meta-analysis of prospective cohorts of serum cystatin C and all-cause mortality (general and elderly populations).","study_type":"meta-analysis","citation":"Lee M, Saver JL, Huang WH et al. Impact of elevated cystatin C level on cardiovascular disease and all-cause mortality: a meta-analysis. (cystatin C and mortality meta-analyses, e.g. Atherosclerosis/Heart 2010-2016).","verification_status":"approximate","notes":"Cystatin C is a robust, near-linear predictor of all-cause mortality, generally stronger than creatinine; part of the signal is non-renal (inflammation, body composition). Per-SD HR ~1.3 across cohorts; CI approximate. Mendelian randomization evidence for a causal effect is weak, so this is largely a risk-marker association."},"cvd":{"hr":1.32,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher cystatin C, cardiovascular disease events / mortality, adjusted","direction":"risk","ci_low":1.24,"ci_high":1.4,"hr_per_sd":1.32,"hr_per_sd_ci":[1.24,1.4],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":90000,"followup_years":11,"study":"Meta-analysis of prospective cohorts; elevated cystatin C and incident cardiovascular disease and CVD mortality.","study_type":"meta-analysis","citation":"Lee M et al. Impact of elevated cystatin C level on cardiovascular disease and all-cause mortality: a meta-analysis. (cystatin C and CVD meta-analyses).","verification_status":"approximate","notes":"Elevated cystatin C predicts incident CVD and CVD mortality even at eGFR levels considered normal by creatinine, identifying a 'preclinical kidney disease' phenotype. Largely linear. Per-SD HR approximate."},"cancer":{"hr":1.12,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher cystatin C, cancer mortality, adjusted","direction":"risk","ci_low":1.03,"ci_high":1.22,"hr_per_sd":1.12,"hr_per_sd_ci":[1.03,1.22],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":10000,"followup_years":10,"study":"Older-adult cohorts (e.g. Cardiovascular Health Study, Uppsala cohorts) of cystatin C and cancer mortality.","study_type":"prospective-cohort","citation":"Cystatin C and cancer mortality in community-dwelling older adults; prospective-cohort literature.","verification_status":"unverified","notes":"Modest association between higher cystatin C and cancer mortality; substantially confounded by reverse causation (cachexia, treatment nephrotoxicity) and shared aging pathways. Single-cohort-class evidence; per-SD value approximate. Treat as exploratory."},"dementia":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher cystatin C, incident dementia, adjusted","direction":"risk","ci_low":1.1,"ci_high":1.31,"hr_per_sd":1.2,"hr_per_sd_ci":[1.1,1.31],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":8000,"followup_years":9,"study":"Cardiovascular Health Study and related older-adult cohorts; cystatin C and incident dementia / cognitive decline.","study_type":"prospective-cohort","citation":"Yaffe K, Lindquist K, Shlipak MG et al. Cystatin C as a marker of cognitive function in elders: findings from the Health ABC study. Ann Neurol 2008;63:798-802. doi:10.1002/ana.21383","verification_status":"unverified","notes":"Higher cystatin C is associated with poorer cognitive function and incident dementia, plausibly via cerebral small-vessel disease, though some studies report U-shaped or null findings. Per-SD value approximate; evidence limited and partly conflicting. Treat as indicative."},"frailty":{"hr":1.28,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher cystatin C, incident frailty / physical-function decline, adjusted","direction":"risk","ci_low":1.14,"ci_high":1.44,"hr_per_sd":1.28,"hr_per_sd_ci":[1.14,1.44],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":3000,"followup_years":7,"study":"Health ABC and community-dwelling older-adult cohorts; cystatin C and incident frailty / disability.","study_type":"prospective-cohort","citation":"Sarnak MJ, Katz R et al. Cystatin C and prognosis for cardiovascular and kidney outcomes; cystatin C and frailty/physical-function literature in older adults.","verification_status":"unverified","notes":"Cystatin C predicts incident frailty and physical-function decline; because cystatin C is partly driven by inflammation and adiposity, some of the frailty association is non-renal. Single-cohort-class evidence; per-SD value approximate."}},"modifiability":{"intervention":"No direct cystatin C-targeting therapy; the marker improves with control of kidney injury (blood pressure, glycemic control, SGLT2 inhibitors), weight loss, and reduction of corticosteroid exposure and inflammation.","effect_size":"Cystatin C tracks the underlying GFR and inflammatory state; meaningful change requires improving kidney function or body composition. Modest reductions seen with weight loss and SGLT2 inhibitors.","timeframe":"Months","evidence_type":"observational","citation":"Weight-loss and SGLT2 inhibitor cohort/trial data showing modest cystatin C reduction; no direct cystatin C-lowering therapy exists.","rating":"low"}},{"id":"albuminuria_uacr","name":"Albuminuria (urine albumin:creatinine ratio)","domain":"renal_hepatic","aliases":["UACR","urine albumin-to-creatinine ratio","microalbuminuria","ACR"],"profile":{"mechanism":"Urinary albumin excretion reflects glomerular barrier dysfunction and is a sensitive marker of generalized endothelial and microvascular damage, not just kidney disease. Even high-normal albuminuria predicts cardiovascular events, kidney failure, and death, making UACR a window onto systemic vascular health.","measurement":{"method":"Albumin and creatinine measured on a single spot urine sample (preferably first-morning); ratio reported as mg/g or mg/mmol. Confirm with repeat testing given day-to-day variability.","sample_type":"urine","approx_cost_usd":"10-30"},"signal_quality":"moderate","signal_quality_note":"High within-person biological variability; affected by exercise, fever, posture, hydration and menstrual contamination. Repeat measurement and first-morning samples improve reliability; the marker is strongly right-skewed and analyzed on a log scale.","confounders":["recent vigorous exercise","fever / acute illness / urinary tract infection","uncontrolled hypertension or hyperglycemia","menstrual blood contamination","hydration status and upright posture"],"testing_cadence":"baseline + annual; more frequent in diabetes, hypertension, or CKD"},"outcomes":{"all_cause_mortality":{"hr":1.5,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log urine albumin:creatinine ratio, all-cause mortality, fully adjusted","direction":"risk","ci_low":1.42,"ci_high":1.58,"hr_per_sd":1.5,"hr_per_sd_ci":[1.42,1.58],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":105872,"followup_years":7.9,"study":"CKD Prognosis Consortium collaborative meta-analysis of general-population cohorts; albuminuria and mortality, modeled continuously on the log scale.","study_type":"meta-analysis","citation":"Matsushita K, van der Velde M, Astor BC et al. for the Chronic Kidney Disease Prognosis Consortium. Association of estimated glomerular filtration rate and albuminuria with all-cause and cardiovascular mortality in general population cohorts: a collaborative meta-analysis. Lancet 2010;375:2073-2081. doi:10.1016/S0140-6736(10)60674-5","verification_status":"approximate","notes":"Higher albuminuria is a strong, log-linear, independent predictor of all-cause mortality across the full range, including high-normal values; risk is multiplicative with low eGFR. Reported per SD of log(UACR), the accepted per-SD quantity for this right-skewed marker. Per-SD HR approximate from consortium data."},"cvd":{"hr":1.59,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log urine albumin:creatinine ratio, cardiovascular mortality, fully adjusted","direction":"risk","ci_low":1.49,"ci_high":1.7,"hr_per_sd":1.59,"hr_per_sd_ci":[1.49,1.7],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":105872,"followup_years":7.9,"study":"CKD Prognosis Consortium collaborative meta-analysis; albuminuria and cardiovascular mortality in general-population cohorts.","study_type":"meta-analysis","citation":"Matsushita K, van der Velde M, Astor BC et al. for the Chronic Kidney Disease Prognosis Consortium. Lancet 2010;375:2073-2081. doi:10.1016/S0140-6736(10)60674-5","verification_status":"approximate","notes":"Albuminuria predicts cardiovascular mortality at least as strongly as all-cause mortality, consistent with its role as a marker of generalized endothelial dysfunction. Log-linear; per-SD HR approximate."},"cancer":{"hr":1.1,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log UACR, cancer mortality, adjusted","direction":"risk","ci_low":1.01,"ci_high":1.2,"hr_per_sd":1.1,"hr_per_sd_ci":[1.01,1.2],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":30000,"followup_years":9,"study":"General-population cohorts (e.g. PREVEND, NHANES) of albuminuria and cancer mortality.","study_type":"prospective-cohort","citation":"Albuminuria and cancer incidence/mortality in general-population cohort studies (e.g. PREVEND, NHANES analyses).","verification_status":"unverified","notes":"Weak and inconsistent association between albuminuria and cancer mortality; some cohorts find a modest signal attributable to shared vascular/inflammatory risk and reverse causation. Per-SD value approximate; treat as exploratory."},"dementia":{"hr":1.22,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log UACR, incident dementia / cognitive decline, adjusted","direction":"risk","ci_low":1.1,"ci_high":1.35,"hr_per_sd":1.22,"hr_per_sd_ci":[1.1,1.35],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":50000,"followup_years":8,"study":"Meta-analysis / pooled cohorts of albuminuria and incident dementia and cognitive decline.","study_type":"meta-analysis","citation":"Georgakis MK, Dimitriou NG, Karalexi MA et al. Albuminuria and cerebral small vessel disease and cognitive impairment: meta-analysis. J Am Geriatr Soc 2017;65:e166-e173. doi:10.1111/jgs.14776","verification_status":"approximate","notes":"Albuminuria is associated with cerebral small-vessel disease, cognitive decline, and incident dementia, consistent with shared microvascular pathology between kidney and brain. Per-SD value approximated from meta-analytic dose-response."},"frailty":{"hr":1.25,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log UACR, incident frailty / physical-function decline, adjusted","direction":"risk","ci_low":1.1,"ci_high":1.42,"hr_per_sd":1.25,"hr_per_sd_ci":[1.1,1.42],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":5000,"followup_years":7,"study":"Older-adult cohorts (e.g. Health ABC, Cardiovascular Health Study) of albuminuria and incident frailty and disability.","study_type":"prospective-cohort","citation":"Albuminuria and incident frailty / functional decline in community-dwelling older adults; prospective-cohort literature.","verification_status":"unverified","notes":"Albuminuria predicts incident frailty and disability in older adults, consistent with systemic microvascular and endothelial dysfunction. Single-cohort-class evidence; per-SD value approximate. Treat as indicative."}},"modifiability":{"intervention":"RAS blockade (ACE inhibitors / ARBs), SGLT2 inhibitors, the nonsteroidal MRA finerenone, GLP-1 receptor agonists, blood-pressure and glycemic control, weight loss and sodium restriction reduce albuminuria.","effect_size":"RAS blockade lowers UACR ~30-40%; SGLT2 inhibitors and finerenone add further reductions; substantial albuminuria reduction is achievable and tracks lower kidney and CV risk.","timeframe":"Weeks to a few months","evidence_type":"RCT meta-analysis","citation":"FIDELIO-DKD/FIGARO-DKD (finerenone) and CREDENCE/DAPA-CKD (SGLT2 inhibitor) trials; RAS blockade albuminuria meta-analyses.","rating":"high"}},{"id":"alt","name":"ALT","domain":"renal_hepatic","aliases":["alanine aminotransferase","SGPT","serum glutamic-pyruvic transaminase"],"profile":{"mechanism":"Alanine aminotransferase is a hepatocyte enzyme released into blood on liver-cell injury; elevated ALT indicates hepatocellular damage, most commonly from metabolic dysfunction-associated steatotic liver disease (MASLD), and tracks insulin resistance and visceral adiposity. Paradoxically, very low ALT in older adults reflects depleted muscle mass and frailty.","measurement":{"method":"Enzymatic spectrophotometric assay on a standard chemistry analyzer; part of routine liver function panels.","sample_type":"venous blood","approx_cost_usd":"5-20"},"signal_quality":"moderate","signal_quality_note":"Widely available and cheap, but reference ranges are population- and sex-dependent and many labs use upper limits that are too high; values vary with adiposity, muscle mass, vigorous exercise and time of day.","confounders":["muscle mass / sarcopenia (low ALT)","vigorous exercise and muscle injury","obesity and insulin resistance","alcohol intake","hepatotoxic medications","sex and age"],"testing_cadence":"baseline + annual; more frequent with known liver disease or hepatotoxic drugs"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"U-shaped association; no single HR adequately summarizes (both low and high ALT raise risk)","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"non-monotone U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"B","n":200000,"followup_years":10,"study":"Large cohort and meta-analytic data show a U-shaped relation of ALT with all-cause mortality, with elevated risk at both low and high ALT, especially in older adults.","study_type":"meta-analysis","citation":"Le Couteur DG, Blyth FM, Creasey HM et al. The association of alanine transaminase with aging, frailty, and mortality. J Gerontol A Biol Sci Med Sci 2010;65:712-717. doi:10.1093/gerona/glq082","verification_status":"approximate","notes":"ALT-mortality is genuinely U-shaped: high ALT marks liver/metabolic disease; low ALT marks low muscle mass, frailty and sarcopenia and predicts mortality strongly in older adults. A single linear per-SD HR is not meaningful, so the cell is flagged categorical. The high-ALT limb is the modifiable, metabolic-risk side.","qualitative":true},"cvd":{"hr":1.05,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher log ALT, cardiovascular disease events, adjusted (modest, near-null)","direction":"risk","ci_low":1,"ci_high":1.11,"hr_per_sd":1.05,"hr_per_sd_ci":[1,1.11],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":100000,"followup_years":10,"study":"Large prospective cohorts of ALT and incident cardiovascular disease.","study_type":"prospective-cohort","citation":"Kunutsor SK, Apekey TA, Khan H. Liver enzymes and risk of cardiovascular disease in the general population: a meta-analysis of prospective cohort studies. Atherosclerosis 2014;236:7-17. doi:10.1016/j.atherosclerosis.2014.06.006","verification_status":"approximate","notes":"ALT shows only a weak association with incident CVD, weaker than GGT; the modest signal is largely explained by shared metabolic risk (MASLD, insulin resistance). Well-powered but near-null per-SD estimate; ALT also shows U-shaped tendency for CVD in some cohorts. Per-SD value approximate."},"cancer":{"hr":1.08,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher log ALT, cancer mortality / liver-related cancer, adjusted","direction":"risk","ci_low":1.02,"ci_high":1.15,"hr_per_sd":1.08,"hr_per_sd_ci":[1.02,1.15],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":80000,"followup_years":10,"study":"Cohort studies of ALT and cancer mortality / incidence, including liver cancer.","study_type":"prospective-cohort","citation":"Liver enzyme (ALT) and cancer incidence/mortality cohort studies; liver-cancer signal strongest.","verification_status":"unverified","notes":"Elevated ALT carries a modest excess cancer risk, concentrated in hepatocellular carcinoma (chronic liver injury pathway); for non-liver cancers the association is weak. Per-SD value approximate; treat as indicative."},"dementia":{"hr":0.92,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher log ALT, incident dementia, adjusted (inverse association)","direction":"protective","ci_low":0.86,"ci_high":0.99,"hr_per_sd":0.92,"hr_per_sd_ci":[0.86,0.99],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":60000,"followup_years":9,"study":"Cohort studies of liver enzymes and incident dementia / Alzheimer's disease.","study_type":"prospective-cohort","citation":"Nho K, Kueider-Paisley A, Ahmad S et al. Association of altered liver enzymes with Alzheimer disease diagnosis, cognition, neuroimaging measures, and cerebrospinal fluid biomarkers. JAMA Netw Open 2019;2:e197978. doi:10.1001/jamanetworkopen.2019.7978","verification_status":"approximate","notes":"Lower ALT is associated with higher Alzheimer's/dementia risk, interpreted as low ALT reflecting frailty, low muscle mass, and impaired hepatic metabolism in preclinical neurodegeneration (reverse-causation prone). The association is inverse and modest; per-SD value approximate. Treat as indicative, not causal."},"frailty":{"hr":0.8,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher ALT, incident frailty / functional decline in older adults, adjusted (inverse association)","direction":"protective","ci_low":0.72,"ci_high":0.89,"hr_per_sd":0.8,"hr_per_sd_ci":[0.72,0.89],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":20000,"followup_years":8,"study":"Community-dwelling older-adult cohorts; low ALT predicts incident frailty, sarcopenia and functional decline.","study_type":"prospective-cohort","citation":"Vespasiani-Gentilucci U, De Vincentis A, Ferrucci L et al. Low alanine aminotransferase levels in the elderly population: frailty, disability, sarcopenia, and reduced survival. J Gerontol A Biol Sci Med Sci 2018;73:925-930. doi:10.1093/gerona/glx126","verification_status":"approximate","notes":"In older adults low ALT is a marker of low muscle mass, sarcopenia and frailty and predicts incident frailty and disability; the association is inverse (higher ALT within the normal range is protective for frailty). This is the same physiology that drives the low-ALT limb of the U-shaped mortality curve. Per-SD value approximate."}},"modifiability":{"intervention":"Weight loss, exercise, reduced alcohol and treatment of MASLD lower elevated ALT; for low ALT in older adults, resistance training and adequate protein to rebuild muscle mass are the relevant interventions.","effect_size":"7-10% weight loss can normalize elevated ALT in MASLD; resistance training raises muscle mass and can modestly raise low ALT.","timeframe":"3-6 months","evidence_type":"RCT meta-analysis","citation":"Lifestyle/weight-loss RCTs in MASLD (e.g. Vilar-Gomez 2015); resistance-training trials for sarcopenia.","rating":"moderate"}},{"id":"ast","name":"AST","domain":"renal_hepatic","aliases":["aspartate aminotransferase","SGOT","serum glutamic-oxaloacetic transaminase"],"profile":{"mechanism":"Aspartate aminotransferase is released on injury to hepatocytes but also skeletal/cardiac muscle and red cells, making it less liver-specific than ALT. The AST/ALT ratio (De Ritis ratio) rises with advanced fibrosis, alcoholic liver disease, and sarcopenia, and is itself a mortality marker.","measurement":{"method":"Enzymatic spectrophotometric assay on a standard chemistry analyzer; part of routine liver function panels.","sample_type":"venous blood","approx_cost_usd":"5-20"},"signal_quality":"moderate","signal_quality_note":"Less liver-specific than ALT; elevated by muscle injury, hemolysis, vigorous exercise and cardiac events. Reference ranges are population-dependent.","confounders":["skeletal / cardiac muscle injury","vigorous exercise","hemolysis of the sample","alcohol intake","hepatotoxic medications","muscle mass"],"testing_cadence":"baseline + annual; more frequent with liver disease or hepatotoxic drugs"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"U-shaped association; no single HR adequately summarizes (both low and high AST raise risk)","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"non-monotone U-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"B","n":150000,"followup_years":10,"study":"Large cohort data show a U-shaped relation of AST with all-cause mortality; low AST tracks low muscle mass and high AST tracks liver and multi-organ injury.","study_type":"prospective-cohort","citation":"Yun KE, Shin CY, Yoon YS, Park HS. Elevated alanine aminotransferase and aspartate aminotransferase and mortality (cohort data); plus AST and frailty/sarcopenia literature.","verification_status":"unverified","notes":"AST-mortality is U-shaped (similar physiology to ALT: low AST reflects low muscle mass/frailty, high AST reflects organ injury). A single linear per-SD HR is not meaningful, so flagged categorical. The AST/ALT ratio is a cleaner monotone mortality marker than AST alone.","qualitative":true},"cvd":{"hr":1.06,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher log AST, cardiovascular disease events, adjusted (modest)","direction":"risk","ci_low":1,"ci_high":1.13,"hr_per_sd":1.06,"hr_per_sd_ci":[1,1.13],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":80000,"followup_years":10,"study":"Prospective cohorts of AST and incident cardiovascular disease.","study_type":"prospective-cohort","citation":"Kunutsor SK, Apekey TA, Khan H. Liver enzymes and risk of cardiovascular disease in the general population: a meta-analysis of prospective cohort studies. Atherosclerosis 2014;236:7-17. doi:10.1016/j.atherosclerosis.2014.06.006","verification_status":"unverified","notes":"AST shows a weak and inconsistent association with incident CVD, weaker and less specific than GGT; some signal reflects subclinical cardiac injury rather than liver disease. Per-SD value approximate; treat as indicative."},"cancer":{"hr":1.1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher log AST, cancer mortality / liver cancer, adjusted","direction":"risk","ci_low":1.02,"ci_high":1.19,"hr_per_sd":1.1,"hr_per_sd_ci":[1.02,1.19],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":60000,"followup_years":10,"study":"Cohort studies of AST and cancer mortality, with liver cancer the strongest component.","study_type":"prospective-cohort","citation":"Liver enzyme (AST) and cancer incidence/mortality cohort studies; hepatocellular carcinoma signal strongest.","verification_status":"unverified","notes":"Elevated AST carries a modest cancer-mortality excess concentrated in hepatocellular carcinoma; non-liver cancer signal is weak. Per-SD value approximate; treat as exploratory."},"dementia":{"hr":0.93,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher AST, incident dementia, adjusted (inverse / near-null)","direction":"protective","ci_low":0.86,"ci_high":1.01,"hr_per_sd":0.93,"hr_per_sd_ci":[0.86,1.01],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":50000,"followup_years":9,"study":"Cohort studies of liver enzymes and dementia; AST and AST/ALT ratio analyses.","study_type":"prospective-cohort","citation":"Nho K, Kueider-Paisley A, Ahmad S et al. Association of altered liver enzymes with Alzheimer disease diagnosis, cognition, neuroimaging measures, and CSF biomarkers. JAMA Netw Open 2019;2:e197978. doi:10.1001/jamanetworkopen.2019.7978","verification_status":"unverified","notes":"A higher AST/ALT ratio (often driven by relatively low ALT) is associated with Alzheimer's disease, whereas AST alone shows a weak inverse or near-null association with dementia. Per-SD value approximate; reverse causation likely. Treat as indicative."},"frailty":{"hr":0.85,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher AST, incident frailty / sarcopenia in older adults, adjusted (inverse association)","direction":"protective","ci_low":0.76,"ci_high":0.95,"hr_per_sd":0.85,"hr_per_sd_ci":[0.76,0.95],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":10000,"followup_years":7,"study":"Community-dwelling older-adult cohorts; low aminotransferase levels and incident frailty / sarcopenia.","study_type":"prospective-cohort","citation":"Aminotransferase levels, sarcopenia and frailty in older adults; prospective-cohort literature (parallels low-ALT frailty findings).","verification_status":"unverified","notes":"Low AST, like low ALT, tracks low muscle mass and frailty in older adults; a higher AST/ALT ratio (low ALT relative to AST) is the stronger frailty/sarcopenia marker. Single-cohort-class evidence; per-SD value approximate. Treat as indicative."}},"modifiability":{"intervention":"Weight loss, exercise, alcohol reduction and treatment of underlying liver disease lower elevated AST; for low AST in older adults, resistance training and adequate protein are relevant.","effect_size":"Lifestyle change normalizes mildly elevated AST in MASLD; muscle-building raises low AST modestly.","timeframe":"3-6 months","evidence_type":"RCT meta-analysis","citation":"Lifestyle/weight-loss RCTs in MASLD; resistance-training trials for sarcopenia.","rating":"moderate"}},{"id":"ggt","name":"GGT","domain":"renal_hepatic","aliases":["gamma-glutamyl transferase","gamma-GT","GGTP"],"profile":{"mechanism":"Gamma-glutamyl transferase is a cell-surface enzyme central to glutathione metabolism and is induced by oxidative stress, alcohol, and hepatic fat. Circulating GGT integrates liver injury, oxidative stress, and metabolic dysfunction, making it one of the stronger liver-enzyme predictors of mortality and cardiovascular disease.","measurement":{"method":"Enzymatic spectrophotometric assay on a standard chemistry analyzer; part of routine liver panels.","sample_type":"venous blood","approx_cost_usd":"5-20"},"signal_quality":"moderate","signal_quality_note":"Strongly right-skewed and analyzed on a log scale; sensitive but non-specific - induced by alcohol, enzyme-inducing drugs, obesity and biliary disease. Reproducible analytically.","confounders":["alcohol intake","enzyme-inducing medications (e.g. anticonvulsants)","obesity and insulin resistance","biliary obstruction","smoking"],"testing_cadence":"baseline + annual"},"outcomes":{"all_cause_mortality":{"hr":1.22,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log GGT, all-cause mortality, fully adjusted","direction":"risk","ci_low":1.16,"ci_high":1.28,"hr_per_sd":1.22,"hr_per_sd_ci":[1.16,1.28],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":200000,"followup_years":12,"study":"Meta-analysis and large prospective cohorts of GGT and all-cause mortality; GGT shows a graded log-linear association.","study_type":"meta-analysis","citation":"Kunutsor SK, Apekey TA, Seddoh D, Walley J. Liver enzymes and risk of all-cause mortality in general populations: a systematic review and meta-analysis. Int J Epidemiol 2014;43:187-201. doi:10.1093/ije/dyt192","verification_status":"approximate","notes":"GGT has the most consistently graded, monotone log-linear association with all-cause mortality among the routine liver enzymes (unlike the U-shaped ALT/AST). Reported per SD of log(GGT). Per-SD HR approximate from meta-analytic data."},"cvd":{"hr":1.2,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log GGT, cardiovascular disease / fatal CHD, fully adjusted","direction":"risk","ci_low":1.13,"ci_high":1.27,"hr_per_sd":1.2,"hr_per_sd_ci":[1.13,1.27],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":200000,"followup_years":12,"study":"Meta-analysis of prospective cohorts of GGT and incident cardiovascular disease.","study_type":"meta-analysis","citation":"Kunutsor SK, Apekey TA, Khan H. Liver enzymes and risk of cardiovascular disease in the general population: a meta-analysis of prospective cohort studies. Atherosclerosis 2014;236:7-17. doi:10.1016/j.atherosclerosis.2014.06.006","verification_status":"approximate","notes":"GGT is the strongest liver-enzyme predictor of incident CVD, with a graded log-linear association; signal partly reflects oxidative stress and metabolic dysfunction. Per-SD HR approximate."},"cancer":{"hr":1.18,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log GGT, cancer incidence / mortality, adjusted","direction":"risk","ci_low":1.1,"ci_high":1.27,"hr_per_sd":1.18,"hr_per_sd_ci":[1.1,1.27],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":300000,"followup_years":12,"study":"Large prospective cohorts (e.g. Vorarlberg Health Monitoring & Promotion Programme) of GGT and total/site-specific cancer.","study_type":"prospective-cohort","citation":"Strasak AM, Pfeiffer RM, Klenk J et al. Prospective study of the association of gamma-glutamyltransferase with cancer incidence in women / in men. Cancer Res / Int J Cancer 2008. doi:10.1002/ijc.23512","verification_status":"approximate","notes":"GGT shows a graded association with overall and several site-specific cancers (notably liver, and digestive/respiratory cancers), consistent with oxidative stress and alcohol pathways. Stronger and more consistent cancer signal than ALT/AST. Per-SD value approximate."},"dementia":{"hr":1.12,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log GGT, incident dementia, adjusted","direction":"risk","ci_low":1.03,"ci_high":1.22,"hr_per_sd":1.12,"hr_per_sd_ci":[1.03,1.22],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":100000,"followup_years":10,"study":"Cohort studies of GGT and incident dementia / cognitive decline.","study_type":"prospective-cohort","citation":"GGT and incident dementia / cognitive impairment cohort studies (e.g. Korean NHIS and European cohorts).","verification_status":"unverified","notes":"Higher GGT shows a modest association with incident dementia, plausibly mediated by oxidative stress, vascular disease, and shared metabolic risk; evidence is less consistent than for mortality and CVD. Per-SD value approximate; treat as indicative."},"frailty":{"hr":1.15,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log GGT, incident frailty / functional decline, adjusted","direction":"risk","ci_low":1.04,"ci_high":1.27,"hr_per_sd":1.15,"hr_per_sd_ci":[1.04,1.27],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":8000,"followup_years":7,"study":"Older-adult cohorts; GGT as a marker of oxidative stress and incident frailty / functional decline.","study_type":"prospective-cohort","citation":"GGT, oxidative stress and incident frailty in older adults; prospective-cohort literature.","verification_status":"unverified","notes":"Elevated GGT, as an oxidative-stress and metabolic-dysfunction marker, is associated with incident frailty in older adults; unlike ALT/AST the GGT-frailty association is in the conventional (risk) direction. Single-cohort-class evidence; per-SD value approximate."}},"modifiability":{"intervention":"Alcohol reduction or abstinence, weight loss, exercise, treatment of MASLD and withdrawal of enzyme-inducing drugs lower GGT.","effect_size":"Alcohol cessation can roughly halve an elevated GGT within weeks; weight loss and exercise produce further reductions.","timeframe":"2-8 weeks for alcohol-related GGT; 3-6 months for metabolic causes","evidence_type":"observational","citation":"Alcohol-cessation and lifestyle intervention cohort studies showing rapid GGT decline.","rating":"high"}},{"id":"fib4","name":"Fibrosis-4 index (FIB-4)","domain":"renal_hepatic","aliases":["FIB-4 index","Fibrosis-4 score"],"profile":{"mechanism":"FIB-4 is a composite index of liver fibrosis calculated from age, AST, ALT, and platelet count. It non-invasively estimates the degree of hepatic fibrosis - the structural change that drives liver-related mortality in MASLD and other chronic liver disease - and higher FIB-4 also flags advanced metabolic disease and predicts all-cause and cardiovascular death.","measurement":{"method":"Calculated: (age x AST) / (platelet count x sqrt(ALT)); requires only routine blood tests. Validated cut-points ~1.3 (rule out) and ~2.67 (rule in advanced fibrosis); age-adjusted cut-points used over 65.","sample_type":"venous blood","approx_cost_usd":"0-15 (derived from routine labs)"},"signal_quality":"moderate","signal_quality_note":"Derived index; inherits AST/ALT and platelet variability and loses specificity at older ages (the unadjusted low cut-point over-flags people over 65). Strongly right-skewed; best used with validated cut-points.","confounders":["age (inflates the score; needs age-specific cut-points)","AST/ALT variability (muscle injury, exercise)","thrombocytopenia from non-liver causes","acute illness","alcohol intake"],"testing_cadence":"baseline + every 1-3 years in metabolic-risk patients; more frequent if elevated"},"outcomes":{"all_cause_mortality":{"hr":1.45,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FIB-4 (log scale), all-cause mortality, adjusted","direction":"risk","ci_low":1.34,"ci_high":1.57,"hr_per_sd":1.45,"hr_per_sd_ci":[1.34,1.57],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":100000,"followup_years":10,"study":"Large general-population / primary-care cohorts of FIB-4 and all-cause mortality.","study_type":"prospective-cohort","citation":"Hagstrom H, Talback M, Andreasson A et al. Repeated FIB-4 measurements and risk of severe liver disease and mortality (and related FIB-4 mortality cohorts). J Hepatol 2020/2023.","verification_status":"approximate","notes":"Higher FIB-4 is a graded predictor of all-cause mortality, with a steep rise above the 2.67 cut-point driven by liver-related death; the marker also captures advanced metabolic disease. Per-SD HR approximate; categorical cut-point HRs (high vs low FIB-4) are often 2-3x. Right-skewed - reported per SD of the log-transformed index."},"cvd":{"hr":1.28,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FIB-4 (log scale), cardiovascular disease events / mortality, adjusted","direction":"risk","ci_low":1.18,"ci_high":1.39,"hr_per_sd":1.28,"hr_per_sd_ci":[1.18,1.39],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":80000,"followup_years":9,"study":"Cohorts of FIB-4 and incident cardiovascular disease in metabolic-risk and general populations.","study_type":"prospective-cohort","citation":"Baratta F, Pastori D, Angelico F et al. Liver fibrosis indices (FIB-4) and cardiovascular events in non-alcoholic fatty liver disease; FIB-4 and CVD cohort literature.","verification_status":"unverified","notes":"Higher FIB-4 is associated with incident CVD and CVD mortality, consistent with advanced liver fibrosis being a marker of systemic metabolic and vascular disease. Per-SD value approximate; treat as indicative."},"cancer":{"hr":1.35,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FIB-4 (log scale), liver / overall cancer, adjusted","direction":"risk","ci_low":1.2,"ci_high":1.52,"hr_per_sd":1.35,"hr_per_sd_ci":[1.2,1.52],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":60000,"followup_years":9,"study":"Cohorts of FIB-4 and incident cancer, with hepatocellular carcinoma the dominant component.","study_type":"prospective-cohort","citation":"FIB-4 and hepatocellular carcinoma / cancer incidence cohort studies.","verification_status":"unverified","notes":"FIB-4 is strongly associated with hepatocellular carcinoma (advanced fibrosis is the principal HCC risk substrate) and shows a weaker association with overall cancer. Per-SD value approximate; the cancer signal is dominated by liver cancer. Treat as indicative."},"dementia":{"hr":1.18,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FIB-4 (log scale), incident dementia, adjusted","direction":"risk","ci_low":1.05,"ci_high":1.33,"hr_per_sd":1.18,"hr_per_sd_ci":[1.05,1.33],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":400000,"followup_years":10,"study":"Large cohort studies (e.g. UK Biobank) of liver fibrosis scores and incident dementia.","study_type":"prospective-cohort","citation":"Liver fibrosis (FIB-4) and incident dementia; UK Biobank and related cohort analyses linking MASLD/fibrosis to dementia risk.","verification_status":"unverified","notes":"Higher FIB-4 / advanced liver fibrosis is associated with modestly higher incident dementia, plausibly through hepatic encephalopathy-spectrum effects, systemic inflammation and shared vascular risk. Per-SD value approximate; evidence emerging and partly confounded. Treat as exploratory."},"frailty":{"hr":1.3,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher FIB-4 (log scale), incident frailty / sarcopenia, adjusted","direction":"risk","ci_low":1.12,"ci_high":1.51,"hr_per_sd":1.3,"hr_per_sd_ci":[1.12,1.51],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":10000,"followup_years":6,"study":"Cohorts of liver fibrosis indices and sarcopenia / frailty in MASLD and older populations.","study_type":"prospective-cohort","citation":"FIB-4 / advanced liver fibrosis and sarcopenia / frailty cohort literature.","verification_status":"unverified","notes":"Advanced liver fibrosis (high FIB-4) is associated with sarcopenia and frailty; the relationship is bidirectional (sarcopenia worsens MASLD and the FIB-4 components partly reflect age and muscle). Single-cohort-class evidence; per-SD value approximate. Treat as exploratory."}},"modifiability":{"intervention":"Weight loss, exercise, alcohol reduction, treatment of MASLD/MASH (including resmetirom and GLP-1 receptor agonists) and control of metabolic risk can stabilize or reduce FIB-4 by improving the underlying fibrosis and its AST/ALT inputs.","effect_size":"Significant weight loss and MASH-directed therapy can lower FIB-4 and reverse early fibrosis; established advanced fibrosis (cirrhosis) is largely fixed.","timeframe":"6-24 months","evidence_type":"RCT meta-analysis","citation":"MASH RCTs (e.g. MAESTRO-NASH resmetirom, GLP-1 RA trials) and lifestyle/weight-loss studies showing fibrosis-marker improvement.","rating":"moderate"}},{"id":"uric_acid","name":"Uric acid","domain":"renal_hepatic","aliases":["serum urate","serum uric acid","SUA"],"profile":{"mechanism":"Uric acid is the end-product of purine metabolism, cleared mainly by the kidney. High levels cause gout and reflect renal impairment, insulin resistance, and metabolic syndrome, and may promote oxidative stress and endothelial dysfunction; yet urate is also a major plasma antioxidant, so very low levels may be detrimental, producing a U-shaped relationship with mortality.","measurement":{"method":"Enzymatic (uricase) colorimetric assay on a standard chemistry analyzer; part of routine metabolic panels.","sample_type":"venous blood","approx_cost_usd":"5-20"},"signal_quality":"moderate","signal_quality_note":"Analytically reliable, but strongly influenced by renal clearance, diuretics, diet, alcohol and sex; the U-shaped outcome relationship complicates interpretation of a single value.","confounders":["kidney function / eGFR","diuretic and urate-lowering medication","alcohol and purine-rich diet","sex and menopausal status","obesity and insulin resistance"],"testing_cadence":"baseline + annual; more frequent during urate-lowering therapy"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"U-/J-shaped association; no single HR adequately summarizes (both low and high urate raise risk)","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"non-monotone U-/J-shaped association; no usable linear per-SD summary","conversion":null,"evidence_tier":"A","n":500000,"followup_years":10,"study":"Meta-analyses and large cohorts (e.g. NHANES, dose-response meta-analysis) show a U-/J-shaped relation of serum uric acid with all-cause mortality.","study_type":"meta-analysis","citation":"Zhang S, Wang Y, Cheng J et al. Hyperuricemia and cardiovascular disease / dose-response meta-analysis of serum uric acid and all-cause mortality. (U-shaped urate-mortality meta-analyses, e.g. Atherosclerosis/Front Cardiovasc Med).","verification_status":"approximate","notes":"Serum uric acid and all-cause mortality form a U-/J-shaped curve: high urate marks gout, renal and metabolic disease, while low urate may reflect frailty, malnutrition and loss of antioxidant capacity. A single linear per-SD HR is not meaningful, so the cell is flagged categorical. The high-urate limb is the modifiable, metabolic side.","qualitative":true},"cvd":{"hr":1.13,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher serum uric acid, cardiovascular / coronary heart disease events, adjusted","direction":"risk","ci_low":1.07,"ci_high":1.2,"hr_per_sd":1.13,"hr_per_sd_ci":[1.07,1.2],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":400000,"followup_years":11,"study":"Meta-analysis of prospective cohorts of hyperuricemia / serum uric acid and incident cardiovascular disease.","study_type":"meta-analysis","citation":"Kim SY, Guevara JP, Kim KM et al. Hyperuricemia and coronary heart disease: a systematic review and meta-analysis. Arthritis Care Res 2010;62:170-180. doi:10.1002/acr.20065","verification_status":"approximate","notes":"Higher uric acid is associated with modestly higher CVD risk over the upper range; the association is monotone enough for a per-SD estimate. Mendelian randomization, however, suggests genetically higher urate is largely NOT causal for coronary heart disease, so this is mostly a risk marker reflecting metabolic syndrome and renal impairment. Per-SD value approximate."},"cancer":{"hr":1.05,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher serum uric acid, cancer mortality, adjusted (modest, near-null)","direction":"risk","ci_low":1,"ci_high":1.11,"hr_per_sd":1.05,"hr_per_sd_ci":[1,1.11],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":400000,"followup_years":10,"study":"Large cohorts (e.g. Austrian VHM&PP, NHANES) of serum uric acid and cancer mortality.","study_type":"prospective-cohort","citation":"Strasak AM, Rapp K, Hilbe W et al. Serum uric acid and risk of cancer mortality in a large prospective male/female cohort. Ann Oncol / Cancer Causes Control 2007-2008.","verification_status":"unverified","notes":"Uric acid shows a weak and inconsistent association with cancer mortality; some cohorts report a modest positive signal at high urate, others a U-shape, with urate's dual pro-oxidant/antioxidant roles invoked. Well-powered but near-null per-SD estimate; treat as indicative."},"dementia":{"hr":0.94,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher serum uric acid, incident dementia (esp. Alzheimer's / Parkinson's-related), adjusted (inverse association)","direction":"protective","ci_low":0.88,"ci_high":1,"hr_per_sd":0.94,"hr_per_sd_ci":[0.88,1],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":80000,"followup_years":9,"study":"Meta-analysis / pooled cohorts of serum uric acid and incident dementia / neurodegenerative disease.","study_type":"meta-analysis","citation":"Khan AA, Quinn TJ, Hewitt J et al. Serum uric acid level and association with cognitive impairment and dementia: systematic review and meta-analysis. Age (Dordr) 2016;38:16. doi:10.1007/s11357-016-9871-8","verification_status":"approximate","notes":"Higher uric acid is associated with modestly LOWER dementia risk, attributed to urate's antioxidant/neuroprotective activity (also seen as slower Parkinson's progression); some studies find vascular-dementia signals in the opposite direction, so the net inverse association is modest and partly heterogeneous. Per-SD value approximate."},"frailty":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"U-shaped association with frailty; both low and high urate associate with higher frailty risk","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"non-monotone U-shaped association with frailty; no usable linear per-SD summary","conversion":null,"evidence_tier":"C","n":10000,"followup_years":6,"study":"Older-adult cohorts of serum uric acid and incident frailty / sarcopenia.","study_type":"prospective-cohort","citation":"Serum uric acid and frailty / sarcopenia in older adults; cohort studies reporting U-shaped associations.","verification_status":"unverified","notes":"Serum uric acid shows a U-shaped relationship with frailty: high urate tracks metabolic disease and gout, while low urate tracks malnutrition, low muscle mass and loss of antioxidant defense. No single per-SD slope is meaningful, so the cell is flagged categorical. Evidence is limited and heterogeneous.","qualitative":true}},"modifiability":{"intervention":"Urate-lowering drugs (allopurinol, febuxostat), weight loss, reduced alcohol and purine intake, and avoidance of urate-raising diuretics lower serum uric acid; SGLT2 inhibitors and losartan modestly lower urate.","effect_size":"Allopurinol/febuxostat reliably lower urate to target (<6 mg/dL); lifestyle change lowers it modestly. Whether lowering urate improves non-gout outcomes is unproven (neutral cardiovascular trials).","timeframe":"2-8 weeks for pharmacologic lowering","evidence_type":"RCT meta-analysis","citation":"Urate-lowering therapy RCTs (e.g. CARES, FAST for safety; ALL-HEART for cardiovascular outcomes - neutral).","rating":"high"}},{"id":"processing_speed","name":"Processing speed","domain":"cognitive","aliases":["cognitive processing speed","psychomotor speed","Digit Symbol Substitution Test","Symbol Digit Modalities Test","perceptual speed","reaction time (cognitive)"],"profile":{"mechanism":"Processing speed is the rate at which simple cognitive operations are executed; it is the cognitive domain most sensitive to aging, cerebral small-vessel disease and white-matter integrity. Slowing reflects diffuse neural and vascular compromise and is an early, sensitive marker of incipient neurodegeneration and global physiologic decline, predicting dementia, disability and death.","measurement":{"method":"Timed paper-and-pencil or computerized tasks: Digit Symbol Substitution Test (DSST), Symbol Digit Modalities Test (SDMT), Trail Making Test A, simple/choice reaction time, and NIH Toolbox Pattern Comparison Processing Speed Test. Cambridge Brain Sciences includes speeded reasoning tasks. Scores are typically standardized to within-cohort z-scores.","sample_type":"functional test","approx_cost_usd":"0-75"},"signal_quality":"moderate","signal_quality_note":"Speeded tasks are reliable (test-retest r ~0.7-0.85) but sensitive to motor speed, vision, fatigue, practice effects and education; cross-instrument comparability is imperfect, so cells are standardized within study.","confounders":["age","education / cognitive reserve","depression","vision and motor impairment","medication (sedatives, anticholinergics)","practice effects","subclinical cerebrovascular disease (reverse causation)"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1.27,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower processing-speed score (slower performance)","direction":"risk","ci_low":1.2,"ci_high":1.34,"hr_per_sd":1.27,"hr_per_sd_ci":[1.2,1.34],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"~50000 across cohorts","followup_years":10,"study":"Meta-analyses and large cohorts of perceptual/processing speed and mortality (e.g. Scottish Mental Survey lifecourse cohorts, Whitehall II, LonGenity); processing speed is consistently the strongest cognitive predictor of mortality among non-memory domains.","study_type":"meta-analysis","citation":"Deary IJ, Der G. Reaction time, age, and cognitive ability: longitudinal findings from age 16 to 63 years in representative population samples. Aging Neuropsychol Cogn. 2005;12:187-215; and cognitive-epidemiology mortality syntheses (Calvin CM, et al. Intelligence in youth and all-cause mortality: systematic review with meta-analysis. Int J Epidemiol. 2011;40(3):626-644. doi:10.1093/ije/dyq190). PMID:21037248","verification_status":"approximate","notes":"Slower processing speed / longer reaction time is a robust independent predictor of all-cause mortality; reaction-time variability often outperforms mean speed. The per-SD HR ~1.27 is a representative pooled estimate; exact pooled CI across heterogeneous instruments could not be confirmed, hence approximate. Largely observational; reverse causation from subclinical disease and 'system integrity' confounding are recognized."},"cvd":{"hr":1.2,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower processing-speed/cognitive score, incident cardiovascular events/CVD mortality","direction":"risk","ci_low":1.1,"ci_high":1.31,"hr_per_sd":1.2,"hr_per_sd_ci":[1.1,1.31],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~30000","followup_years":10,"study":"Prospective cohorts of midlife cognitive function and incident CVD (e.g. Whitehall II, ARIC, MIDUS); slower processing speed predicts incident coronary disease and stroke independent of vascular risk factors.","study_type":"prospective-cohort","citation":"Sabia S, et al. and ARIC investigators: midlife cognitive performance and cardiovascular outcomes; representative per-SD estimate from cognition-CVD cohort literature. PMID:21037248 (related cognitive-epidemiology synthesis).","verification_status":"unverified","notes":"Processing speed shares vascular substrate (small-vessel disease) with CVD, so the association is partly shared-risk-factor rather than causal. Per-SD HR ~1.20 is a representative figure from general domain knowledge; specific pooled study not confirmed. Reverse causation likely (subclinical atherosclerosis slows cognition)."},"cancer":{"hr":1.05,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower processing-speed/general cognitive score, cancer mortality","direction":"risk","ci_low":0.98,"ci_high":1.13,"hr_per_sd":1.05,"hr_per_sd_ci":[0.98,1.13],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"~30000","followup_years":12,"study":"Cognitive-epidemiology cohorts examining cognition and cancer mortality; associations are weak and inconsistent, much smaller than for CVD/all-cause mortality.","study_type":"prospective-cohort","citation":"Calvin CM, et al. Int J Epidemiol. 2011;40(3):626-644. doi:10.1093/ije/dyq190. PMID:21037248 — cognition shows only a weak association with cancer mortality relative to vascular causes.","verification_status":"unverified","notes":"Cognition (including processing speed) is at best weakly related to cancer mortality, plausibly via health behaviours, screening uptake and treatment adherence rather than biology. The cell is recorded as a near-null (HR ~1.05) to document the well-known weak signal; tier C, unverified specific estimate."},"dementia":{"hr":1.65,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower processing-speed score, incident all-cause dementia","direction":"risk","ci_low":1.45,"ci_high":1.88,"hr_per_sd":1.65,"hr_per_sd_ci":[1.45,1.88],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"~25000 across cohorts","followup_years":9,"study":"Prospective cohorts and meta-analyses of baseline processing speed and incident dementia (e.g. Whitehall II, Framingham, ACTIVE, Three-City); slower processing speed is among the earliest detectable predictors of incident dementia.","study_type":"meta-analysis","citation":"Whitehall II and pooled cognitive-aging cohorts: low baseline processing speed predicts incident dementia with per-SD HR ~1.5-1.8 (e.g. Singh-Manoux A, et al. Timing of onset of cognitive decline. BMJ. 2012;344:d7622. doi:10.1136/bmj.d7622). PMID:22223828","verification_status":"approximate","notes":"Processing speed decline precedes dementia diagnosis by 5-10 years; the per-SD HR is strong but partly reflects prodromal disease (reverse causation), so it is best read as an early marker rather than a modifiable cause. Representative pooled per-SD HR ~1.65; exact pooled CI not confirmed."},"frailty":{"hr":1.35,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower processing-speed/cognitive score, incident physical frailty","direction":"risk","ci_low":1.2,"ci_high":1.52,"hr_per_sd":1.35,"hr_per_sd_ci":[1.2,1.52],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~15000","followup_years":7,"study":"Prospective cohorts of cognition and incident frailty (e.g. ELSA, InCHIANTI, Health ABC); slow processing speed predicts incident Fried frailty and is itself a candidate cognitive-frailty marker.","study_type":"prospective-cohort","citation":"English Longitudinal Study of Ageing and InCHIANTI analyses linking slower processing speed to incident physical frailty; 'cognitive frailty' literature (Kelaiditi E, et al. J Nutr Health Aging. 2013;17(9):726-734).","verification_status":"unverified","notes":"Processing speed and physical frailty share neural and vascular substrate and decline together ('motoric cognitive risk' / cognitive frailty). Per-SD HR ~1.35 is representative; specific pooled estimate not confirmed. Bidirectional relationship likely."}},"modifiability":{"intervention":"Aerobic and combined exercise training, speed-of-processing cognitive training (e.g. ACTIVE-trial Useful Field of View training), and management of vascular risk factors (blood pressure, glycemia).","effect_size":"ACTIVE speed-of-processing training produced large immediate gains (effect size ~1.5 SD on trained tasks) with partial 10-year persistence; aerobic exercise yields small-to-moderate gains (~0.2-0.3 SD). Far transfer to function is modest.","timeframe":"Weeks for trained-task gains; 6-12 months for exercise/vascular effects.","evidence_type":"RCT","citation":"Rebok GW, et al. Ten-year effects of the ACTIVE cognitive training trial. J Am Geriatr Soc. 2014;62(1):16-24. doi:10.1111/jgs.12607. PMID:24417410","rating":"moderate"}},{"id":"working_memory","name":"Working memory","domain":"cognitive","aliases":["working memory capacity","n-back performance","digit span","list sorting","NIH Toolbox List Sorting","Cambridge Brain Sciences Monkey Ladder"],"profile":{"mechanism":"Working memory is the capacity to hold and manipulate information over short intervals; it depends on frontoparietal networks and is sensitive to aging, dopaminergic tone and early Alzheimer pathology. Decline contributes to loss of independence and predicts dementia, though it is a weaker mortality predictor than processing speed.","measurement":{"method":"Digit span backward, spatial span, n-back tasks, NIH Toolbox List Sorting Working Memory Test, and Cambridge Brain Sciences spatial-span/Monkey-Ladder tasks. Scored as within-cohort standardized z-scores.","sample_type":"functional test","approx_cost_usd":"0-75"},"signal_quality":"moderate","signal_quality_note":"Span tasks are moderately reliable (test-retest r ~0.7-0.8); n-back reliability is lower. Sensitive to attention, motivation, anxiety and practice effects; cross-instrument standardization is required.","confounders":["age","education / cognitive reserve","depression and anxiety","attention/effort","practice effects","subclinical neurodegeneration (reverse causation)"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1.15,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower working-memory/executive composite score","direction":"risk","ci_low":1.08,"ci_high":1.23,"hr_per_sd":1.15,"hr_per_sd_ci":[1.08,1.23],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~20000","followup_years":10,"study":"Prospective cognitive-aging cohorts (e.g. Whitehall II, ELSA, MIDUS) examining domain-specific cognition and mortality; working memory predicts mortality but more weakly than processing speed.","study_type":"prospective-cohort","citation":"Domain-specific analyses within cognitive-epidemiology cohorts; representative per-SD estimate consistent with Calvin CM, et al. Int J Epidemiol. 2011;40(3):626-644. doi:10.1093/ije/dyq190. PMID:21037248","verification_status":"unverified","notes":"Working memory contributes to the general cognition-mortality association but adds little beyond processing speed once that is adjusted. Per-SD HR ~1.15 is a representative figure from domain knowledge; specific study not confirmed."},"cvd":{"hr":1.12,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower working-memory/executive score, incident CVD","direction":"risk","ci_low":1.03,"ci_high":1.22,"hr_per_sd":1.12,"hr_per_sd_ci":[1.03,1.22],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"~15000","followup_years":10,"study":"Cohort analyses of executive/working-memory function and incident cardiovascular events; signal is modest and overlaps with processing-speed and global-cognition findings.","study_type":"prospective-cohort","citation":"Cognition-CVD cohort literature (Whitehall II, ARIC); no working-memory-specific pooled HR confirmed.","verification_status":"unverified","notes":"Working-memory-specific incident-CVD HRs are sparse; most evidence is for global cognition or executive function. Per-SD HR ~1.12 recorded as a representative weak association; tier C, unverified."},"cancer":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no working-memory-specific per-SD HR for cancer outcomes identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: no prospective cohort reports a working-memory-specific per-SD hazard ratio for cancer incidence or mortality","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study reporting a working-memory-specific HR for cancer outcomes.","study_type":"prospective-cohort","citation":"None located.","verification_status":"unverified","notes":"Cognition-cancer associations are weak even for global cognition; no domain-specific working-memory HR exists. Left null rather than borrowing a global-cognition estimate.","qualitative":true},"dementia":{"hr":1.55,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower working-memory score, incident all-cause dementia / MCI-to-dementia progression","direction":"risk","ci_low":1.35,"ci_high":1.78,"hr_per_sd":1.55,"hr_per_sd_ci":[1.35,1.78],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~15000","followup_years":8,"study":"Prospective cohorts of baseline working memory / executive function and incident dementia (e.g. Framingham, Three-City, ADNI MCI-progression cohorts).","study_type":"prospective-cohort","citation":"Cognitive-aging cohort literature linking low baseline working memory to incident dementia; representative per-SD HR consistent with domain-specific analyses in Framingham and Three-City studies.","verification_status":"unverified","notes":"Working memory is impaired early in Alzheimer disease and predicts incident dementia, but episodic memory and processing speed are generally stronger discriminators. Per-SD HR ~1.55 is representative; specific pooled estimate not confirmed. Reverse causation from prodromal disease likely."},"frailty":{"hr":1.25,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower working-memory/executive score, incident frailty","direction":"risk","ci_low":1.1,"ci_high":1.42,"hr_per_sd":1.25,"hr_per_sd_ci":[1.1,1.42],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"~10000","followup_years":7,"study":"Cohort analyses of executive/working-memory function and incident physical frailty (e.g. ELSA, InCHIANTI) within the cognitive-frailty literature.","study_type":"prospective-cohort","citation":"Cognitive-frailty literature (Kelaiditi E, et al. J Nutr Health Aging. 2013;17(9):726-734); no working-memory-specific pooled HR confirmed.","verification_status":"unverified","notes":"Working memory predicts incident frailty within the broader cognitive-frailty construct, but executive function is the more commonly studied domain. Per-SD HR ~1.25 is representative; tier C, unverified."}},"modifiability":{"intervention":"Working-memory and process-based cognitive training, aerobic and combined exercise, and vascular-risk management.","effect_size":"Working-memory training produces reliable near-transfer gains (~0.5-0.7 SD on trained tasks) but limited far transfer to untrained abilities; exercise yields small gains (~0.1-0.2 SD).","timeframe":"Weeks for trained-task gains; 3-6 months for exercise effects.","evidence_type":"RCT meta-analysis","citation":"Melby-Lervag M, Hulme C. Is working memory training effective? A meta-analytic review. Dev Psychol. 2013;49(2):270-291. doi:10.1037/a0028228. PMID:22612437 (near transfer reliable, far transfer minimal).","rating":"low"}},{"id":"executive_function","name":"Executive function","domain":"cognitive","aliases":["executive control","cognitive flexibility","Trail Making Test B","Stroop","verbal fluency","NIH Toolbox Flanker / DCCS","Cambridge Brain Sciences reasoning"],"profile":{"mechanism":"Executive function comprises inhibition, set-shifting and goal management, dependent on prefrontal-subcortical circuits. It governs self-care, medication adherence and health decision-making, and its decline reflects frontal-lobe and small-vessel pathology; it strongly predicts dementia, disability and mortality.","measurement":{"method":"Trail Making Test B (and B-A), Stroop interference, verbal/category fluency, Wisconsin Card Sorting, and NIH Toolbox Flanker Inhibitory Control and Dimensional Change Card Sort; Cambridge Brain Sciences includes planning/reasoning tasks. Scored as within-cohort standardized composite z-scores.","sample_type":"functional test","approx_cost_usd":"0-75"},"signal_quality":"moderate","signal_quality_note":"Composite executive scores are moderately reliable (r ~0.7-0.85); individual tasks are less reliable and 'task-impure' (load on processing speed and working memory). Composite standardization mitigates instrument heterogeneity.","confounders":["age","education / cognitive reserve","processing-speed contamination of timed tasks","depression","practice effects","subclinical cerebrovascular and neurodegenerative disease (reverse causation)"],"testing_cadence":"baseline + every 1-2 years"},"outcomes":{"all_cause_mortality":{"hr":1.22,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower executive-function composite score","direction":"risk","ci_low":1.14,"ci_high":1.31,"hr_per_sd":1.22,"hr_per_sd_ci":[1.14,1.31],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"~40000 across cohorts","followup_years":10,"study":"Prospective cohorts and syntheses of executive function and mortality (e.g. Whitehall II, Health ABC, LASA, Lothian Birth Cohorts); executive dysfunction is a consistent independent predictor of all-cause mortality.","study_type":"meta-analysis","citation":"Cognitive-epidemiology syntheses (Calvin CM, et al. Int J Epidemiol. 2011;40(3):626-644. doi:10.1093/ije/dyq190. PMID:21037248) and Health ABC / Whitehall II domain-specific mortality analyses; executive function per-SD HR ~1.2.","verification_status":"approximate","notes":"Executive function predicts mortality nearly as strongly as processing speed and partly via behavioural pathways (adherence, self-care, risk behaviour). Per-SD HR ~1.22 is a representative pooled estimate; exact CI across heterogeneous instruments not confirmed. Reverse causation and 'system integrity' confounding apply."},"cvd":{"hr":1.18,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower executive-function score, incident cardiovascular events","direction":"risk","ci_low":1.08,"ci_high":1.29,"hr_per_sd":1.18,"hr_per_sd_ci":[1.08,1.29],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~20000","followup_years":9,"study":"Prospective cohorts of midlife/late-life executive function and incident CVD (e.g. Whitehall II, ARIC-NCS, Framingham); executive dysfunction predicts coronary events and stroke.","study_type":"prospective-cohort","citation":"ARIC Neurocognitive Study and Whitehall II analyses linking executive dysfunction to incident cardiovascular disease and stroke; representative per-SD HR ~1.18.","verification_status":"unverified","notes":"Executive function and CVD share vascular substrate and behavioural mediators (medication adherence, lifestyle). Per-SD HR ~1.18 is representative; specific pooled study not confirmed. Bidirectional and shared-risk-factor relationships likely."},"cancer":{"hr":1.04,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower executive-function/general cognitive score, cancer mortality","direction":"risk","ci_low":0.97,"ci_high":1.12,"hr_per_sd":1.04,"hr_per_sd_ci":[0.97,1.12],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"C","n":"~20000","followup_years":12,"study":"Cognitive-epidemiology cohorts examining cognition and cancer mortality; associations are weak and not domain-specific to executive function.","study_type":"prospective-cohort","citation":"Calvin CM, et al. Int J Epidemiol. 2011;40(3):626-644. doi:10.1093/ije/dyq190. PMID:21037248 — cognition weakly related to cancer mortality.","verification_status":"unverified","notes":"As with other cognitive domains, executive function shows at best a weak association with cancer mortality, plausibly via screening, treatment adherence and health behaviours. Recorded as a near-null (HR ~1.04) to document the weak signal; tier C, unverified."},"dementia":{"hr":1.6,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower executive-function composite score, incident all-cause dementia","direction":"risk","ci_low":1.42,"ci_high":1.81,"hr_per_sd":1.6,"hr_per_sd_ci":[1.42,1.81],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"~25000 across cohorts","followup_years":8,"study":"Prospective cohorts and meta-analyses of baseline executive function and incident dementia (e.g. Framingham, Three-City, Whitehall II, ACTIVE); executive dysfunction is a leading early predictor, especially of vascular and mixed dementia.","study_type":"meta-analysis","citation":"Cognitive-aging cohort syntheses; baseline executive dysfunction predicts incident dementia with per-SD HR ~1.5-1.8 (Framingham and Three-City domain-specific analyses; Singh-Manoux A, et al. BMJ. 2012;344:d7622. PMID:22223828 for trajectory data).","verification_status":"approximate","notes":"Executive dysfunction precedes dementia diagnosis and is particularly predictive of vascular and mixed dementia. Per-SD HR ~1.60 is a representative pooled estimate; exact pooled CI not confirmed. Substantial prodromal-disease (reverse causation) contribution."},"frailty":{"hr":1.4,"hr_metric":"per_sd","hr_unit_detail":"per 1-SD lower executive-function score, incident physical frailty","direction":"risk","ci_low":1.24,"ci_high":1.58,"hr_per_sd":1.4,"hr_per_sd_ci":[1.24,1.58],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"~15000","followup_years":7,"study":"Prospective cohorts of executive function and incident frailty (e.g. ELSA, InCHIANTI, Health ABC); executive dysfunction predicts incident Fried frailty and gait slowing ('motoric cognitive risk syndrome').","study_type":"prospective-cohort","citation":"English Longitudinal Study of Ageing and motoric-cognitive-risk literature (Verghese J, et al. Motoric cognitive risk syndrome. Neurology. 2014); executive function strongly linked to incident frailty.","verification_status":"unverified","notes":"Executive function shares prefrontal-subcortical substrate with gait and physical frailty and is the cognitive domain most consistently tied to incident frailty. Per-SD HR ~1.40 is representative; specific pooled estimate not confirmed. Bidirectional relationship."}},"modifiability":{"intervention":"Aerobic and combined exercise training, multidomain lifestyle interventions (e.g. FINGER trial), and vascular-risk-factor management.","effect_size":"Multidomain intervention (FINGER) improved executive-function composite by ~0.15-0.25 SD versus control over 2 years; aerobic exercise yields small gains (~0.1-0.2 SD).","timeframe":"6-24 months for measurable change.","evidence_type":"RCT","citation":"Ngandu T, et al. A 2 year multidomain intervention of diet, exercise, cognitive training, and vascular risk monitoring versus control (FINGER): a randomised controlled trial. Lancet. 2015;385(9984):2255-2263. doi:10.1016/S0140-6736(15)60461-5. PMID:25771249","rating":"moderate"}},{"id":"ptau217","name":"pTau-217","domain":"cognitive","aliases":["plasma phosphorylated tau 217","p-tau217","phospho-tau 217"],"profile":{"mechanism":"Plasma phosphorylated tau at threonine-217 rises early in the Alzheimer pathophysiological cascade, tracking cerebral amyloid-beta deposition before tau-tangle accumulation and symptoms. It is the most accurate blood marker of Alzheimer pathology and predicts progression from preclinical/MCI states to dementia.","measurement":{"method":"Immunoassay (e.g. Lilly/MSD, ALZpath, Janssen) or mass spectrometry on plasma; results are concentration-dependent and assay-specific, with %p-tau217 ratio variants. Increasingly available as a clinical lab test.","sample_type":"venous blood","approx_cost_usd":"200-700"},"signal_quality":"clean","signal_quality_note":"Excellent analytical performance and large effect sizes for Alzheimer pathology (AUC ~0.9-0.95 versus amyloid PET); main caveats are assay-to-assay non-comparability and renal-function/BMI effects on absolute levels.","confounders":["chronic kidney disease (raises levels)","BMI (dilutional, lowers levels)","assay platform differences","age","APOE genotype","acute illness"],"testing_cadence":"baseline; repeat at 1-2 years if monitoring"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no robust prospective per-SD HR for pTau-217 and all-cause mortality identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: pTau-217 is a young marker and no large prospective cohort yet reports a per-SD hazard ratio for all-cause mortality","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study reporting a pTau-217 all-cause-mortality HR.","study_type":"prospective-cohort","citation":"None located; pTau-217 mortality evidence is immature relative to NfL.","verification_status":"unverified","notes":"Unlike NfL and GFAP, pTau-217 has not yet been studied as a predictor of all-cause mortality in large cohorts; its evidence base is overwhelmingly about Alzheimer pathology and dementia progression. Left null.","qualitative":true},"cvd":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no prospective per-SD HR for pTau-217 and cardiovascular outcomes identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: no cohort reports a pTau-217 per-SD hazard ratio for incident cardiovascular disease","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study.","study_type":"prospective-cohort","citation":"None located.","verification_status":"unverified","notes":"pTau-217 is Alzheimer-pathology-specific and is not expected to, and has not been shown to, predict cardiovascular outcomes. Left null.","qualitative":true},"cancer":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no evidence for pTau-217 and cancer outcomes","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: pTau-217 has no plausible or studied link to cancer outcomes","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study.","study_type":"prospective-cohort","citation":"None located.","verification_status":"unverified","notes":"No mechanistic rationale or empirical evidence linking pTau-217 to cancer. Left null.","qualitative":true},"dementia":{"hr":1.76,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma pTau-217, progression to Alzheimer dementia (cognitively unimpaired / MCI)","direction":"risk","ci_low":1.45,"ci_high":2.14,"hr_per_sd":1.76,"hr_per_sd_ci":[1.45,2.14],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":"~1100 across BioFINDER / memory-clinic cohorts","followup_years":4,"study":"BioFINDER and memory-clinic prospective cohorts of plasma pTau-217 and progression to Alzheimer dementia in cognitively unimpaired and MCI participants.","study_type":"prospective-cohort","citation":"Palmqvist S, et al. Discriminative accuracy of plasma phospho-tau217 for Alzheimer disease. JAMA. 2020;324(8):772-781. doi:10.1001/jama.2020.12134. PMID:32722745; and Mattsson-Carlgren N, et al. longitudinal pTau-217 progression analyses (Nat Med / JAMA Neurol).","verification_status":"approximate","notes":"pTau-217 is a strong predictor of progression to Alzheimer dementia, especially among amyloid-positive individuals; per-SD HRs ~1.7-3 are reported depending on baseline cognitive stage and follow-up. The figure here is a representative per-log-SD estimate from memory-clinic/research cohorts and is not a general-population incidence HR — exact pooled CI not confirmed. Marker is young; evidence base is growing rapidly."},"frailty":{"hr":null,"hr_metric":"per_sd","hr_unit_detail":"no prospective per-SD HR for pTau-217 and incident frailty identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: no cohort reports a pTau-217 per-SD hazard ratio for incident frailty","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study.","study_type":"prospective-cohort","citation":"None located.","verification_status":"unverified","notes":"No prospective evidence links pTau-217 to incident physical frailty; the marker is Alzheimer-pathology-specific and frailty studies have focused on NfL and GFAP. Left null.","qualitative":true}},"modifiability":{"intervention":"Anti-amyloid monoclonal antibodies (lecanemab, donanemab) lower plasma pTau-217 as a treatment-response biomarker; no lifestyle intervention has an established effect on pTau-217.","effect_size":"Anti-amyloid therapy reduces plasma pTau-217 by roughly 20-40% over 12-18 months, paralleling amyloid-PET clearance; lifestyle effects unproven.","timeframe":"6-18 months with anti-amyloid therapy.","evidence_type":"RCT","citation":"Donanemab (TRAILBLAZER-ALZ 2; Sims JR, et al. JAMA. 2023;330(6):512-527) and lecanemab (Clarity AD; van Dyck CH, et al. N Engl J Med. 2023;388:9-21) trials report plasma pTau-217 reductions with treatment.","rating":"low"}},{"id":"nfl","name":"Neurofilament light chain (NfL)","domain":"cognitive","aliases":["neurofilament light","NEFL","plasma NfL","serum NfL"],"profile":{"mechanism":"Neurofilament light chain is a structural axonal protein released into blood upon neuro-axonal injury. Plasma NfL is a non-specific but highly sensitive marker of neurodegeneration that rises with age and across diverse neurological diseases, and elevated levels predict cognitive decline, dementia and mortality.","measurement":{"method":"Ultrasensitive single-molecule immunoassay (Simoa) on serum or plasma; widely used in research and increasingly clinically available. Levels rise steeply with age, so age-adjusted reference ranges are needed.","sample_type":"venous blood","approx_cost_usd":"100-400"},"signal_quality":"moderate","signal_quality_note":"Excellent analytical sensitivity and reproducibility, but biologically non-specific: elevated by any neuro-axonal injury, strongly age- and renal-function-dependent. Disease specificity is low, so it is best read as a general neurodegeneration index.","confounders":["age (strong)","chronic kidney disease (raises levels)","BMI / blood volume (dilutional)","any concurrent neurological injury or comorbidity","cardiovascular disease"],"testing_cadence":"baseline; repeat at 1-2 years if monitoring"},"outcomes":{"all_cause_mortality":{"hr":1.4,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma NfL, all-cause mortality","direction":"risk","ci_low":1.3,"ci_high":1.51,"hr_per_sd":1.4,"hr_per_sd_ci":[1.3,1.51],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":"~25000","followup_years":10,"study":"Large population-based and clinical cohorts of plasma NfL and all-cause mortality (e.g. UK Biobank, ASPREE, AGES-Reykjavik, Rotterdam-type cohorts); higher NfL consistently predicts mortality.","study_type":"prospective-cohort","citation":"Population-based plasma NfL mortality analyses, e.g. ASPREE and AGES-Reykjavik cohort studies; per-SD HR ~1.3-1.5 for all-cause mortality. Representative pooled estimate.","verification_status":"approximate","notes":"Plasma NfL is a robust per-SD predictor of all-cause mortality in older adults, reflecting general neuro-axonal injury and overall health status. Per-log-SD HR ~1.40 is a representative figure; exact pooled CI across cohorts not confirmed. Strongly age- and renal-confounded."},"cvd":{"hr":1.3,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma NfL, incident cardiovascular events / CVD mortality","direction":"risk","ci_low":1.18,"ci_high":1.43,"hr_per_sd":1.3,"hr_per_sd_ci":[1.18,1.43],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":"~15000","followup_years":9,"study":"Prospective cohorts of plasma NfL and incident cardiovascular and cerebrovascular outcomes (e.g. ARIC, Framingham, UK Biobank); NfL predicts stroke and CVD mortality, partly via small-vessel disease.","study_type":"prospective-cohort","citation":"ARIC and Framingham plasma NfL cardiovascular/stroke analyses; representative per-SD HR ~1.3.","verification_status":"unverified","notes":"Higher NfL predicts incident stroke and CVD events, plausibly because cerebral small-vessel disease and systemic vascular damage both raise NfL and cause CVD (shared substrate / reverse causation). Per-log-SD HR ~1.30 is representative; specific pooled study not confirmed."},"cancer":{"hr":null,"hr_metric":"per_log_sd","hr_unit_detail":"no prospective per-SD HR for NfL and cancer outcomes identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: no cohort reports an NfL per-SD hazard ratio for cancer incidence or mortality","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study reporting an NfL cancer HR.","study_type":"prospective-cohort","citation":"None located.","verification_status":"unverified","notes":"NfL has no established link to cancer outcomes; it may rise with chemotherapy-induced neurotoxicity but no incident-cancer HR exists. Left null.","qualitative":true},"dementia":{"hr":1.5,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma NfL, incident all-cause dementia","direction":"risk","ci_low":1.35,"ci_high":1.67,"hr_per_sd":1.5,"hr_per_sd_ci":[1.35,1.67],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":"~20000 across cohorts","followup_years":9,"study":"Prospective population-based cohorts and meta-analyses of plasma NfL and incident dementia (e.g. Rotterdam Study, AGES-Reykjavik, UK Biobank, ARIC).","study_type":"meta-analysis","citation":"Rotterdam Study and pooled analyses: higher plasma NfL predicts incident all-cause dementia with per-SD HR ~1.4-1.6 (e.g. Rotterdam NfL-dementia cohort; UK Biobank NfL-dementia analyses).","verification_status":"approximate","notes":"Plasma NfL is a consistent per-SD predictor of incident all-cause dementia, though non-specific to Alzheimer pathology (it also rises before vascular and other dementias). Per-log-SD HR ~1.50 is a representative pooled estimate; exact pooled CI not confirmed. Reverse causation over short follow-up likely."},"frailty":{"hr":1.35,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma NfL, incident frailty","direction":"risk","ci_low":1.18,"ci_high":1.54,"hr_per_sd":1.35,"hr_per_sd_ci":[1.18,1.54],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":"~5000","followup_years":6,"study":"Prospective cohorts of plasma NfL and incident physical frailty / frailty-index progression in older adults (e.g. ASPREE, Health ABC-type cohorts).","study_type":"prospective-cohort","citation":"ASPREE and related ageing-cohort analyses linking higher plasma NfL to incident frailty and accelerated frailty-index accumulation.","verification_status":"unverified","notes":"Higher NfL predicts incident frailty, consistent with NfL as a general index of neuro-axonal and biological aging. Per-log-SD HR ~1.35 is representative; specific study not confirmed. Evidence base for NfL-frailty is small (tier C)."}},"modifiability":{"intervention":"No established intervention reliably lowers plasma NfL in non-disease states; disease-modifying therapies (e.g. in MS, SMA) reduce NfL, and vascular-risk control may slow NfL rise. Lifestyle effects are unproven.","effect_size":"Disease-modifying drugs in active neurological disease lower NfL substantially (30-70%); no demonstrated lifestyle-driven reduction in healthy aging.","timeframe":"Months with effective disease-modifying therapy; no established lifestyle timeframe.","evidence_type":"RCT","citation":"NfL reductions with disease-modifying therapy are established in multiple sclerosis and spinal muscular atrophy trials; no RCT shows lifestyle modification lowers NfL in healthy older adults.","rating":"low"}},{"id":"gfap","name":"GFAP","domain":"cognitive","aliases":["glial fibrillary acidic protein","plasma GFAP","serum GFAP"],"profile":{"mechanism":"Glial fibrillary acidic protein is an astrocytic intermediate-filament protein released into blood during reactive astrogliosis. Plasma GFAP rises early in Alzheimer disease (tracking amyloid pathology and astrocyte activation) and predicts cognitive decline and incident dementia; it is more Alzheimer-associated than NfL.","measurement":{"method":"Ultrasensitive single-molecule immunoassay (Simoa) on serum or plasma; research-grade and increasingly clinically available. Levels rise with age and are affected by renal function and BMI.","sample_type":"venous blood","approx_cost_usd":"100-400"},"signal_quality":"moderate","signal_quality_note":"Good analytical performance; elevated by astrogliosis from Alzheimer pathology, traumatic brain injury and other CNS insults, so it is moderately but not fully Alzheimer-specific. Age, kidney function and BMI confound absolute levels.","confounders":["age","chronic kidney disease","BMI (dilutional)","traumatic brain injury and other acute CNS insults","assay platform differences"],"testing_cadence":"baseline; repeat at 1-2 years if monitoring"},"outcomes":{"all_cause_mortality":{"hr":1.35,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma GFAP, all-cause mortality","direction":"risk","ci_low":1.22,"ci_high":1.49,"hr_per_sd":1.35,"hr_per_sd_ci":[1.22,1.49],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":"~10000","followup_years":9,"study":"Prospective cohorts of plasma GFAP and all-cause mortality in older adults (e.g. ASPREE, UK Biobank-type cohorts); higher GFAP predicts mortality, though evidence is younger than for NfL.","study_type":"prospective-cohort","citation":"ASPREE and population-cohort plasma GFAP mortality analyses; representative per-SD HR ~1.3 for all-cause mortality.","verification_status":"unverified","notes":"Higher plasma GFAP predicts all-cause mortality, but the mortality evidence base is smaller and younger than NfL's. Per-log-SD HR ~1.35 is a representative figure; specific study not confirmed. Strongly age- and renal-confounded."},"cvd":{"hr":1.2,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma GFAP, incident cardiovascular / cerebrovascular events","direction":"risk","ci_low":1.06,"ci_high":1.36,"hr_per_sd":1.2,"hr_per_sd_ci":[1.06,1.36],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"C","n":"~8000","followup_years":8,"study":"Prospective cohorts of plasma GFAP and incident stroke / cardiovascular events; GFAP rises with cerebral small-vessel disease and predicts stroke.","study_type":"prospective-cohort","citation":"Plasma GFAP and incident-stroke cohort analyses (e.g. UK Biobank, Framingham-type cohorts); representative per-SD HR ~1.2.","verification_status":"unverified","notes":"GFAP elevation accompanies cerebral small-vessel disease and predicts incident stroke, but cardiovascular-outcome evidence is limited and the marker is primarily a neuro-glial index. Per-log-SD HR ~1.20 is representative; specific study not confirmed. Tier C."},"cancer":{"hr":null,"hr_metric":"per_log_sd","hr_unit_detail":"no prospective per-SD HR for GFAP and cancer outcomes identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: no cohort reports a GFAP per-SD hazard ratio for cancer outcomes","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study reporting a GFAP cancer HR.","study_type":"prospective-cohort","citation":"None located.","verification_status":"unverified","notes":"GFAP is markedly elevated in glioma (where it has diagnostic use) but no prospective cohort reports a GFAP HR for incident cancer or cancer mortality in general populations. Left null.","qualitative":true},"dementia":{"hr":1.55,"hr_metric":"per_log_sd","hr_unit_detail":"per 1-SD higher log-transformed plasma GFAP, incident all-cause dementia","direction":"risk","ci_low":1.38,"ci_high":1.74,"hr_per_sd":1.55,"hr_per_sd_ci":[1.38,1.74],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"B","n":"~15000 across cohorts","followup_years":9,"study":"Prospective population-based cohorts of plasma GFAP and incident dementia (e.g. ASPREE, AGES-Reykjavik, UK Biobank, Rotterdam-type cohorts); GFAP often outperforms NfL for incident Alzheimer dementia.","study_type":"prospective-cohort","citation":"Population-based plasma GFAP and incident-dementia analyses (e.g. ASPREE and AGES-Reykjavik cohorts); per-SD HR ~1.4-1.7, with GFAP a strong early predictor of Alzheimer-type dementia.","verification_status":"approximate","notes":"Plasma GFAP is a strong per-SD predictor of incident dementia, particularly Alzheimer dementia, and frequently shows larger effect sizes than NfL for amyloid-driven disease. Per-log-SD HR ~1.55 is a representative pooled estimate; exact pooled CI not confirmed. Reverse causation over short follow-up likely."},"frailty":{"hr":null,"hr_metric":"per_log_sd","hr_unit_detail":"no prospective per-SD HR for GFAP and incident frailty identified","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"no usable evidence: no cohort reports a GFAP per-SD hazard ratio for incident frailty","conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No identified study reporting a GFAP incident-frailty HR.","study_type":"prospective-cohort","citation":"None located.","verification_status":"unverified","notes":"GFAP-frailty prospective evidence is essentially absent; frailty biomarker work has focused on NfL among the neuro-glial markers. Left null rather than borrowing an NfL estimate.","qualitative":true}},"modifiability":{"intervention":"Anti-amyloid monoclonal antibodies lower plasma GFAP modestly as a downstream response biomarker; no lifestyle intervention has an established effect on GFAP.","effect_size":"Anti-amyloid therapy produces modest GFAP reductions over 12-18 months; lifestyle effects unproven.","timeframe":"12-18 months with anti-amyloid therapy.","evidence_type":"RCT","citation":"Anti-amyloid trials (donanemab, lecanemab) report plasma GFAP reductions as exploratory biomarkers; no RCT shows lifestyle modification lowers GFAP in healthy aging.","rating":"low"}},{"id":"total_sleep_time","name":"Total sleep time","domain":"sleep","aliases":["sleep duration","habitual sleep duration","TST"],"comparability_tag":"U-shaped","comparability_note":"Total sleep time has a robust U-shaped relation with mortality and CVD — both short (<6h) and long (>9h) sleep raise risk — so no single per-SD slope is meaningful; the off-scale cells use short-vs-reference and long-vs-reference contrasts.","profile":{"mechanism":"Sleep duration is the total time spent asleep per 24h. Sleep supports glymphatic clearance, metabolic and immune regulation, blood-pressure dipping, and neural restoration. Both insufficient and excessively long sleep are associated with adverse cardiometabolic, cognitive and mortality outcomes; long sleep is partly a marker of underlying ill-health, fragmentation or comorbidity rather than a cause.","measurement":{"method":"Self-report (questionnaire/diary) in most large cohorts; objectively by actigraphy, wearable accelerometry or polysomnography. Self-report and objective estimates correlate only moderately.","sample_type":"wearable","approx_cost_usd":"0-150"},"signal_quality":"moderate","signal_quality_note":"Self-reported duration is prone to recall and rounding bias and over-estimates objective sleep; objective measures vary by device and night. Single-night and single-question estimates are noisy; multi-night averages are more stable.","confounders":["depression and psychiatric illness","shift work","underlying chronic disease (reverse causation, especially for long sleep)","socioeconomic status","obesity and sleep-disordered breathing","age","medications (sedatives)"],"testing_cadence":"baseline + annual; continuous if wearable-tracked"},"outcomes":{"all_cause_mortality":{"hr":1.12,"hr_metric":"categorical","hr_unit_detail":"short sleep (<7h, typically ~5h) vs reference 7h, all-cause mortality (U-shaped; long sleep >=9h HR ~1.38)","direction":"risk","ci_low":1.06,"ci_high":1.18,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":1382999,"followup_years":9.3,"study":"Cappuccio 2010, Sleep, meta-analysis of 16 prospective cohorts of sleep duration and all-cause mortality.","study_type":"meta-analysis","citation":"Cappuccio FP, D'Elia L, Strazzullo P, Miller MA. Sleep duration and all-cause mortality: a systematic review and meta-analysis of prospective studies. Sleep. 2010;33(5):585-592. doi:10.1093/sleep/33.5.585. PMID:20469800","verification_status":"verified","notes":"Relationship is U-shaped: short sleep RR ~1.12 (1.06-1.18) and long sleep RR ~1.30-1.38 (1.22-1.38) vs ~7h reference; lowest mortality at ~7h. Subsequent dose-response meta-analyses (Liu 2017, Yin 2017) confirm the J/U shape with each direction roughly symmetric in magnitude. Long-sleep signal is heavily confounded by reverse causation (illness, depression, frailty). A single linear per-SD HR is not defensible; flagged categorical."},"cvd":{"hr":1.11,"hr_metric":"categorical","hr_unit_detail":"short sleep (<7h) vs 7h reference, total CVD incidence/mortality (U-shaped; long sleep >=9h HR ~1.33-1.38)","direction":"risk","ci_low":1.05,"ci_high":1.16,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":3340684,"followup_years":9,"study":"Yin 2017, J Am Heart Assoc, dose-response meta-analysis of 67 cohorts, sleep duration and cardiovascular outcomes.","study_type":"meta-analysis","citation":"Yin J, Jin X, Shan Z, et al. Relationship of sleep duration with all-cause mortality and cardiovascular events: a systematic review and dose-response meta-analysis of prospective cohort studies. J Am Heart Assoc. 2017;6(9):e005947. doi:10.1161/JAHA.117.005947. PMID:28889101","verification_status":"verified","notes":"U-shaped: short sleep RR ~1.11 (1.05-1.16) and long sleep RR ~1.33 (1.25-1.41) for total CVD vs 7h. Cappuccio 2011 (Eur Heart J) similarly found short-sleep RR 1.48 for CHD and long-sleep RR 1.38. Stroke shows a particularly strong long-sleep association. Non-linear; flagged categorical — a per-SD slope would misrepresent both tails."},"cancer":{"hr":1.01,"hr_metric":"per_unit","hr_unit_detail":"per 1 hour longer sleep duration, total cancer incidence (essentially null overall)","direction":"risk","ci_low":0.98,"ci_high":1.04,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"B","n":"varies (pooled, >1,000,000)","followup_years":null,"study":"Meta-analyses of sleep duration and total/site-specific cancer incidence (Chen 2018; Stone 2019).","study_type":"meta-analysis","citation":"Chen Y, Tan F, Wei L, et al. Sleep duration and the risk of cancer: a systematic review and meta-analysis including dose-response relationship. BMC Cancer. 2018;18:1149. doi:10.1186/s12885-018-5025-y. PMID:30463535","verification_status":"approximate","notes":"Pooled sleep duration shows essentially no association with overall cancer incidence (per-hour HR ~1.00-1.02). Site-specific findings diverge — some studies report higher colorectal cancer with long sleep and a modest inverse signal for breast cancer with short sleep — but the overall estimate is a well-powered near-null. No defensible directional per-SD cancer HR; flagged unconvertible (recorded as a real null)."},"dementia":{"hr":1.06,"hr_metric":"per_unit","hr_unit_detail":"per 1 hour deviation from ~7h sleep, incident all-cause dementia (U-shaped; short AND long sleep raise risk)","direction":"risk","ci_low":1.04,"ci_high":1.08,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"B","n":246786,"followup_years":9.5,"study":"Wong 2023 / Fan 2019 dose-response meta-analyses of sleep duration and incident dementia; plus Whitehall II 25-year analysis (Sabia 2021).","study_type":"meta-analysis","citation":"Fan L, Xu W, Cai Y, Hu Y, Wu C. Sleep duration and the risk of dementia: a systematic review and meta-analysis of prospective cohort studies. J Am Med Dir Assoc. 2019;20(12):1480-1487.e5. doi:10.1016/j.jamda.2019.06.009. PMID:31399359","verification_status":"approximate","notes":"U-shaped: long sleep (>=9h) is the more consistent signal (RR ~1.5-1.8 for incident dementia), while short midlife sleep (<=6h) also raises risk — Whitehall II (Sabia 2021, Nat Commun) found ~30% higher dementia with persistent short sleep at age 50-60. Long-sleep association is partly prodromal (preclinical dementia lengthens sleep), so reverse causation is substantial. Non-linear; flagged categorical."},"frailty":{"hr":1.21,"hr_metric":"categorical","hr_unit_detail":"short and/or long sleep (vs ~7-8h) and incident frailty; pooled OR/RR ~1.2-1.5, predominantly cross-sectional/short-prospective","direction":"risk","ci_low":1.08,"ci_high":1.36,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"varies (pooled)","followup_years":null,"study":"Meta-analyses and cohort studies of sleep duration and frailty in older adults (e.g., Pourmotabbed 2020; English Longitudinal Study of Ageing).","study_type":"meta-analysis","citation":"Pourmotabbed A, Boozari B, Babaei A, et al. Sleep duration and frailty risk: a systematic review and meta-analysis. Sleep Med Rev. 2020;? / J Sleep Res 2020;29(6):e13013. doi:10.1111/jsr.13013. PMID:32125045","verification_status":"approximate","notes":"Both short and long sleep associate with prevalent and incident frailty (pooled OR/RR ~1.2-1.5), with long sleep generally the stronger and more consistent signal. Much of the evidence is cross-sectional or short-prospective and uses odds ratios; reverse causation (frailty disrupting sleep) is severe. U-shaped and metric-heterogeneous; flagged categorical, tier C."}},"modifiability":{"intervention":"Sleep hygiene, cognitive behavioural therapy for insomnia (CBT-I), consistent sleep scheduling, and treatment of underlying disorders (apnea, depression). Extending habitually short sleep toward 7-8h is achievable; shortening pathologically long sleep depends on treating the underlying cause.","effect_size":"CBT-I and sleep-extension interventions can increase total sleep time by ~20-60 minutes; effect on hard outcomes is unproven.","timeframe":"Weeks to a few months for behavioural change.","evidence_type":"RCT","citation":"Meta-analyses of CBT-I (e.g., van Straten 2018, Sleep Med Rev) and sleep-extension RCTs; outcome trials on mortality are lacking.","rating":"moderate"}},{"id":"sleep_efficiency","name":"Sleep efficiency","domain":"sleep","aliases":["SE","time asleep / time in bed","sleep continuity"],"profile":{"mechanism":"Sleep efficiency is the percentage of time in bed actually spent asleep (total sleep time / time in bed x 100). Low efficiency reflects fragmented or difficult-to-initiate/maintain sleep; fragmentation impairs glymphatic clearance, sympathetic down-regulation and metabolic recovery, and predicts mortality and cognitive decline independent of total sleep time.","measurement":{"method":"Derived from polysomnography, actigraphy or wearable accelerometry; can be approximated from sleep diaries. Objective measurement is preferred because perceived efficiency diverges from measured.","sample_type":"wearable","approx_cost_usd":"0-300"},"signal_quality":"moderate","signal_quality_note":"Objective efficiency is reasonably reproducible across nights but device- and algorithm-dependent; diary-based efficiency is biased. Affected by time-in-bed behaviour, not only sleep quality.","confounders":["age (efficiency declines with age)","depression and anxiety","sleep-disordered breathing","pain and nocturia","time-in-bed behaviour","device/algorithm differences","medications"],"testing_cadence":"baseline + annual; continuous if wearable-tracked"},"outcomes":{"all_cause_mortality":{"hr":1.84,"hr_metric":"categorical","hr_unit_detail":"low actigraphic sleep efficiency (<80%) vs higher efficiency, all-cause mortality in older adults","direction":"risk","ci_low":1.19,"ci_high":2.84,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":2675,"followup_years":11,"study":"Osteoporotic Fractures in Men (MrOS) and Study of Osteoporotic Fractures (SOF) actigraphy cohorts of objective sleep and mortality in older adults.","study_type":"prospective-cohort","citation":"Dew MA et al. (and MrOS/SOF analyses, e.g., Stone KL et al.). Actigraphic sleep characteristics and mortality in older men/women. Sleep / J Am Geriatr Soc, c.2011-2015.","verification_status":"unverified","notes":"Low objective sleep efficiency predicts higher all-cause mortality in older-adult actigraphy cohorts (MrOS, SOF), with HRs roughly 1.5-2.0 for the lowest efficiency stratum; estimates vary by cohort and cut-point. Sleep efficiency is a bounded, left-skewed percentage typically analysed in clinical strata (<80% / <85%), so a per-SD slope is not standard; flagged categorical. Specific HR/CI not confirmed against a single source — unverified."},"cvd":{"hr":1.36,"hr_metric":"categorical","hr_unit_detail":"low sleep efficiency / poor sleep continuity vs adequate, incident cardiovascular events","direction":"risk","ci_low":1.1,"ci_high":1.7,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Cohort studies of objective sleep continuity / efficiency and incident CVD (e.g., MESA Sleep, MrOS).","study_type":"prospective-cohort","citation":"Multi-Ethnic Study of Atherosclerosis (MESA) Sleep ancillary study and related actigraphy cohorts of sleep efficiency / fragmentation and cardiovascular events.","verification_status":"unverified","notes":"Lower objective sleep efficiency and greater fragmentation associate with higher incident CVD and hypertension in actigraphy cohorts (MESA Sleep, MrOS), with HRs commonly in the ~1.3-1.7 range; effect attenuates after adjustment for sleep-disordered breathing. Bounded percentage exposure analysed categorically; flagged categorical, tier C. HR/CI approximate range, not confirmed to one source — unverified."},"cancer":null,"dementia":{"hr":1.32,"hr_metric":"categorical","hr_unit_detail":"low sleep efficiency / high fragmentation (e.g., highest quartile of fragmentation) vs low, incident Alzheimer's dementia / cognitive impairment in older adults","direction":"risk","ci_low":1.08,"ci_high":1.63,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":737,"followup_years":3.3,"study":"Rush Memory and Aging Project: actigraphic sleep fragmentation and incident Alzheimer's dementia in community-dwelling older adults.","study_type":"prospective-cohort","citation":"Lim ASP, Kowgier M, Yu L, Buchman AS, Bennett DA. Sleep fragmentation and the risk of incident Alzheimer's disease and cognitive decline in older persons. Sleep. 2013;36(7):1027-1032. doi:10.5665/sleep.2802. PMID:23814339","verification_status":"approximate","notes":"Higher actigraphic sleep fragmentation (the inverse of efficient, continuous sleep) was associated with ~1.5x higher incident Alzheimer's dementia per 1 SD of fragmentation in the Rush MAP cohort and faster cognitive decline. Reported here as a categorical/strata contrast because efficiency and fragmentation are bounded, skewed and metric-heterogeneous across studies. Reverse causation possible (preclinical AD fragments sleep). Tier C; HR approximate."},"frailty":{"hr":1.4,"hr_metric":"categorical","hr_unit_detail":"low objective sleep efficiency / fragmented sleep vs adequate, incident frailty in older adults","direction":"risk","ci_low":1.05,"ci_high":1.86,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":3133,"followup_years":3.4,"study":"Osteoporotic Fractures in Men (MrOS) actigraphy cohort: objective sleep and incident frailty in older men.","study_type":"prospective-cohort","citation":"Ensrud KE, Blackwell TL, Ancoli-Israel S, et al. (MrOS Study Group). Sleep disturbances and risk of frailty and mortality in older men. Sleep Med. 2012;13(10):1217-1225. doi:10.1016/j.sleep.2012.04.010. PMID:22705247","verification_status":"approximate","notes":"In MrOS, poor objective sleep (low efficiency, fragmentation, prolonged wake after sleep onset) predicted higher incident frailty and worsening frailty status, with HRs roughly 1.3-1.5 for the worst sleep strata. Bounded, skewed exposure analysed categorically; reverse causation plausible. Tier C; HR/CI approximate."}},"modifiability":{"intervention":"CBT-I (especially sleep-restriction and stimulus-control components, which raise efficiency by design), treatment of pain/nocturia, and treatment of sleep-disordered breathing.","effect_size":"CBT-I reliably raises sleep efficiency by ~5-12 percentage points; among the most modifiable sleep parameters.","timeframe":"4-8 weeks of CBT-I.","evidence_type":"RCT meta-analysis","citation":"Trauer JM et al. Cognitive behavioral therapy for chronic insomnia: a systematic review and meta-analysis. Ann Intern Med 2015;163:191-204.","rating":"high"},"comparability_tag":"Clinical cutpoint","comparability_note":"Sleep-efficiency HRs are reported as low-vs-adequate category contrasts (e.g. <80% efficiency, or fragmentation quartiles), not a continuous per-SD exposure."},{"id":"deep_sleep_duration","name":"Deep (slow-wave) sleep duration","domain":"sleep","aliases":["slow-wave sleep","N3 sleep","deep sleep","SWS"],"profile":{"mechanism":"Slow-wave sleep (N3) is the deepest non-REM stage, dominated by delta-frequency cortical oscillations. It drives glymphatic clearance of metabolic waste including amyloid-beta, growth-hormone secretion, memory consolidation, parasympathetic dominance and blood-pressure dipping. Slow-wave sleep declines markedly with age; its loss is implicated in neurodegeneration and cardiometabolic risk.","measurement":{"method":"Gold standard is polysomnography with EEG staging; consumer wearables estimate 'deep sleep' from accelerometry and heart-rate but agree only modestly with PSG-staged N3.","sample_type":"wearable","approx_cost_usd":"0-1500","approx_cost_note":"in-lab PSG several hundred to >1000 USD; wearable estimate near-zero marginal cost"},"signal_quality":"noisy","signal_quality_note":"PSG N3 staging is reliable but single-night; consumer-wearable 'deep sleep' has poor stage-level agreement with PSG and large between-device variability. Strongly age-dependent.","confounders":["age (dominant confounder)","sleep-disordered breathing","alcohol and sedatives","first-night effect / single-night PSG","device staging error (wearables)","depression","prior sleep debt"],"testing_cadence":"baseline + periodic; continuous trend if wearable-tracked"},"outcomes":{"all_cause_mortality":{"hr":1.27,"hr_metric":"per_unit","hr_unit_detail":"per 5% lower percentage of slow-wave (N3) sleep, all-cause mortality (approx; older-adult PSG cohorts)","direction":"risk","ci_low":1.08,"ci_high":1.5,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"C","n":"varies (pooled PSG cohorts)","followup_years":null,"study":"Polysomnography cohorts of sleep architecture and mortality (e.g., Sleep Heart Health Study, MrOS Sleep).","study_type":"prospective-cohort","citation":"Sleep Heart Health Study / MrOS Sleep analyses of PSG-derived sleep stages and mortality; slow-wave sleep and N3 percentage as predictors.","verification_status":"unverified","notes":"Lower slow-wave sleep has been associated with higher all-cause mortality in older-adult PSG cohorts, but evidence is thinner and less consistent than for total sleep time — several analyses find the association attenuates after adjustment for age, sleep-disordered breathing and comorbidity. No verified native per-SD HR was located; the per-5% figure is an approximate range and could not be converted without a defensible N3% SD. Flagged unconvertible, tier C, unverified."},"cvd":{"hr":1.27,"hr_metric":"categorical","hr_unit_detail":"lowest quartile of slow-wave sleep vs higher, incident hypertension/cardiovascular events in older men","direction":"risk","ci_low":1.03,"ci_high":1.57,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":784,"followup_years":3.4,"study":"Osteoporotic Fractures in Men (MrOS) Sleep Study: slow-wave sleep and incident hypertension in older men.","study_type":"prospective-cohort","citation":"Fung MM, Peters K, Redline S, et al. (Osteoporotic Fractures in Men Research Group). Decreased slow wave sleep increases risk of developing hypertension in elderly men. Hypertension. 2011;58(4):596-603. doi:10.1161/HYPERTENSIONAHA.111.174409. PMID:21876074","verification_status":"approximate","notes":"MrOS found men in the lowest quartile of slow-wave sleep had ~1.8x higher odds of incident hypertension over 3.4 years; the association was independent of sleep duration and partly of sleep-disordered breathing. Broader hard-CVD-endpoint evidence for slow-wave sleep specifically is thin. Reported as a categorical quartile contrast on a skewed, age-dominated exposure. Tier C; HR/CI approximate."},"cancer":null,"dementia":{"hr":1.27,"hr_metric":"per_unit","hr_unit_detail":"per 1% per year decline in slow-wave sleep, incident all-cause dementia (Framingham Heart Study)","direction":"risk","ci_low":1.06,"ci_high":1.54,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"C","n":346,"followup_years":17,"study":"Framingham Heart Study: longitudinal change in slow-wave sleep across two overnight PSGs and subsequent incident dementia.","study_type":"prospective-cohort","citation":"Himali JJ, Baril AA, Cavuoto MG, et al. Association between slow-wave sleep loss and incident dementia. JAMA Neurol. 2023;80(12):1326-1333. doi:10.1001/jamaneurol.2023.3889. PMID:37902739","verification_status":"verified","notes":"Framingham found each percentage-point per-year decline in slow-wave sleep was associated with ~27% higher incident dementia risk (HR 1.27, 1.06-1.54), consistent with slow-wave sleep's role in amyloid clearance. The exposure is a longitudinal decline RATE, not a cross-sectional level, and cannot be standardized to a per-SD level contrast; flagged unconvertible. Mechanistically supported but reverse causation (preclinical neurodegeneration eroding slow-wave sleep) cannot be excluded."},"frailty":null},"modifiability":{"intervention":"Slow-wave sleep is largely age-determined and not robustly modifiable. Regular aerobic exercise, avoidance of alcohol and certain sedatives near bedtime, and treatment of sleep-disordered breathing modestly preserve or increase slow-wave sleep; acoustic/closed-loop slow-oscillation stimulation can enhance delta power experimentally.","effect_size":"Lifestyle measures produce small increases in slow-wave sleep (minutes); no intervention reliably restores youthful slow-wave sleep amounts.","timeframe":"Weeks to months for exercise effects; acute for acoustic stimulation.","evidence_type":"RCT","citation":"Exercise-and-sleep RCT meta-analyses; closed-loop acoustic stimulation trials (e.g., Ngo 2013, Neuron). No hard-outcome RCTs.","rating":"low"},"comparability_tag":"No usable SD","comparability_note":"Slow-wave-sleep HRs are reported per percentage point or per year of decline with no population SD available, and one cell is a quartile contrast — none can be standardized to per SD."},{"id":"rem_sleep_duration","name":"REM sleep duration","domain":"sleep","aliases":["rapid eye movement sleep","REM%","paradoxical sleep"],"profile":{"mechanism":"REM sleep is characterized by cortical activation, vivid dreaming, muscle atonia and irregular autonomic activity. It supports emotional memory processing, synaptic regulation and thermoregulatory and autonomic functions. Reduced REM has been linked in cohort data to higher mortality and dementia risk; loss of REM atonia (REM behaviour disorder) is a strong prodrome of synucleinopathy.","measurement":{"method":"Gold standard is polysomnography with EEG/EOG/EMG staging; consumer wearables estimate REM from heart-rate variability and movement with moderate-to-poor stage agreement vs PSG.","sample_type":"wearable","approx_cost_usd":"0-1500","approx_cost_note":"in-lab PSG several hundred to >1000 USD; wearable estimate near-zero marginal cost"},"signal_quality":"noisy","signal_quality_note":"PSG REM staging is reliable but single-night and sensitive to first-night effects, sleep timing and prior REM deprivation; consumer-wearable REM estimates agree only modestly with PSG.","confounders":["age","antidepressants and other REM-suppressing drugs","alcohol","sleep-disordered breathing (REM-related desaturation)","first-night effect / single-night PSG","depression","circadian timing of recording"],"testing_cadence":"baseline + periodic; continuous trend if wearable-tracked"},"outcomes":{"all_cause_mortality":{"hr":1.13,"hr_metric":"per_unit","hr_unit_detail":"per 5% lower percentage of REM sleep, all-cause mortality (pooled MrOS + Wisconsin Sleep Cohort)","direction":"risk","ci_low":1.08,"ci_high":1.19,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"B","n":4050,"followup_years":12.1,"study":"Leary 2020, JAMA Neurology: pooled analysis of the Osteoporotic Fractures in Men (MrOS) Sleep Study and the Wisconsin Sleep Cohort.","study_type":"prospective-cohort","citation":"Leary EB, Watson KT, Ancoli-Israel S, et al. Association of rapid eye movement sleep with mortality in middle-aged and older adults. JAMA Neurol. 2020;77(10):1241-1251. doi:10.1001/jamaneurol.2020.2108. PMID:32628261","verification_status":"verified","notes":"Leary 2020 found each 5% lower REM sleep associated with ~13% higher all-cause mortality (and ~13% higher cardiovascular mortality) in older men, replicated for all-cause mortality in the younger, mixed-sex Wisconsin cohort. The exposure is a percentage of total sleep; without a defensible REM% population SD it cannot be reliably converted to per-SD, so flagged unconvertible. Association is robust but observational; reverse causation possible."},"cvd":{"hr":1.11,"hr_metric":"per_unit","hr_unit_detail":"per 5% lower percentage of REM sleep, cardiovascular mortality (MrOS Sleep Study)","direction":"risk","ci_low":1.04,"ci_high":1.19,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"C","n":2675,"followup_years":12.1,"study":"Leary 2020, JAMA Neurology: Osteoporotic Fractures in Men (MrOS) Sleep Study, cardiovascular mortality.","study_type":"prospective-cohort","citation":"Leary EB, Watson KT, Ancoli-Israel S, et al. Association of rapid eye movement sleep with mortality in middle-aged and older adults. JAMA Neurol. 2020;77(10):1241-1251. doi:10.1001/jamaneurol.2020.2108. PMID:32628261","verification_status":"approximate","notes":"In MrOS, lower REM sleep was associated with higher cardiovascular mortality (~11-13% per 5% lower REM). Evidence for incident CVD events (vs CVD mortality) specifically attributable to REM is thin. Percentage exposure not convertible to per-SD without a defensible REM% SD; flagged unconvertible. Tier C; observational, single principal cohort."},"cancer":null,"dementia":{"hr":1.09,"hr_metric":"per_unit","hr_unit_detail":"per 1% lower REM sleep, incident all-cause dementia (Framingham Heart Study Offspring)","direction":"risk","ci_low":1.02,"ci_high":1.16,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"per_unit but population SD unavailable — not standardized","conversion":null,"evidence_tier":"C","n":321,"followup_years":12,"study":"Framingham Heart Study: baseline polysomnographic sleep architecture and incident dementia in adults over 60.","study_type":"prospective-cohort","citation":"Pase MP, Himali JJ, Grima NA, et al. Sleep architecture and the risk of incident dementia in the community. Neurology. 2017;89(12):1244-1250. doi:10.1212/WNL.0000000000004373. PMID:28835407","verification_status":"verified","notes":"Framingham found lower REM percentage and longer REM latency associated with higher incident all-cause dementia and Alzheimer's dementia; each percentage-point lower REM corresponded to ~9% higher dementia risk, and slow-wave sleep was not significantly associated. Small sample (n=321, 32 dementia cases) so tier C. Percentage exposure not convertible to per-SD without a defensible REM% SD; flagged unconvertible. Reverse causation (preclinical disease altering REM) possible."},"frailty":null},"modifiability":{"intervention":"REM duration is largely physiologically and age-determined. Discontinuing or minimizing REM-suppressing medications (many antidepressants) and alcohol near bedtime, treating sleep-disordered breathing, and maintaining adequate total sleep time (REM is concentrated in the last third of the night) modestly preserve REM.","effect_size":"Avoiding REM-suppressant exposures and protecting late-night sleep produce modest increases in REM; no intervention reliably and durably augments REM beyond physiologic levels.","timeframe":"Days to weeks after removing a REM-suppressant.","evidence_type":"mechanistic","citation":"Pharmacology of REM-suppressing agents; observational sleep-architecture studies. No hard-outcome RCTs targeting REM duration.","rating":"low"},"comparability_tag":"No usable SD","comparability_note":"REM-sleep HRs are reported per percentage point of REM with no population SD available to convert them to a per-SD basis."},{"id":"sleep_apnea_severity","name":"Sleep apnea severity (ODI / AHI)","domain":"sleep","aliases":["obstructive sleep apnea","OSA","apnea-hypopnea index","AHI","oxygen desaturation index","ODI","home sleep apnea testing"],"comparability_tag":"Clinical strata","comparability_note":"Sleep apnea severity is graded into clinical strata (normal/mild/moderate/severe by AHI cut-points) and is highly right-skewed; hard-outcome HRs are reported as severe-vs-none contrasts rather than per-SD slopes.","profile":{"mechanism":"Obstructive sleep apnea causes repetitive upper-airway collapse with intermittent hypoxia, arousals and intrathoracic pressure swings. Severity is indexed by the apnea-hypopnea index (AHI) or oxygen desaturation index (ODI) — events per hour of sleep. Intermittent hypoxia and sympathetic surges drive hypertension, atrial fibrillation, endothelial dysfunction, insulin resistance, neuroinflammation and oxidative stress, linking severe OSA to cardiovascular, cognitive and mortality risk.","measurement":{"method":"Attended in-lab polysomnography (gold standard) or validated home sleep apnea testing (HSAT) recording airflow, respiratory effort and pulse oximetry; ODI is derived from oximetry alone. Severity strata: AHI <5 normal, 5-15 mild, 15-30 moderate, >=30 severe.","sample_type":"in-office device","approx_cost_usd":"150-3000","approx_cost_note":"home sleep apnea test ~150-500 USD; attended in-lab PSG ~1000-3000 USD"},"signal_quality":"moderate","signal_quality_note":"AHI is reasonably reproducible but varies by hypopnea scoring rule, body position, sleep stage and night-to-night; HSAT can underestimate AHI by dividing events over recording time rather than sleep time. ODI is robust but captures only desaturation events.","confounders":["obesity (strong shared cause)","age and male sex","hypopnea scoring criteria","supine sleep proportion","alcohol and sedatives","single-night variability","REM-related vs non-REM events"],"testing_cadence":"diagnostic test then re-test after intervention or major weight change"},"outcomes":{"all_cause_mortality":{"hr":1.39,"hr_metric":"categorical","hr_unit_detail":"severe OSA (AHI >=30) vs no/minimal OSA (AHI <5), all-cause mortality","direction":"risk","ci_low":1.25,"ci_high":1.54,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":"varies (pooled, multiple cohorts)","followup_years":null,"study":"Meta-analyses of obstructive sleep apnea severity and all-cause mortality (e.g., Pan 2016; Fu 2017), pooling prospective cohorts including the Wisconsin Sleep Cohort and Busselton Health Study.","study_type":"meta-analysis","citation":"Pan L, Xie X, Liu D, et al. Obstructive sleep apnoea and risks of all-cause mortality: preliminary evidence from prospective cohort studies. Sleep Breath. 2016;20(1):345-353. doi:10.1007/s11325-015-1295-7. PMID:26779902","verification_status":"approximate","notes":"Pooled prospective evidence shows severe OSA (AHI >=30) is associated with ~1.4-1.9x higher all-cause mortality vs no OSA; the Wisconsin Sleep Cohort 18-year follow-up reported an adjusted HR of ~3.0 for severe OSA. Mild-to-moderate OSA shows weak or null mortality associations. AHI is analysed in clinical strata and is highly skewed; flagged categorical. CPAP RCTs (SAVE) have not shown a mortality benefit, raising questions about causality vs confounding by obesity."},"cvd":{"hr":1.79,"hr_metric":"categorical","hr_unit_detail":"severe OSA (AHI >=30) vs no OSA, composite incident cardiovascular events / cardiovascular mortality","direction":"risk","ci_low":1.33,"ci_high":2.41,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":"varies (pooled prospective cohorts)","followup_years":null,"study":"Meta-analyses of OSA severity and incident cardiovascular disease (e.g., Xie 2018; Dong 2013), pooling cohorts including the Sleep Heart Health Study.","study_type":"meta-analysis","citation":"Xie C, Zhu R, Tian Y, Wang K. Association of obstructive sleep apnoea with the risk of vascular outcomes and all-cause mortality: a meta-analysis. BMJ Open. 2017;7(12):e013983. doi:10.1136/bmjopen-2016-013983. PMID:29275335","verification_status":"approximate","notes":"Severe OSA is consistently associated with higher incident CVD, coronary heart disease, stroke, atrial fibrillation, heart failure and CVD mortality (pooled HRs roughly 1.6-2.5 for severe vs no OSA); the Sleep Heart Health Study showed a graded relation, strongest in middle-aged men. AHI analysed in clinical strata, highly skewed; flagged categorical. Note: CPAP RCTs in established CVD (SAVE 2016, ISAACC, RICCADSA) did not reduce events, so observational HRs likely overstate the causal effect."},"cancer":{"hr":1.4,"hr_metric":"categorical","hr_unit_detail":"severe OSA / highest hypoxemia (ODI or T90) burden vs none, cancer incidence and cancer mortality","direction":"risk","ci_low":1.1,"ci_high":1.8,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"varies (pooled cohorts)","followup_years":null,"study":"Cohort studies and meta-analyses of OSA / nocturnal hypoxemia and cancer incidence and mortality (e.g., Wisconsin Sleep Cohort; Busselton; Spanish multicentre cohort).","study_type":"meta-analysis","citation":"Gozal D, Almendros I, Hakim F. Sleep apnea awakens cancer: a unifying immunologic hypothesis. / Meta-analyses such as Cheong AJY et al., Sleep Med Rev 2022, OSA and cancer incidence/mortality.","verification_status":"unverified","notes":"Intermittent hypoxia promotes tumour angiogenesis and immune evasion mechanistically, and some cohorts (Wisconsin, Busselton, Spanish multicentre) link severe OSA or high nocturnal hypoxemia burden to higher cancer incidence and cancer mortality, with hypoxemia indices (ODI, T90) often stronger predictors than AHI. Evidence is inconsistent across cohorts and confounded by obesity and smoking; tier C. Analysed in strata; flagged categorical. HR is an approximate representative range, not confirmed to a single source — unverified."},"dementia":{"hr":1.26,"hr_metric":"categorical","hr_unit_detail":"obstructive sleep apnea present vs absent, incident all-cause dementia / cognitive impairment in older adults","direction":"risk","ci_low":1.05,"ci_high":1.51,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"varies (pooled)","followup_years":null,"study":"Meta-analyses of obstructive sleep apnea / sleep-disordered breathing and incident dementia and cognitive impairment.","study_type":"meta-analysis","citation":"Bubu OM, Andrade AG, Umasabor-Bubu OQ, et al. Obstructive sleep apnea, cognition and Alzheimer's disease: a systematic review integrating three decades of multidisciplinary research. Sleep Med Rev. 2020;50:101250. doi:10.1016/j.smrv.2019.101250. PMID:31881487","verification_status":"approximate","notes":"Pooled evidence shows OSA / sleep-disordered breathing associated with ~25-85% higher risk of incident cognitive impairment and dementia; nocturnal hypoxemia correlates with amyloid burden and hippocampal change. Yaffe 2011 (JAMA) found sleep-disordered breathing predicted incident mild cognitive impairment/dementia in older women (OR ~1.85). Analysed categorically; flagged categorical. Bidirectionality and shared vascular risk factors complicate causal inference; CPAP may slow cognitive decline in observational data. Tier B."},"frailty":{"hr":1.5,"hr_metric":"categorical","hr_unit_detail":"moderate-to-severe OSA / sleep-disordered breathing vs none, prevalent or incident frailty in older adults","direction":"risk","ci_low":1.1,"ci_high":2,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":"varies","followup_years":null,"study":"Cross-sectional and cohort studies of sleep-disordered breathing and frailty in older adults (e.g., MrOS; Toronto and European geriatric cohorts).","study_type":"prospective-cohort","citation":"Studies and reviews of obstructive sleep apnea and frailty in older adults (e.g., Moreno-Tamayo K et al.; Piovezan RD et al., reviews of OSA, sarcopenia and frailty).","verification_status":"unverified","notes":"OSA is associated with prevalent and, in limited prospective data, incident frailty and sarcopenia in older adults (pooled OR/HR roughly 1.3-2.0), plausibly via intermittent hypoxia, inflammation, daytime sleepiness and reduced physical activity. Evidence is largely cross-sectional with odds ratios and substantial reverse-causation and obesity confounding; tier C. Analysed categorically; flagged categorical. HR is an approximate representative range — unverified."}},"modifiability":{"intervention":"Continuous positive airway pressure (CPAP) is first-line and reliably normalizes AHI/ODI; weight loss (including bariatric surgery and GLP-1 agonists such as tirzepatide), mandibular advancement devices, positional therapy, and hypoglossal-nerve stimulation are alternatives.","effect_size":"CPAP reduces AHI to <5 in most adherent users; ~10% weight loss can roughly halve AHI; tirzepatide reduced AHI by ~25-30 events/h in the SURMOUNT-OSA trial.","timeframe":"Immediate for CPAP; weeks to months for weight-loss approaches.","evidence_type":"RCT meta-analysis","citation":"CPAP RCTs and meta-analyses (SAVE 2016; meta-analyses on blood pressure and sleepiness); SURMOUNT-OSA tirzepatide RCT (Malhotra 2024, NEJM).","rating":"high"}},{"id":"sleep_regularity","name":"Wearable-derived sleep regularity","domain":"sleep","aliases":["sleep consistency","sleep regularity index","SRI","sleep timing variability","social jetlag"],"profile":{"mechanism":"Sleep regularity captures the day-to-day consistency of sleep timing and duration. The Sleep Regularity Index (SRI) scores the probability of being in the same state (asleep/awake) at the same clock time on consecutive days (0-100). Irregular sleep misaligns the circadian system from behaviour, disrupting metabolic, autonomic and inflammatory rhythms; emerging cohort data suggest irregularity predicts mortality and cardiometabolic risk independent of sleep duration.","measurement":{"method":"Computed from multi-day accelerometry or wearable sleep tracking (typically 7+ days). Common metrics: Sleep Regularity Index, standard deviation of sleep onset/midpoint, and social jetlag (weekday-weekend midpoint difference).","sample_type":"wearable","approx_cost_usd":"0-300"},"signal_quality":"moderate","signal_quality_note":"Requires multiple consecutive nights, making it more stable than single-night metrics, but depends on device sleep-detection accuracy and the chosen regularity metric; definitions are not yet standardized across studies.","confounders":["shift work and irregular work schedules","age","depression and psychiatric illness","caregiving and social obligations","device/algorithm and metric definition differences","underlying illness","weekend/weekday measurement window"],"testing_cadence":"rolling multi-day window; continuous if wearable-tracked"},"outcomes":{"all_cause_mortality":{"hr":1.53,"hr_metric":"categorical","hr_unit_detail":"most irregular sleep (lowest ~5th percentile of Sleep Regularity Index) vs most regular (~95th percentile), all-cause mortality, UK Biobank accelerometry","direction":"risk","ci_low":1.41,"ci_high":1.66,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":88975,"followup_years":7.1,"study":"Windred 2024, Sleep: UK Biobank accelerometer-derived Sleep Regularity Index and all-cause and cause-specific mortality.","study_type":"prospective-cohort","citation":"Windred DP, Burns AC, Lane JM, et al. Sleep regularity is a stronger predictor of mortality risk than sleep duration: a prospective cohort study. Sleep. 2024;47(1):zsad253. doi:10.1093/sleep/zsad253. PMID:37738616","verification_status":"verified","notes":"In UK Biobank, the most irregular sleepers (SRI ~5th percentile) had ~1.5x higher all-cause mortality than the most regular (~95th percentile), and sleep regularity predicted mortality more strongly than sleep duration. The contrast is an extreme-percentile comparison on a bounded 0-100 index, not a per-SD slope, so flagged categorical. Strong, recent, large-cohort evidence but single principal cohort and observational; tier B."},"cvd":{"hr":1.4,"hr_metric":"categorical","hr_unit_detail":"most irregular vs most regular sleep (SRI extreme percentiles, or irregular vs regular tertile), incident major cardiovascular events","direction":"risk","ci_low":1.2,"ci_high":1.63,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":72269,"followup_years":8,"study":"UK Biobank accelerometry analyses of the Sleep Regularity Index and incident cardiovascular disease (e.g., Huang 2023; Windred 2024).","study_type":"prospective-cohort","citation":"Huang T, Mariani S, Redline S. Sleep irregularity and risk of cardiovascular events: the Multi-Ethnic Study of Atherosclerosis. / UK Biobank SRI-CVD analyses such as Full KM et al., J Am Heart Assoc 2023.","verification_status":"approximate","notes":"Irregular sleep timing/duration predicts higher incident cardiovascular events independent of sleep duration; MESA (Huang 2020, JACC) found ~2x higher CVD incidence comparing the most vs least irregular sleep duration/timing, and UK Biobank SRI analyses report HRs around 1.3-1.6 for irregular sleep. Metrics and contrasts differ across studies; reported as a group contrast on a bounded index, flagged categorical. HR/CI an approximate representative figure across cohorts — approximate; tier B."},"cancer":{"hr":1.28,"hr_metric":"categorical","hr_unit_detail":"most irregular vs most regular sleep (SRI extreme percentiles), cancer incidence, UK Biobank accelerometry","direction":"risk","ci_low":1.13,"ci_high":1.45,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":88975,"followup_years":7.1,"study":"UK Biobank accelerometry analyses of the Sleep Regularity Index and cancer incidence/mortality (Windred 2024 and related).","study_type":"prospective-cohort","citation":"Windred DP, Burns AC, Lane JM, et al. Sleep regularity is a stronger predictor of mortality risk than sleep duration: a prospective cohort study. Sleep. 2024;47(1):zsad253. doi:10.1093/sleep/zsad253. PMID:37738616","verification_status":"approximate","notes":"UK Biobank found irregular sleepers had modestly higher cancer mortality and incidence (HR roughly 1.2-1.4 for the most vs least regular), consistent with circadian-disruption mechanisms and the IARC classification of shift work as a probable carcinogen. Single principal cohort, short follow-up for cancer, and confounding by shift work and lifestyle; tier C. Bounded-index extreme-percentile contrast; flagged categorical. CI/exact figure approximate."},"dementia":{"hr":1.53,"hr_metric":"categorical","hr_unit_detail":"irregular sleep (lowest vs middle/highest quintile of Sleep Regularity Index), incident all-cause dementia, UK Biobank accelerometry","direction":"risk","ci_low":1.24,"ci_high":1.89,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":88094,"followup_years":7.2,"study":"Cavaillès 2024, Neurology: UK Biobank accelerometer-derived Sleep Regularity Index and incident dementia.","study_type":"prospective-cohort","citation":"Cavaillès C, Wallace ML, Berr C, et al. Association of sleep regularity with incident dementia. Neurology. 2024;103(1):e209533. doi:10.1212/WNL.0000000000209533. PMID:38889384","verification_status":"verified","notes":"UK Biobank found the least regular sleepers had ~1.5x higher incident dementia vs more regular sleepers, with a non-linear dose-response that plateaued at higher regularity. The contrast is across quintiles of a bounded, non-normal index with a non-linear shape, so a per-SD slope is not defensible; flagged categorical. Single cohort, short follow-up, possible reverse causation (prodromal dementia disrupting sleep timing); tier C."},"frailty":null},"modifiability":{"intervention":"Consistent sleep-wake scheduling (fixed bedtime and wake time, including weekends), light exposure timing, limiting late-night screen/social activity, and managing shift-work schedules. Wearable feedback and CBT-I components can support regular timing.","effect_size":"Behavioural scheduling can substantially raise the Sleep Regularity Index and cut social jetlag within weeks; durability depends on work and social constraints.","timeframe":"Days to weeks for timing changes; sustained adherence is the limiting factor.","evidence_type":"observational","citation":"Circadian and sleep-timing intervention studies; no hard-outcome RCTs targeting sleep regularity specifically.","rating":"moderate"},"comparability_tag":"Index extremes","comparability_note":"Sleep-regularity HRs contrast extreme percentiles of the Sleep Regularity Index (most vs least regular), an index-based contrast rather than a per-SD continuum."},{"id":"vitamin_d_25oh","name":"Vitamin D (25-OH)","domain":"micronutrient","aliases":["25-hydroxyvitamin D","25(OH)D","calcidiol","serum vitamin D"],"comparability_tag":"U-shaped","comparability_note":"25(OH)D shows a non-linear, reverse-J/U-shaped relation with mortality (risk concentrated at deficiency; little or no gradient at high-normal); single linear per-SD HRs understate the deficiency-end effect.","profile":{"mechanism":"25-hydroxyvitamin D is the circulating storage form and the standard index of vitamin D status. Beyond calcium/bone homeostasis, the vitamin D receptor is expressed in immune, vascular and muscle tissue; deficiency is associated with impaired immune regulation, sarcopenia and adverse cardiometabolic profiles. Observational associations are strong but largely non-causal: Mendelian randomization and large supplementation RCTs show little effect on hard outcomes except in frank deficiency.","measurement":{"method":"Immunoassay or LC-MS/MS (reference method) on serum; standardized to the Vitamin D Standardization Program.","sample_type":"venous blood","approx_cost_usd":"30-65"},"signal_quality":"moderate","signal_quality_note":"Marked seasonal and assay-platform variability; immunoassays differ from LC-MS/MS. Status is heavily confounded by adiposity, sun exposure, skin pigmentation and outdoor activity, so a low value is partly a marker of poor general health.","confounders":["season and latitude","adiposity (volumetric dilution)","skin pigmentation and sun exposure","outdoor physical activity","supplement use","assay platform differences","reverse causation (illness reduces outdoor activity)"],"testing_cadence":"baseline; recheck after supplementation or seasonally if deficient"},"outcomes":{"all_cause_mortality":{"hr":1.25,"hr_metric":"categorical","hr_unit_detail":"lowest vs highest 25(OH)D category (deficient <25-30 nmol/L vs sufficient), all-cause mortality; non-linear reverse-J relation","direction":"protective","ci_low":1.19,"ci_high":1.31,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":"26916 (pooled), 8 cohorts","followup_years":10.5,"study":"Schottker B et al., consortium of 8 European/US prospective cohorts; individual-participant meta-analysis of 25(OH)D and mortality.","study_type":"meta-analysis","citation":"Schottker B et al. Vitamin D and mortality: meta-analysis of individual participant data from a large consortium of cohort studies from Europe and the United States. BMJ. 2014;348:g3656. doi:10.1136/bmj.g3656","verification_status":"approximate","notes":"The 25(OH)D-mortality relation is non-linear: pooled IPD analyses and umbrella reviews show steeply elevated mortality only in the deficient range, with a flat curve above ~50 nmol/L. Bottom-vs-top quintile HRs (~1.5-1.6) overstate the per-SD effect because the gradient is concentrated at the low end. Crucially the association is largely NOT causal: Mendelian randomization (Genetic-MR of 25(OH)D, ~386,000 participants) found no effect on all-cause mortality across the normal range, and the VITAL RCT (25,871 participants, 2 IU-equivalents) showed no mortality benefit. Flagged categorical."},"cvd":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD genetically predicted 25(OH)D, cardiovascular disease; well-powered MR null","direction":"risk","ci_low":0.95,"ci_high":1.06,"hr_per_sd":1,"hr_per_sd_ci":[0.95,1.06],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":386406,"followup_years":"genetic instrument","study":"Mendelian randomization of 25(OH)D and cardiovascular outcomes (UK Biobank / large genetic consortia).","study_type":"mendelian-randomization","citation":"Zhou A et al. Non-linear Mendelian randomization analyses support a role for vitamin D deficiency in cardiovascular disease risk. Eur Heart J. 2022;43(18):1731-1739. doi:10.1093/eurheartj/ehab809","verification_status":"approximate","notes":"Well-powered null at the population level: standard linear MR finds no overall effect of 25(OH)D on CVD, and the VITAL and ViDA RCTs showed no reduction in major cardiovascular events. Non-linear MR (Zhou 2022) does suggest a benefit confined to genuinely deficient individuals, consistent with the reverse-J observational shape. Per-SD HR recorded as ~1.0 to register the well-powered linear null; the residual signal is deficiency-restricted, not a continuous gradient."},"cancer":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD genetically predicted 25(OH)D, total cancer incidence; well-powered MR null","direction":"risk","ci_low":0.95,"ci_high":1.06,"hr_per_sd":1,"hr_per_sd_ci":[0.95,1.06],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":70563,"followup_years":"genetic instrument","study":"Mendelian randomization of 25(OH)D and total/site-specific cancer (large genetic consortia).","study_type":"mendelian-randomization","citation":"Ong JS et al. Vitamin D and overall cancer risk and cancer mortality: a Mendelian randomization study. Hum Mol Genet. 2018;27(24):4315-4322. doi:10.1093/hmg/ddy307","verification_status":"approximate","notes":"MR found no effect of genetically predicted 25(OH)D on overall cancer incidence (OR ~1.0). RCT evidence is concordant for incidence: VITAL showed no reduction in cancer incidence. There is a weaker, more consistent signal for reduced cancer MORTALITY in meta-analyses of supplementation trials (RR ~0.87-0.94), possibly via effects on tumor progression rather than initiation. Per-SD HR recorded as ~1.0 for incidence; treat the mortality signal as suggestive, not established."},"dementia":{"hr":1.19,"hr_metric":"categorical","hr_unit_detail":"severe deficiency (<25 nmol/L) vs sufficient (>=50 nmol/L), incident all-cause dementia; non-linear","direction":"protective","ci_low":1.06,"ci_high":1.35,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":1658,"followup_years":5.6,"study":"Littlejohns TJ et al., Cardiovascular Health Study prospective cohort of older adults, 25(OH)D and incident dementia.","study_type":"prospective-cohort","citation":"Littlejohns TJ et al. Vitamin D and the risk of dementia and Alzheimer disease. Neurology. 2014;83(10):920-928. doi:10.1212/WNL.0000000000000755","verification_status":"approximate","notes":"Observational cohorts (CHS; UK Biobank non-linear analyses) show higher dementia risk only in the deficient range, with a threshold near 25-50 nmol/L. UK Biobank non-linear MR (Navale 2022) reported that genetically low 25(OH)D was associated with higher dementia risk, suggesting a deficiency-restricted causal component. The association is not a continuous per-SD gradient; flagged categorical. Supplementation RCTs have not shown cognitive benefit."},"frailty":{"hr":1.3,"hr_metric":"categorical","hr_unit_detail":"deficient (<25-50 nmol/L) vs sufficient 25(OH)D, incident/prevalent frailty; non-linear","direction":"protective","ci_low":1.16,"ci_high":1.45,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"pooled, multiple cohorts","followup_years":5,"study":"Systematic review/meta-analysis of prospective cohorts of 25(OH)D status and incident frailty in older adults.","study_type":"meta-analysis","citation":"Ju SY et al. Serum 25-hydroxyvitamin D levels and the risk of frailty: a systematic review and meta-analysis. J Nutr Health Aging. 2018;22(3):362-368. doi:10.1007/s12603-017-0934-z","verification_status":"approximate","notes":"Vitamin D deficiency is consistently associated with prevalent and incident frailty and sarcopenia, with a threshold-type relation. However the association is strongly confounded by reverse causation (frail, housebound elders get less sun) and the modifiability is weak: supplementation RCTs have not reliably reduced falls or frailty progression, and high-dose vitamin D increased falls in some trials. Flagged categorical; observational signal far exceeds RCT-confirmed benefit."}},"modifiability":{"intervention":"Oral vitamin D3 supplementation; sunlight exposure. Correcting frank deficiency raises 25(OH)D reliably.","effect_size":"800-2000 IU/day typically raises 25(OH)D by ~20-40 nmol/L; status is highly modifiable, but hard-outcome benefit is largely confined to correcting genuine deficiency.","timeframe":"8-12 weeks to a new steady state","evidence_type":"RCT meta-analysis","citation":"VITAL (Manson 2019, NEJM), ViDA, D-Health and the VITAL/D-Health mortality meta-analyses: 25(OH)D is highly modifiable but supplementation did NOT reduce all-cause mortality, CVD events or cancer incidence in vitamin-D-replete populations.","rating":"moderate"}},{"id":"vitamin_b12","name":"Vitamin B12","domain":"micronutrient","aliases":["cobalamin","serum B12","holotranscobalamin"],"comparability_tag":"U-shaped","comparability_note":"Serum B12 has a U-shaped mortality association: both deficiency and high/elevated B12 (often reflecting liver disease, malignancy or renal impairment) carry excess risk, so no linear per-SD HR is defensible.","profile":{"mechanism":"Vitamin B12 (cobalamin) is a cofactor for methionine synthase and methylmalonyl-CoA mutase; deficiency causes megaloblastic anemia, peripheral neuropathy, cognitive impairment and elevated homocysteine and methylmalonic acid. Elevated serum B12 is rarely a true nutritional state and usually flags hepatic release, myeloproliferative/neoplastic disease or renal impairment, which explains the high-end mortality signal.","measurement":{"method":"Competitive-binding immunoassay for total serum B12; holotranscobalamin and functional markers (MMA, homocysteine) used to confirm deficiency.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"noisy","signal_quality_note":"Total serum B12 is a poor index of tissue status: it includes inactive haptocorrin-bound B12, so normal values can mask functional deficiency. Confirmation with MMA/holoTC is often needed; high values are frequently epiphenomena of disease.","confounders":["liver disease (elevates B12)","malignancy and myeloproliferative disorders (elevate B12)","renal impairment","supplement and fortified-food intake","metformin and PPI use (lower B12)","pregnancy","haptocorrin-bound inactive fraction"],"testing_cadence":"baseline; recheck if symptomatic or on metformin/PPI long-term"},"outcomes":{"all_cause_mortality":{"hr":1,"hr_metric":"categorical","hr_unit_detail":"U-shaped: both low and high serum B12 quintiles vs mid-range associate with higher all-cause mortality","direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":25259,"followup_years":8.2,"study":"Wolffenbuttel BHR et al., Dutch Lifelines / hospital cohorts of serum B12 and mortality; concordant with Danish nationwide cohort (Arendt 2016).","study_type":"prospective-cohort","citation":"Arendt JFB et al. Elevated plasma vitamin B12 levels and cancer prognosis: a population-based cohort study. Cancer Epidemiol Biomarkers Prev. 2016;25(5):768-775. doi:10.1158/1055-9965.EPI-15-1136; and Flores-Guerrero JL et al. Association of plasma concentration of vitamin B12 with all-cause mortality. JAMA Netw Open. 2020;3(1):e1919274.","verification_status":"approximate","notes":"Large cohorts (Flores-Guerrero 2020, JAMA Netw Open; Danish nationwide registry) show a clear U-shaped relation: the highest B12 quartile/quintile carries the strongest excess all-cause mortality (HR ~1.5-1.6 top vs reference), driven by occult liver disease and malignancy, while deficiency carries risk at the low end. The high-end signal is overwhelmingly a marker of underlying disease, not causal. Flagged categorical; no defensible linear per-SD HR."},"cvd":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"B-vitamin homocysteine-lowering RCTs report cardiovascular endpoints but not a serum-B12-level CVD hazard ratio.","study_type":"RCT","citation":"B-Vitamin Treatment Trialists' Collaboration. Homocysteine-lowering trials for prevention of cardiovascular events. Arch Intern Med. 2010;170(18):1622-1631.","verification_status":"unverified","notes":"Searched specifically: there is no well-characterized per-SD or per-quantile HR for serum B12 level and incident CVD in general-population cohorts. The relevant trial evidence is for B12-containing homocysteine-lowering supplementation (with folate/B6), which the B-Vitamin Treatment Trialists' meta-analysis found did NOT reduce cardiovascular events despite lowering homocysteine. Left null rather than fabricate a per-SD estimate.","qualitative":true},"cancer":{"hr":3,"hr_metric":"categorical","hr_unit_detail":"very high plasma B12 (>800 pmol/L) vs reference, cancer incidence within ~1 year of measurement","direction":"risk","ci_low":2.5,"ci_high":3.6,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":333667,"followup_years":5,"study":"Arendt JFB et al., Danish nationwide registry cohort, elevated plasma B12 and subsequent cancer diagnosis.","study_type":"prospective-cohort","citation":"Arendt JFB et al. Elevated plasma vitamin B12 levels as a marker for cancer: a population-based cohort study. J Natl Cancer Inst. 2013;105(23):1799-1805. doi:10.1093/jnci/djt315","verification_status":"approximate","notes":"Very high plasma B12 is a strong short-term marker of occult (especially hematologic, liver and lung) cancer, with the highest risk in the first year after measurement. This is reverse causation / a diagnostic flag, NOT a causal effect of B12 intake. Flagged categorical; the magnitude is large but represents detection of existing disease. B12 supplementation has not been shown to raise cancer risk in RCTs (though high-dose B6/B12 raised lung cancer in male smokers in one trial -- a separate signal)."},"dementia":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher serum B12, incident dementia; broadly null in cohort meta-analysis","direction":"protective","ci_low":0.92,"ci_high":1.08,"hr_per_sd":1,"hr_per_sd_ci":[0.92,1.08],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled, multiple cohorts","followup_years":7,"study":"Systematic review/meta-analysis of prospective cohorts of serum B12 and incident dementia/cognitive decline.","study_type":"meta-analysis","citation":"O'Leary F et al. Vitamin B12 status, cognitive decline and dementia: a systematic review of prospective cohort studies. Br J Nutr. 2012;108(11):1948-1961. doi:10.1017/S0007114512004175","verification_status":"unverified","notes":"Serum total B12 is, surprisingly, a weak and inconsistent predictor of incident dementia; functional markers (holotranscobalamin, MMA, homocysteine) perform better. Pooled cohort evidence is broadly null for total B12, recorded here as HR ~1.0 per SD. Frank B12 deficiency causes a reversible cognitive syndrome, but supplementation RCTs (with folate/B6) have not prevented dementia or slowed decline in replete populations. CI approximate."},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Cross-sectional and small longitudinal studies of B12 status and frailty/physical function in older adults.","study_type":"prospective-cohort","citation":"Cross-sectional analyses linking low B12 / functional B12 deficiency to anemia, neuropathy and reduced physical performance in community-dwelling elders.","verification_status":"unverified","notes":"Searched specifically: B12 deficiency contributes to anemia and peripheral neuropathy that can impair physical function, but no robust prospective incident-frailty hazard ratio for serum B12 was located. Associations are mostly cross-sectional and confounded by general nutritional and disease status. Left null rather than fabricate precision.","qualitative":true}},"modifiability":{"intervention":"Oral or intramuscular B12 (cobalamin) for deficiency; address malabsorption (pernicious anemia, metformin/PPI effect).","effect_size":"Replacement reliably normalizes serum B12 and corrects deficiency-related anemia/neuropathy; high baseline B12 is not a treatment target (it reflects underlying disease).","timeframe":"Weeks (hematologic response); months for neurologic recovery","evidence_type":"RCT meta-analysis","citation":"B-Vitamin Treatment Trialists' Collaboration (homocysteine-lowering trials); B12 deficiency correction is effective for the deficiency syndrome, but supplementation in replete people has not reduced cardiovascular events, cancer or dementia.","rating":"moderate"}},{"id":"folate","name":"Folate","domain":"micronutrient","aliases":["serum folate","RBC folate","vitamin B9","5-methyltetrahydrofolate"],"profile":{"mechanism":"Folate is the methyl donor for one-carbon metabolism, required for DNA synthesis/repair, methionine regeneration and homocysteine remethylation. Deficiency causes megaloblastic anemia, elevated homocysteine and (periconceptionally) neural tube defects. Population folate status improved markedly after grain fortification, compressing the deficiency range in fortified countries.","measurement":{"method":"Immunoassay for serum folate (recent intake) or red-cell folate (longer-term stores); LC-MS/MS for 5-MTHF.","sample_type":"venous blood","approx_cost_usd":"20-45"},"signal_quality":"moderate","signal_quality_note":"Serum folate fluctuates with recent diet; RBC folate is a steadier index of stores. Interpretation is intertwined with B12 status (masking of B12 deficiency) and varies between fortified and non-fortified populations.","confounders":["recent dietary intake (serum folate)","grain fortification status of the population","concurrent B12 status","alcohol use","MTHFR genotype","supplement use","hemolysis (affects RBC folate assay)"],"testing_cadence":"baseline; recheck if anemic or planning pregnancy"},"outcomes":{"all_cause_mortality":{"hr":1.16,"hr_metric":"quartile","hr_unit_detail":"lowest vs highest serum folate quartile, all-cause mortality, fully adjusted","direction":"protective","ci_low":1.03,"ci_high":1.31,"hr_per_sd":1.0602,"hr_per_sd_ci":[1.0117,1.1122],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":14787,"followup_years":8.5,"study":"Peng Y, Dong B, Wang Z. Serum folate concentrations and all-cause, cardiovascular and cancer mortality, NHANES III prospective cohort.","study_type":"prospective-cohort","citation":"Peng Y, Dong B, Wang Z. Serum folate concentrations and all-cause, cardiovascular disease and cancer mortality: a cohort study based on 1999-2010 NHANES. Int J Cardiol. 2016;219:136-142. doi:10.1016/j.ijcard.2016.05.012","verification_status":"approximate","notes":"Low serum folate is associated with modestly higher all-cause mortality in NHANES, but the signal is confounded by overall diet quality, alcohol and socioeconomic status. Quartile contrast converted to per-SD. The association is largely non-causal; in fortified populations the deficiency range is narrow and the gradient weak. Status approximate (exact NHANES quartile HR varies by analysis cycle)."},"cvd":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"folate-containing homocysteine-lowering supplementation vs placebo, major cardiovascular events; well-powered RCT meta-analysis null","direction":"protective","ci_low":0.97,"ci_high":1.05,"hr_per_sd":1,"hr_per_sd_ci":[0.97,1.05],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":37485,"followup_years":5,"study":"B-Vitamin Treatment Trialists' Collaboration, individual-participant meta-analysis of folic-acid-based homocysteine-lowering RCTs.","study_type":"meta-analysis","citation":"Clarke R et al. (B-Vitamin Treatment Trialists' Collaboration). Effects of lowering homocysteine levels with B vitamins on cardiovascular disease. Arch Intern Med. 2010;170(18):1622-1631. doi:10.1001/archinternmed.2010.348","verification_status":"verified","notes":"This is the central RCT message: folic acid supplementation lowers homocysteine ~25% but does NOT reduce major vascular events, MI or vascular death in well-powered IPD meta-analysis. A modest stroke reduction is seen in non-fortified populations (e.g., CSPPT in China). Observational low-folate/CVD associations therefore appear largely non-causal/confounded. Recorded as a well-powered null."},"cancer":{"hr":1.06,"hr_metric":"categorical","hr_unit_detail":"folic acid supplementation vs placebo, total cancer incidence; pooled RCT meta-analysis (non-significant)","direction":"risk","ci_low":0.99,"ci_high":1.13,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":49621,"followup_years":5.2,"study":"Vollset SE et al., individual-participant meta-analysis of folic acid supplementation RCTs and cancer incidence.","study_type":"meta-analysis","citation":"Vollset SE et al. Effects of folic acid supplementation on overall and site-specific cancer incidence during the randomised trials: meta-analyses of data on 50,000 individuals. Lancet. 2013;381(9871):1029-1036. doi:10.1016/S0140-6736(12)62001-7","verification_status":"verified","notes":"The IPD meta-analysis found folic acid supplementation did NOT significantly change total cancer incidence (RR 1.06, 0.99-1.13). There remains a debated concern that high-dose folic acid could promote progression of pre-existing colorectal neoplasia, but no clear net harm or benefit on incidence. Flagged categorical (an intervention contrast, not a biomarker-level per-SD exposure). Observational low-folate/cancer links are confounded."},"dementia":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher serum folate, incident dementia / folic-acid trials on cognition; broadly null","direction":"protective","ci_low":0.9,"ci_high":1.1,"hr_per_sd":1,"hr_per_sd_ci":[0.9,1.1],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled cohorts and RCTs","followup_years":6,"study":"Cohort studies and B-vitamin cognition RCTs (e.g., FACIT trial) of folate status and incident dementia/cognitive decline.","study_type":"meta-analysis","citation":"Durga J et al. Effect of 3-year folic acid supplementation on cognitive function in older adults (FACIT trial). Lancet. 2007;369(9557):208-216. doi:10.1016/S0140-6736(07)60109-3","verification_status":"unverified","notes":"Folate-dementia associations are inconsistent. The FACIT RCT suggested folic acid modestly improved some cognitive domains in those with raised homocysteine, but B-vitamin trials overall (including VITACOG) have not reliably prevented incident dementia. Recorded as an approximate per-SD null. Both low folate and, in some analyses, high folate with low B12 have been linked to cognitive harm. CI approximate."},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Cross-sectional studies of folate status and physical function/frailty in older adults.","study_type":"prospective-cohort","citation":"Cross-sectional analyses associating low folate / elevated homocysteine with reduced physical performance in community-dwelling elders.","verification_status":"unverified","notes":"Searched specifically: no robust prospective incident-frailty hazard ratio for serum or RBC folate was located. Low folate co-travels with poor diet quality and elevated homocysteine, both weakly linked to physical decline cross-sectionally, but a defensible longitudinal HR does not exist. Left null rather than fabricate precision.","qualitative":true}},"modifiability":{"intervention":"Dietary folate (leafy greens, legumes), folic acid supplements, and population-level grain fortification.","effect_size":"Fortification and supplementation reliably raise serum/RBC folate and lower homocysteine ~20-25%; status is highly modifiable.","timeframe":"4-8 weeks for serum folate; ~3-4 months for RBC folate","evidence_type":"RCT meta-analysis","citation":"B-Vitamin Treatment Trialists' Collaboration (Clarke 2010) and Vollset 2013 cancer meta-analysis: folate is highly modifiable but supplementation did not reduce cardiovascular events or cancer; periconceptional benefit (neural tube defects) is the clear exception.","rating":"high"},"comparability_tag":"Trial contrast","comparability_note":"The folate cancer cell is a supplementation-vs-placebo randomized contrast (folic acid did not significantly change cancer incidence), not a per-SD estimate of circulating folate."},{"id":"methylmalonic_acid","name":"Methylmalonic acid (MMA)","domain":"micronutrient","aliases":["MMA","serum methylmalonic acid","functional B12 marker"],"profile":{"mechanism":"Methylmalonic acid accumulates when methylmalonyl-CoA mutase activity is impaired by functional vitamin B12 deficiency; it is the most specific functional marker of cellular B12 status. Elevated MMA also rises with renal impairment and ageing, and emerging work links circulating MMA to mitochondrial dysfunction and a tumor-progression-promoting metabolic state.","measurement":{"method":"LC-MS/MS or GC-MS quantification of serum/plasma methylmalonic acid.","sample_type":"venous blood","approx_cost_usd":"60-150"},"signal_quality":"moderate","signal_quality_note":"MMA is a specific functional marker of B12 status but is strongly raised by reduced renal clearance and rises with age independent of B12, so an elevated value must be interpreted against eGFR.","confounders":["renal function / eGFR (major)","age","true functional B12 deficiency","gut microbiome-derived propionate","intra-individual variability"],"testing_cadence":"as needed to confirm functional B12 deficiency"},"outcomes":{"all_cause_mortality":{"hr":1.6,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest serum MMA quartile, all-cause mortality, fully adjusted (including renal function)","direction":"risk","ci_low":1.39,"ci_high":1.84,"hr_per_sd":1.2033,"hr_per_sd_ci":[1.1384,1.2713],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":5571,"followup_years":5.4,"study":"NHANES 2011-2014 prospective analysis of serum methylmalonic acid and mortality in US adults.","study_type":"prospective-cohort","citation":"Wang S et al. Serum methylmalonic acid and all-cause and cardiovascular mortality: a nationwide prospective cohort study (NHANES 2011-2014). PMC, 2023.","verification_status":"approximate","notes":"Elevated serum MMA predicts higher all-cause mortality in NHANES even after adjustment for renal function and B12 -- it appears to capture a functional metabolic-deficiency / mitochondrial-stress state. Quartile contrast converted to per-SD. The association is predictive, not established causal; much of the signal co-travels with age and subclinical renal impairment. Status approximate (CI from reported quartile model)."},"cvd":{"hr":1.45,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest serum MMA quartile, cardiovascular mortality, fully adjusted","direction":"risk","ci_low":1.12,"ci_high":1.88,"hr_per_sd":1.1575,"hr_per_sd_ci":[1.0456,1.2821],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":5571,"followup_years":5.4,"study":"NHANES 2011-2014 prospective analysis of serum methylmalonic acid and cardiovascular mortality.","study_type":"prospective-cohort","citation":"Wang S et al. Serum methylmalonic acid and all-cause and cardiovascular mortality: a nationwide prospective cohort study (NHANES 2011-2014). PMC, 2023.","verification_status":"approximate","notes":"Higher MMA was associated with elevated cardiovascular mortality in the same NHANES analysis. Evidence is limited (single cohort) and the signal is partly an age/renal-function epiphenomenon. Quartile contrast converted to per-SD. Treat as predictive/exploratory; no causal or trial evidence links lowering MMA to CVD outcomes."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Mechanistic work links circulating MMA to cancer progression, but no general-population incidence HR exists.","study_type":"mechanistic","citation":"Gomes AP et al. Age-induced accumulation of methylmalonic acid promotes tumour progression. Nature. 2020;585(7824):283-287. doi:10.1038/s41586-020-2630-0","verification_status":"unverified","notes":"Searched specifically: a landmark mechanistic study (Gomes 2020, Nature) showed age-associated circulating MMA can promote tumor aggressiveness/metastasis in models, but there is no prospective general-population hazard ratio for serum MMA and cancer incidence or mortality. Left null rather than convert a mechanistic finding into an epidemiologic HR.","qualitative":true},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Small cohort studies of MMA as a functional B12 marker and cognitive decline.","study_type":"prospective-cohort","citation":"Cross-sectional and small longitudinal studies relating elevated MMA (functional B12 deficiency) to cognitive performance in older adults.","verification_status":"unverified","notes":"Searched specifically: elevated MMA, as a marker of functional B12 deficiency, has been linked to worse cognition in some small studies, but no robust prospective incident-dementia hazard ratio specifically for serum MMA was located. Left null rather than fabricate precision.","qualitative":true},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective incident-frailty hazard ratio for serum MMA was located.","study_type":"prospective-cohort","citation":"No usable prospective study identified.","verification_status":"unverified","notes":"Searched specifically: although MMA rises with age and tracks functional B12 deficiency and mitochondrial stress -- all plausibly linked to physical decline -- no prospective incident-frailty hazard ratio for serum MMA exists. Left null. Honest emptiness.","qualitative":true}},"modifiability":{"intervention":"Vitamin B12 replacement lowers MMA when elevation is due to functional B12 deficiency; renally driven elevation is not nutritionally modifiable.","effect_size":"B12 repletion reliably lowers MMA when it is the cause; the portion driven by reduced renal clearance or ageing is not modifiable.","timeframe":"Weeks after B12 repletion","evidence_type":"observational","citation":"B12 supplementation studies show MMA falls with repletion; no outcome trial has tested whether lowering MMA itself reduces mortality.","rating":"moderate"}},{"id":"omega3_index","name":"Omega-3 index","domain":"micronutrient","aliases":["O3I","RBC EPA+DHA","erythrocyte omega-3 index"],"profile":{"mechanism":"The omega-3 index is the percentage of EPA + DHA in red-cell membrane fatty acids, an integrated index of long-chain omega-3 status over ~3-4 months. Higher membrane omega-3 content is associated with lower triglycerides, reduced platelet aggregation, anti-arrhythmic membrane effects and lower systemic inflammation; it is a candidate modifiable substrate for cardiovascular and possibly brain ageing.","measurement":{"method":"Gas chromatography of red-cell membrane fatty acids, expressed as % EPA+DHA of total fatty acids.","sample_type":"venous blood","approx_cost_usd":"60-120"},"signal_quality":"moderate","signal_quality_note":"RBC omega-3 index is more stable than plasma fatty acids (reflects ~120-day membrane turnover) but assay standardization across labs is imperfect and the index varies with diet, fish/supplement intake and genetics.","confounders":["fish and seafood intake","fish-oil supplement use","overall diet quality","genetics of fatty-acid desaturation (FADS locus)","assay/lab standardization"],"testing_cadence":"baseline; recheck ~3-4 months after dietary change"},"outcomes":{"all_cause_mortality":{"hr":0.66,"hr_metric":"quintile","hr_unit_detail":"highest vs lowest omega-3 index quintile, all-cause mortality, fully adjusted (pooled FORCE consortium)","direction":"protective","ci_low":0.61,"ci_high":0.72,"hr_per_sd":0.8621,"hr_per_sd_ci":[0.8382,0.8893],"comparability":"converted","hr_per_sd_basis":"quintile contrast; k = 1/2.8 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"A","n":42466,"followup_years":16,"study":"Harris WS et al. (FORCE consortium), pooled individual-participant analysis of 17 prospective cohorts of blood omega-3 fatty acids and all-cause mortality.","study_type":"pooled-cohort","citation":"Harris WS et al. Blood n-3 fatty acid levels and total and cause-specific mortality from 17 prospective studies. Nat Commun. 2021;12:2329. doi:10.1038/s41467-021-22370-2","verification_status":"verified","notes":"The FORCE pooled IPD analysis found a robust inverse association: highest vs lowest omega-3-index quintile, ~15-18% lower all-cause mortality (and lower CVD, cancer and other-cause mortality). Quintile contrast converted to per-SD. The association is consistent across cohorts, but supplementation RCTs of EPA/DHA have shown smaller and more variable mortality effects than the observational gradient implies -- some residual confounding by fish-consuming healthy lifestyle is likely."},"cvd":{"hr":0.75,"hr_metric":"quintile","hr_unit_detail":"highest vs lowest omega-3 index quintile, fatal coronary heart disease / CVD mortality, pooled","direction":"protective","ci_low":0.66,"ci_high":0.85,"hr_per_sd":0.9024,"hr_per_sd_ci":[0.8621,0.9436],"comparability":"converted","hr_per_sd_basis":"quintile contrast; k = 1/2.8 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"A","n":42466,"followup_years":16,"study":"FORCE consortium pooled IPD analysis of blood omega-3 fatty acids and cardiovascular mortality.","study_type":"pooled-cohort","citation":"Harris WS et al. Blood n-3 fatty acid levels and total and cause-specific mortality from 17 prospective studies. Nat Commun. 2021;12:2329. doi:10.1038/s41467-021-22370-2","verification_status":"verified","notes":"Higher omega-3 index is associated with lower CVD/fatal CHD mortality. Quintile contrast converted to per-SD. RCT evidence is mixed: REDUCE-IT (high-dose icosapent ethyl) reduced cardiovascular events, but VITAL, STRENGTH and OMEGA trials of standard-dose EPA/DHA were largely null for events -- the observational gradient overstates the benefit achievable by routine fish-oil supplementation."},"cancer":{"hr":0.85,"hr_metric":"quintile","hr_unit_detail":"highest vs lowest omega-3 index quintile, cancer mortality, pooled","direction":"protective","ci_low":0.76,"ci_high":0.96,"hr_per_sd":0.9436,"hr_per_sd_ci":[0.9066,0.9855],"comparability":"converted","hr_per_sd_basis":"quintile contrast; k = 1/2.8 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":42466,"followup_years":16,"study":"FORCE consortium pooled IPD analysis of blood omega-3 fatty acids and cancer mortality.","study_type":"pooled-cohort","citation":"Harris WS et al. Blood n-3 fatty acid levels and total and cause-specific mortality from 17 prospective studies. Nat Commun. 2021;12:2329. doi:10.1038/s41467-021-22370-2","verification_status":"approximate","notes":"FORCE found a modest inverse association of omega-3 index with cancer mortality. Quintile contrast converted to per-SD. The signal is weaker and likely more confounded than the CVD/all-cause findings; VITAL and other RCTs found no reduction in cancer incidence with omega-3 supplementation. Treat as observational/suggestive."},"dementia":{"hr":0.8,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest omega-3 (DHA) status tertile, incident dementia / Alzheimer disease","direction":"protective","ci_low":0.65,"ci_high":0.98,"hr_per_sd":0.9027,"hr_per_sd_ci":[0.8207,0.9908],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":1490,"followup_years":9.1,"study":"Framingham Heart Study and pooled cohorts of red-cell DHA / omega-3 status and incident dementia.","study_type":"prospective-cohort","citation":"Schaefer EJ et al. Plasma phosphatidylcholine docosahexaenoic acid content and risk of dementia and Alzheimer disease: the Framingham Heart Study. Arch Neurol. 2006;63(11):1545-1550. doi:10.1001/archneur.63.11.1545","verification_status":"approximate","notes":"Higher DHA/omega-3 status is associated with lower incident dementia in observational cohorts (Framingham; later UK Biobank red-cell omega-3 analyses). Tertile/quartile contrast converted to per-SD. RCT evidence is disappointing: omega-3 supplementation trials have not reliably slowed cognitive decline or prevented dementia, so the observational signal likely includes confounding and reverse causation. Status approximate."},"frailty":{"hr":0.82,"hr_metric":"quartile","hr_unit_detail":"highest vs lowest omega-3 (EPA/DHA) status quartile, incident frailty in older adults","direction":"protective","ci_low":0.68,"ci_high":0.99,"hr_per_sd":0.9248,"hr_per_sd_ci":[0.8591,0.9961],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":2154,"followup_years":5,"study":"InCHIANTI / Cardiovascular Health Study analyses of plasma/RBC omega-3 fatty acids and incident frailty.","study_type":"prospective-cohort","citation":"Reinders I et al. Higher plasma omega-3 polyunsaturated fatty acids and lower risk of frailty: prospective cohort analyses. (InCHIANTI/CHS-type cohorts).","verification_status":"unverified","notes":"Higher omega-3 status is associated with lower incident frailty / better physical performance in older-adult cohorts, plausibly via anti-inflammatory and muscle-membrane effects. Evidence is limited and the quartile contrast converted to per-SD. Some trials suggest omega-3 plus exercise/protein modestly preserves muscle, but standalone supplementation has not robustly prevented frailty. Status unverified."}},"modifiability":{"intervention":"Increased oily-fish intake or EPA/DHA supplementation reliably raises the red-cell omega-3 index.","effect_size":"~1-2 g/day EPA+DHA typically raises the index by 3-5 percentage points (e.g., from ~4% to ~8%); dose-dependent and durable.","timeframe":"~3-4 months to a new steady state (RBC membrane turnover)","evidence_type":"RCT meta-analysis","citation":"Dose-response supplementation trials of EPA/DHA and the omega-3 index; outcome trials (VITAL, STRENGTH, REDUCE-IT) show the index is highly modifiable but routine-dose supplementation has mostly NOT reduced hard CVD or mortality endpoints outside high-triglyceride/high-dose contexts.","rating":"high"}},{"id":"magnesium_rbc","name":"Magnesium (RBC)","domain":"micronutrient","aliases":["red blood cell magnesium","erythrocyte magnesium","serum magnesium"],"profile":{"mechanism":"Magnesium is a cofactor for >300 enzymes, including those of ATP metabolism, and stabilizes membranes and cardiac electrical activity. Most serum-magnesium epidemiology actually uses serum (not RBC) magnesium; low magnesium status is linked to insulin resistance, hypertension, arrhythmia and vascular calcification. RBC magnesium is a somewhat better index of intracellular stores but is far less studied in outcome cohorts.","measurement":{"method":"Colorimetric or atomic-absorption assay; serum magnesium is routine, RBC magnesium requires red-cell isolation.","sample_type":"venous blood","approx_cost_usd":"20-60"},"signal_quality":"noisy","signal_quality_note":"Serum magnesium reflects only ~1% of body magnesium and is tightly homeostatically buffered; RBC magnesium better tracks stores but is poorly standardized and rarely used in outcome studies, so most evidence rests on serum magnesium.","confounders":["renal function","diuretic and PPI use","diet quality and alcohol","diabetes / insulin resistance","homeostatic buffering of serum magnesium","hemolysis (affects RBC assay)"],"testing_cadence":"baseline; recheck if on diuretics/PPIs or symptomatic"},"outcomes":{"all_cause_mortality":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher serum magnesium, all-cause mortality; near-null with slight inverse trend","direction":"protective","ci_low":0.93,"ci_high":1.03,"hr_per_sd":1,"hr_per_sd_ci":[0.93,1.03],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"pooled, multiple cohorts","followup_years":10,"study":"Meta-analyses of serum / dietary magnesium and all-cause mortality in prospective cohorts.","study_type":"meta-analysis","citation":"Fang X et al. Dietary magnesium intake and the risk of cardiovascular disease, type 2 diabetes, and all-cause mortality: a dose-response meta-analysis of prospective cohort studies. BMC Med. 2016;14:210. doi:10.1186/s12916-016-0742-z","verification_status":"approximate","notes":"Pooled cohort evidence shows at most a weak inverse association of magnesium status/intake with all-cause mortality; serum magnesium is tightly buffered so the per-SD signal is small. Recorded as an approximate per-SD near-null. RBC magnesium specifically has little outcome evidence. Status approximate; mostly observational, no convincing supplementation mortality trial."},"cvd":{"hr":0.93,"hr_metric":"per_unit","hr_unit_detail":"per 0.1 mmol/L higher serum magnesium, total cardiovascular disease, dose-response meta-analysis","direction":"protective","ci_low":0.89,"ci_high":0.97,"hr_per_sd":0.9436,"hr_per_sd_ci":[0.911,0.9759],"comparability":"converted","hr_per_sd_basis":"per_unit: native HR per 0.1; population SD 0.08 (Approximate population SD of serum magnesium (~0.08 mmol/L) from general-population cohorts (e.g., ARIC / NHANES adult distributions).); k = SD/unit = 0.8","conversion":{"unit_value":0.1,"population_sd":0.08,"log2_sd":null,"sd_source":"Approximate population SD of serum magnesium (~0.08 mmol/L) from general-population cohorts (e.g., ARIC / NHANES adult distributions)."},"evidence_tier":"A","n":313041,"followup_years":11,"study":"Del Gobbo LC et al., dose-response meta-analysis of circulating and dietary magnesium and cardiovascular disease.","study_type":"meta-analysis","citation":"Del Gobbo LC et al. Circulating and dietary magnesium and risk of cardiovascular disease: a systematic review and meta-analysis of prospective studies. Am J Clin Nutr. 2013;98(1):160-173. doi:10.1093/ajcn.113.053132","verification_status":"approximate","notes":"Higher circulating magnesium is associated with lower CVD, with the strongest signal for ischemic heart disease and fatal CHD. Reported per 0.1 mmol/L; converted to per-SD using an approximate population SD (~0.08 mmol/L) -- the SD is itself uncertain, so status approximate. Largely observational; no large supplementation trial has shown CVD-event reduction, though MR evidence gives some support for a causal link to blood pressure."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Site-specific (mainly colorectal) magnesium-cancer cohort studies; no coherent general-cancer HR.","study_type":"prospective-cohort","citation":"Meta-analyses of dietary magnesium and colorectal cancer risk (e.g., Wark PA et al.); evidence does not generalize to total cancer.","verification_status":"unverified","notes":"Searched specifically: dietary magnesium has a weak inverse association with colorectal cancer in some meta-analyses, but there is no defensible per-SD HR for serum/RBC magnesium and total cancer incidence or mortality. Left null rather than over-generalize a site-specific dietary finding.","qualitative":true},"dementia":{"hr":0.9,"hr_metric":"quintile","hr_unit_detail":"highest vs lowest serum magnesium quintile, incident all-cause dementia (U-shaped: low and high both elevated)","direction":"protective","ci_low":0.79,"ci_high":1.02,"hr_per_sd":0.9631,"hr_per_sd_ci":[0.9193,1.0071],"comparability":"converted","hr_per_sd_basis":"quintile contrast; k = 1/2.8 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":9569,"followup_years":7.8,"study":"Rotterdam Study prospective cohort of serum magnesium and incident dementia.","study_type":"prospective-cohort","citation":"Kieboom BCT et al. Serum magnesium and the risk of dementia: the Rotterdam Study. Neurology. 2017;89(16):1716-1722. doi:10.1212/WNL.0000000000004517","verification_status":"approximate","notes":"The Rotterdam Study found a U-shaped relation: both low and high serum magnesium were associated with higher dementia risk. The quintile contrast converted to per-SD is therefore only a rough summary and likely understates non-monotonic structure -- the cell is borderline categorical. Evidence is limited (single cohort); no trial evidence. Status approximate."},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Cross-sectional studies of magnesium status and muscle performance/frailty in older adults.","study_type":"prospective-cohort","citation":"Cross-sectional analyses linking low magnesium intake/status to reduced muscle strength and physical performance in older adults.","verification_status":"unverified","notes":"Searched specifically: low magnesium status correlates cross-sectionally with reduced grip strength and physical performance, but no robust prospective incident-frailty hazard ratio for serum or RBC magnesium was located. Left null rather than fabricate precision.","qualitative":true}},"modifiability":{"intervention":"Magnesium-rich diet (whole grains, nuts, leafy greens, legumes) and oral magnesium supplements; address depleting medications (diuretics, PPIs).","effect_size":"Supplementation modestly raises serum and RBC magnesium and lowers blood pressure ~2-4 mmHg; deficiency correction is reliable.","timeframe":"Weeks to a few months","evidence_type":"RCT meta-analysis","citation":"RCT meta-analyses of magnesium supplementation and blood pressure / insulin sensitivity show modest physiologic effects; no large trial demonstrates reduced mortality, CVD events or dementia.","rating":"moderate"}},{"id":"zinc","name":"Zinc","domain":"micronutrient","aliases":["serum zinc","plasma zinc"],"profile":{"mechanism":"Zinc is a structural and catalytic cofactor for hundreds of enzymes and transcription factors, essential for immune function, antioxidant defense (Cu/Zn-SOD) and protein synthesis. Low zinc status is linked to impaired immunity, poor wound healing and, in older adults, to sarcopenia and infection risk. Serum zinc is a weak status index because it is homeostatically buffered and falls as an acute-phase response.","measurement":{"method":"Atomic-absorption spectroscopy or ICP-MS on serum/plasma; trace-metal-free collection required.","sample_type":"venous blood","approx_cost_usd":"25-60"},"signal_quality":"noisy","signal_quality_note":"Serum zinc reflects a small, tightly buffered pool and drops during inflammation/infection (redistribution), so a low value often signals illness rather than dietary deficiency. Diurnal variation and fasting state also affect it.","confounders":["acute-phase response / inflammation (lowers zinc)","fasting state and time of day","hypoalbuminemia","trace-metal contamination of collection tubes","diet and supplement use"],"testing_cadence":"baseline; interpret alongside CRP"},"outcomes":{"all_cause_mortality":{"hr":1.3,"hr_metric":"quartile","hr_unit_detail":"lowest vs highest serum zinc quartile, all-cause mortality, fully adjusted","direction":"protective","ci_low":1.11,"ci_high":1.52,"hr_per_sd":1.1088,"hr_per_sd_ci":[1.0419,1.1792],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":9416,"followup_years":12,"study":"NHANES-based and European cohort analyses of serum zinc and all-cause mortality in adults.","study_type":"prospective-cohort","citation":"Yu L et al. Serum zinc and all-cause mortality: prospective cohort analyses of NHANES participants. (NHANES iron/zinc biomarker mortality literature.)","verification_status":"unverified","notes":"Low serum zinc is associated with higher all-cause mortality in cohort studies, but the signal is strongly confounded: serum zinc falls with inflammation, hypoalbuminemia and acute illness, so a low value partly marks underlying disease (reverse causation). Quartile contrast converted to per-SD. Largely observational; status unverified, magnitude indicative only."},"cvd":{"hr":1.2,"hr_metric":"tertile","hr_unit_detail":"lowest vs highest serum zinc tertile, cardiovascular mortality, adjusted","direction":"protective","ci_low":1,"ci_high":1.44,"hr_per_sd":1.0872,"hr_per_sd_ci":[1,1.1821],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":3575,"followup_years":8,"study":"Cohort analyses of serum zinc and the zinc/copper ratio with cardiovascular mortality in older adults.","study_type":"prospective-cohort","citation":"Leone N et al. Zinc, copper, and magnesium and risks for all-cause, cancer, and cardiovascular mortality. Epidemiology. 2006;17(3):308-314.","verification_status":"unverified","notes":"Low serum zinc (and a low zinc/copper ratio) is associated with higher cardiovascular mortality in some cohorts, but evidence is limited and confounded by inflammation. Tertile contrast converted to per-SD. No trial evidence that zinc supplementation reduces CVD events. Status unverified; treat as exploratory."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Direction-inconsistent observational studies of zinc status/intake and cancer.","study_type":"prospective-cohort","citation":"Heterogeneous prospective and case-control studies of zinc intake/status and site-specific cancers.","verification_status":"unverified","notes":"Searched specifically: zinc-cancer associations are direction-inconsistent across sites (some inverse for digestive cancers, neutral or positive for prostate cancer with high supplemental intake). No coherent general-population per-SD HR for serum zinc and cancer exists. Left null rather than fabricate a pooled estimate.","qualitative":true},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Cross-sectional studies of zinc status and cognition; no prospective incident-dementia HR.","study_type":"prospective-cohort","citation":"Cross-sectional analyses of serum zinc and cognitive performance in older adults.","verification_status":"unverified","notes":"Searched specifically: zinc dyshomeostasis is mechanistically implicated in Alzheimer pathology, but no robust prospective incident-dementia hazard ratio for serum zinc was located. Evidence is mechanistic and cross-sectional. Left null rather than fabricate precision.","qualitative":true},"frailty":{"hr":1.25,"hr_metric":"tertile","hr_unit_detail":"lowest vs highest serum zinc tertile, incident frailty / functional decline in older adults","direction":"protective","ci_low":1.02,"ci_high":1.53,"hr_per_sd":1.1078,"hr_per_sd_ci":[1.0091,1.2154],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":1000,"followup_years":6,"study":"InCHIANTI-type cohort analyses of zinc status and incident frailty / physical decline in older adults.","study_type":"prospective-cohort","citation":"Cabrera AJR et al. and InCHIANTI analyses of micronutrient status (including zinc) and incident frailty in community-dwelling elders.","verification_status":"unverified","notes":"Low zinc status is associated with incident frailty and functional decline in older-adult cohorts, plausibly via immune and muscle effects, but the signal is confounded by overall nutritional status and inflammation. Tertile contrast converted to per-SD. Evidence limited; status unverified. Zinc supplementation has not been shown to prevent frailty in trials."}},"modifiability":{"intervention":"Zinc-rich diet (meat, shellfish, legumes, nuts) and oral zinc supplements; address malabsorption and excess copper/iron competition.","effect_size":"Supplementation reliably corrects deficiency; serum zinc is buffered so changes are modest, and excess zinc can cause copper deficiency.","timeframe":"Weeks to months","evidence_type":"observational","citation":"Zinc supplementation trials show benefit for deficiency syndromes (immune function, growth) but no large trial demonstrates reduced mortality, CVD or dementia; over-supplementation risks copper depletion.","rating":"moderate"}},{"id":"copper","name":"Copper","domain":"micronutrient","aliases":["serum copper","plasma copper"],"comparability_tag":"U-shaped","comparability_note":"Serum copper shows a non-monotonic mortality relation: both deficiency and (more strongly) elevated copper carry risk, and high copper is largely an acute-phase / inflammation epiphenomenon, so a linear per-SD HR is not defensible.","profile":{"mechanism":"Copper is a cofactor for cytochrome c oxidase, Cu/Zn-SOD, lysyl oxidase and ceruloplasmin. ~90% of serum copper is carried on ceruloplasmin, an acute-phase reactant, so serum copper rises with inflammation, infection, malignancy and estrogen exposure. Elevated serum copper is therefore largely a marker of inflammatory or neoplastic disease rather than copper intake.","measurement":{"method":"Atomic-absorption spectroscopy or ICP-MS on serum/plasma.","sample_type":"venous blood","approx_cost_usd":"25-60"},"signal_quality":"noisy","signal_quality_note":"Serum copper is dominated by ceruloplasmin-bound copper and behaves as an acute-phase reactant; a high value usually reflects inflammation, malignancy, pregnancy or estrogen use, not dietary copper. Poor index of true copper status.","confounders":["inflammation / acute-phase response (raises copper)","malignancy","estrogen / oral contraceptives / pregnancy","liver disease","ceruloplasmin level","smoking"],"testing_cadence":"baseline; interpret alongside CRP and ceruloplasmin"},"outcomes":{"all_cause_mortality":{"hr":1.5,"hr_metric":"categorical","hr_unit_detail":"highest vs lowest serum copper tertile/quartile, all-cause mortality; non-monotonic (elevated end strongly driven by inflammation)","direction":"risk","ci_low":1.31,"ci_high":1.72,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":14045,"followup_years":12,"study":"NHANES and European cohort analyses of serum copper and all-cause mortality in adults.","study_type":"prospective-cohort","citation":"Leone N et al. Zinc, copper, and magnesium and risks for all-cause, cancer, and cardiovascular mortality. Epidemiology. 2006;17(3):308-314; concordant with later NHANES copper-mortality analyses.","verification_status":"approximate","notes":"Elevated serum copper consistently predicts higher all-cause mortality (top vs bottom group HR ~1.4-1.6), but this is overwhelmingly because copper rises as an acute-phase reactant with inflammation, malignancy and chronic disease -- it is a marker of illness, not a causal exposure. Copper deficiency at the low end also carries risk, giving a non-monotonic shape. Flagged categorical; no defensible linear per-SD HR."},"cvd":{"hr":1.4,"hr_metric":"categorical","hr_unit_detail":"highest vs lowest serum copper category, cardiovascular mortality; high-end signal confounded by inflammation","direction":"risk","ci_low":1.18,"ci_high":1.66,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":14045,"followup_years":12,"study":"Cohort and meta-analytic evidence on serum copper and cardiovascular mortality.","study_type":"meta-analysis","citation":"Ford ES. Serum copper concentration and coronary heart disease among US adults. Am J Epidemiol. 2000;151(12):1182-1188; and later copper-CVD meta-analyses.","verification_status":"approximate","notes":"Higher serum copper is associated with elevated cardiovascular mortality across cohorts, but the association is heavily confounded by ceruloplasmin/inflammation. MR evidence does not support a causal copper-CVD effect. Flagged categorical; the native HR is retained but no per-SD value is defensible."},"cancer":{"hr":1.45,"hr_metric":"categorical","hr_unit_detail":"elevated vs reference serum copper, cancer mortality; largely reverse causation (copper rises with malignancy)","direction":"risk","ci_low":1.2,"ci_high":1.75,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":14045,"followup_years":12,"study":"Cohort analyses of serum copper and cancer mortality in adults.","study_type":"prospective-cohort","citation":"Leone N et al. Zinc, copper, and magnesium and risks for all-cause, cancer, and cardiovascular mortality. Epidemiology. 2006;17(3):308-314.","verification_status":"approximate","notes":"Elevated serum copper is associated with higher cancer mortality, but copper/ceruloplasmin rise as an acute-phase response to malignancy -- this is largely reverse causation and a prognostic epiphenomenon. Flagged categorical. (Note: copper-dependent cell death, 'cuproptosis', and copper chelation are active oncology research areas, but that is mechanistic, not an epidemiologic per-SD exposure.)"},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Studies of 'free' (non-ceruloplasmin-bound) copper and cognitive decline; no usable serum-copper per-SD HR.","study_type":"prospective-cohort","citation":"Squitti R et al. Non-ceruloplasmin copper distinguishes a distinct subtype of Alzheimer's disease. (Copper-dyshomeostasis Alzheimer literature.)","verification_status":"unverified","notes":"Searched specifically: a body of work links elevated non-ceruloplasmin-bound ('free') copper to Alzheimer risk and progression, but total serum copper performs inconsistently and no robust prospective incident-dementia hazard ratio for total serum copper was located. Left null rather than convert a specialized 'free copper' finding into a total-copper HR.","qualitative":true},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Cross-sectional studies of copper status and frailty in older adults.","study_type":"prospective-cohort","citation":"Cross-sectional analyses linking elevated serum copper / copper-zinc imbalance to frailty in community-dwelling elders.","verification_status":"unverified","notes":"Searched specifically: elevated serum copper correlates with frailty cross-sectionally, but this largely reflects copper's behavior as an inflammatory marker rather than a causal nutritional exposure. No robust prospective incident-frailty hazard ratio was located. Left null rather than fabricate precision.","qualitative":true}},"modifiability":{"intervention":"Copper status is rarely a clinical target; deficiency (rare, e.g., excess zinc, bariatric surgery, malabsorption) is corrected with copper repletion. Elevated serum copper reflects inflammation/disease and is not itself a modifiable nutritional target.","effect_size":"Deficiency correction is reliable; elevated serum copper falls only when the underlying inflammatory or neoplastic cause resolves.","timeframe":"Weeks (deficiency correction)","evidence_type":"mechanistic","citation":"No outcome trial shows benefit from lowering serum copper in the general population; high serum copper is an epiphenomenon of inflammation/malignancy, not a treatment target.","rating":"low"}},{"id":"ceruloplasmin","name":"Ceruloplasmin","domain":"micronutrient","aliases":["serum ceruloplasmin","ferroxidase"],"profile":{"mechanism":"Ceruloplasmin is the main copper-carrying plasma protein and a ferroxidase essential for iron loading onto transferrin; it is also a positive acute-phase reactant. Elevated ceruloplasmin reflects inflammation, estrogen exposure or copper status; very low ceruloplasmin is a hallmark of Wilson disease and aceruloplasminemia. As a biomarker it largely overlaps with serum copper and inflammatory signaling.","measurement":{"method":"Immunoturbidimetric/nephelometric assay (protein mass) or enzymatic ferroxidase activity assay.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"noisy","signal_quality_note":"Ceruloplasmin behaves as an acute-phase reactant and rises with estrogen, pregnancy and inflammation; immunoassays measure both holo- and apo-protein, so values do not cleanly index copper status or any single pathway.","confounders":["inflammation / acute-phase response","estrogen / oral contraceptives / pregnancy","liver synthetic function","copper status","smoking"],"testing_cadence":"baseline; mainly used diagnostically (e.g., Wilson disease workup)"},"outcomes":{"all_cause_mortality":{"hr":1.4,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest serum ceruloplasmin tertile, all-cause mortality, adjusted","direction":"risk","ci_low":1.18,"ci_high":1.66,"hr_per_sd":1.1669,"hr_per_sd_ci":[1.0789,1.2617],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":4500,"followup_years":10,"study":"Cohort analyses of serum ceruloplasmin and all-cause mortality in adults.","study_type":"prospective-cohort","citation":"Cohort studies relating elevated ceruloplasmin to all-cause and cardiovascular mortality (ceruloplasmin as an inflammatory/oxidative marker).","verification_status":"unverified","notes":"Elevated ceruloplasmin is associated with higher all-cause mortality, but as a positive acute-phase reactant it largely co-tracks CRP and serum copper -- the signal is an inflammation epiphenomenon, not an independent causal exposure. Tertile contrast converted to per-SD. Evidence limited; status unverified."},"cvd":{"hr":1.5,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest serum ceruloplasmin tertile, coronary heart disease / cardiovascular events, adjusted","direction":"risk","ci_low":1.25,"ci_high":1.8,"hr_per_sd":1.2044,"hr_per_sd_ci":[1.1078,1.3095],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":13000,"followup_years":10,"study":"Prospective cohort analyses (e.g., ARIC-type) of serum ceruloplasmin and incident coronary heart disease.","study_type":"prospective-cohort","citation":"Engstrom G et al. and related cohort analyses linking elevated ceruloplasmin to incident cardiovascular events.","verification_status":"unverified","notes":"Higher ceruloplasmin predicts incident CHD in cohort studies, consistent with its role as an inflammatory/oxidative marker, and it correlates with hsCRP and fibrinogen. The association is predictive but not established as causal; it is largely redundant with general inflammation markers. Tertile contrast converted to per-SD. Status unverified."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Ceruloplasmin is studied as a tumor-associated/prognostic marker, not as a general-population incidence predictor.","study_type":"prospective-cohort","citation":"Studies of ceruloplasmin as a prognostic marker within diagnosed malignancies.","verification_status":"unverified","notes":"Searched specifically: ceruloplasmin rises within established malignancy and has been studied as a prognostic marker, but no robust prospective per-SD/per-quantile HR for serum ceruloplasmin and general-population cancer incidence was located. Left null rather than fabricate precision.","qualitative":true},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Mechanistic/cross-sectional studies of ceruloplasmin ferroxidase activity and neurodegeneration.","study_type":"prospective-cohort","citation":"Studies of ceruloplasmin ferroxidase activity, brain iron and neurodegeneration.","verification_status":"unverified","notes":"Searched specifically: impaired ceruloplasmin ferroxidase activity is mechanistically linked to brain iron accumulation and neurodegeneration (aceruloplasminemia is a model), but no robust prospective incident-dementia hazard ratio for serum ceruloplasmin in the general population was located. Left null rather than fabricate precision.","qualitative":true},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective incident-frailty hazard ratio for serum ceruloplasmin was located.","study_type":"prospective-cohort","citation":"No usable prospective study identified.","verification_status":"unverified","notes":"Searched specifically: ceruloplasmin behaves as an acute-phase reactant and would be expected to co-track inflammation-related frailty, but no prospective incident-frailty hazard ratio specific to ceruloplasmin was located. Left null. Honest emptiness.","qualitative":true}},"modifiability":{"intervention":"Ceruloplasmin is not a stand-alone intervention target; it is used diagnostically (Wilson disease, copper deficiency). Treating an underlying inflammatory state lowers reactive elevation.","effect_size":"Reactive elevation falls when the inflammatory cause resolves; there is no rationale for targeting ceruloplasmin per se.","timeframe":"Weeks to months (with resolution of inflammation)","evidence_type":"mechanistic","citation":"No outcome trial targets ceruloplasmin; its elevation in the general population is an inflammatory epiphenomenon.","rating":"low"}},{"id":"transferrin_saturation","name":"Transferrin saturation","domain":"micronutrient","aliases":["TSAT","transferrin saturation %","iron saturation"],"comparability_tag":"U-shaped","comparability_note":"Transferrin saturation has a U-shaped mortality relation: both low TSAT (iron deficiency) and high TSAT (iron overload) carry excess risk, so no single linear per-SD HR is defensible.","profile":{"mechanism":"Transferrin saturation is the percentage of transferrin iron-binding sites occupied (serum iron / TIBC x 100); it indexes iron availability for erythropoiesis and tissue delivery. Low TSAT indicates iron deficiency; high TSAT indicates iron overload (e.g., hemochromatosis) with risk of catalytic free-iron-driven oxidative tissue damage. It is a more dynamic iron-status marker than ferritin and less inflammation-confounded.","measurement":{"method":"Calculated from serum iron and total iron-binding capacity (or transferrin); colorimetric/immunoturbidimetric assays.","sample_type":"venous blood","approx_cost_usd":"15-40"},"signal_quality":"moderate","signal_quality_note":"TSAT has marked diurnal variation (serum iron peaks in the morning) and responds to recent intake and inflammation; a single measurement is noisy, but it is less acute-phase-confounded than ferritin and tracks functional iron availability.","confounders":["diurnal variation in serum iron","recent dietary iron / supplements","inflammation (lowers serum iron)","fasting state","HFE genotype","menstrual blood loss"],"testing_cadence":"baseline (morning, fasting); part of an iron panel with ferritin and TIBC"},"outcomes":{"all_cause_mortality":{"hr":1.2,"hr_metric":"categorical","hr_unit_detail":"extreme (low <20% or high >50%) vs mid-range transferrin saturation, all-cause mortality; U-shaped","direction":"risk","ci_low":1.1,"ci_high":1.31,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":132542,"followup_years":8,"study":"Copenhagen General Population Study and NHANES analyses of transferrin saturation and all-cause mortality.","study_type":"prospective-cohort","citation":"Ellervik C et al. Total and cause-specific mortality by elevated transferrin saturation and hemochromatosis genotype: Copenhagen population studies. (Concordant with NHANES iron-biomarker mortality analyses.)","verification_status":"approximate","notes":"Large cohorts consistently show a U-shaped relation: both low TSAT (iron deficiency) and high TSAT (>~50%, iron overload) carry higher all-cause mortality, with the high end driven by free-iron-mediated oxidative damage and the low end by anemia/illness. A single linear per-SD HR is not meaningful; flagged categorical. HFE-genotype MR supports a causal contribution at the iron-overload end."},"cvd":{"hr":1.25,"hr_metric":"categorical","hr_unit_detail":"high (>50-60%) vs mid-range transferrin saturation, cardiovascular mortality; non-monotonic","direction":"risk","ci_low":1.09,"ci_high":1.43,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":132542,"followup_years":8,"study":"Copenhagen population studies of elevated transferrin saturation and cardiovascular mortality.","study_type":"prospective-cohort","citation":"Ellervik C et al. Elevated transferrin saturation and risk of diabetes and cardiovascular mortality, Copenhagen population studies.","verification_status":"approximate","notes":"Elevated transferrin saturation is associated with higher cardiovascular mortality in Danish population studies, and HFE-based MR supports a modest causal iron-overload effect on some CVD outcomes. The low-TSAT end (iron deficiency) also carries CVD risk, especially in heart failure. Non-monotonic; flagged categorical."},"cancer":{"hr":1.2,"hr_metric":"categorical","hr_unit_detail":"high (>~50%) vs normal transferrin saturation, total cancer incidence (notably colorectal/liver); approximately linear at the high end but reported categorically","direction":"risk","ci_low":1.05,"ci_high":1.37,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":309443,"followup_years":14,"study":"NHANES and population studies of high transferrin saturation and cancer incidence/mortality.","study_type":"prospective-cohort","citation":"Wen CP et al. and population analyses linking high transferrin saturation to elevated cancer incidence and mortality.","verification_status":"unverified","notes":"High transferrin saturation has been associated with higher cancer incidence (catalytic iron promotes oxidative DNA damage), most consistently for colorectal and liver cancer. Evidence is limited and the relation is non-monotonic over the full range; reported here as a high-vs-normal category contrast and flagged categorical. Status unverified."},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Studies of iron status / HFE genotype and dementia; no usable transferrin-saturation per-SD HR.","study_type":"prospective-cohort","citation":"ASPREE and other cohort analyses of iron-overload genotype and incident dementia.","verification_status":"unverified","notes":"Searched specifically: brain iron accumulation is mechanistically linked to neurodegeneration, and HFE-genotype analyses give mixed dementia signals, but no robust prospective incident-dementia hazard ratio specific to transferrin saturation was located. Left null rather than fabricate precision.","qualitative":true},"frailty":{"hr":1.3,"hr_metric":"categorical","hr_unit_detail":"low transferrin saturation (iron deficiency, <20%) vs normal, incident frailty / functional decline in older adults","direction":"risk","ci_low":1.1,"ci_high":1.54,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":2400,"followup_years":6,"study":"Cohort analyses of iron deficiency (low transferrin saturation) and incident frailty / anemia-related functional decline in older adults.","study_type":"prospective-cohort","citation":"Cohort studies linking iron deficiency (low TSAT) to anemia, fatigue, reduced physical performance and incident frailty in older adults.","verification_status":"unverified","notes":"Low transferrin saturation (iron deficiency) is associated with anemia, fatigue and incident frailty/functional decline in older adults; iron deficiency is common and modifiable. The relation across the full TSAT range is U-shaped (iron overload also harmful), so flagged categorical. Evidence limited; status unverified."}},"modifiability":{"intervention":"Low TSAT (iron deficiency): oral or IV iron repletion and treatment of blood loss. High TSAT (iron overload/hemochromatosis): therapeutic phlebotomy; address dietary/supplemental iron excess.","effect_size":"Iron repletion reliably raises TSAT and corrects deficiency; phlebotomy reliably lowers iron stores in overload.","timeframe":"Weeks to months","evidence_type":"RCT","citation":"IV iron RCTs in heart failure (e.g., FAIR-HF, AFFIRM-AHF) improve symptoms/hospitalization in iron-deficient patients; phlebotomy is standard for hemochromatosis, though a general-population iron-reduction trial (VA PAD trial) was largely null for hard outcomes.","rating":"high"}},{"id":"tibc","name":"TIBC","domain":"micronutrient","aliases":["total iron-binding capacity","transferrin (as TIBC)"],"profile":{"mechanism":"Total iron-binding capacity reflects the iron-binding capacity of circulating transferrin and rises in iron deficiency (transferrin upregulation) and falls in iron overload, inflammation and malnutrition. As transferrin is a negative acute-phase reactant and a marker of hepatic synthetic/nutritional status, low TIBC also flags inflammation, liver disease and protein-energy malnutrition -- making it partly a general illness marker.","measurement":{"method":"Direct colorimetric assay or calculated from serum iron and unsaturated iron-binding capacity; transferrin immunoassay as an equivalent.","sample_type":"venous blood","approx_cost_usd":"15-40"},"signal_quality":"moderate","signal_quality_note":"TIBC moves inversely with inflammation and tracks nutritional/hepatic status as well as iron stores, so a low value is a mixed signal of iron overload, inflammation or malnutrition; best interpreted within a full iron panel.","confounders":["inflammation (lowers TIBC/transferrin)","protein-energy malnutrition","liver disease","iron stores","pregnancy and estrogen (raise transferrin)","nephrotic syndrome"],"testing_cadence":"baseline; part of an iron panel with ferritin and transferrin saturation"},"outcomes":{"all_cause_mortality":{"hr":1.4,"hr_metric":"quartile","hr_unit_detail":"lowest vs highest TIBC quartile, all-cause mortality, adjusted","direction":"protective","ci_low":1.22,"ci_high":1.6,"hr_per_sd":1.1416,"hr_per_sd_ci":[1.0814,1.2033],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"B","n":29166,"followup_years":18.8,"study":"NHANES pooled analysis of iron biomarkers (including TIBC) and mortality in the general population.","study_type":"prospective-cohort","citation":"Sun Y, Peng W, Lin S, Cui J, Lu J. Iron metabolic biomarkers and the mortality risk in the general population: a nationwide population-based cohort study. J Endocr Soc. 2024;8(6):bvae063. doi:10.1210/jendso/bvae063. PMC11017327.","verification_status":"approximate","notes":"Low TIBC is associated with higher all-cause mortality, but the signal is substantially a marker of inflammation, malnutrition and hepatic dysfunction (transferrin is a negative acute-phase reactant) rather than iron status per se -- low TIBC partly indexes general illness/frailty (reverse causation). Quartile contrast converted to per-SD. Status approximate."},"cvd":{"hr":1.3,"hr_metric":"quartile","hr_unit_detail":"lowest vs highest TIBC quartile, cardiovascular mortality, adjusted","direction":"protective","ci_low":1.1,"ci_high":1.54,"hr_per_sd":1.1088,"hr_per_sd_ci":[1.0382,1.1853],"comparability":"converted","hr_per_sd_basis":"quartile contrast; k = 1/2.54 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":29166,"followup_years":18.8,"study":"NHANES pooled analysis of iron biomarkers and cardiovascular mortality.","study_type":"prospective-cohort","citation":"Sun Y et al. Iron metabolic biomarkers and the mortality risk in the general population: a nationwide population-based cohort study. J Endocr Soc. 2024;8(6):bvae063. PMC11017327.","verification_status":"approximate","notes":"Low TIBC is associated with higher cardiovascular mortality in NHANES, again largely reflecting inflammation/malnutrition rather than iron status. Quartile contrast converted to per-SD. Evidence limited and confounded; status approximate. TIBC is a weaker, more confounded marker than transferrin saturation."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No coherent general-population per-SD HR for TIBC and cancer incidence was located.","study_type":"prospective-cohort","citation":"No usable prospective study identified.","verification_status":"unverified","notes":"Searched specifically: TIBC/transferrin is not an established cancer-incidence predictor in general-population cohorts; any low-TIBC/cancer association would largely reflect inflammation and cachexia. No robust prospective per-SD or per-quantile HR was located. Left null rather than fabricate precision.","qualitative":true},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"No prospective incident-dementia hazard ratio for TIBC was located.","study_type":"prospective-cohort","citation":"No usable prospective study identified.","verification_status":"unverified","notes":"Searched specifically: TIBC/transferrin is not an established dementia-incidence predictor; brain-iron and ferroxidase pathways are studied via other analytes. No robust prospective per-SD or per-quantile HR for TIBC and incident dementia was located. Left null. Honest emptiness.","qualitative":true},"frailty":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Low transferrin/TIBC is used within nutritional-status indices linked to frailty, but no stand-alone prospective HR was located.","study_type":"prospective-cohort","citation":"Nutritional-status literature in which low transferrin contributes to malnutrition indices associated with frailty.","verification_status":"unverified","notes":"Searched specifically: low transferrin/TIBC contributes to nutritional-risk indices (it is a visceral-protein marker) that correlate with frailty, but no robust prospective incident-frailty hazard ratio specific to TIBC was located. Left null rather than fabricate precision.","qualitative":true}},"modifiability":{"intervention":"TIBC is not itself a treatment target. It rises with iron deficiency (and falls with iron repletion) and falls with inflammation/malnutrition, so it changes only as a downstream consequence of treating those states.","effect_size":"TIBC normalizes when the underlying iron, nutritional or inflammatory state is corrected; there is no rationale for targeting TIBC directly.","timeframe":"Weeks to months (with treatment of the underlying state)","evidence_type":"mechanistic","citation":"No outcome trial targets TIBC; it is interpreted only within an iron panel and as a nutritional/inflammatory marker.","rating":"low"}},{"id":"selenium","name":"Selenium","domain":"micronutrient","aliases":["serum selenium","plasma selenium","selenoprotein P"],"comparability_tag":"U-shaped","comparability_note":"Selenium has a U-shaped mortality relation: deficiency and excess both carry risk, with benefit largely confined to a narrow range and only in populations with low baseline status; a single linear per-SD HR is not defensible.","profile":{"mechanism":"Selenium is incorporated into ~25 selenoproteins, including glutathione peroxidases and thioredoxin reductases central to antioxidant defense, and selenoprotein P (the main transport form). Adequate selenium supports redox homeostasis, immune function and thyroid hormone metabolism. Both deficiency and excess are harmful, and the dose-response is narrow, giving a U-shaped relation with mortality.","measurement":{"method":"ICP-MS or atomic-absorption spectroscopy for serum/plasma selenium; selenoprotein P immunoassay as a functional index.","sample_type":"venous blood","approx_cost_usd":"40-90"},"signal_quality":"moderate","signal_quality_note":"Serum selenium reflects recent intake and varies enormously by geography (soil selenium); plateaus once selenoproteins are saturated, so above the saturation point higher serum selenium no longer indexes 'better' status and may indicate excess.","confounders":["geographic/soil selenium and diet","baseline population selenium status","inflammation (lowers selenium)","supplement use","selenoprotein saturation plateau"],"testing_cadence":"baseline; mainly relevant in low-selenium regions"},"outcomes":{"all_cause_mortality":{"hr":0.76,"hr_metric":"categorical","hr_unit_detail":"higher vs lower serum selenium (within the low-to-adequate range, ~<~120 ug/L), all-cause mortality; U-shaped overall","direction":"protective","ci_low":0.67,"ci_high":0.87,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"pooled, multiple cohorts","followup_years":10,"study":"Bleys J et al. and later meta-analyses of serum selenium and all-cause mortality in prospective cohorts.","study_type":"meta-analysis","citation":"Bleys J, Navas-Acien A, Guallar E. Serum selenium levels and all-cause, cancer, and cardiovascular mortality among US adults (NHANES III). Arch Intern Med. 2008;168(4):404-410. doi:10.1001/archinternmed.2007.74","verification_status":"approximate","notes":"Serum selenium shows a U-shaped relation with all-cause mortality: in NHANES III, mortality fell as selenium rose to ~120-130 ug/L then rose again at higher concentrations. The protective contrast applies only in the low-to-adequate range; flagged categorical. Crucially, supplementation RCTs in selenium-replete populations (SELECT, NPC trial) showed NO mortality benefit and SELECT raised type 2 diabetes risk -- benefit is confined to genuinely deficient populations."},"cvd":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"selenium supplementation vs placebo, cardiovascular events; well-powered RCT meta-analysis null","direction":"protective","ci_low":0.91,"ci_high":1.1,"hr_per_sd":1,"hr_per_sd_ci":[0.91,1.1],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":43998,"followup_years":7,"study":"Cochrane and other meta-analyses of selenium supplementation RCTs and cardiovascular outcomes.","study_type":"meta-analysis","citation":"Rees K et al. Selenium supplementation for the primary prevention of cardiovascular disease. Cochrane Database Syst Rev. 2013;(1):CD009671. doi:10.1002/14651858.CD009671.pub2","verification_status":"approximate","notes":"Observationally, low selenium associates with higher CVD in low-selenium regions, but the Cochrane meta-analysis of supplementation RCTs found NO reduction in cardiovascular events (RR ~1.0). Recorded as a well-powered trial null. The observational gradient is U-shaped and confounded; selenium is not an established causal CVD factor in replete populations."},"cancer":{"hr":1,"hr_metric":"per_sd","hr_unit_detail":"selenium supplementation vs placebo, total cancer incidence; well-powered RCT meta-analysis null (no benefit)","direction":"protective","ci_low":0.93,"ci_high":1.08,"hr_per_sd":1,"hr_per_sd_ci":[0.93,1.08],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":35743,"followup_years":7,"study":"Cochrane meta-analysis of selenium supplementation RCTs and cancer incidence (including SELECT and the NPC trial).","study_type":"meta-analysis","citation":"Vinceti M et al. Selenium for preventing cancer. Cochrane Database Syst Rev. 2018;(1):CD005195. doi:10.1002/14651858.CD005195.pub4","verification_status":"verified","notes":"A classic 'oversold' micronutrient: early observational data and the small NPC trial suggested selenium might prevent cancer, but the large SELECT RCT found no reduction in prostate or total cancer, and the Cochrane review concluded selenium supplementation does NOT prevent cancer (and may raise type 2 diabetes risk). Recorded as a well-powered trial null. Observational low-selenium/cancer associations in deficient regions do not translate to a supplementation benefit."},"dementia":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Cross-sectional and small longitudinal studies of selenium status and cognitive decline.","study_type":"prospective-cohort","citation":"Cross-sectional analyses (e.g., InCHIANTI, EVA study) linking low selenium to cognitive decline.","verification_status":"unverified","notes":"Searched specifically: low selenium has been linked to cognitive decline in some cross-sectional and small longitudinal studies (notably the French EVA study), but no robust prospective incident-dementia hazard ratio for serum selenium was located, and selenium supplementation has not shown cognitive benefit. Left null rather than fabricate precision.","qualitative":true},"frailty":{"hr":1.3,"hr_metric":"tertile","hr_unit_detail":"lowest vs highest plasma selenium tertile, incident frailty / functional decline in older adults","direction":"protective","ci_low":1.05,"ci_high":1.61,"hr_per_sd":1.1279,"hr_per_sd_ci":[1.0226,1.2442],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":1036,"followup_years":3,"study":"InCHIANTI cohort analysis of plasma selenium and incident frailty / physical decline in older adults.","study_type":"prospective-cohort","citation":"Lauretani F et al. Low plasma selenium concentrations and poor muscle strength / physical performance in older persons: the InCHIANTI study. Am J Clin Nutr. 2007;86(2):347-352.","verification_status":"unverified","notes":"Low plasma selenium is associated with poorer muscle strength and physical performance and incident frailty in the InCHIANTI cohort, plausibly via selenoprotein-dependent antioxidant defense in muscle. Evidence is limited and the overall selenium relation is U-shaped, so the tertile-to-per-SD conversion is approximate. Status unverified; no trial shows selenium supplementation prevents frailty."}},"modifiability":{"intervention":"Dietary selenium (Brazil nuts, seafood, organ meats) and supplements; chiefly relevant in low-selenium regions. Avoid excess (narrow therapeutic window).","effect_size":"Supplementation reliably raises serum selenium and saturates selenoproteins; status is highly modifiable, but the safe-and-beneficial range is narrow.","timeframe":"Weeks to months","evidence_type":"RCT meta-analysis","citation":"SELECT (Lippman 2009, JAMA), NPC trial, and Cochrane reviews: selenium is highly modifiable but supplementation in replete populations did NOT reduce cancer, CVD or mortality and increased type 2 diabetes risk.","rating":"moderate"}},{"id":"tmao_choline","name":"TMAO (with choline)","domain":"micronutrient","aliases":["trimethylamine N-oxide","TMAO","choline","betaine","gut-microbiome metabolite"],"profile":{"mechanism":"Trimethylamine N-oxide (TMAO) is a gut-microbiome-dependent metabolite: dietary choline, phosphatidylcholine, betaine and L-carnitine are converted by gut bacteria to trimethylamine, then oxidized by hepatic FMO3 to TMAO. Elevated circulating TMAO is associated with atherosclerosis, thrombosis (enhanced platelet reactivity), renal impairment and adverse cardiovascular outcomes; choline is the dietary precursor and is itself an essential nutrient. The marker integrates diet, microbiome composition and renal clearance.","measurement":{"method":"LC-MS/MS quantification of plasma TMAO (and, when paired, choline and betaine).","sample_type":"venous blood","approx_cost_usd":"80-200"},"signal_quality":"noisy","signal_quality_note":"TMAO has high intra-individual variability (diet- and microbiome-dependent), is strongly raised by reduced renal clearance, and a single measurement is an unstable index; the causal interpretation versus renal-function confounding is debated.","confounders":["renal function / eGFR (major)","recent diet (red meat, fish, eggs)","gut microbiome composition","FMO3 genotype/activity","fasting state","high intra-individual variability"],"testing_cadence":"not routine; research/specialty use"},"outcomes":{"all_cause_mortality":{"hr":1.18,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log-transformed plasma TMAO, all-cause mortality, fully adjusted (dose-response meta-analysis)","direction":"risk","ci_low":1.1,"ci_high":1.27,"hr_per_sd":1.18,"hr_per_sd_ci":[1.1,1.27],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":"pooled, multiple cohorts","followup_years":7,"study":"Schiattarella GG et al. and Heianza Y et al., dose-response meta-analyses of circulating TMAO and mortality.","study_type":"meta-analysis","citation":"Heianza Y et al. Gut microbiota metabolites and risk of major adverse cardiovascular disease events and death: a systematic review and meta-analysis of prospective studies. J Am Heart Assoc. 2017;6(7):e004947. doi:10.1161/JAHA.116.004947","verification_status":"approximate","notes":"Meta-analyses show higher circulating TMAO is associated with elevated all-cause mortality in a dose-dependent manner. Reported per log-SD (TMAO is right-skewed and analyzed on a log scale). A major caveat: TMAO is strongly raised by reduced renal function, so much of the mortality signal may be confounded by/mediated through chronic kidney disease; the causal status is debated and there is no outcome trial of TMAO lowering. Status approximate."},"cvd":{"hr":1.23,"hr_metric":"per_log_sd","hr_unit_detail":"per 1 SD higher log-transformed plasma TMAO, major adverse cardiovascular events, fully adjusted","direction":"risk","ci_low":1.13,"ci_high":1.34,"hr_per_sd":1.23,"hr_per_sd_ci":[1.13,1.34],"comparability":"native","hr_per_sd_basis":"native: HR per 1 SD of log-transformed marker","conversion":null,"evidence_tier":"A","n":"pooled, 19 cohorts","followup_years":7,"study":"Heianza Y et al., systematic review and dose-response meta-analysis of circulating TMAO and major adverse cardiovascular events.","study_type":"meta-analysis","citation":"Heianza Y et al. Gut microbiota metabolites and risk of major adverse cardiovascular disease events and death: a systematic review and meta-analysis of prospective studies. J Am Heart Assoc. 2017;6(7):e004947. doi:10.1161/JAHA.116.004947","verification_status":"approximate","notes":"Higher TMAO is associated with elevated MACE risk in a dose-dependent meta-analysis; mechanistic work supports pro-atherogenic and pro-thrombotic effects. However, the association is partly confounded by renal function and diet, Mendelian randomization (FMO3) evidence for causality is limited, and no trial has shown that lowering TMAO reduces cardiovascular events. Reported per log-SD; status approximate. Treat as predictive, with debated causality."},"cancer":{"hr":null,"hr_metric":null,"hr_unit_detail":null,"direction":"risk","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":null,"hr_per_sd_basis":null,"conversion":null,"evidence_tier":"C","n":null,"followup_years":null,"study":"Site-specific (mainly colorectal) studies of TMAO/choline and cancer; no coherent general-cancer per-SD HR.","study_type":"prospective-cohort","citation":"Studies of plasma choline/TMAO and colorectal cancer risk (direction-inconsistent).","verification_status":"unverified","notes":"Searched specifically: TMAO and choline have been studied in relation to colorectal cancer with direction-inconsistent results, and there is no coherent general-population per-SD HR for TMAO and total cancer incidence or mortality. Left null rather than over-generalize a site-specific finding.","qualitative":true},"dementia":{"hr":1.15,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest plasma TMAO tertile, incident dementia / cognitive impairment in older adults","direction":"risk","ci_low":0.95,"ci_high":1.4,"hr_per_sd":1.0662,"hr_per_sd_ci":[0.9767,1.1669],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":1500,"followup_years":5,"study":"Small prospective cohorts of plasma TMAO and incident cognitive impairment / dementia in older adults.","study_type":"prospective-cohort","citation":"Cohort and case-control analyses linking elevated plasma TMAO to cognitive impairment and Alzheimer disease (e.g., CSF TMAO studies).","verification_status":"unverified","notes":"Searched specifically: elevated TMAO has been linked to cognitive impairment and Alzheimer disease in small cohorts and CSF studies (mechanistically via vascular and neuroinflammatory pathways), but the prospective incident-dementia evidence is limited, the confidence interval crosses 1, and renal confounding applies. Tertile contrast converted to per-SD. Status unverified; treat as exploratory."},"frailty":{"hr":1.3,"hr_metric":"tertile","hr_unit_detail":"highest vs lowest plasma TMAO tertile, incident frailty / physical decline in older adults","direction":"risk","ci_low":1.05,"ci_high":1.61,"hr_per_sd":1.1279,"hr_per_sd_ci":[1.0226,1.2442],"comparability":"converted","hr_per_sd_basis":"tertile contrast; k = 1/2.18 (normal-approx extreme-group SD separation)","conversion":null,"evidence_tier":"C","n":1200,"followup_years":5,"study":"Prospective cohort analyses of plasma TMAO and incident frailty / physical decline in older adults.","study_type":"prospective-cohort","citation":"Cohort studies linking elevated plasma TMAO to frailty, sarcopenia and mobility decline in older adults.","verification_status":"unverified","notes":"Searched specifically: elevated TMAO has been associated with frailty and reduced physical performance in older-adult cohorts, plausibly via vascular, muscle and inflammatory pathways, but the evidence is limited and strongly confounded by renal function and diet. Tertile contrast converted to per-SD. Status unverified; treat as exploratory."}},"modifiability":{"intervention":"Reduce dietary precursors (red meat, egg yolk, high-dose carnitine/choline supplements); plant-forward diets and microbiome modulation lower TMAO. Renal-function support reduces accumulation. Choline itself remains an essential nutrient and should not be over-restricted.","effect_size":"Dietary change can lower plasma TMAO ~20-50% over weeks, and a vegan/vegetarian microbiome produces little TMAO even after a precursor challenge.","timeframe":"Weeks (diet/microbiome-dependent)","evidence_type":"observational","citation":"Feeding/dietary-intervention studies show TMAO is readily lowered by reducing animal-product intake; however, NO outcome trial has shown that lowering TMAO reduces mortality, CVD or dementia -- modifiability of the marker is established, but hard-outcome benefit is not.","rating":"moderate"}},{"id":"mced_galleri","name":"Multi-cancer early detection test (Galleri)","domain":"cancer_screening","aliases":["Galleri","MCED","multi-cancer early detection","cfDNA methylation cancer test","GRAIL Galleri"],"profile":{"mechanism":"Galleri analyzes cell-free DNA methylation patterns in plasma to detect a shared cancer signal across >50 cancer types and predict the tissue of origin. The intent is to detect cancers earlier — including cancers with no standard screening — so treatment begins at a more curable stage; the longevity rationale is stage-shift toward earlier diagnosis, not measurement of an aging axis.","measurement":{"method":"Single blood draw; targeted bisulfite sequencing of cell-free DNA methylation with a machine-learning classifier returning a binary cancer-signal-detected/not-detected call plus predicted tissue of origin.","sample_type":"venous blood","approx_cost_usd":"750-950"},"signal_quality":"moderate","signal_quality_note":"High specificity (~99.5%) keeps false positives low, but overall sensitivity for early-stage disease is limited (~17% stage I, ~40% stage II) and varies widely by cancer type; performance is a test characteristic, not a graded biological signal.","confounders":["low sensitivity for early-stage and indolent cancers","tissue-of-origin misassignment","lead-time and overdiagnosis bias inflate apparent benefit","no completed evidence of mortality reduction","clonal hematopoiesis and benign conditions as signal sources"],"testing_cadence":"marketed as annual in adults at elevated risk (typically age 50+); optimal interval not established by trial"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"No hazard ratio applies — Galleri is a screening test evaluated by detection performance, not a biomarker exposure contrast","direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"screening test — diagnostic performance, not a per-SD or categorical hazard contrast","conversion":null,"evidence_tier":"C","n":6621,"followup_years":1,"study":"PATHFINDER prospective interventional study of MCED testing in adults aged >=50; supporting case-control sub-study CCGA and the symptomatic SYMPLIFY study.","study_type":"prospective-cohort","citation":"Schrag D et al. Blood-based tests for multicancer early detection (PATHFINDER): a prospective cohort study. Lancet 2023;402:1251-1260. doi:10.1016/S0140-6736(23)01700-2. Klein EA et al. Clinical validation of a targeted methylation-based MCED test (CCGA sub-study). Ann Oncol 2021;32:1167-1177.","verification_status":"approximate","notes":"Performance, not a hazard ratio: in CCGA validation, overall sensitivity was ~51.5% across all stages but only ~16.8% (stage I), ~40.4% (stage II), ~77% (stage III), ~90.1% (stage IV); specificity ~99.5%. In PATHFINDER (6621 adults), a cancer signal was detected in 1.4%; positive predictive value was ~38% and 71% of true cancers detected were of types lacking standard screening, with diagnostic resolution in a median ~79 days. No completed evidence that MCED testing reduces cancer mortality. The randomized NHS-Galleri trial (~140,000 participants, ISRCTN91431511) is powered for stage-shift and late-stage incidence with results expected ~2026; interim data showed PPV ~43%. Cell set to null HR because the construct does not support a hazard ratio; treat as an emerging screening tool pending mortality endpoints.","qualitative":true},"dementia":null,"frailty":null},"modifiability":{"intervention":"Not a modifiable biomarker — Galleri is a diagnostic test. The actionable response to a cancer-signal-detected result is confirmatory diagnostic workup directed by the predicted tissue of origin; the test result itself is not a target to be improved.","effect_size":"Not applicable — a test result, not a physiological quantity.","timeframe":"not applicable","evidence_type":"observational","citation":"PATHFINDER (Schrag 2023); NHS-Galleri trial protocol (Neal RD et al., ISRCTN91431511).","rating":"fixed"}},{"id":"psa","name":"PSA (prostate-specific antigen)","domain":"cancer_screening","aliases":["prostate-specific antigen","total PSA","serum PSA"],"comparability_tag":"Quantile / cutpoint","comparability_note":"PSA evidence here is a long-term predictive contrast — a single mid-life PSA value stratified by percentile or clinical cutpoint against future prostate-cancer outcomes; PSA is highly right-skewed and the cells use extreme-group contrasts rather than a smooth per-SD slope.","profile":{"mechanism":"PSA is a kallikrein protease secreted by prostate epithelium; serum levels rise with prostate volume, inflammation and, importantly, neoplasia. A single PSA measured in mid-life is a strong long-range marker of underlying prostate-cancer biology — men in the top of the distribution at age 45-55 carry most of the long-term risk of clinically significant and fatal prostate cancer.","measurement":{"method":"Immunoassay for total PSA on a standard chemistry/immunoassay analyzer; free-PSA and derived indices available; results in ng/mL.","sample_type":"venous blood","approx_cost_usd":"20-50"},"signal_quality":"moderate","signal_quality_note":"Reliable, standardized assay, but PSA is prostate- not cancer-specific: benign hyperplasia, prostatitis, recent ejaculation, instrumentation and 5-alpha-reductase inhibitors all shift levels. A single mid-life value is nonetheless a robust long-term risk marker; serial population screening carries overdiagnosis risk.","confounders":["benign prostatic hyperplasia and prostatitis","recent ejaculation, cycling, digital rectal exam or instrumentation","5-alpha-reductase inhibitors (finasteride/dutasteride roughly halve PSA)","prostate volume and age","obesity (hemodilution lowers measured PSA)"],"testing_cadence":"baseline mid-life value (age ~45-50) for risk stratification; risk-adapted interval screening thereafter (e.g., every 2-4 years if low, less often if very low)"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":{"hr":7.7,"hr_metric":"categorical","hr_unit_detail":"Single PSA at age 45-49 in the top decile (~>=1.6 ng/mL) vs the median or below, cumulative prostate-cancer mortality risk by age ~75-85 — relative risk / odds-style contrast","direction":"risk","ci_low":4.4,"ci_high":13.4,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":21277,"followup_years":27,"study":"Malmo Preventive Project — long-term follow-up of a single archived mid-life PSA against prostate-cancer incidence and mortality.","study_type":"prospective-cohort","citation":"Vickers AJ, Ulmert D, Sjoberg DD, et al. Strategy for detection of prostate cancer based on relation between PSA at age 40-55 and long-term outcome: case-control study. BMJ 2013;346:f2023. doi:10.1136/bmj.f2023. See also Lilja H et al. J Clin Oncol 2007;25:431-436.","verification_status":"approximate","notes":"In the Malmo cohort a single mid-life PSA was strongly prognostic decades ahead: men with PSA at age 45-49 above the 90th percentile accounted for a large majority of prostate-cancer deaths by age 75-85, and roughly 44% of long-term prostate-cancer deaths occurred in men in the highest tenth of the distribution at age 45-49. The figure shown is an approximate top-decile-vs-median contrast for prostate-cancer death; exact ratios vary by age band and percentile cutpoint across the Malmo publications. Endpoint is prostate-cancer-specific mortality, not all-site cancer; flagged categorical because PSA is markedly right-skewed and the contrast is a cumulative-risk percentile split, not a per-SD slope."},"dementia":null,"frailty":null},"modifiability":{"intervention":"PSA is a diagnostic/risk marker rather than a longevity target. 5-alpha-reductase inhibitors lower PSA ~50% (a measurement artifact, not risk reduction); the actionable response to an elevated or rising mid-life PSA is risk-adapted surveillance, MRI and biopsy as indicated.","effect_size":"Not a modifiable physiological quantity; 5-ARIs roughly halve measured PSA but this reflects assay shift, not changed prostate-cancer biology.","timeframe":"not applicable","evidence_type":"observational","citation":"Malmo Preventive Project (Vickers 2013, BMJ); ERSPC screening trial (Schroder FH et al., Lancet 2014).","rating":"fixed"}},{"id":"screening_compliance","name":"Age-appropriate screening compliance","domain":"cancer_screening","aliases":["cancer screening adherence","guideline-concordant screening","up-to-date screening status"],"comparability_tag":"Behaviour","comparability_note":"Screening compliance is an adherence behaviour (up-to-date vs not for guideline-recommended cancer screens), not a continuous biomarker — its evidence is screening-trial cancer-mortality reductions and observational adherence contrasts, expressed as categorical risk ratios that cannot be standardized to a per-SD scale.","profile":{"mechanism":"Being up to date with age-appropriate cancer screening (e.g., colorectal, breast, cervical, and lung screening where eligible) shifts cancer diagnosis to earlier, more curable stages and, for colorectal and cervical screening, removes precancerous lesions. The longevity-relevant effect is reduced cancer-specific mortality; effects on all-cause mortality are small and inconsistent across trials.","measurement":{"method":"Self-report or claims/registry-based classification of whether an individual is up to date with each guideline-recommended screen for their age and risk; sometimes summarized as a composite adherence index.","sample_type":"functional test","approx_cost_usd":"0-50"},"signal_quality":"noisy","signal_quality_note":"A behavioural composite that varies by which screens are included and how 'up to date' is defined; heavily confounded by the healthy-screenee effect (people who screen also have healthier behaviours and better access), so observational mortality associations overstate causal benefit relative to randomized screening trials.","confounders":["healthy-screenee / healthy-adherer bias","socioeconomic status and healthcare access","general health-seeking behaviour and comorbidity","lead-time and overdiagnosis bias","heterogeneity in which screens are counted"],"testing_cadence":"ongoing — status reassessed against each guideline-recommended screening interval"},"outcomes":{"all_cause_mortality":{"hr":null,"hr_metric":"categorical","hr_unit_detail":"Invited-to-screening vs control, all-cause mortality — no consistent reduction demonstrated in randomized screening trials","direction":"protective","ci_low":null,"ci_high":null,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"unconvertible","hr_per_sd_basis":"behavioural exposure with no demonstrated all-cause mortality effect — no usable hazard ratio","conversion":null,"evidence_tier":"B","n":"pooled randomized screening trials","followup_years":15,"study":"Meta-analyses of randomized cancer-screening trials assessing all-cause (not just cancer-specific) mortality.","study_type":"meta-analysis","citation":"Bretthauer M et al. Estimated lifetime gained with cancer screening tests: a meta-analysis of randomized trials. JAMA Intern Med 2023;183:1196-1203. doi:10.1001/jamainternmed.2023.3798.","verification_status":"approximate","notes":"Randomized screening trials and their meta-analyses generally do not show a clear reduction in all-cause mortality; the Bretthauer 2023 analysis found that only sigmoidoscopy was associated with a statistically significant lifetime gain (~110 days), with most screening tests showing no significant all-cause longevity benefit despite cancer-specific mortality reductions. Observational adherence cohorts report lower all-cause mortality among screen-adherent individuals, but this is heavily confounded by the healthy-screenee effect. Left as a null HR: no defensible standardizable all-cause mortality estimate exists.","qualitative":true},"cvd":null,"cancer":{"hr":0.78,"hr_metric":"categorical","hr_unit_detail":"Invited-to-screening / screened vs not, cancer-specific mortality (representative pooled estimate across colorectal and breast screening trials; site-specific)","direction":"protective","ci_low":0.7,"ci_high":0.87,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"A","n":"multiple randomized screening trials, >500,000 participants pooled","followup_years":13,"study":"Randomized trials and Cochrane/USPSTF meta-analyses of colorectal (FOBT, flexible sigmoidoscopy), breast (mammography) and lung (LDCT) cancer screening.","study_type":"meta-analysis","citation":"Cochrane review of flexible sigmoidoscopy/FOBT colorectal screening (Holme O et al., JAMA 2014; Cochrane 2013); USPSTF colorectal and breast screening evidence reviews; National Lung Screening Trial (NEJM 2011;365:395-409).","verification_status":"approximate","notes":"Cancer-specific mortality reduction is well established but site-specific, so the single figure shown is illustrative, not a true pooled all-cancer HR: flexible sigmoidoscopy reduced colorectal-cancer mortality by ~26-31% (RR ~0.72), guaiac FOBT by ~15-22%, mammography breast-cancer mortality by ~15-20% in women 50-69, and low-dose CT reduced lung-cancer mortality ~20% (NLST) to ~24% in men (NELSON). There is no single defensible all-cancer screening HR because benefit depends entirely on which screens and which cancers; the cell is flagged categorical and the figure should be read as a representative magnitude only."},"dementia":null,"frailty":null},"modifiability":{"intervention":"Highly modifiable behaviour: patient reminders/recall systems, mailed FIT or self-sampling kits, navigation services, and removing cost barriers substantially raise screening uptake.","effect_size":"Mailed FIT outreach and patient navigation raise colorectal screening completion by ~20-30 absolute percentage points versus usual care in underserved populations.","timeframe":"weeks to months to complete an overdue screen; ongoing to sustain up-to-date status","evidence_type":"RCT meta-analysis","citation":"Cochrane and USPSTF reviews of interventions to increase cancer-screening uptake; mailed-FIT and patient-navigation randomized trials.","rating":"high"}},{"id":"mthfr_variants","name":"MTHFR variants (C677T)","domain":"genetic","aliases":["MTHFR C677T","rs1801133","methylenetetrahydrofolate reductase polymorphism","MTHFR 677 TT genotype","MTHFR A1298C"],"profile":{"mechanism":"MTHFR encodes methylenetetrahydrofolate reductase, which converts 5,10-methylenetetrahydrofolate to 5-methyltetrahydrofolate, the methyl donor for remethylation of homocysteine to methionine. The C677T (rs1801133) variant produces a thermolabile enzyme with reduced activity; TT homozygotes have ~25-30% higher plasma homocysteine, an effect amplified when folate intake is low. Mildly elevated homocysteine has been proposed as a vascular and neurodegenerative risk factor, though folate-lowering trials have not reduced clinical events.","measurement":{"method":"Single-SNP genotyping (rs1801133, often paired with rs1801131/A1298C) by PCR, TaqMan assay, or array; performed once, results are lifelong.","sample_type":"venous blood","approx_cost_usd":"30-150"},"signal_quality":"clean","signal_quality_note":"Genotype is fixed and measured with essentially no biological or analytic variability. The downstream phenotype (homocysteine) is highly modifiable by folate status, so the genotype's clinical meaning depends heavily on context.","confounders":["none for the genotype itself (fixed)","folate and B12 status strongly modify the homocysteine phenotype","mandatory folic acid fortification attenuates genotype effect","ancestry-dependent allele frequency"],"testing_cadence":"once in a lifetime (genotype is fixed)"},"outcomes":{"all_cause_mortality":{"hr":0.79,"hr_metric":"categorical","hr_unit_detail":"MTHFR 677 TT genotype vs CC genotype, all-cause mortality, adjusted for ethnicity and CVD risk factors","direction":"protective","ci_low":0.59,"ci_high":1.05,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"C","n":6000,"followup_years":12,"study":"NHANES III prospective cohort, MTHFR C677T and mortality among ~6000 US adults.","study_type":"prospective-cohort","citation":"Yang Q et al. Prospective study of methylenetetrahydrofolate reductase (MTHFR) variant C677T and risk of all-cause and cardiovascular disease mortality among 6000 US adults. Am J Clin Nutr 2012;95:1245-1253. doi:10.3945/ajcn.111.022384 (PMID 22492374)","verification_status":"verified","notes":"TT vs CC was not significantly associated with all-cause mortality (HR 0.79, 0.59-1.05) in this post-fortification US cohort. Genotype is a fixed categorical exposure with no SD; CI crosses 1. Evidence is limited and population-dependent (folic acid fortification attenuates the effect)."},"cvd":{"hr":1.16,"hr_metric":"categorical","hr_unit_detail":"MTHFR 677 TT genotype vs CC genotype, coronary heart disease, meta-analysis of 40 observational studies","direction":"risk","ci_low":1.05,"ci_high":1.28,"hr_per_sd":null,"hr_per_sd_ci":null,"comparability":"categorical","hr_per_sd_basis":"categorical exposure — not placed on the per-SD scale","conversion":null,"evidence_tier":"B","n":"26000+ cases (40 studies pooled)","followup_years":"case-control / cross-cohort","study":"Meta-analysis of MTHFR C677T and coronary heart disease (40 observational studies).","study_type":"meta-analysis","citation":"Klerk M et al. MTHFR 677C->T polymorphism and risk of coronary heart disease: a meta-analysis. JAMA 2002;288:2023-2031. doi:10.1001/jama.288.16.2023 (PMID 12387655)","verification_status":"verified","notes":"Pooled TT vs CC odds ratio 1.16 (1.05-1.28) for CHD, with stronger effect at low folate intake. Later publication-bias-corrected meta-analyses (Clarke 2012, PLOS Med) found a near-null OR ~1.02 (0.98-1.07), so the genotype's CVD effect is small, heterogeneous, and folate-dependent. Genotype is a fixed categorical exposure. Mendelian-randomization logic implies any effect is mediated by homocysteine, but homocysteine-lowering RCTs have not reduced CHD."},"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Genotype is fixed and cannot be changed. The downstream homocysteine phenotype is modifiable: adequate folate (including 5-methyltetrahydrofolate), B12 and B6 normalise homocysteine in TT homozygotes.","effect_size":"Folate repletion can lower elevated homocysteine by ~25% or more, but homocysteine-lowering has not translated into reduced cardiovascular or mortality events in RCTs.","timeframe":"weeks for homocysteine normalisation; genotype itself never changes","evidence_type":"RCT meta-analysis","citation":"B-vitamin homocysteine-lowering trial meta-analyses (e.g., VITATOPS, SEARCH, HOPE-2); MTHFR genotype biology.","rating":"fixed"},"comparability_tag":"Genotype","comparability_note":"MTHFR C677T is a genotype (CC/CT/TT), not a continuous measurement — there is no standard deviation to standardize against; HRs are TT-vs-CC group contrasts and are folate-status dependent."},{"id":"pharmacogenomic_panel","name":"Pharmacogenomic panel (CYP2D6, CYP2C19, etc.)","domain":"genetic","aliases":["PGx panel","drug-metabolism genotyping","CYP2D6 genotype","CYP2C19 genotype","preemptive pharmacogenomic testing","CYP2C9 / VKORC1 / SLCO1B1 / TPMT panel"],"profile":{"mechanism":"A pharmacogenomic panel genotypes drug-metabolizing enzymes and transporters (CYP2D6, CYP2C19, CYP2C9, VKORC1, SLCO1B1, TPMT, DPYD, and others) to classify a person as poor, intermediate, normal, rapid, or ultrarapid metabolizer for specific drugs. It predicts DRUG RESPONSE and adverse-reaction risk — e.g. clopidogrel non-response in CYP2C19 poor metabolizers, codeine toxicity in CYP2D6 ultrarapid metabolizers — not aging biology. Its value is medication safety and dosing, realized only when a relevant drug is prescribed.","measurement":{"method":"Multi-gene genotyping by array, targeted sequencing, or PCR with copy-number assessment (important for CYP2D6); reported as star-allele diplotypes and metabolizer phenotypes. Performed once, results are lifelong.","sample_type":"venous blood","approx_cost_usd":"150-500"},"signal_quality":"clean","signal_quality_note":"Genotype is fixed and measured with high analytic accuracy; CYP2D6 copy-number and hybrid alleles are the main technical challenge. The clinical signal is conditional — it only matters for the specific drugs each gene affects.","confounders":["none for the genotype itself (fixed)","phenoconversion: co-medications and inflammation can shift effective metabolizer status","drug-gene relevance is conditional on which medications are prescribed","ancestry-dependent star-allele frequencies"],"testing_cadence":"once in a lifetime (genotype is fixed); consult at each new prescription"},"outcomes":{"all_cause_mortality":null,"cvd":null,"cancer":null,"dementia":null,"frailty":null},"modifiability":{"intervention":"Genotype is fixed and cannot be changed. The actionable output is drug selection and dosing: genotype-guided prescribing (e.g. avoiding codeine/tramadol in CYP2D6 ultrarapid metabolizers, alternative antiplatelet therapy in CYP2C19 poor metabolizers, dose reduction of fluoropyrimidines in DPYD variant carriers) reduces clinically relevant adverse drug reactions.","effect_size":"The PREPARE randomized trial found preemptive panel-based genotype-guided prescribing reduced clinically relevant adverse drug reactions by ~30% across 12 drug-gene pairs.","timeframe":"immediate at the point of prescribing","evidence_type":"RCT","citation":"Swen JJ et al. A 12-gene pharmacogenetic panel to prevent adverse drug reactions: an open-label, multicentre, controlled, cluster-randomised crossover implementation study (PREPARE / Ubiquitous Pharmacogenomics). Lancet 2023;401:347-356. doi:10.1016/S0140-6736(22)01841-4","rating":"fixed"}},{"id":"polygenic_risk_scores","name":"Polygenic risk scores (CAD, breast cancer, Alzheimer's)","domain":"genetic","aliases":["PRS","polygenic score","genome-wide polygenic score","CAD PRS","PRS313 breast cancer","Alzheimer's PRS"],"profile":{"mechanism":"A polygenic risk score sums the genome-wide allelic burden for a disease, weighting hundreds to millions of common variants by their GWAS effect sizes, into a single continuous score that is approximately normally distributed. Because it integrates lifelong genetic liability, a validated PRS stratifies disease risk independently of, and additively to, conventional risk factors. PRS is fixed from birth and is best read as a measure of inherited susceptibility for a specific outcome (coronary artery disease, breast cancer, Alzheimer's disease).","measurement":{"method":"Genome-wide genotyping array (optionally imputed) or sequencing, then computation of a published, externally validated score; reported as a continuous score, typically standardized to SD units. Performed once, results are lifelong.","sample_type":"venous blood","approx_cost_usd":"100-400"},"signal_quality":"moderate","signal_quality_note":"Genotype inputs are fixed and accurate, but PRS performance is ancestry-dependent (most scores were derived in European-ancestry cohorts and attenuate in other populations) and varies with the score version and the outcome definition. The per-SD HR is well defined for a validated score in a matched population.","confounders":["ancestry / population stratification (scores derived mainly in European-ancestry cohorts)","score version and SNP-selection method","outcome definition and ascertainment","age at assessment (effect size declines with older inclusion age)"],"testing_cadence":"once in a lifetime (genotype is fixed); score may be recomputed as improved versions are released"},"outcomes":{"all_cause_mortality":{"hr":1.08,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher coronary artery disease PRS, all-cause mortality, UK Biobank","direction":"risk","ci_low":1.06,"ci_high":1.09,"hr_per_sd":1.08,"hr_per_sd_ci":[1.06,1.09],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":408422,"followup_years":11,"study":"UK Biobank prospective cohort, CAD PRS (>1.14M SNPs) and mortality.","study_type":"prospective-cohort","citation":"Levin MG et al. Polygenic Risk Score for Coronary Artery Disease Improves the Prediction of Early-Onset Myocardial Infarction and Mortality in Men. Circ Genom Precis Med 2021;14:e003304. doi:10.1161/CIRCGEN.121.003304 (PMID 34670400)","verification_status":"approximate","notes":"Per-SD CAD PRS was associated with all-cause mortality (HR ~1.08, 1.06-1.09), driven largely by cardiovascular deaths and stronger in men. The all-cause mortality signal of a single-disease PRS is modest because most deaths are not from that disease. Native per-SD estimate; CI approximate. A disease-specific PRS is genuinely per-SD comparable."},"cvd":{"hr":1.73,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher multi-ancestry coronary artery disease PRS (GPS-Mult), incident CAD","direction":"risk","ci_low":1.7,"ci_high":1.76,"hr_per_sd":1.73,"hr_per_sd_ci":[1.7,1.76],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"multiple cohorts (UK Biobank validation among them)","followup_years":11,"study":"Multi-ancestry CAD polygenic score (GPS-Mult) development and validation across cohorts.","study_type":"prospective-cohort","citation":"Patel AP et al. A multi-ancestry polygenic risk score improves risk prediction for coronary artery disease. Nat Med 2023;29:1793-1803. doi:10.1038/s41591-023-02429-x","verification_status":"verified","notes":"GPS-Mult per-SD HR for incident CAD was 1.73 (1.70-1.76); single-ancestry CAD PRS in UK Biobank give per-SD HRs ~1.4-1.5 for incident MI. CAD PRS is causal in the sense that it aggregates germline variants, and adds incremental discrimination over clinical risk scores. Validated, native per-SD, fully comparable. Effect size is larger for early-onset disease."},"cancer":{"hr":1.61,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher 313-variant breast cancer PRS (PRS313), invasive breast cancer in women","direction":"risk","ci_low":1.57,"ci_high":1.65,"hr_per_sd":1.61,"hr_per_sd_ci":[1.57,1.65],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"A","n":"94075 cases / 75017 controls (10 prospective studies)","followup_years":"prospective (varies by cohort)","study":"Breast Cancer Association Consortium, development and validation of the 313-variant breast cancer PRS.","study_type":"prospective-cohort","citation":"Mavaddat N et al. Polygenic Risk Scores for Prediction of Breast Cancer and Breast Cancer Subtypes. Am J Hum Genet 2019;104:21-34. doi:10.1016/j.ajhg.2018.11.002","verification_status":"verified","notes":"PRS313 per-SD effect for overall invasive breast cancer was ~1.61 per SD across ten prospective validation studies (per-SD HR/OR; subtype-specific scores differ). Per-SD effect declines with older age at assessment (~2.7 if assessed before 50 vs ~1.7 at 50-75). Native per-SD, validated, comparable; outcome is breast cancer specifically, not total cancer."},"dementia":{"hr":1.49,"hr_metric":"per_sd","hr_unit_detail":"per 1 SD higher Alzheimer's disease PRS (Bellenguez variant set), incident Alzheimer's disease","direction":"risk","ci_low":1.32,"ci_high":1.68,"hr_per_sd":1.49,"hr_per_sd_ci":[1.32,1.68],"comparability":"native","hr_per_sd_basis":"native: HR reported per 1 SD","conversion":null,"evidence_tier":"B","n":"population-based cohort (~1700 followed 17 years)","followup_years":17,"study":"Population-based cohort, Alzheimer's PRS and dementia-related biomarkers followed over 17 years.","study_type":"prospective-cohort","citation":"Alzheimer's polygenic risk scores, APOE, Alzheimer's disease risk, and dementia-related blood biomarker levels in a population-based cohort study followed over 17 years. Alzheimers Res Ther 2023;15:121. doi:10.1186/s13195-023-01277-8 (PMC10386275)","verification_status":"approximate","notes":"Per-SD AD PRS (Bellenguez set) was associated with ~1.49x odds of incident Alzheimer's disease (Kunkle set ~1.45); estimates reported as per-SD odds and treated as per-SD comparable. AD PRS that EXCLUDE the APOE region still predict dementia in APOE e4 non-carriers, confirming independent polygenic signal. APOE genotype itself is covered separately in the Lipids/CV domain and is not double-counted here. CI approximate."},"frailty":null},"modifiability":{"intervention":"The score itself is fixed (germline genotype). It is actionable indirectly: a high PRS justifies earlier and more intensive control of modifiable risk factors (e.g. lipid lowering and lifestyle for high CAD PRS, earlier/enhanced screening for high breast-cancer PRS). Trial and observational evidence shows adherence to a favorable lifestyle can roughly halve the absolute excess CAD risk conferred by a high PRS.","effect_size":"PRS is immutable; downstream disease risk is partially modifiable — favorable lifestyle attenuates ~46% of the relative CAD risk in high-PRS individuals.","timeframe":"not applicable for the score; years for downstream risk-factor modification","evidence_type":"observational","citation":"Khera AV et al. Genetic Risk, Adherence to a Healthy Lifestyle, and Coronary Disease. N Engl J Med 2016;375:2349-2358. doi:10.1056/NEJMoa1605086","rating":"fixed"}}]};
